CREATE OR REPLACE FUNCTION "public"."_cancel_ticket_internal"("p_ticket_id" "uuid", "p_previous_status" "text", "p_reason_code" "text", "p_actor_type" "text", "p_actor_id" "uuid", "p_comment" "text") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Terminal update
  UPDATE tickets
  SET
    status = 'CANCELLED',
    updated_at = NOW(),
    completed_at = NOW()
  WHERE id = p_ticket_id;

  -- Immutable event
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    previous_status,
    new_status,
    reason_code,
    actor_type,
    actor_id,
    comment,
    created_at
  ) VALUES (
    p_ticket_id,
    'CANCELLED',
    p_previous_status,
    'CANCELLED',
    p_reason_code,
    p_actor_type,
    p_actor_id,
    TRIM(p_comment),
    NOW()
  );
END;
$$;


ALTER FUNCTION "public"."_cancel_ticket_internal"("p_ticket_id" "uuid", "p_previous_status" "text", "p_reason_code" "text", "p_actor_type" "text", "p_actor_id" "uuid", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."accept_food_order"("p_order_id" "uuid", "p_hotel_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    -- Authorization
    IF NOT EXISTS (
        SELECT 1
        FROM hotel_members hm
        JOIN hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
        JOIN hotel_roles r ON r.id = hmr.role_id
        WHERE hm.hotel_id = p_hotel_id
          AND hm.user_id = auth.uid()
          AND r.code IN ('KITCHEN','KITCHEN_MANAGER','ADMIN','OWNER')
    ) THEN
        RAISE EXCEPTION 'Unauthorized kitchen action';
    END IF;

    PERFORM 1 FROM food_orders WHERE id = p_order_id FOR UPDATE;

    UPDATE food_orders
    SET status = 'ACCEPTED', updated_at = now()
    WHERE id = p_order_id
      AND status = 'CREATED';

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Order cannot be accepted';
    END IF;

    -- Assign kitchen staff (ownership)
    INSERT INTO food_order_assignments (
        id, 
        food_order_id,
        hotel_member_id,
        role,
        assigned_at
    )
    SELECT
        gen_random_uuid(),
        p_order_id,
        hm.id, -- Use hotel_member_id
        'KITCHEN',
        now()
    FROM hotel_members hm
    WHERE hm.hotel_id = p_hotel_id 
      AND hm.user_id = auth.uid()
    ON CONFLICT DO NOTHING;

    -- Start SLA (anchored to order creation time, not accept time)
    INSERT INTO food_order_sla_state (
        food_order_id,
        sla_started_at,
        sla_target_at
    )
    SELECT
        p_order_id,
        now(),
        fo.created_at + (COALESCE(sp.target_minutes, 30) || ' minutes')::interval
    FROM food_orders fo
    JOIN departments d ON d.hotel_id = fo.hotel_id AND d.code = 'KITCHEN'
    LEFT JOIN sla_policies sp ON sp.department_id = d.id AND sp.is_active = true AND sp.valid_to IS NULL
    WHERE fo.id = p_order_id
    ON CONFLICT DO NOTHING;

    INSERT INTO food_order_events
    VALUES (
        gen_random_uuid(),
        p_order_id,
        'ORDER_ACCEPTED',
        'KITCHEN',
        auth.uid(),
        '{}',
        now()
    );
END;
$$;


ALTER FUNCTION "public"."accept_food_order"("p_order_id" "uuid", "p_hotel_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."accept_hotel_invite"("p_token" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_invite RECORD;
    v_user_id uuid;
    v_user_email text;
    v_membership_id uuid;
    v_role_code text;
    v_hotel_status public.hotel_lifecycle_status;
    v_full_name text;
BEGIN
    -- 1. Require authentication & Fetch user info STRICT
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    SELECT u.email INTO STRICT v_user_email
    FROM auth.users u
    WHERE u.id = v_user_id;

    -- 2. Lock invite row FIRST (Atomic Lock)
    SELECT *
    INTO v_invite
    FROM public.hotel_invites
    WHERE token = p_token
    FOR UPDATE;

    -- 3. Handle Already Accepted / Membership Case
    -- We do this after lock attempt for consistency
    IF NOT FOUND THEN
        -- Check if user is already a member (might have accepted already, causing token scramble)
        SELECT id INTO v_membership_id
        FROM public.hotel_members
        WHERE hotel_id = (SELECT hotel_id FROM public.hotel_invites WHERE (token = p_token OR email = v_user_email) AND status = 'accepted' LIMIT 1)
        AND user_id = v_user_id;

        IF v_membership_id IS NOT NULL THEN
            SELECT hotel_id INTO v_invite.hotel_id FROM public.hotel_members WHERE id = v_membership_id;
            RETURN jsonb_build_object(
                'success', true,
                'hotel_id', v_invite.hotel_id,
                'membership_id', v_membership_id,
                'message', 'Invite already accepted'
            );
        END IF;

        RAISE EXCEPTION 'Invalid invite token';
    END IF;

    -- 4. Validation Layer
    IF v_invite.status = 'accepted' THEN
         SELECT id INTO v_membership_id FROM public.hotel_members WHERE hotel_id = v_invite.hotel_id AND user_id = v_user_id;
         RETURN jsonb_build_object('success', true, 'hotel_id', v_invite.hotel_id, 'membership_id', v_membership_id, 'message', 'Invite already accepted');
    END IF;

    IF v_invite.status <> 'pending' THEN
        RAISE EXCEPTION 'This invite session has expired. Please open the invite link again.';
    END IF;

    IF v_invite.expires_at < now() THEN
        UPDATE public.hotel_invites SET status = 'expired' WHERE id = v_invite.id AND status = 'pending';
        RAISE EXCEPTION 'Invite has expired';
    END IF;

    -- Enforce claim (Anti-Race & Anti-Forwarding)
    IF v_invite.claimed_by IS NULL THEN
        RAISE EXCEPTION 'This invite session has expired. Please open the invite link again.';
    END IF;

    IF v_invite.claimed_by <> v_user_id THEN
        -- Secure Takeover Rule: Only allow if current user's email matches the invite's email
        IF lower(v_invite.email) <> lower(v_user_email) THEN
            RAISE EXCEPTION 'This invitation was sent to %. Please sign in using that email address to continue.', v_invite.email;
        END IF;
    END IF;

    -- Email match validation (case-insensitive)
    IF lower(v_invite.email) <> lower(v_user_email) THEN
        RAISE EXCEPTION 'This invite is not assigned to your email';
    END IF;

    -- 5. Extract Full Name from Metadata & Update Profile
    v_full_name := v_invite.invite_metadata->>'full_name';
    IF v_full_name IS NOT NULL AND v_full_name <> '' THEN
        UPDATE public.profiles
        SET full_name = COALESCE(full_name, v_full_name),
            updated_at = now()
        WHERE id = v_user_id
        AND (full_name IS NULL OR full_name = '');
    END IF;

    -- 6. Core Transaction: Create membership and assign role
    BEGIN
        INSERT INTO public.hotel_members (
            hotel_id, user_id, role, status, is_active, created_at
        )
        VALUES (
            v_invite.hotel_id, v_user_id, 'STAFF', 'active', true, now()
        )
        RETURNING id INTO v_membership_id;

        INSERT INTO public.hotel_member_roles (hotel_member_id, role_id)
        VALUES (v_membership_id, v_invite.role_id);

    EXCEPTION
        WHEN unique_violation THEN
            SELECT id INTO v_membership_id FROM public.hotel_members WHERE hotel_id = v_invite.hotel_id AND user_id = v_user_id;
            INSERT INTO public.hotel_member_roles (hotel_member_id, role_id)
            VALUES (v_membership_id, v_invite.role_id) ON CONFLICT DO NOTHING;
    END;

    -- 7. Mark invite accepted (Replay Protection)
    UPDATE public.hotel_invites
    SET status = 'accepted',
        accepted_at = now(),
        token = gen_random_uuid()
    WHERE id = v_invite.id
    AND status = 'pending';

    -- 8. Lifecycle & Audit
    SELECT code INTO v_role_code FROM public.hotel_roles WHERE id = v_invite.role_id;
    IF v_role_code = 'OWNER' THEN
        SELECT lifecycle_status INTO v_hotel_status FROM public.hotels WHERE id = v_invite.hotel_id;
        IF v_hotel_status = 'DRAFT' THEN
            UPDATE public.hotels 
            SET lifecycle_status = 'CONFIGURING',
                status = 'active',
                onboarding_started_at = COALESCE(onboarding_started_at, now())
            WHERE id = v_invite.hotel_id;
            
            INSERT INTO public.hotel_audit_logs (hotel_id, user_id, action, entity_type, entity_id, changes)
            VALUES (v_invite.hotel_id, v_user_id, 'STATUS_CHANGED', 'hotels', v_invite.hotel_id, jsonb_build_object('from', 'DRAFT', 'to', 'CONFIGURING', 'reason', 'First Owner Accepted Invite'));
        END IF;
    END IF;

    INSERT INTO public.hotel_audit_logs (hotel_id, user_id, action, entity_type, entity_id, changes)
    VALUES (v_invite.hotel_id, v_user_id, 'INVITE_ACCEPTED', 'hotel_invites', v_invite.id, jsonb_build_object('email', v_invite.email, 'role_id', v_invite.role_id));

    RETURN jsonb_build_object(
        'success', true,
        'hotel_id', v_invite.hotel_id,
        'membership_id', v_membership_id,
        'role_id', v_invite.role_id
    );
END;
$$;


ALTER FUNCTION "public"."accept_hotel_invite"("p_token" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."accept_ticket"("p_ticket_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  UPDATE tickets
  SET status = 'IN_PROGRESS'
  WHERE id = p_ticket_id;

  INSERT INTO ticket_events (ticket_id, event_type, new_status)
  VALUES (p_ticket_id, 'STARTED', 'IN_PROGRESS');
END;
$$;


ALTER FUNCTION "public"."accept_ticket"("p_ticket_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."activate_hotel"("p_hotel_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_status public.hotel_billing_status;
    v_override boolean;
BEGIN
    PERFORM 1 FROM public.hotels WHERE id = p_hotel_id FOR UPDATE;

    IF NOT public.are_required_onboarding_steps_complete(p_hotel_id) THEN
        RAISE EXCEPTION 'Onboarding incomplete';
    END IF;

    IF NOT public.hotel_has_owner(p_hotel_id) THEN
        RAISE EXCEPTION 'Cannot activate hotel without an OWNER assigned';
    END IF;

    SELECT billing_status, billing_override
    INTO v_status, v_override
    FROM public.hotels
    WHERE id = p_hotel_id;

    IF NOT v_override THEN
        IF v_status NOT IN ('active','trialing') THEN
            RAISE EXCEPTION 'Billing not active';
        END IF;
    END IF;

    UPDATE public.hotels
    SET lifecycle_status = 'ACTIVE',
        status = 'active',
        go_live_at = now()
    WHERE id = p_hotel_id;
END;
$$;


ALTER FUNCTION "public"."activate_hotel"("p_hotel_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."add_guest_comment"("p_ticket_id" "uuid", "p_comment" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_ticket_stay_id UUID;
  v_ticket_status TEXT;
BEGIN
  -- 1. Get ticket info (no lock - comments don't modify workflow)
  SELECT
    stay_id,
    status
  INTO
    v_ticket_stay_id,
    v_ticket_status
  FROM tickets
  WHERE id = p_ticket_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found: %', p_ticket_id;
  END IF;

  -- 2. Security: ticket must belong to authenticated guest
  IF NOT EXISTS (
    SELECT 1
    FROM stays
    WHERE id = v_ticket_stay_id
      AND guest_id = auth.uid()
  ) THEN
    RAISE EXCEPTION 'Unauthorized: ticket does not belong to this guest';
  END IF;

  -- 3. Validation: only allow comments on active tickets
  IF v_ticket_status NOT IN ('NEW', 'IN_PROGRESS', 'BLOCKED') THEN
    RAISE EXCEPTION 
      'Cannot comment on ticket with status: % (only NEW, IN_PROGRESS, BLOCKED allowed)',
      v_ticket_status;
  END IF;

  -- 4. Validation: comment must not be empty
  IF p_comment IS NULL OR TRIM(p_comment) = '' THEN
    RAISE EXCEPTION 'Comment cannot be empty';
  END IF;

  -- 5. Validation: comment length limit (500 chars)
  IF LENGTH(TRIM(p_comment)) > 500 THEN
    RAISE EXCEPTION 'Comment too long (max 500 characters)';
  END IF;

  -- 6. Anti-spam: soft rate-limit (10 second cooldown)
  IF EXISTS (
    SELECT 1
    FROM ticket_events
    WHERE ticket_id = p_ticket_id
      AND actor_type = 'GUEST'
      AND event_type = 'GUEST_COMMENT'
      AND created_at > NOW() - INTERVAL '10 seconds'
  ) THEN
    RAISE EXCEPTION 'Please wait before sending another message';
  END IF;

  -- 7. Insert COMMENT_ADDED event
  -- This does NOT change ticket status or affect SLA
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    actor_type,
    actor_id,
    comment,
    created_at
  ) VALUES (
    p_ticket_id,
    'COMMENT_ADDED',
    'GUEST',
    auth.uid(),
    TRIM(p_comment),
    NOW()
  );

  -- 8. Update ticket updated_at (for tracking)
  UPDATE tickets
  SET updated_at = NOW()
  WHERE id = p_ticket_id;

  RETURN jsonb_build_object(
    'success', true,
    'ticket_id', p_ticket_id,
    'comment_added', true
  );
END;
$$;


ALTER FUNCTION "public"."add_guest_comment"("p_ticket_id" "uuid", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."add_staff_comment"("p_ticket_id" "uuid", "p_comment" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_staff_member_id UUID;
  v_ticket_hotel_id UUID;
  v_ticket_status TEXT;
  v_comment_id UUID;
BEGIN
  -- 1. Get ticket info (no lock - comments don't modify workflow)
  SELECT hotel_id, status
  INTO v_ticket_hotel_id, v_ticket_status
  FROM tickets
  WHERE id = p_ticket_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found';
  END IF;

  -- 2. Verify staff belongs to this hotel
  SELECT id
  INTO v_staff_member_id
  FROM hotel_members
  WHERE user_id = auth.uid()
    AND hotel_id = v_ticket_hotel_id
    AND is_active = true;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Unauthorized: staff not in this hotel';
  END IF;

  -- 3. Validate comment
  IF TRIM(p_comment) = '' THEN
    RAISE EXCEPTION 'Comment cannot be empty';
  END IF;

  IF LENGTH(TRIM(p_comment)) > 1000 THEN
    RAISE EXCEPTION 'Comment too long (max 1000 chars)';
  END IF;

  -- 4. Validate ticket status
  -- Allow comments on all tickets except CANCELLED
  -- (comments are passive and do not affect SLA or workflow)
  IF v_ticket_status = 'CANCELLED' THEN
    RAISE EXCEPTION 'Cannot comment on cancelled tickets';
  END IF;

  -- 5. Insert COMMENT_ADDED event
  -- actor_id = hotel_members.id (domain actor, not auth.uid)
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    actor_type,
    actor_id,
    comment,
    created_at
  ) VALUES (
    p_ticket_id,
    'COMMENT_ADDED',
    'STAFF',
    v_staff_member_id,
    TRIM(p_comment),
    NOW()
  )
  RETURNING id INTO v_comment_id;

  -- 6. Touch ticket timestamp
  UPDATE tickets
  SET updated_at = NOW()
  WHERE id = p_ticket_id;

  RETURN jsonb_build_object(
    'success', true,
    'ticket_id', p_ticket_id,
    'comment_id', v_comment_id
  );
END;
$$;


ALTER FUNCTION "public"."add_staff_comment"("p_ticket_id" "uuid", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_owner_application"("p_app_id" "uuid", "p_reviewer" "uuid", "p_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
declare
  app record;
  new_prop_id uuid;
begin
  select * into app
  from public.owner_applications
  where id = p_app_id and status = 'pending';

  if not found then
    raise exception 'Application not found or not pending';
  end if;

  insert into public.properties (
    name, type, city, country, map_link,
    approx_room_count, website_links, cover_url,
    owner_contact_name, owner_contact_email, owner_contact_phone
  )
  values (
    app.property_name, app.property_type, app.city, app.country, app.map_link,
    app.room_count, app.links, app.cover_url,
    app.contact_name, app.contact_email, app.contact_phone
  )
  returning id into new_prop_id;

  update public.owner_applications
  set status = 'approved',
      reviewer_id = p_reviewer,
      reviewed_at = now(),
      review_notes = p_notes,
      property_id = new_prop_id
  where id = p_app_id;

  return new_prop_id;
end;
$$;


ALTER FUNCTION "public"."approve_owner_application"("p_app_id" "uuid", "p_reviewer" "uuid", "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."are_required_onboarding_steps_complete"("p_hotel_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    required_count integer;
    completed_count integer;
BEGIN
    SELECT COUNT(*) INTO required_count
    FROM public.hotel_onboarding_required_steps;

    SELECT COUNT(*) INTO completed_count
    FROM public.hotel_onboarding_progress hop
    JOIN public.hotel_onboarding_required_steps hrs
      ON hop.step_name = hrs.step_name
    WHERE hop.hotel_id = p_hotel_id;

    RETURN completed_count = required_count;
END;
$$;


ALTER FUNCTION "public"."are_required_onboarding_steps_complete"("p_hotel_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."assign_shift"("p_staff_id" "uuid", "p_shift_start" timestamp with time zone, "p_shift_end" timestamp with time zone, "p_shift_type" "text", "p_zone_id" "uuid", "p_created_by" "uuid", "p_department_id" "uuid" DEFAULT NULL::"uuid", "p_action_reason" "text" DEFAULT NULL::"text", "p_explanation" "jsonb" DEFAULT NULL::"jsonb", "p_dry_run" boolean DEFAULT false) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare 
  v_id uuid;
  v_dept_id uuid := p_department_id;
begin
  -- 🛡 1. SECURITY: Verify caller is an active member of the same hotel as the staff
  if not exists (
    select 1
    from public.hotel_members hm_staff
    where hm_staff.id = p_staff_id
      and hm_staff.is_active = true
      and hm_staff.hotel_id in (
        select hotel_id
        from public.hotel_members
        where user_id = auth.uid()
          and is_active = true
      )
  ) then
    raise exception 'Unauthorized or invalid active hotel membership context';
  end if;

  -- 🔄 2. CONCURRENCY: Lock the staff member
  perform 1
  from public.hotel_members
  where id = p_staff_id
  for update;

  -- 🧩 3. INTEGRITY: Zone-to-Department enforcement
  if v_dept_id is null and p_zone_id is not null then
    select department_id into v_dept_id
    from public.hotel_zones
    where id = p_zone_id;
  end if;

  if v_dept_id is null then
    -- 🎯 3B: Fallback to PRIMARY department
    select department_id into v_dept_id
    from public.staff_departments
    where staff_id = p_staff_id
      and is_primary = true
      and is_active = true
    limit 1;
  end if;

  if v_dept_id is null then
    -- 🎯 3C: Final Fallback to ANY active department (Safety)
    select department_id into v_dept_id
    from public.staff_departments
    where staff_id = p_staff_id
      and is_active = true
    order by priority desc, department_id asc
    limit 1;
  end if;

  -- 🛡 3D: Hard Assertion before INSERT
  if v_dept_id is null then
    raise exception 'Validation failed: Staff member has no active department assignments';
  end if;

  -- 📝 4. AUDIT CONTEXT: Pass reasoning securely to trigger layer
  perform set_config(
    'vaiyu.action_reason',
    coalesce(p_action_reason, 'Manual assignment'),
    true
  );

  perform set_config(
    'vaiyu.explanation',
    coalesce(p_explanation::text, ''),
    true
  );

  -- 💾 5. EXECUTION: Insert the active shift
  insert into public.staff_shifts (
    staff_id,
    shift_start,
    shift_end,
    shift_type,
    zone_id,
    department_id,
    created_by,
    is_active,
    status
  )
  values (
    p_staff_id,
    p_shift_start,
    p_shift_end,
    p_shift_type::shift_type_enum,
    p_zone_id,
    v_dept_id,
    p_created_by,
    true,
    'scheduled'
  )
  returning id into v_id;

  -- 🧹 6. CLEANUP: Prevent session leak
  perform set_config('vaiyu.action_reason', '', true);
  perform set_config('vaiyu.explanation', '', true);

  -- 🛑 7. DRY RUN ABORT: Cancel the entire transaction safely, but prove success constraints passed
  if p_dry_run then
    raise exception 'DRY_RUN_SUCCESS';
  end if;

  return v_id;
end;
$$;


ALTER FUNCTION "public"."assign_shift"("p_staff_id" "uuid", "p_shift_start" timestamp with time zone, "p_shift_end" timestamp with time zone, "p_shift_type" "text", "p_zone_id" "uuid", "p_created_by" "uuid", "p_department_id" "uuid", "p_action_reason" "text", "p_explanation" "jsonb", "p_dry_run" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."attendance_sync_day"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  -- prefer work_date when present
  if new.work_date is not null then
    new.day := new.work_date;
  elsif new.day is not null and new.work_date is null then
    new.work_date := new.day;
  end if;
  return new;
end$$;


ALTER FUNCTION "public"."attendance_sync_day"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_assign_next_ticket"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_ticket RECORD;
  v_staff_id UUID;
  v_max_load INT := 20; -- Limit 20 active tickets/person
BEGIN
  -- 🚀 MAJOR CHANGE v2.5:
  -- We fetch the batch UP FRONT.
  -- This ensures correct ordering but allows us to "skip" tickets 
  -- that can't be assigned without stopping the job.
  
  FOR v_ticket IN
    SELECT
      t.id,
      t.hotel_id,
      t.service_department_id,
      t.zone_id,
      t.priority
    FROM tickets t
    LEFT JOIN ticket_sla_state ss
      ON ss.ticket_id = t.id
    WHERE
      t.status = 'NEW'
      AND t.current_assignee_id IS NULL
    ORDER BY
      -- Criticality First:
      CASE
        WHEN ss.current_remaining_seconds IS NOT NULL
             AND ss.current_remaining_seconds <= 300 THEN 0  -- SLA risk (≤5 min)
        ELSE 1
      END,
      -- Then Ticket Priority:
      CASE t.priority
        WHEN 'URGENT' THEN 0
        WHEN 'HIGH' THEN 1
        WHEN 'NORMAL' THEN 2
        WHEN 'LOW' THEN 3
        ELSE 4
      END,
      -- FIFO fallback:
      t.created_at ASC
    LIMIT 20 -- Process batch of 20
    FOR UPDATE OF t SKIP LOCKED -- Lock them all so other workers skip them
  LOOP
    
    ------------------------------------------------------------------
    -- 2️⃣ Select best eligible staff (deterministic & fair)
    ------------------------------------------------------------------
    SELECT hm.id
    INTO v_staff_id
    FROM hotel_members hm
    
    -- ✅ Role Check (Multi-Role Support v2.4)
    JOIN hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
    JOIN hotel_roles hr ON hr.id = hmr.role_id AND hr.code = 'STAFF'

    -- ✅ Must be on active shift
    JOIN staff_shifts ss
      ON ss.staff_id = hm.id
     AND ss.is_active = true
     AND now() BETWEEN ss.shift_start AND ss.shift_end
     
    -- ✅ Must be capable (Department match)
    JOIN staff_departments sd
      ON sd.staff_id = hm.id
     AND sd.department_id = v_ticket.service_department_id
     
    -- ✅ Zone affinity (Soft Preference)
    LEFT JOIN staff_zone_assignments sz
      ON sz.staff_id = hm.id
     AND sz.zone_id = v_ticket.zone_id
     AND sz.effective_to IS NULL
     
    -- ✅ Load calculation
    LEFT JOIN tickets t_load
      ON t_load.current_assignee_id = hm.id
     AND t_load.status IN ('NEW','IN_PROGRESS','BLOCKED')
     
    WHERE
      hm.hotel_id = v_ticket.hotel_id
      AND hm.is_active = true
      AND hm.is_verified = true

    GROUP BY hm.id, sz.id
    HAVING COUNT(t_load.id) < v_max_load
    ORDER BY
      -- 1. Zone Affinity (Soft Preference): Prefer matching zone (0) over mismatch (1)
      CASE 
        WHEN v_ticket.zone_id IS NOT NULL AND sz.id IS NULL THEN 1 
        ELSE 0 
      END ASC,
      -- 2. Fairness/Load:
      COUNT(t_load.id) ASC,                 -- Primary: Least loaded
      hm.last_assigned_at NULLS FIRST,       -- Secondary: Hasn't had a task in longest time
      hm.created_at ASC                      -- Tertiary: Deterministic tie-breaker
    LIMIT 1;

    
    -- 🚀 KEY FIX v2.5:
    -- If no staff found, we DO NOTHING for this ticket.
    -- The loop naturally continues to the NEXT ticket in the batch.
    
    IF v_staff_id IS NOT NULL THEN
      
      ------------------------------------------------------------------
      -- 3️⃣ Assign ticket
      ------------------------------------------------------------------
      UPDATE tickets
      SET
        current_assignee_id = v_staff_id,
        updated_at = clock_timestamp()
      WHERE id = v_ticket.id;

      ------------------------------------------------------------------
      -- 4️⃣ Record assignment event
      ------------------------------------------------------------------
      INSERT INTO ticket_events (
        ticket_id,
        event_type,
        actor_type,
        actor_id,
        comment
      )
      VALUES (
        v_ticket.id,
        'ASSIGNED',
        'SYSTEM',
        v_staff_id, 
        'Auto-assigned by scheduler'
      );

      ------------------------------------------------------------------
      -- 5️⃣ Update staff fairness marker
      ------------------------------------------------------------------
      UPDATE hotel_members
      SET last_assigned_at = clock_timestamp()
      WHERE id = v_staff_id;

    END IF;
    
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."auto_assign_next_ticket"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."best_staff_performance_for_slug"("p_slug" "text") RETURNS TABLE("name" "text", "orders_served" integer, "avg_rating_30d" numeric, "avg_completion_min" numeric, "volume_score" integer, "rating_score" integer, "speed_score" integer, "performance_score" integer)
    LANGUAGE "plpgsql" STABLE
    AS $$
DECLARE
  v_has_staff_id boolean;
BEGIN
  SELECT EXISTS (
    SELECT 1
    FROM information_schema.columns
    WHERE table_schema='public'
      AND table_name='reviews'
      AND column_name='staff_id'
  ) INTO v_has_staff_id;

  IF v_has_staff_id THEN
    -- ====== Branch A: reviews.staff_id EXISTS (per-staff ratings) ======
    RETURN QUERY
    WITH h AS (
      SELECT id AS hotel_id FROM hotels WHERE slug = p_slug LIMIT 1
    ),
    sla AS (
      SELECT COALESCE((
               SELECT target_minutes
               FROM sla_targets t, h
               WHERE t.hotel_id = h.hotel_id AND t.key = 'order_delivery_min'
             ), 20) AS target_min
    ),
    work_spans AS (
      SELECT
        st.staff_id,
        st.order_id,
        EXTRACT(EPOCH FROM (MAX(st.created_at) - MIN(st.created_at)))/60.0 AS span_min
      FROM staff_tasks st, h
      WHERE st.hotel_id = h.hotel_id
        AND st.task_type = 'order'
        AND st.created_at >= now() - interval '30 days'
      GROUP BY st.staff_id, st.order_id
    ),
    order_speeds AS (
      SELECT staff_id,
             AVG(NULLIF(GREATEST(span_min,0),0))::numeric AS avg_completion_min
      FROM work_spans GROUP BY staff_id
    ),
    top_volume AS (
      SELECT MAX(cnt) AS max_orders
      FROM (SELECT staff_id, COUNT(DISTINCT order_id) AS cnt
            FROM work_spans GROUP BY staff_id) x
    ),
    staff_orders AS (
      SELECT s.id AS staff_id, s.name, COUNT(DISTINCT ws.order_id) AS orders_served
      FROM staff s
      JOIN h ON s.hotel_id = h.hotel_id
      LEFT JOIN work_spans ws ON ws.staff_id = s.id
      WHERE s.active
      GROUP BY s.id, s.name
    ),
    staff_rating AS (
      SELECT s.id AS staff_id, ROUND(AVG(r.rating)::numeric, 2) AS avg_rating_30d
      FROM staff s
      JOIN h ON s.hotel_id = h.hotel_id
      LEFT JOIN reviews r
        ON r.hotel_id = s.hotel_id
       AND r.staff_id = s.id
       AND r.created_at >= now() - interval '30 days'
      WHERE s.active
      GROUP BY s.id
    )
    SELECT
      so.name,
      so.orders_served,
      sr.avg_rating_30d,
      os.avg_completion_min,
      LEAST(100, ROUND(100.0 * so.orders_served / NULLIF(tv.max_orders,1), 0)) AS volume_score,
      ROUND((COALESCE(sr.avg_rating_30d,0) / 5.0) * 100, 0)                     AS rating_score,
      (CASE WHEN os.avg_completion_min IS NULL OR os.avg_completion_min <= 0
            THEN 50
            ELSE LEAST(100, ROUND(100.0 * (SELECT target_min FROM sla)
                                   / NULLIF(os.avg_completion_min,1), 0))
       END)                                                                      AS speed_score,
      ROUND(
        0.40 * LEAST(100, 100.0 * so.orders_served / NULLIF(tv.max_orders,1)) +
        0.30 * ((COALESCE(sr.avg_rating_30d,0) / 5.0) * 100) +
        0.30 * (CASE WHEN os.avg_completion_min IS NULL OR os.avg_completion_min <= 0
                     THEN 50
                     ELSE LEAST(100, 100.0 * (SELECT target_min FROM sla)
                                         / NULLIF(os.avg_completion_min,1))
                END)
      , 0) AS performance_score
    FROM staff_orders so
    LEFT JOIN staff_rating sr   ON sr.staff_id = so.staff_id
    LEFT JOIN order_speeds os   ON os.staff_id = so.staff_id
    CROSS JOIN top_volume tv
    ORDER BY performance_score DESC, so.orders_served DESC
    LIMIT 20;

  ELSE
    -- ====== Branch B: reviews.staff_id DOES NOT EXIST (fallback hotel-average rating) ======
    RETURN QUERY
    WITH h AS (
      SELECT id AS hotel_id FROM hotels WHERE slug = p_slug LIMIT 1
    ),
    sla AS (
      SELECT COALESCE((
               SELECT target_minutes
               FROM sla_targets t, h
               WHERE t.hotel_id = h.hotel_id AND t.key = 'order_delivery_min'
             ), 20) AS target_min
    ),
    hotel_avg_rating AS (
      SELECT h.hotel_id,
             ROUND(AVG(r.rating)::numeric, 2) AS avg_rating_30d
      FROM h
      LEFT JOIN reviews r
             ON r.hotel_id = h.hotel_id
            AND r.created_at >= now() - interval '30 days'
      GROUP BY h.hotel_id
    ),
    work_spans AS (
      SELECT
        st.staff_id,
        st.order_id,
        EXTRACT(EPOCH FROM (MAX(st.created_at) - MIN(st.created_at)))/60.0 AS span_min
      FROM staff_tasks st, h
      WHERE st.hotel_id = h.hotel_id
        AND st.task_type = 'order'
        AND st.created_at >= now() - interval '30 days'
      GROUP BY st.staff_id, st.order_id
    ),
    order_speeds AS (
      SELECT staff_id,
             AVG(NULLIF(GREATEST(span_min,0),0))::numeric AS avg_completion_min
      FROM work_spans GROUP BY staff_id
    ),
    top_volume AS (
      SELECT MAX(cnt) AS max_orders
      FROM (SELECT staff_id, COUNT(DISTINCT order_id) AS cnt
            FROM work_spans GROUP BY staff_id) x
    ),
    staff_orders AS (
      SELECT s.id AS staff_id, s.name, COUNT(DISTINCT ws.order_id) AS orders_served
      FROM staff s
      JOIN h ON s.hotel_id = h.hotel_id
      LEFT JOIN work_spans ws ON ws.staff_id = s.id
      WHERE s.active
      GROUP BY s.id, s.name
    )
    SELECT
      so.name,
      so.orders_served,
      har.avg_rating_30d,
      os.avg_completion_min,
      LEAST(100, ROUND(100.0 * so.orders_served / NULLIF(tv.max_orders,1), 0)) AS volume_score,
      ROUND((COALESCE(har.avg_rating_30d,0) / 5.0) * 100, 0)                    AS rating_score,
      (CASE WHEN os.avg_completion_min IS NULL OR os.avg_completion_min <= 0
            THEN 50
            ELSE LEAST(100, ROUND(100.0 * (SELECT target_min FROM sla)
                                   / NULLIF(os.avg_completion_min,1), 0))
       END)                                                                      AS speed_score,
      ROUND(
        0.40 * LEAST(100, 100.0 * so.orders_served / NULLIF(tv.max_orders,1)) +
        0.30 * ((COALESCE(har.avg_rating_30d,0) / 5.0) * 100) +
        0.30 * (CASE WHEN os.avg_completion_min IS NULL OR os.avg_completion_min <= 0
                     THEN 50
                     ELSE LEAST(100, 100.0 * (SELECT target_min FROM sla)
                                         / NULLIF(os.avg_completion_min,1))
                END)
      , 0) AS performance_score
    FROM staff_orders so
    LEFT JOIN order_speeds os     ON os.staff_id = so.staff_id
    LEFT JOIN hotel_avg_rating har ON har.hotel_id = (SELECT hotel_id FROM h)
    CROSS JOIN top_volume tv
    ORDER BY performance_score DESC, so.orders_served DESC
    LIMIT 20;
  END IF;
END;
$$;


ALTER FUNCTION "public"."best_staff_performance_for_slug"("p_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."block_task"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text" DEFAULT NULL::"text", "p_resume_after" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
  v_member_id UUID;
  v_hotel_id UUID;
  v_status TEXT;
  v_current_assignee UUID;
  v_ticket JSONB;
BEGIN
  ----------------------------------------------------------------
  -- 1️⃣ Authentication
  ----------------------------------------------------------------
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  ----------------------------------------------------------------
  -- 2️⃣ Lock ticket row (race-safe)
  ----------------------------------------------------------------
  SELECT
    hotel_id,
    status,
    current_assignee_id
  INTO
    v_hotel_id,
    v_status,
    v_current_assignee
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found';
  END IF;

  ----------------------------------------------------------------
  -- 3️⃣ Validate ticket state
  ----------------------------------------------------------------
  IF v_status <> 'IN_PROGRESS' THEN
    RAISE EXCEPTION
      'Only IN_PROGRESS tasks can be blocked (current status: %)',
      v_status;
  END IF;

  ----------------------------------------------------------------
  -- 4️⃣ Validate staff membership (must be assignee)
  ----------------------------------------------------------------
  SELECT id
  INTO v_member_id
  FROM hotel_members
  WHERE user_id = v_user_id
    AND hotel_id = v_hotel_id
    AND is_active = true;

  IF v_member_id IS NULL THEN
    RAISE EXCEPTION 'Unauthorized: not an active staff member';
  END IF;

  IF v_current_assignee IS DISTINCT FROM v_member_id THEN
    RAISE EXCEPTION 'Only the assigned staff can block this task';
  END IF;

  ----------------------------------------------------------------
  -- 5️⃣ Validate block reason
  ----------------------------------------------------------------
  IF NOT EXISTS (
    SELECT 1
    FROM block_reasons
    WHERE code = p_reason_code
  ) THEN
    RAISE EXCEPTION 'Invalid block reason: %', p_reason_code;
  END IF;

  ----------------------------------------------------------------
  -- 6️⃣ Update ticket → BLOCKED
  -- SLA pause handled by trigger trg_pause_sla_on_block
  ----------------------------------------------------------------
  UPDATE tickets
  SET
    status = 'BLOCKED',
    reason_code = p_reason_code, -- <== CRITICAL FIX: Trigger needs this!
    updated_at = now()
  WHERE id = p_ticket_id
    AND status = 'IN_PROGRESS';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Task was modified concurrently';
  END IF;

  ----------------------------------------------------------------
  -- 7️⃣ Insert immutable BLOCKED event
  ----------------------------------------------------------------
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    previous_status,
    new_status,
    reason_code,
    comment,
    resume_after,
    actor_type,
    actor_id
  )
  VALUES (
    p_ticket_id,
    'BLOCKED',
    'IN_PROGRESS',
    'BLOCKED',
    p_reason_code,
    p_comment,
    p_resume_after,
    'STAFF',
    v_member_id
  );

  ----------------------------------------------------------------
  -- 8️⃣ Return updated ticket
  ----------------------------------------------------------------
  SELECT to_jsonb(t.*)
  INTO v_ticket
  FROM tickets t
  WHERE id = p_ticket_id;

  RETURN v_ticket;
END;
$$;


ALTER FUNCTION "public"."block_task"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text", "p_resume_after" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."bulk_assign_shifts"("p_shifts" "jsonb", "p_user" "uuid", "p_dry_run" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_item jsonb;
  v_result jsonb := '[]'::jsonb;
  v_shift_id uuid;
begin
  for v_item in select * from jsonb_array_elements(p_shifts)
  loop
    begin
      -- Standardize logic via core engine
      v_shift_id := public.assign_shift(
        (v_item->>'staff_id')::uuid,
        (v_item->>'shift_start')::timestamptz,
        (v_item->>'shift_end')::timestamptz,
        v_item->>'shift_type',
        (v_item->>'zone_id')::uuid,
        p_user,
        (v_item->>'department_id')::uuid,
        nullif(v_item->>'action_reason', ''),
        (v_item->'explanation')::jsonb,
        p_dry_run -- Pass dry run constraint
      );

      -- If we reach here, p_dry_run=false AND execution was successful.
      v_result := v_result || jsonb_build_object(
        'staff_id', v_item->>'staff_id',
        'shift_start', v_item->>'shift_start',
        'shift_end', v_item->>'shift_end',
        'status', 'success',
        'message', 'Clear',
        'shift_id', v_shift_id
      );

    exception
      when raise_exception then
        if sqlerrm = 'DRY_RUN_SUCCESS' then
          -- The transaction was intentionally rolled back by the engine to simulate dryness
          v_result := v_result || jsonb_build_object(
            'staff_id', v_item->>'staff_id',
            'shift_start', v_item->>'shift_start',
            'shift_end', v_item->>'shift_end',
            'status', 'success',
            'message', 'Clear'
          );
        else
          v_result := v_result || jsonb_build_object(
            'staff_id', v_item->>'staff_id',
            'shift_start', v_item->>'shift_start',
            'shift_end', v_item->>'shift_end',
            'status', 'error',
            'message', SQLERRM
          );
        end if;
      when exclusion_violation then
        v_result := v_result || jsonb_build_object(
          'staff_id', v_item->>'staff_id',
          'shift_start', v_item->>'shift_start',
          'shift_end', v_item->>'shift_end',
          'status', 'conflict',
          'message', 'Overlaps with an existing shift'
        );
      when others then
        v_result := v_result || jsonb_build_object(
          'staff_id', v_item->>'staff_id',
          'shift_start', v_item->>'shift_start',
          'shift_end', v_item->>'shift_end',
          'status', 'error',
          'message', SQLERRM
        );
    end;
  end loop;

  return v_result;
end;
$$;


