CREATE OR REPLACE FUNCTION "public"."cancel_food_order"("p_order_id" "uuid", "p_reason" "text", "p_actor_type" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    PERFORM 1 FROM food_orders WHERE id = p_order_id FOR UPDATE;

    UPDATE food_orders
    SET status = 'CANCELLED',
        cancelled_reason = p_reason,
        cancelled_by = p_actor_type,
        updated_at = now()
    WHERE id = p_order_id
      AND status IN ('CREATED','ACCEPTED','PREPARING');

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Order cannot be cancelled';
    END IF;

    INSERT INTO food_order_events
    VALUES (
        gen_random_uuid(),
        p_order_id,
        'ORDER_CANCELLED',
        p_actor_type,
        auth.uid(),
        jsonb_build_object('reason', p_reason),
        now()
    );
END;
$$;


ALTER FUNCTION "public"."cancel_food_order"("p_order_id" "uuid", "p_reason" "text", "p_actor_type" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_shift"("p_shift_id" "uuid", "p_version" integer, "p_user" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
declare v record;
begin
  select * into v from public.staff_shifts where id = p_shift_id for update;

  if not found then raise exception 'Shift not found'; end if;
  if v.version != p_version then raise exception 'Version mismatch'; end if;

  if v.locked_at is not null
     and v.locked_at > now() - interval '5 minutes'
     and v.locked_by is distinct from p_user then
    raise exception 'Locked';
  end if;

  update public.staff_shifts
  set status = 'cancelled',
      is_active = false,
      cancelled_at = now()
  where id = p_shift_id;
end;
$$;


ALTER FUNCTION "public"."cancel_shift"("p_shift_id" "uuid", "p_version" integer, "p_user" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_ticket"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_ticket RECORD;
  v_staff_member_id UUID;
  v_reason RECORD;
  v_previous_status TEXT;
BEGIN
  -- ------------------------------------------------------------
  -- 1. Fetch ticket (lock to prevent double-terminal transitions)
  -- ------------------------------------------------------------
  SELECT *
  INTO v_ticket
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found';
  END IF;

  -- ------------------------------------------------------------
  -- 2. Reject if already terminal
  -- ------------------------------------------------------------
  IF v_ticket.status IN ('COMPLETED', 'CANCELLED') THEN
    RAISE EXCEPTION
      'Ticket already in terminal state: %',
      v_ticket.status;
  END IF;

  v_previous_status := v_ticket.status;

  -- ------------------------------------------------------------
  -- 3. Resolve staff domain actor (hotel-scoped)
  -- ------------------------------------------------------------
  SELECT id
  INTO v_staff_member_id
  FROM hotel_members
  WHERE user_id = auth.uid()
    AND hotel_id = v_ticket.hotel_id
    AND is_active = true;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Unauthorized: staff not in this hotel';
  END IF;

  -- ------------------------------------------------------------
  -- 4. Fetch and validate cancel reason
  -- ------------------------------------------------------------
  SELECT *
  INTO v_reason
  FROM cancel_reasons
  WHERE code = p_reason_code
    AND is_active = true;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Invalid or inactive cancel reason';
  END IF;

  -- Role enforcement
  IF v_reason.allowed_for_staff IS NOT TRUE THEN
    RAISE EXCEPTION 'Cancel reason not allowed for staff';
  END IF;

  -- Workflow enforcement
  IF v_ticket.status = 'NEW'
     AND v_reason.allow_when_new IS NOT TRUE THEN
    RAISE EXCEPTION
      'Cancel reason not allowed when ticket is NEW';
  END IF;

  IF v_ticket.status = 'IN_PROGRESS'
     AND v_reason.allow_when_in_progress IS NOT TRUE THEN
    RAISE EXCEPTION
      'Cancel reason not allowed when ticket is IN_PROGRESS';
  END IF;

  -- ------------------------------------------------------------
  -- 5. Comment enforcement
  -- ------------------------------------------------------------
  IF v_reason.requires_comment = true THEN
    IF p_comment IS NULL OR TRIM(p_comment) = '' THEN
      RAISE EXCEPTION 'Comment required for this cancel reason';
    END IF;
  END IF;

  -- ------------------------------------------------------------
  -- 6. Update ticket (terminal transition)
  -- ------------------------------------------------------------
  UPDATE tickets
  SET
    status = 'CANCELLED',
    updated_at = NOW(),
    completed_at = NOW()   -- terminal timestamp
  WHERE id = p_ticket_id;

  -- ------------------------------------------------------------
  -- 7. Emit CANCELLED event (immutable)
  -- ------------------------------------------------------------
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    previous_status,
    new_status,
    reason_code,
    actor_type,
    actor_id,
    comment,
    created_at
  ) VALUES (
    p_ticket_id,
    'CANCELLED',
    v_previous_status,
    'CANCELLED',
    p_reason_code,
    'STAFF',
    v_staff_member_id,
    TRIM(p_comment),
    NOW()
  );

  -- ------------------------------------------------------------
  -- 8. Return success
  -- ------------------------------------------------------------
  RETURN jsonb_build_object(
    'success', true,
    'ticket_id', p_ticket_id,
    'status', 'CANCELLED',
    'reason_code', p_reason_code
  );
END;
$$;


ALTER FUNCTION "public"."cancel_ticket"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_ticket_by_guest"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_ticket RECORD;

  v_reason RECORD;
  v_prev_status TEXT;
BEGIN
  -- Lock ticket
  SELECT *
  INTO v_ticket
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found';
  END IF;

  -- Ownership check
  -- Direct check against auth.uid() since there is no 'guests' table
  IF v_ticket.created_by_type <> 'GUEST' OR v_ticket.created_by_id <> auth.uid() THEN
    RAISE EXCEPTION 'Unauthorized: not your ticket';
  END IF;

  -- State rules
  IF v_ticket.status NOT IN ('NEW', 'IN_PROGRESS') THEN
    RAISE EXCEPTION 'Guest cannot cancel ticket in status %', v_ticket.status;
  END IF;

  v_prev_status := v_ticket.status;

  -- Cancel reason validation
  SELECT *
  INTO v_reason
  FROM cancel_reasons
  WHERE code = p_reason_code
    AND is_active = TRUE
    AND allowed_for_guest = TRUE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Invalid cancel reason for guest';
  END IF;

  -- Workflow rule
  IF v_ticket.status = 'IN_PROGRESS'
     AND v_reason.allow_when_in_progress IS NOT TRUE THEN
    RAISE EXCEPTION 'Cancel reason not allowed when IN_PROGRESS';
  END IF;

  -- Comment enforcement
  IF v_reason.requires_comment
     AND (p_comment IS NULL OR TRIM(p_comment) = '') THEN
    RAISE EXCEPTION 'Comment required for this cancel reason';
  END IF;

  -- Execute cancellation
  PERFORM _cancel_ticket_internal(
    p_ticket_id,
    v_prev_status,
    p_reason_code,
    'GUEST',
    auth.uid(),
    p_comment
  );

  RETURN jsonb_build_object(
    'success', TRUE,
    'ticket_id', p_ticket_id,
    'status', 'CANCELLED'
  );
END;
$$;


ALTER FUNCTION "public"."cancel_ticket_by_guest"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_ticket_by_staff"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_ticket RECORD;
  v_staff_id UUID;
  v_reason RECORD;
  v_prev_status TEXT;
BEGIN
  -- Lock ticket
  SELECT *
  INTO v_ticket
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found';
  END IF;

  -- Reject terminal
  IF v_ticket.status IN ('COMPLETED', 'CANCELLED') THEN
    RAISE EXCEPTION 'Ticket already terminal';
  END IF;

  -- Staff membership validation
  SELECT id
  INTO v_staff_id
  FROM hotel_members
  WHERE user_id = auth.uid()
    AND hotel_id = v_ticket.hotel_id
    AND is_active = TRUE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Unauthorized staff';
  END IF;

  -- State rules: staff cannot cancel BLOCKED tickets
  IF v_ticket.status = 'BLOCKED' THEN
    RAISE EXCEPTION 'Staff cannot cancel BLOCKED tickets';
  END IF;

  v_prev_status := v_ticket.status;

  -- Cancel reason validation
  SELECT *
  INTO v_reason
  FROM cancel_reasons
  WHERE code = p_reason_code
    AND is_active = TRUE
    AND allowed_for_staff = TRUE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Invalid cancel reason for staff';
  END IF;

  -- Workflow enforcement
  IF v_ticket.status = 'IN_PROGRESS'
     AND v_reason.allow_when_in_progress IS NOT TRUE THEN
    RAISE EXCEPTION 'Cancel reason not allowed when IN_PROGRESS';
  END IF;

  -- Comment enforcement
  IF v_reason.requires_comment
     AND (p_comment IS NULL OR TRIM(p_comment) = '') THEN
    RAISE EXCEPTION 'Comment required for this cancel reason';
  END IF;

  -- Execute cancellation
  PERFORM _cancel_ticket_internal(
    p_ticket_id,
    v_prev_status,
    p_reason_code,
    'STAFF',
    v_staff_id,
    p_comment
  );

  RETURN jsonb_build_object(
    'success', TRUE,
    'ticket_id', p_ticket_id,
    'status', 'CANCELLED'
  );
END;
$$;


ALTER FUNCTION "public"."cancel_ticket_by_staff"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_ticket_by_supervisor"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_ticket RECORD;
  v_supervisor_id UUID;
  v_reason RECORD;
  v_prev_status TEXT;
BEGIN
  -- Lock ticket
  SELECT *
  INTO v_ticket
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found';
  END IF;

  -- Reject terminal
  IF v_ticket.status IN ('COMPLETED', 'CANCELLED') THEN
    RAISE EXCEPTION 'Ticket already terminal';
  END IF;

  -- Supervisor membership validation
  SELECT hm.id
  INTO v_supervisor_id
  FROM hotel_members hm
  INNER JOIN hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
  INNER JOIN hotel_roles hr ON hr.id = hmr.hotel_role_id
  WHERE hm.user_id = auth.uid()
    AND hm.hotel_id = v_ticket.hotel_id
    AND hm.is_active = TRUE
    AND hr.code = 'SUPERVISOR'
    AND hr.is_active = TRUE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Unauthorized supervisor';
  END IF;

  v_prev_status := v_ticket.status;

  -- Cancel reason validation
  SELECT *
  INTO v_reason
  FROM cancel_reasons
  WHERE code = p_reason_code
    AND is_active = TRUE
    AND allowed_for_supervisor = TRUE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Invalid cancel reason for supervisor';
  END IF;

  -- Comment enforcement
  IF v_reason.requires_comment
     AND (p_comment IS NULL OR TRIM(p_comment) = '') THEN
    RAISE EXCEPTION 'Comment required for this cancel reason';
  END IF;

  -- Execute cancellation
  PERFORM _cancel_ticket_internal(
    p_ticket_id,
    v_prev_status,
    p_reason_code,
    'SUPERVISOR',
    v_supervisor_id,
    p_comment
  );

  RETURN jsonb_build_object(
    'success', TRUE,
    'ticket_id', p_ticket_id,
    'status', 'CANCELLED'
  );
END;
$$;


ALTER FUNCTION "public"."cancel_ticket_by_supervisor"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."catalog_menu2"("hotelid" "uuid") RETURNS json
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select json_build_object(
    'items',
    coalesce(
      (
        select json_agg(
          json_build_object(
            'item_key', mi.item_key,
            'name',     mi.name,
            -- prefer price if set, otherwise base_price
            'base_price', coalesce(
              nullif(mi.price, 0),
              mi.base_price
            )
          )
        )
        from public.menu_items mi
        where mi.hotel_id = catalog_menu2.hotelid
          and mi.active = true
      ),
      '[]'::json
    )
  );
$$;


