CREATE OR REPLACE FUNCTION "public"."check_booking_room_hotel"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM bookings b
    WHERE b.id = NEW.booking_id
    AND b.hotel_id = NEW.hotel_id
  ) THEN
    RAISE EXCEPTION 'Booking Room must belong to the same Hotel as the Booking';
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_booking_room_hotel"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_stay_booking_room_hotel"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.booking_room_id IS NOT NULL THEN
    IF NOT EXISTS (
      SELECT 1 FROM booking_rooms br
      WHERE br.id = NEW.booking_room_id
      AND br.hotel_id = NEW.hotel_id
    ) THEN
      RAISE EXCEPTION 'Booking Room must belong to the same Hotel as the Stay';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


