CREATE OR REPLACE FUNCTION "public"."checkout_booking"("p_booking_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    v_balance NUMERIC;
BEGIN
    SELECT COALESCE(SUM(amount), 0) INTO v_balance
    FROM folio_entries
    WHERE booking_id = p_booking_id;

    IF COALESCE(v_balance,0) > 0 THEN -- Changed from <> 0 to allow checkouts with credit/zero balance
        RETURN jsonb_build_object(
            'success', false,
            'message', 'Outstanding balance must be settled before checkout'
        );
    END IF;

    UPDATE folios
    SET status = 'CLOSED'
    WHERE booking_id = p_booking_id;

    UPDATE stays
    SET actual_checkout_at = now()
    WHERE booking_id = p_booking_id
    AND actual_checkout_at IS NULL;

    RETURN jsonb_build_object('success', true);
END;
$$;


ALTER FUNCTION "public"."checkout_booking"("p_booking_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."checkout_stay"("p_hotel_id" "uuid", "p_booking_id" "uuid", "p_stay_id" "uuid", "p_force" boolean DEFAULT false, "p_source" "text" DEFAULT 'GUEST'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_pending_amount NUMERIC;
    v_room_id UUID;
    v_stay_status TEXT;
    v_now TIMESTAMPTZ := now();
    v_feedback_token TEXT;
    v_folio_id UUID;
    v_hotel_id UUID;
BEGIN

    ---------------------------------------------------------
    -- 1️⃣ Pessimistic Locking & Validation
    ---------------------------------------------------------
    SELECT room_id, status, hotel_id INTO v_room_id, v_stay_status, v_hotel_id
    FROM stays
    WHERE id = p_stay_id
      AND booking_id = p_booking_id
      AND (
          status = 'checkout_requested'
          OR (status = 'inhouse' AND p_source = 'STAFF')
      )
    FOR UPDATE;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', CASE WHEN p_source = 'STAFF'
                THEN 'Stay not found or not eligible for checkout.'
                ELSE 'Stay not found or checkout hasn''t been requested yet.'
            END
        );
    END IF;

    -- Lock booking row
    PERFORM 1 FROM bookings WHERE id = p_booking_id FOR UPDATE;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Booking not found'
        );
    END IF;


    ---------------------------------------------------------
    -- 2️⃣ Explicit Folio Locking & Lazy Creation
    ---------------------------------------------------------
    SELECT id INTO v_folio_id
    FROM folios
    WHERE booking_id = p_booking_id
    FOR UPDATE;

    IF NOT FOUND THEN
        -- Create it just-in-time
        INSERT INTO folios (booking_id, hotel_id, status)
        VALUES (p_booking_id, v_hotel_id, 'OPEN')
        ON CONFLICT (booking_id) DO NOTHING
        RETURNING id INTO v_folio_id;

        -- Fallback if conflict happened and it wasn't returned
        IF v_folio_id IS NULL THEN
            SELECT id INTO v_folio_id FROM folios WHERE booking_id = p_booking_id FOR UPDATE;
        END IF;
    END IF;


    ---------------------------------------------------------
    -- 3️⃣ Revalidate Operational Safety
    ---------------------------------------------------------
    IF EXISTS (
        SELECT 1 FROM tickets
        WHERE stay_id = p_stay_id
        AND status NOT IN ('COMPLETED', 'CANCELLED')
    ) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Open service requests exist'
        );
    END IF;

    IF EXISTS (
        SELECT 1
        FROM food_orders fo
        JOIN stays s ON s.id = fo.stay_id
        WHERE s.id = p_stay_id
        AND fo.status NOT IN ('DELIVERED','CANCELLED', 'REJECTED')
    ) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Pending food orders exist'
        );
    END IF;


    ---------------------------------------------------------
    -- 4️⃣ Robust Ledger Scoping & Payment Validation
    ---------------------------------------------------------
    SELECT COALESCE(SUM(amount), 0)
    INTO v_pending_amount
    FROM folio_entries
    WHERE folio_id IN (
        SELECT id FROM folios WHERE booking_id = p_booking_id
    );

    IF v_pending_amount > 0 AND p_force = FALSE THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Pending balance exists',
            'pending_amount', v_pending_amount
        );
    END IF;


    ---------------------------------------------------------
    -- 5️⃣ Close Stay
    ---------------------------------------------------------
    UPDATE stays
    SET
        status = 'checked_out',
        actual_checkout_at = v_now
    WHERE id = p_stay_id;


    ---------------------------------------------------------
    -- 6️⃣ Update Booking Status
    ---------------------------------------------------------
    UPDATE bookings
    SET status = 'CHECKED_OUT',
        updated_at = v_now
    WHERE id = p_booking_id;

    UPDATE booking_rooms
    SET status = 'CHECKED_OUT',
        updated_at = v_now
    WHERE booking_id = p_booking_id
      AND room_id = v_room_id;


    ---------------------------------------------------------
    -- 7️⃣ Mark Room Dirty
    ---------------------------------------------------------
    PERFORM 1 FROM rooms WHERE id = v_room_id FOR UPDATE;

    UPDATE rooms
    SET housekeeping_status = 'dirty',
        updated_at = v_now
    WHERE id = v_room_id;


    ---------------------------------------------------------
    -- 8️⃣ Log Arrival Event
    ---------------------------------------------------------
    INSERT INTO arrival_events (
        hotel_id,
        booking_id,
        event_type,
        details,
        performed_by
    )
    VALUES (
        p_hotel_id,
        p_booking_id,
        'CHECKOUT',
        jsonb_build_object(
            'stay_id', p_stay_id,
            'room_id', v_room_id,
            'force', p_force,
            'balance_at_checkout', v_pending_amount,
            'origin', p_source
        ),
        COALESCE(auth.uid(), NULL)
    );


    ---------------------------------------------------------
    -- 9️⃣ Generate Feedback Token & Queue Post-Checkout Email
    ---------------------------------------------------------
    BEGIN
        -- Create feedback token
        SELECT (create_feedback_token(p_booking_id))->>'token'
        INTO v_feedback_token;

        -- Queue email notification (1-hour delay for optimal response rate)
        INSERT INTO public.notification_queue (
            booking_id, channel, template_code, payload, status, next_attempt_at
        )
        SELECT
            p_booking_id,
            'email',
            'post_checkout_thankyou',
            jsonb_build_object(
                'booking_id', p_booking_id,
                'guest_name', b.guest_name,
                'email', b.email,
                'feedback_token', v_feedback_token,
                'hotel_name', h.name
            ),
            'pending',
            v_now + interval '1 hour'  -- 1-hour delay: optimal feedback response window
        FROM bookings b
        JOIN hotels h ON h.id = b.hotel_id
        WHERE b.id = p_booking_id
        AND b.email IS NOT NULL AND b.email != '';

        -- Queue WhatsApp notification (2nd priority, for future use)
        INSERT INTO public.notification_queue (
            booking_id, channel, template_code, payload, status, next_attempt_at
        )
        SELECT
            p_booking_id,
            'whatsapp',
            'post_checkout_thankyou',
            jsonb_build_object(
                'booking_id', p_booking_id,
                'guest_name', b.guest_name,
                'phone', b.phone,
                'feedback_token', v_feedback_token,
                'hotel_name', h.name
            ),
            'pending',
            v_now + interval '1 hour'
        FROM bookings b
        JOIN hotels h ON h.id = b.hotel_id
        WHERE b.id = p_booking_id
        AND b.phone IS NOT NULL AND b.phone != '';

    EXCEPTION WHEN OTHERS THEN
        -- Non-blocking: log but don't fail checkout if notification fails
        RAISE WARNING 'Post-checkout notification failed: %', SQLERRM;
    END;


    ---------------------------------------------------------
    -- 🔟 Success Response
    ---------------------------------------------------------
    RETURN jsonb_build_object(
        'success', true,
        'checked_out_at', v_now,
        'feedback_token', v_feedback_token
    );

END;
$$;


ALTER FUNCTION "public"."checkout_stay"("p_hotel_id" "uuid", "p_booking_id" "uuid", "p_stay_id" "uuid", "p_force" boolean, "p_source" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."claim_hotel_invite"("p_token" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_user uuid;
    v_user_email text;
    v_invite RECORD;
BEGIN
    v_user := auth.uid();
    IF v_user IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    -- Lock invite row first
    SELECT *
    INTO v_invite
    FROM public.hotel_invites
    WHERE token = p_token
    FOR UPDATE;
 
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Invite not found';
    END IF;
 
    -- 1. Expiration check
    IF v_invite.expires_at < now() THEN
        RAISE EXCEPTION 'This invite session has expired. Please open the invite link again.';
    END IF;

    IF v_invite.status <> 'pending' THEN
        RAISE EXCEPTION 'This invite session has expired. Please open the invite link again.';
    END IF;
 
    -- 2. Fetch current user's email STRICTLY once
    SELECT email INTO STRICT v_user_email
    FROM auth.users
    WHERE id = v_user;

    -- Already claimed by someone else
    IF v_invite.claimed_by IS NOT NULL AND v_invite.claimed_by <> v_user THEN
        -- Secure Takeover Rule: Only allow if current user's email matches the invite's email
        IF lower(v_invite.email) <> lower(v_user_email) THEN
            RAISE EXCEPTION 'This invitation was sent to %. Please sign in using that email address to continue.', v_invite.email;
        END IF;
        
        -- If we reached here, email matches, so we allow the silent takeover.
    END IF;
 
    UPDATE public.hotel_invites
    SET
        claimed_by = v_user,
        claimed_at = now()
    WHERE id = v_invite.id
    AND status = 'pending'; -- Replay protection
 
    RETURN jsonb_build_object('success', true);
END;
$$;


ALTER FUNCTION "public"."claim_hotel_invite"("p_token" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."claim_pending_booking_groups"("p_limit" integer DEFAULT 20) RETURNS TABLE("booking_reference" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    WITH picked AS (
        SELECT ir.booking_reference
        FROM public.import_rows ir
        WHERE ir.status = 'pending'
        ORDER BY ir.id
        LIMIT p_limit
        FOR UPDATE SKIP LOCKED
    ),
    claimed AS (
        UPDATE public.import_rows r
        SET status = 'processing',
            processed_at = now()
        FROM picked p
        WHERE r.booking_reference = p.booking_reference
        RETURNING r.booking_reference
    )
    SELECT DISTINCT claimed.booking_reference
    FROM claimed;
END;
$$;


