    "retry_count" integer DEFAULT 0,
    "next_attempt_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "notification_queue_channel_check" CHECK (("channel" = ANY (ARRAY['sms'::"text", 'email'::"text", 'whatsapp'::"text"]))),
