CREATE OR REPLACE FUNCTION "public"."claim_rewards"("p_hotel_id" "uuid", "p_amount_paise" integer) RETURNS "public"."reward_vouchers"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
declare
v_user uuid := auth.uid();
v_needed int := p_amount_paise;
v_code text;
v_voucher reward_vouchers;
r record;
begin
if v_user is null then
raise exception 'not_authenticated';
end if;
if p_amount_paise is null or p_amount_paise < 10000 then -- min ₹100
raise exception 'minimum_claim_violated';
end if;
if (p_amount_paise % 100) <> 0 then
raise exception 'amount_must_be_whole_rupees';
end if;


for r in
select id, amount_paise from reward_credits
where user_id = v_user and hotel_id = p_hotel_id and status = 'available'
order by created_at asc
for update
loop
update reward_credits set status = 'locked' where id = r.id;
v_needed := v_needed - r.amount_paise;
exit when v_needed <= 0;
end loop;


if v_needed > 0 then
update reward_credits set status = 'available'
where user_id = v_user and hotel_id = p_hotel_id and status = 'locked';
raise exception 'insufficient_funds';
end if;


v_code := upper(encode(gen_random_bytes(6), 'hex'));


insert into reward_vouchers(code, user_id, hotel_id, amount_paise, status, expires_at)
values (v_code, v_user, p_hotel_id, p_amount_paise, 'active', now() + interval '6 months')
returning * into v_voucher;


v_needed := p_amount_paise;
for r in
select id, amount_paise from reward_credits
where user_id = v_user and hotel_id = p_hotel_id and status = 'locked'
order by created_at asc
loop
update reward_credits
set status = 'spent', voucher_id = v_voucher.id
where id = r.id;
v_needed := v_needed - r.amount_paise;
exit when v_needed <= 0;
end loop;


return v_voucher;
end;
$$;


ALTER FUNCTION "public"."claim_rewards"("p_hotel_id" "uuid", "p_amount_paise" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."claim_rewards"("p_hotel_id" "uuid", "p_amount_paise" bigint) RETURNS "public"."reward_vouchers"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid;
  v_code text;
  v_voucher reward_vouchers;
begin
  -- who’s calling
  select auth.uid() into v_user_id;
  if v_user_id is null then
    raise exception 'Not signed in';
  end if;

  -- validation
  if p_amount_paise is null or p_amount_paise < 100*100 then
    raise exception 'Minimum claim is ₹100';
  end if;

  -- check available balance for THIS user (view is already user-scoped via RLS)
  if not exists (
    select 1
    from rewards_overview o
    where o.hotel_id = p_hotel_id
      and o.available_paise >= p_amount_paise
  ) then
    raise exception 'Not enough available balance';
  end if;

  -- code = 12 hex chars from pgcrypto in extensions schema
  v_code := upper(encode(extensions.gen_random_bytes(6), 'hex'));

  insert into reward_vouchers (code, user_id, hotel_id, amount_paise, status)
  values (v_code, v_user_id, p_hotel_id, p_amount_paise, 'active')
  returning * into v_voucher;

  return v_voucher;
end;
$$;


