CREATE OR REPLACE FUNCTION "public"."collect_payment"("p_booking_id" "uuid", "p_amount" numeric, "p_method" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_folio_id UUID;
    v_payment_id UUID;
    v_hotel_id UUID;
    v_outstanding NUMERIC;
    v_booking_status TEXT;
BEGIN

    -- 1. Basic & Method Validation
    IF p_amount IS NULL OR p_amount <= 0 THEN
        RAISE EXCEPTION 'Invalid payment amount';
    END IF;

    IF p_method NOT IN ('CASH', 'CARD', 'UPI', 'BANK_TRANSFER') THEN
        RAISE EXCEPTION 'Invalid payment method: %', p_method;
    END IF;

    -- 2. Pessimistic Lock on Booking (Prevents Race Conditions)
    SELECT hotel_id, status INTO v_hotel_id, v_booking_status
    FROM bookings 
    WHERE id = p_booking_id
    FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Booking not found';
    END IF;

    -- 3. Enforce Booking Status
    IF UPPER(v_booking_status) NOT IN ('CHECKED_IN', 'INHOUSE', 'PRE_CHECKED_IN') THEN
        RAISE EXCEPTION 'Payments not allowed for booking status: %', v_booking_status;
    END IF;

    -- 4. Get and Lock Folio Row
    SELECT id INTO v_folio_id
    FROM folios
    WHERE booking_id = p_booking_id
    LIMIT 1
    FOR UPDATE;

    IF v_folio_id IS NULL THEN
        RAISE EXCEPTION 'Folio not found';
    END IF;

    -- 5. Calculate Outstanding Balance (Scoped strictly to Folio)
    SELECT COALESCE(SUM(amount), 0)
    INTO v_outstanding
    FROM folio_entries
    WHERE folio_id = v_folio_id;

    -- 6. Prevent Zero/Overpayment
    IF v_outstanding <= 0 THEN
        RAISE EXCEPTION 'No outstanding balance on this folio';
    END IF;

    IF p_amount > v_outstanding THEN
        RAISE EXCEPTION 'Payment of % exceeds outstanding balance of %', p_amount, v_outstanding;
    END IF;

    -- 7. Insert Payment Record (Trigger handles Folio Entry)
    INSERT INTO payments (
        hotel_id,
        booking_id,
        folio_id,
        amount,
        method,
        status,
        collected_by
    )
    VALUES (
        v_hotel_id,
        p_booking_id,
        v_folio_id,
        p_amount,
        p_method,
        'COMPLETED',
        auth.uid()
    )
    RETURNING id INTO v_payment_id;

    RETURN jsonb_build_object(
        'success', true,
        'payment_id', v_payment_id
    );
END;
$$;


ALTER FUNCTION "public"."collect_payment"("p_booking_id" "uuid", "p_amount" numeric, "p_method" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."collect_payment"("p_booking_id" "uuid", "p_amount" numeric, "p_method" "text", "p_user" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    v_folio_id UUID;
    v_payment_id UUID;
    v_hotel_id UUID;
BEGIN

    -- get hotel and folio
    SELECT hotel_id INTO v_hotel_id FROM bookings WHERE id = p_booking_id;
    
    SELECT id INTO v_folio_id
    FROM folios
    WHERE booking_id = p_booking_id
    LIMIT 1;

    -- create payment record
    INSERT INTO payments (hotel_id, booking_id, folio_id, amount, method, status, collected_by)
    VALUES (v_hotel_id, p_booking_id, v_folio_id, p_amount, p_method, 'COMPLETED', p_user)
    RETURNING id INTO v_payment_id;

    -- The trigger trg_payment_completed will handle inserting the folio_entry automatically!
    -- So we DO NOT need to insert it manually here to avoid duplication.
    -- (As added in the earlier enterprise checkout step)

    RETURN jsonb_build_object('success', true);
END;
$$;


