CREATE OR REPLACE FUNCTION "public"."create_feedback_token"("p_booking_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
    v_token TEXT;
    v_hotel_id UUID;
    v_expires_at TIMESTAMPTZ;
    v_existing_id UUID;
BEGIN
    SELECT hotel_id INTO v_hotel_id FROM public.bookings WHERE id = p_booking_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'Booking not found'; END IF;

    v_expires_at := now() + interval '30 days';

    SELECT id INTO v_existing_id FROM public.feedback_tokens
    WHERE booking_id = p_booking_id AND used_at IS NULL FOR UPDATE;

    IF FOUND THEN
        UPDATE public.feedback_tokens
        SET token = encode(extensions.gen_random_bytes(32), 'hex'), -- Explicit schema reference
            expires_at = v_expires_at,
            updated_at = now()
        WHERE id = v_existing_id
        RETURNING token INTO v_token;
    ELSE
        INSERT INTO public.feedback_tokens (booking_id, hotel_id, token, expires_at)
        VALUES (
            p_booking_id,
            v_hotel_id,
            encode(extensions.gen_random_bytes(32), 'hex'), -- Explicit schema reference
            v_expires_at
        )
        RETURNING token INTO v_token;
    END IF;

    RETURN jsonb_build_object('booking_id', p_booking_id, 'token', v_token, 'expires_at', v_expires_at);
END;
$$;


ALTER FUNCTION "public"."create_feedback_token"("p_booking_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_food_order"("p_hotel_id" "uuid", "p_stay_id" "uuid", "p_room_id" "uuid", "p_items" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_order_id UUID := gen_random_uuid();
    v_total NUMERIC := 0;
BEGIN
    INSERT INTO food_orders (
        id, hotel_id, stay_id, room_id, status
    )
    VALUES (
        v_order_id, p_hotel_id, p_stay_id, p_room_id, 'CREATED'
    );

    INSERT INTO food_order_items (
        id,
        food_order_id,
        menu_item_id,
        item_name,
        quantity,
        unit_price,
        total_price,
        modifiers,
        status
    )
    SELECT
        gen_random_uuid(),
        v_order_id,
        (i->>'menu_item_id')::UUID,
        i->>'name',
        (i->>'qty')::INT,
        (i->>'unit_price')::NUMERIC,
        (i->>'qty')::INT * (i->>'unit_price')::NUMERIC,
        COALESCE(i->'modifiers','{}'),
        'PENDING'
    FROM jsonb_array_elements(p_items) i;

    SELECT SUM(total_price)
    INTO v_total
    FROM food_order_items
    WHERE food_order_id = v_order_id;

    UPDATE food_orders
    SET total_amount = v_total
    WHERE id = v_order_id;

    INSERT INTO food_order_events
    VALUES (
        gen_random_uuid(),
        v_order_id,
        'ORDER_CREATED',
        'GUEST',
        auth.uid(),
        '{}',
        now()
    );

    RETURN v_order_id;
END;
$$;


ALTER FUNCTION "public"."create_food_order"("p_hotel_id" "uuid", "p_stay_id" "uuid", "p_room_id" "uuid", "p_items" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_food_order"("p_hotel_id" "uuid", "p_stay_id" "uuid", "p_room_id" "uuid", "p_items" "jsonb", "p_total_amount" numeric DEFAULT 0, "p_special_instructions" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_order_id UUID := gen_random_uuid();
    v_display_id TEXT;
    v_total NUMERIC := 0;
BEGIN
    -- Pre-generate display_id so we can return it
    v_display_id := 'ORD-' || nextval('food_order_display_id_seq');

    INSERT INTO food_orders (
        id, display_id, hotel_id, stay_id, room_id, status, total_amount, special_instructions
    )
    VALUES (
        v_order_id, v_display_id, p_hotel_id, p_stay_id, p_room_id, 'CREATED', p_total_amount, p_special_instructions
    );

    INSERT INTO food_order_items (
        id,
        food_order_id,
        menu_item_id,
        item_name,
        quantity,
        unit_price,
        total_price,
        modifiers,
        status
    )
    SELECT
        gen_random_uuid(),
        v_order_id,
        (i->>'menu_item_id')::UUID,
        i->>'name',
        (i->>'qty')::INT,
        (i->>'unit_price')::NUMERIC,
        (i->>'qty')::INT * (i->>'unit_price')::NUMERIC,
        COALESCE(i->'modifiers','{}'),
        'PENDING'
    FROM jsonb_array_elements(p_items) i;

    -- If total wasn't passed or is 0, calculate it
    IF p_total_amount <= 0 THEN
        SELECT SUM(total_price)
        INTO v_total
        FROM food_order_items
        WHERE food_order_id = v_order_id;

        UPDATE food_orders
        SET total_amount = v_total
        WHERE id = v_order_id;
    END IF;

    -- Event
    INSERT INTO food_order_events
    VALUES (
        gen_random_uuid(),
        v_order_id,
        'ORDER_CREATED',
        'GUEST',
        auth.uid(),
        '{}',
        now()
    );

    -- Notify
    PERFORM pg_notify(
        'food_orders',
        json_build_object(
            'event', 'ORDER_CREATED',
            'order_id', v_order_id,
            'hotel_id', p_hotel_id,
            'display_id', v_display_id
        )::text
    );

    RETURN jsonb_build_object('id', v_order_id, 'display_id', v_display_id);
END;
$$;


ALTER FUNCTION "public"."create_food_order"("p_hotel_id" "uuid", "p_stay_id" "uuid", "p_room_id" "uuid", "p_items" "jsonb", "p_total_amount" numeric, "p_special_instructions" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_hotel_invite"("p_hotel_id" "uuid", "p_email" "text", "p_role_id" "uuid", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_invite RECORD;
BEGIN
    p_email := lower(trim(p_email));

    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    -- [SECURITY] Domain safety check
    IF p_email ILIKE '%@mailinator.com' OR p_email ILIKE '%@10minutemail.com' OR p_email ILIKE '%@tempmail.com' THEN
       RAISE EXCEPTION 'Disallowed email domain provided. Please use a standard email address.';
    END IF;

    -- [SECURITY] Hotel rate limit (prevent hotel spam)
    IF (
        SELECT count(*)
        FROM public.hotel_invites
        WHERE hotel_id = p_hotel_id
        AND created_at > now() - interval '1 hour'
    ) >= 50
    THEN
        RAISE EXCEPTION 'Invite limit exceeded for this hotel. Please try again later.';
    END IF;

    -- [SECURITY] User rate limit (prevent staff spam)
    IF (
        SELECT count(*)
        FROM public.hotel_invites
        WHERE created_by = auth.uid()
        AND created_at > now() - interval '1 hour'
    ) >= 20
    THEN
        RAISE EXCEPTION 'You have sent too many invites recently. Please try again later.';
    END IF;

    -- Permission check: Caller must be OWNER, ADMIN, MANAGER OR Platform Admin
    IF NOT public.is_platform_admin() AND NOT EXISTS (
        SELECT 1
        FROM public.hotel_members hm
        JOIN public.hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
        JOIN public.hotel_roles hr ON hr.id = hmr.role_id
        WHERE hm.hotel_id = p_hotel_id
        AND hm.user_id = auth.uid()
        AND hr.code IN ('OWNER', 'ADMIN', 'MANAGER')
        AND hm.is_active = true
        AND hr.is_active = true
    ) THEN
        RAISE EXCEPTION 'Insufficient permissions to create invites for this hotel';
    END IF;

    -- Insert the invite (idempotency handled by unique index ux_unique_active_invite)
    INSERT INTO public.hotel_invites (
        hotel_id,
        email,
        role_id,
        invite_metadata,
        created_by
    )
    VALUES (
        p_hotel_id,
        p_email,
        p_role_id,
        p_metadata,
        auth.uid()
    )
    RETURNING * INTO v_invite;

    -- Queue the email notification
    INSERT INTO public.notification_queue (
        channel,
        template_code,
        payload
    )
    VALUES (
        'email',
        'staff_invite',
        jsonb_build_object(
            'email', v_invite.email,
            'invite_token', v_invite.token,
            'hotel_id', v_invite.hotel_id,
            'role_id', v_invite.role_id
        )
    );

    -- Enterprise Audit Log
    INSERT INTO public.hotel_audit_logs (
        hotel_id,
        user_id,
        action,
        entity_type,
        entity_id,
        changes
    )
    VALUES (
        p_hotel_id,
        auth.uid(),
        'INVITE_CREATED',
        'hotel_invites',
        v_invite.id,
        jsonb_build_object(
            'email', v_invite.email,
            'role_id', v_invite.role_id
        )
    );

    RETURN jsonb_build_object(
        'success', true,
        'invite_id', v_invite.id,
        'token', v_invite.token
    );
END;
$$;


ALTER FUNCTION "public"."create_hotel_invite"("p_hotel_id" "uuid", "p_email" "text", "p_role_id" "uuid", "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_hotel_onboarding"("payload" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    new_hotel_id uuid;
    owner_role_id uuid;
    owner_member_id uuid;
    v_owner_user_id uuid;
BEGIN
    IF payload->>'name' IS NULL OR payload->>'slug' IS NULL THEN
        RAISE EXCEPTION 'Hotel name and slug are required';
    END IF;

    v_owner_user_id := (payload->>'owner_user_id')::uuid;

    -- 1. Insert Hotel Core
    INSERT INTO public.hotels (
        name, slug, description, phone, email, address,
        city, state, country, postal_code,
        latitude, longitude, legal_name, gst_number,
        logo_path, cover_image_path, brand_color,
        onboarding_started_at
    )
    VALUES (
        payload->>'name',
        payload->>'slug',
        payload->>'description',
        payload->>'phone',
        payload->>'email',
        payload->>'address',
        payload->>'city',
        payload->>'state',
        payload->>'country',
        payload->>'postal_code',
        (payload->>'latitude')::numeric,
        (payload->>'longitude')::numeric,
        payload->>'legal_name',
        payload->>'gst_number',
        payload->>'logo_path',
        payload->>'cover_image_path',
        payload->>'brand_color',
        now()
    )
    RETURNING id INTO new_hotel_id;

    -- 2. Insert Guest Info Extensions from Onboarding Step 1
    INSERT INTO public.hotel_guest_info (
        hotel_id, 
        wifi_ssid, 
        wifi_password, 
        breakfast_start, 
        breakfast_end, 
        notes
    )
    VALUES (
        new_hotel_id,
        payload->>'wifi_ssid',
        payload->>'wifi_password',
        CAST(NULLIF(payload->>'breakfast_start', '') AS time),
        CAST(NULLIF(payload->>'breakfast_end', '') AS time),
        payload->>'guest_notes'
    );

    PERFORM public.mark_onboarding_step_complete(
        new_hotel_id,
        'hotel_details'
    );

    INSERT INTO public.hotel_audit_logs (
        hotel_id, user_id, action, entity_type, entity_id, changes, created_at
    )
    VALUES (
        new_hotel_id,
        auth.uid(),
        'HOTEL_CREATED',
        'hotels',
        new_hotel_id,
        jsonb_build_object(
            'name', payload->>'name',
            'slug', payload->>'slug',
            'owner_user_id', v_owner_user_id,
            'wifi_ssid', payload->>'wifi_ssid'
        ),
        now()
    );

    RETURN new_hotel_id;
END;
$$;


ALTER FUNCTION "public"."create_hotel_onboarding"("payload" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_menu_item"("p_hotel_id" "uuid", "p_name" "text", "p_category_id" "uuid", "p_price" numeric, "p_is_veg" boolean, "p_active" boolean, "p_metadata" "jsonb", "p_internal_notes" "text", "p_availability_days" integer[], "p_start_time" time without time zone, "p_end_time" time without time zone, "p_hide_outside" boolean) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_item_id UUID;
    v_item_key TEXT;
BEGIN
    -- --------------------------------------------------------
    -- 0. AUTHORIZATION (role-table aware)
    -- --------------------------------------------------------
    IF NOT EXISTS (
        SELECT 1
        FROM hotel_members hm
        JOIN hotel_member_roles hmr
          ON hmr.hotel_member_id = hm.id
        JOIN hotel_roles r
          ON r.id = hmr.role_id
        WHERE hm.hotel_id = p_hotel_id
          AND hm.user_id = auth.uid()
          AND r.code IN ('OWNER', 'ADMIN', 'KITCHEN_MANAGER')
    ) THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Unauthorized menu item creation',
            ERRCODE = 'P0001';
    END IF;

    -- --------------------------------------------------------
    -- 1. BASIC VALIDATION
    -- --------------------------------------------------------
    IF p_name IS NULL OR trim(p_name) = '' THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Item name cannot be empty',
            ERRCODE = 'P0002';
    END IF;

    IF p_price < 0 THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Price must be non-negative',
            ERRCODE = 'P0002';
    END IF;

    IF p_start_time >= p_end_time THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Start time must be before end time',
            ERRCODE = 'P0002';
    END IF;

    IF p_availability_days IS NOT NULL
       AND EXISTS (
           SELECT 1
           FROM unnest(p_availability_days) d
           WHERE d < 1 OR d > 7
       ) THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Availability days must be between 1 (Mon) and 7 (Sun)',
            ERRCODE = 'P0002';
    END IF;

    -- --------------------------------------------------------
    -- 2. CATEGORY VALIDATION (hotel-scoped & active)
    -- --------------------------------------------------------
    IF NOT EXISTS (
        SELECT 1
        FROM menu_categories mc
        WHERE mc.id = p_category_id
          AND mc.hotel_id = p_hotel_id
          AND mc.active = true
    ) THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Invalid or inactive menu category',
            ERRCODE = 'P0003';
    END IF;

    -- --------------------------------------------------------
    -- 3. GENERATE ITEM KEY (system-owned)
    -- --------------------------------------------------------
    v_item_key :=
        UPPER(
          REGEXP_REPLACE(
            TRIM(p_name),
            '[^a-zA-Z0-9]+',
            '_',
            'g'
          )
        );

    -- --------------------------------------------------------
    -- 4. DUPLICATE KEY PROTECTION (per hotel)
    -- --------------------------------------------------------
    IF EXISTS (
        SELECT 1
        FROM menu_items
        WHERE hotel_id = p_hotel_id
          AND item_key = v_item_key
    ) THEN
        RAISE EXCEPTION USING
            MESSAGE = format('Menu item with name "%s" already exists', p_name),
            ERRCODE = 'P0004';
    END IF;

    -- --------------------------------------------------------
    -- 5. INSERT MENU ITEM
    -- --------------------------------------------------------
    INSERT INTO menu_items (
        hotel_id,
        item_key,
        name,
        category_id,
        price,
        is_veg,
        active,
        metadata,
        internal_notes
    )
    VALUES (
        p_hotel_id,
        v_item_key,
        p_name,
        p_category_id,
        p_price,
        p_is_veg,
        p_active,
        COALESCE(p_metadata, '{"veg":false,"jain":false,"vegan":false}'::jsonb),
        p_internal_notes
    )
    RETURNING id INTO v_item_id;

    -- --------------------------------------------------------
    -- 6. INSERT AVAILABILITY (optional)
    -- --------------------------------------------------------
    IF p_availability_days IS NOT NULL
       AND array_length(p_availability_days, 1) > 0 THEN

        INSERT INTO menu_item_availability (
            menu_item_id,
            day_of_week,
            start_time,
            end_time,
            hide_outside_window
        )
        SELECT
            v_item_id,
            d.day,
            p_start_time,
            p_end_time,
            p_hide_outside
        FROM unnest(p_availability_days) AS d(day);

    END IF;

    -- --------------------------------------------------------
    -- 7. RETURN CREATED ITEM ID
    -- --------------------------------------------------------
    RETURN v_item_id;
END;
$$;


ALTER FUNCTION "public"."create_menu_item"("p_hotel_id" "uuid", "p_name" "text", "p_category_id" "uuid", "p_price" numeric, "p_is_veg" boolean, "p_active" boolean, "p_metadata" "jsonb", "p_internal_notes" "text", "p_availability_days" integer[], "p_start_time" time without time zone, "p_end_time" time without time zone, "p_hide_outside" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_precheckin_token"("p_booking_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_token TEXT;
    v_expires_at TIMESTAMPTZ;
    v_checkin_date DATE;
    v_hotel_id UUID;
BEGIN
    -- Get scheduled checkin date and hotel_id
    SELECT scheduled_checkin_at, hotel_id INTO v_checkin_date, v_hotel_id
    FROM public.bookings
    WHERE id = p_booking_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Booking not found';
    END IF;

    -- Default expiry: 23:59:59 on check-in day
    v_expires_at := (v_checkin_date::timestamp + interval '1 day' - interval '1 second');
    
    -- Fallback if checkin date is missing or invalid logic: 30 days
    IF v_expires_at IS NULL THEN
        v_expires_at := now() + INTERVAL '30 days';
    END IF;

    -- Hardening 3: Refresh token on conflict
    -- Using ON CONSTRAINT for unambiguous target matching
    INSERT INTO public.precheckin_tokens (booking_id, hotel_id, token, expires_at)
    VALUES (
        p_booking_id,
        v_hotel_id,
        translate(gen_random_uuid()::text, '-', '') || translate(gen_random_uuid()::text, '-', ''),
        v_expires_at
    )
    ON CONFLICT ON CONSTRAINT uq_precheckin_booking
    DO UPDATE SET 
        token = EXCLUDED.token,
        hotel_id = EXCLUDED.hotel_id,
        expires_at = EXCLUDED.expires_at,
        updated_at = now()
    RETURNING token INTO v_token;

    RETURN jsonb_build_object(
        'booking_id', p_booking_id,
        'token', v_token,
        'expires_at', v_expires_at
    );
END;
$$;


ALTER FUNCTION "public"."create_precheckin_token"("p_booking_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_service_request"("p_hotel_id" "uuid", "p_room_id" "uuid", "p_zone_id" "uuid", "p_service_id" "uuid", "p_description" "text", "p_created_by_type" "text", "p_created_by_id" "uuid", "p_stay_id" "uuid" DEFAULT NULL::"uuid", "p_media_urls" "jsonb" DEFAULT '[]'::"jsonb", "p_priority" "text" DEFAULT 'NORMAL'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_ticket_id UUID;
  v_display_id TEXT;  -- To capture display_id
  v_service_title TEXT;
  v_department_id UUID;
  v_url TEXT;
  v_final_priority TEXT;
BEGIN
  ----------------------------------------------------------------
  -- 0️⃣ Input validation & Service Lookup
  ----------------------------------------------------------------
  -- Enforce location XOR rule
  IF (p_room_id IS NULL AND p_zone_id IS NULL)
     OR (p_room_id IS NOT NULL AND p_zone_id IS NOT NULL) THEN
    RAISE EXCEPTION 'Exactly one of room_id or zone_id must be provided';
  END IF;

  -- Validate creator type
  IF p_created_by_type NOT IN ('GUEST','STAFF','FRONT_DESK','SYSTEM') THEN
    RAISE EXCEPTION 'Invalid created_by_type: %', p_created_by_type;
  END IF;
  
  -- Validate & Normalize priority
  v_final_priority := UPPER(p_priority);
  IF v_final_priority NOT IN ('LOW', 'NORMAL', 'HIGH', 'URGENT') THEN
     v_final_priority := 'NORMAL';
  END IF;

  -- Lookup Service & Department
  SELECT label, department_id INTO v_service_title, v_department_id
  FROM services WHERE id = p_service_id AND hotel_id = p_hotel_id;

  IF v_service_title IS NULL THEN
     RAISE EXCEPTION 'Service not found or invalid for this hotel (ID: %)', p_service_id;
  END IF;

  -- Ensure active SLA policy exists
  IF NOT EXISTS (SELECT 1 FROM sla_policies WHERE department_id = v_department_id AND is_active = true) THEN
    RAISE EXCEPTION 'No active SLA policy found for department %', v_department_id;
  END IF;

  ----------------------------------------------------------------
  -- 1️⃣ Create ticket
  ----------------------------------------------------------------
  INSERT INTO tickets (
    hotel_id, service_department_id, service_id, stay_id, room_id, zone_id, 
    title, description, status, current_assignee_id, created_by_type, created_by_id, priority
  ) VALUES (
    p_hotel_id, v_department_id, p_service_id, p_stay_id, p_room_id, p_zone_id, 
    v_service_title, p_description, 'NEW', NULL, p_created_by_type, p_created_by_id, v_final_priority
  ) 
  RETURNING id, display_id INTO v_ticket_id, v_display_id; -- Capture both ID and display_id

  ----------------------------------------------------------------
  -- 1️⃣(b) Insert Attachments
  ----------------------------------------------------------------
  IF p_media_urls IS NOT NULL AND jsonb_array_length(p_media_urls) > 0 THEN
    FOR v_url IN SELECT value::text FROM jsonb_array_elements_text(p_media_urls)
    LOOP
      v_url := trim(both '"' from v_url);
      INSERT INTO ticket_attachments (ticket_id, file_path, uploaded_by)
      VALUES (
        v_ticket_id, v_url, 
        CASE 
          WHEN p_created_by_type IN ('STAFF', 'FRONT_DESK') AND p_created_by_id IS NOT NULL 
          THEN (SELECT user_id FROM hotel_members WHERE id = p_created_by_id)
          ELSE auth.uid() 
        END
      );
    END LOOP;
  END IF;

  ----------------------------------------------------------------
  -- 2️⃣ Audit: CREATED event
  ----------------------------------------------------------------
  INSERT INTO ticket_events (
    ticket_id, event_type, new_status, actor_type, actor_id, comment
  ) VALUES (
    v_ticket_id, 'CREATED', 'NEW', p_created_by_type,
    CASE WHEN p_created_by_type IN ('STAFF','FRONT_DESK') THEN p_created_by_id ELSE NULL END,
    'Service request created: ' || v_service_title
  );

  ----------------------------------------------------------------
  -- 3️⃣ Initialize SLA runtime state
  ----------------------------------------------------------------
  INSERT INTO ticket_sla_state (ticket_id, sla_policy_id)
  SELECT v_ticket_id, sp.id
  FROM sla_policies sp
  WHERE sp.department_id = v_department_id AND sp.is_active = true
  LIMIT 1;

  -- Return JSON object with both IDs
  RETURN jsonb_build_object(
    'id', v_ticket_id,
    'display_id', v_display_id
  );
END;
$$;


ALTER FUNCTION "public"."create_service_request"("p_hotel_id" "uuid", "p_room_id" "uuid", "p_zone_id" "uuid", "p_service_id" "uuid", "p_description" "text", "p_created_by_type" "text", "p_created_by_id" "uuid", "p_stay_id" "uuid", "p_media_urls" "jsonb", "p_priority" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_ticket"("p_service_department_id" "uuid", "p_title" "text", "p_description" "text", "p_created_by_type" "text", "p_created_by_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_ticket_id uuid := gen_random_uuid();
BEGIN
  INSERT INTO tickets (
    id,
    service_department_id,
    title,
    description,
    status,
    created_by_type,
    created_by_id
  )
  VALUES (
    v_ticket_id,
    p_service_department_id,
    p_title,
    p_description,
    'NEW',
    p_created_by_type,
    p_created_by_id
  );

  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    new_status,
    actor_type
  )
  VALUES (
    v_ticket_id,
    'CREATED',
    'NEW',
    'SYSTEM'
  );

  RETURN v_ticket_id;
END;
$$;


ALTER FUNCTION "public"."create_ticket"("p_service_department_id" "uuid", "p_title" "text", "p_description" "text", "p_created_by_type" "text", "p_created_by_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_walkin_v2"("p_hotel_id" "uuid", "p_guest_details" "jsonb", "p_room_selections" "jsonb", "p_checkin_date" "date", "p_checkout_date" "date", "p_adults" integer DEFAULT 1, "p_children" integer DEFAULT 0, "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_guest_id UUID;
  v_booking_id UUID;
  v_booking_room_id UUID;
  v_stay_id UUID;
  v_booking_code TEXT;
  v_checkin_ts TIMESTAMPTZ;
  v_checkout_ts TIMESTAMPTZ;
  v_room_id UUID;
  v_room_type_id UUID;
  v_stay_ids UUID[] := '{}';
  v_rooms_count INT;
  v_first_room_id UUID;
  v_first_room_type_id UUID;
BEGIN
  -- ── 1. Validate Input ──
  IF p_room_selections IS NULL OR jsonb_array_length(p_room_selections) = 0 THEN
    RAISE EXCEPTION 'At least one room selection is required';
  END IF;
  v_rooms_count := jsonb_array_length(p_room_selections);

  IF coalesce(trim(p_guest_details->>'full_name'),'') = '' THEN
    RAISE EXCEPTION 'Guest name required';
  END IF;

  -- ── 2. Compute & Validate Timestamps ──
  IF p_checkin_date = CURRENT_DATE THEN
    v_checkin_ts := now();
  ELSE
    v_checkin_ts := (p_checkin_date || ' 14:00:00')::timestamptz;
  END IF;

  v_checkout_ts := (p_checkout_date || ' 11:00:00')::timestamptz;

  IF v_checkout_ts <= v_checkin_ts THEN
    RAISE EXCEPTION 'Checkout must be after checkin';
  END IF;

  -- ── 3. Room Validation & Pre-loop Safety ──
  -- Validate no duplicate rooms in the input array
  IF (
    SELECT COUNT(DISTINCT room_id)
    FROM jsonb_to_recordset(p_room_selections) AS r(room_id UUID)
  ) != v_rooms_count THEN
    RAISE EXCEPTION 'Duplicate rooms selected';
  END IF;

  -- Extract first room for header-level compatibility
  SELECT room_id, room_type_id 
  INTO v_first_room_id, v_first_room_type_id
  FROM jsonb_to_recordset(p_room_selections) AS r(room_id UUID, room_type_id UUID)
  LIMIT 1;

  -- ── Validate Header Room Existence, Hotel Association & Resolve Type ──
  SELECT room_type_id
  INTO v_first_room_type_id
  FROM rooms
  WHERE id = v_first_room_id
  AND hotel_id = p_hotel_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Invalid room % or does not belong to hotel', v_first_room_id;
  END IF;

  -- ── 4. Create/Upsert Guest (Modular) ──
  v_guest_id := public.upsert_guest_v2(p_guest_details);

  -- ── 5. Guest Idempotency Lock ──
  -- Prevents concurrent double walk-in bookings for the same guest
  PERFORM pg_advisory_xact_lock(
    hashtextextended(p_hotel_id::text || ':' || v_guest_id::text, 0)
  );

  -- ── 6. Create Booking ──
  v_booking_code := 'W-' || to_char(now(), 'YYMMDDHH24MISS') || '-' || substring(gen_random_uuid()::text, 1, 4);

  INSERT INTO bookings (
    hotel_id, guest_id, guest_name, phone, email,
    status, source, code,
    scheduled_checkin_at, scheduled_checkout_at,
    adults, children,
    adults_total, children_total,
    rooms_total,
    room_id, room_type_id
  ) VALUES (
    p_hotel_id, v_guest_id,
    p_guest_details->>'full_name', p_guest_details->>'mobile', p_guest_details->>'email',
    'CONFIRMED', 'walk_in', v_booking_code,
    v_checkin_ts, v_checkout_ts,
    p_adults, p_children,
    p_adults, p_children,
    v_rooms_count,
    v_first_room_id, v_first_room_type_id
  ) RETURNING id INTO v_booking_id;

  -- ── 7. Process Each Room (Loop) ──
  -- Optimized: Use jsonb_to_recordset to parse JSON once and loop over typed records
  FOR v_room_id IN 
    SELECT room_id 
    FROM jsonb_to_recordset(p_room_selections) AS r(room_id UUID)
  LOOP
    -- 7a. Room Advisory Lock (Concurrency Safety)
    PERFORM pg_advisory_xact_lock(
      hashtextextended(p_hotel_id::text || ':' || v_room_id::text, 0)
    );

    -- 7b. Validate room, lock it (row-level), and resolve room_type_id in one hit
    SELECT room_type_id
    INTO v_room_type_id
    FROM rooms
    WHERE id = v_room_id
    AND hotel_id = p_hotel_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Room % does not belong to hotel', v_room_id;
    END IF;

    -- 7d. Create booking_room
    INSERT INTO booking_rooms (
      booking_id, hotel_id, room_type_id, room_id, status
    ) VALUES (
      v_booking_id, p_hotel_id, v_room_type_id, v_room_id, 'CHECKED_IN'
    ) RETURNING id INTO v_booking_room_id;

    -- 7e. Create stay (linked to booking_room)
    INSERT INTO stays (
      hotel_id, guest_id, room_id, booking_id, booking_room_id,
      booking_code, status, source,
      scheduled_checkin_at, scheduled_checkout_at, actual_checkin_at
    ) VALUES (
      p_hotel_id, v_guest_id, v_room_id, v_booking_id, v_booking_room_id,
      v_booking_code, 'inhouse', 'walk_in',
      v_checkin_ts, v_checkout_ts, now()
    ) RETURNING id INTO v_stay_id;

    v_stay_ids := array_append(v_stay_ids, v_stay_id);

    -- 7f. Log event per room
    INSERT INTO checkin_events (stay_id, event_type, actor_id, meta)
    VALUES (
      v_stay_id, 'COMPLETED', p_actor_id,
      jsonb_build_object(
        'method', 'walk_in',
        'actor_id', p_actor_id,
        'device', 'kiosk',
        'hotel_id', p_hotel_id,
        'room_id', v_room_id,
        'booking_room_id', v_booking_room_id,
        'rooms_total', v_rooms_count
      )
    );
  END LOOP;

  -- ── 8. Transition Booking to CHECKED_IN ──
  -- This satisfies the trigger that requires a stay record before status update.
  UPDATE bookings
  SET
    status = 'CHECKED_IN',
    checked_in_at = now()
  WHERE id = v_booking_id;

  RETURN jsonb_build_object(
    'stay_ids', to_jsonb(v_stay_ids),
    'booking_id', v_booking_id,
    'booking_code', v_booking_code,
    'rooms_checked_in', v_rooms_count,
    'status', 'SUCCESS'
  );
EXCEPTION
  WHEN exclusion_violation THEN
    -- Covers both stays overlap and unique_active_room constraint
    RAISE EXCEPTION 'One or more selected rooms are currently busy or checked-in';
  WHEN OTHERS THEN
    RAISE;
END;
$$;


ALTER FUNCTION "public"."create_walkin_v2"("p_hotel_id" "uuid", "p_guest_details" "jsonb", "p_room_selections" "jsonb", "p_checkin_date" "date", "p_checkout_date" "date", "p_adults" integer, "p_children" integer, "p_actor_id" "uuid") OWNER TO "postgres";


