    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    e.id,
    e.name,
    e.start_at,
    e.end_at,
    e.venue,
    e.status,
    e.risk_status,
    e.progress_pct
