CREATE OR REPLACE FUNCTION "public"."fetch_pending_booking_groups"("p_limit" integer DEFAULT 50) RETURNS TABLE("booking_reference" "text")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
    SELECT g.booking_reference
    FROM (
        SELECT booking_reference,
               MIN(id::text)::uuid AS lock_id
        FROM public.import_rows
        WHERE status = 'pending'
        GROUP BY booking_reference
        ORDER BY booking_reference
        LIMIT p_limit
    ) g
    JOIN public.import_rows r ON r.id = g.lock_id
    FOR UPDATE OF r SKIP LOCKED;
$$;


ALTER FUNCTION "public"."fetch_pending_booking_groups"("p_limit" integer) OWNER TO "postgres";


