CREATE TABLE IF NOT EXISTS "public"."import_rows" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "batch_id" "uuid" NOT NULL,
    "hotel_id" "uuid" NOT NULL,
    "row_number" integer,
    "booking_reference" "text" NOT NULL,
    "row_data" "jsonb",
    "status" "text" DEFAULT 'uploaded'::"text",
    "error_message" "text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "processed_at" timestamp with time zone,
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "room_seq" integer,
    "guest_seq" integer,
    "primary_guest_flag" boolean DEFAULT false,
    "source" "text" DEFAULT 'csv'::"text",
    "source_updated_at" timestamp with time zone,
    "source_hash" "text",
    CONSTRAINT "import_rows_status_check" CHECK (("status" = ANY (ARRAY['uploaded'::"text", 'pending'::"text", 'validating'::"text", 'valid'::"text", 'processing'::"text", 'importing'::"text", 'imported'::"text", 'notified'::"text", 'error'::"text"])))
);


ALTER TABLE "public"."import_rows" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fetch_pending_rows"("p_limit" integer DEFAULT 100) RETURNS SETOF "public"."import_rows"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
    SELECT r.*
    FROM public.import_rows r
    JOIN public.import_batches b ON b.id = r.batch_id
    WHERE r.status = 'pending'
    AND b.status = 'processing' -- Only process if batch is confirmed
    ORDER BY r.id
    LIMIT p_limit
    FOR UPDATE OF r SKIP LOCKED; -- Lock the ROW, not the batch join
$$;


ALTER FUNCTION "public"."fetch_pending_rows"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."gen_vaiyu_id"() RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
declare
  candidate text;
  exists_id boolean;
begin
  loop
    candidate := 'V-' || lpad((floor(random()*1000000))::int::text, 6, '0');
    select exists(select 1 from public.profiles p where p.vaiyu_id = candidate)
      into exists_id;
    exit when not exists_id;
  end loop;
  return candidate;
end;
$$;


ALTER FUNCTION "public"."gen_vaiyu_id"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_ai_schedule_v2"("p_week_start" "date", "p_zone_id" "uuid", "p_demand" "jsonb", "p_hotel_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_day date;
  v_shift_type text;
  v_required int;

  v_result jsonb := '[]'::jsonb;

  v_candidate record;
  v_candidates jsonb;

  v_selected jsonb;
  v_attempt int;

  v_score int;
  v_conflicts int;

  -- in-memory tracking
  v_temp_assignments jsonb := '[]'::jsonb;

begin

  -- =====================================================
  -- LOOP DAYS
  -- =====================================================
  for v_day in 
    select generate_series(p_week_start, p_week_start + 6, interval '1 day')::date
  loop

    for v_shift_type in select * from jsonb_object_keys(p_demand)
    loop

      v_required := (p_demand ->> v_shift_type)::int;

      for i in 1..v_required
      loop

        -- =====================================================
        -- BUILD CANDIDATE LIST (TOP N)
        -- =====================================================
        v_candidates := '[]'::jsonb;

        for v_candidate in
          select 
            hm.id as staff_id,
            sd.department_id,
            sd.priority,
            sd.is_primary
          from public.hotel_members hm
          join public.staff_departments sd 
            on sd.staff_id = hm.id
          where hm.hotel_id = p_hotel_id
            and hm.is_active = true
            and sd.is_active = true
        loop

          v_score := 0;

          -- =========================
          -- SCORING
          -- =========================

          -- department match
          if p_zone_id is not null then
            if exists (
              select 1 from public.hotel_zones z
              where z.id = p_zone_id
                and z.department_id = v_candidate.department_id
            ) then
              v_score := v_score + case when v_candidate.is_primary then 40 else 25 end;
            else
              v_score := v_score - 100;
            end if;
          else
            -- If no specific zone, reward primary departments globally
            v_score := v_score + case when v_candidate.is_primary then 40 else 25 end;
          end if;

          -- priority
          v_score := v_score + (30 - (coalesce(v_candidate.priority, 1) * 10));

          -- workload penalty (temp + real)
          v_score := v_score - (
            select count(*) * 5
            from jsonb_array_elements(v_temp_assignments) x
            where (x->>'staff_id')::uuid = v_candidate.staff_id
          );

          -- fatigue (temp simulation)
          if exists (
            select 1
            from jsonb_array_elements(v_temp_assignments) x
            where (x->>'staff_id')::uuid = v_candidate.staff_id
              and (x->>'shift_date')::date = v_day
          ) then
            v_score := v_score - 50;
          end if;

          -- add to candidate list
          v_candidates := v_candidates || jsonb_build_object(
            'staff_id', v_candidate.staff_id,
            'department_id', v_candidate.department_id,
            'score', v_score
          );

        end loop;

        -- =====================================================
        -- SORT CANDIDATES (TOP 3)
        -- =====================================================
        v_candidates := (
          select jsonb_agg(elem)
          from (
            select elem
            from jsonb_array_elements(v_candidates) elem
            order by (elem->>'score')::int desc
            limit 3
          ) t
        );

        -- =====================================================
        -- TRY BEST → BACKTRACK IF NEEDED
        -- =====================================================
        v_selected := null;

        for v_attempt in 0..coalesce(jsonb_array_length(v_candidates)-1, -1)
        loop

          v_selected := v_candidates -> v_attempt;

          -- simulate conflict count
          v_conflicts := (
            select count(*)
            from jsonb_array_elements(v_temp_assignments) x
            where (x->>'staff_id') = (v_selected->>'staff_id')
              and (x->>'shift_date') = v_day::text
          );

          -- if acceptable → pick
          if v_conflicts = 0 then
            exit;
          end if;

        end loop;

        -- =====================================================
        -- FINALIZE ASSIGNMENT
        -- =====================================================
        if v_selected is not null then

          v_temp_assignments := v_temp_assignments || jsonb_build_object(
            'staff_id', v_selected->>'staff_id',
            'department_id', v_selected->>'department_id',
            'shift_date', v_day,
            'shift_type', v_shift_type
          );

          v_result := v_result || jsonb_build_object(
            'staff_id', v_selected->>'staff_id',
            'department_id', v_selected->>'department_id',
            'shift_date', v_day,
            'shift_type', v_shift_type,
            'score', v_selected->>'score',
            'reason', 'Optimized with conflict minimization'
          );

        else
          v_result := v_result || jsonb_build_object(
            'shift_date', v_day,
            'shift_type', v_shift_type,
            'status', 'unfilled'
          );
        end if;

      end loop;

    end loop;

  end loop;

  return v_result;

end;
$$;


ALTER FUNCTION "public"."generate_ai_schedule_v2"("p_week_start" "date", "p_zone_id" "uuid", "p_demand" "jsonb", "p_hotel_id" "uuid") OWNER TO "postgres";


