CREATE OR REPLACE FUNCTION "public"."generate_precheckin_reminders"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN

    ------------------------------------------------------------------
    -- T-1 DAY REMINDER (Safe Atomic Update with Multi-Channel)
    ------------------------------------------------------------------
    WITH targets_1 AS (
        SELECT b.id, b.phone, b.email, t.token
        FROM public.bookings b
        JOIN public.hotels h ON h.id = b.hotel_id
        LEFT JOIN public.precheckin_tokens t ON t.booking_id = b.id
        WHERE b.status IN ('CREATED','CONFIRMED')
          AND b.precheckin_reminder1_sent_at IS NULL
          AND (b.scheduled_checkin_at AT TIME ZONE h.timezone)::date =
              ((now() AT TIME ZONE h.timezone)::date + 1)
          AND b.status NOT IN ('CHECKED_IN', 'CANCELLED', 'NO_SHOW', 'COMPLETED')
          AND NOT EXISTS (
              SELECT 1 FROM public.stays s WHERE s.booking_id = b.id
          )
          AND ( (b.phone IS NOT NULL AND b.phone <> '') OR (b.email IS NOT NULL AND b.email <> '') )
        FOR UPDATE
    ),
    channels_1 AS (
        SELECT id, 'whatsapp' as channel, token
        FROM targets_1 WHERE phone IS NOT NULL AND phone <> ''
        UNION ALL
        SELECT id, 'email' as channel, token
        FROM targets_1 WHERE email IS NOT NULL AND email <> ''
    ),
    inserted_1 AS (
        INSERT INTO public.notification_queue (
            booking_id, channel, template_code, payload, status
        )
        SELECT 
            id, channel, 'precheckin_reminder_1', 
            jsonb_build_object('booking_id', id, 'token', token), 'pending'
        FROM channels_1
        RETURNING booking_id
    )
    UPDATE public.bookings b
    SET precheckin_reminder1_sent_at = now()
    WHERE b.id IN (SELECT DISTINCT booking_id FROM inserted_1);

    ------------------------------------------------------------------
    -- ARRIVAL MORNING REMINDER (Safe Atomic Update with Multi-Channel)
    ------------------------------------------------------------------
    WITH targets_2 AS (
        SELECT b.id, b.phone, b.email, t.token
        FROM public.bookings b
        JOIN public.hotels h ON h.id = b.hotel_id
        LEFT JOIN public.precheckin_tokens t ON t.booking_id = b.id
        WHERE b.status IN ('CREATED','CONFIRMED')
          AND b.precheckin_reminder2_sent_at IS NULL
          AND (b.scheduled_checkin_at AT TIME ZONE h.timezone)::date =
              (now() AT TIME ZONE h.timezone)::date
          AND (now() AT TIME ZONE h.timezone)::time >= time '06:00'
          AND b.status NOT IN ('CHECKED_IN', 'CANCELLED', 'NO_SHOW', 'COMPLETED')
          AND NOT EXISTS (
              SELECT 1 FROM public.stays s WHERE s.booking_id = b.id
          )
          AND ( (b.phone IS NOT NULL AND b.phone <> '') OR (b.email IS NOT NULL AND b.email <> '') )
        FOR UPDATE
    ),
    channels_2 AS (
        SELECT id, 'whatsapp' as channel, token
        FROM targets_2 WHERE phone IS NOT NULL AND phone <> ''
        UNION ALL
        SELECT id, 'email' as channel, token
        FROM targets_2 WHERE email IS NOT NULL AND email <> ''
    ),
    inserted_2 AS (
        INSERT INTO public.notification_queue (
            booking_id, channel, template_code, payload, status
        )
        SELECT 
            id, channel, 'precheckin_reminder_2', 
            jsonb_build_object('booking_id', id, 'token', token), 'pending'
        FROM channels_2
        RETURNING booking_id
    )
    UPDATE public.bookings b
    SET precheckin_reminder2_sent_at = now()
    WHERE b.id IN (SELECT DISTINCT booking_id FROM inserted_2);

END;
$$;


ALTER FUNCTION "public"."generate_precheckin_reminders"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_precheckin_tokens"("p_hotel_id" "uuid", "p_days_before" integer DEFAULT 1) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count INT;
BEGIN
  INSERT INTO precheckin_tokens (booking_id, hotel_id, expires_at)
  SELECT
    b.id,
    b.hotel_id,
    b.scheduled_checkin_at + INTERVAL '23 hours'  -- expires at 11 PM on check-in day
  FROM bookings b
  WHERE b.hotel_id = p_hotel_id
    AND b.status IN ('CREATED', 'CONFIRMED')
    AND b.scheduled_checkin_at::date BETWEEN
        CURRENT_DATE AND
        (CURRENT_DATE + (p_days_before || ' days')::INTERVAL)
    AND NOT EXISTS (
      SELECT 1 FROM precheckin_tokens pt WHERE pt.booking_id = b.id
    )
  ON CONFLICT (booking_id) DO NOTHING;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."generate_precheckin_tokens"("p_hotel_id" "uuid", "p_days_before" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_schedule_plan"("p_hotel_id" "uuid", "p_week_start" "date", "p_zone_id" "uuid" DEFAULT NULL::"uuid", "p_demand" "jsonb" DEFAULT NULL::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_day date;
  v_shift record;
  v_staff record;

  v_assignments jsonb := '[]'::jsonb;
  v_conflicts jsonb := '[]'::jsonb;
  v_already_planned jsonb := '[]'::jsonb;

  v_assigned int;
begin

  -- =========================================================
  -- 🛡 0. SAFETY: No staff in hotel
  -- =========================================================
  if not exists (
    select 1 from public.hotel_members
    where hotel_id = p_hotel_id and is_active = true
  ) then
    return jsonb_build_object(
      'assignments', '[]'::jsonb,
      'conflicts', jsonb_build_array(
        jsonb_build_object('reason','no_staff_in_hotel')
      )
    );
  end if;

  -- =========================================================
  -- 🛡 1. DEFAULT DEMAND
  -- =========================================================
  if p_demand is null then
    p_demand := jsonb_build_array(
      jsonb_build_object('shift_type','morning','required',1),
      jsonb_build_object('shift_type','evening','required',1),
      jsonb_build_object('shift_type','night','required',1)
    );
  end if;

  -- =========================================================
  -- 🔁 2. LOOP 7 DAYS
  -- =========================================================
  for i in 0..6 loop
    v_day := p_week_start + i;

    -- =========================================================
    -- 🔁 3. LOOP SHIFT TYPES
    -- =========================================================
    for v_shift in
      select * from jsonb_to_recordset(p_demand)
      as x(shift_type text, required int)
    loop

      -- 🛡 VALIDATE SHIFT TYPE
      if v_shift.shift_type not in ('morning','evening','night') then
        v_conflicts := v_conflicts || jsonb_build_object(
          'date', v_day,
          'shift_type', v_shift.shift_type,
          'reason', 'invalid_shift_type'
        );
        continue;
      end if;

      v_assigned := 0;

      -- =========================================================
      -- 🔁 4. FILL REQUIRED SLOTS
      -- =========================================================
      while v_assigned < v_shift.required loop

        -- 🎯 FIND BEST STAFF
        select hm.id as staff_id
        into v_staff
        from public.hotel_members hm
        where hm.hotel_id = p_hotel_id
          and hm.is_active = true

          -- zone filter
          and (
            p_zone_id is null
            or exists (
              select 1 from public.staff_zone_assignments sza
              where sza.staff_id = hm.id
                and sza.zone_id = p_zone_id
            )
          )

          -- ❌ already assigned in DB that day
          and not exists (
            select 1 from public.staff_shifts ss
            where ss.staff_id = hm.id
              and ss.shift_start::date = v_day
              and ss.is_active = true
              and ss.status = 'scheduled'
          )

          -- ❌ already assigned in this plan
          and not exists (
            select 1 from jsonb_array_elements(v_already_planned) as p
            where (p->>'staff_id')::uuid = hm.id
              and (p->>'day')::date = v_day
          )

        order by
          -- 🧠 fairness (DB + planned)
          (
            (select count(*) from public.staff_shifts s2
             where s2.staff_id = hm.id
               and s2.shift_start >= p_week_start
               and s2.shift_start < p_week_start + interval '7 days'
               and s2.is_active = true
               and s2.status = 'scheduled')
            +
            (select count(*) from jsonb_array_elements(v_already_planned) as p2
             where (p2->>'staff_id')::uuid = hm.id)
          ) asc,
          hm.id -- deterministic (no randomness)
        limit 1;

        -- ❌ NO STAFF FOUND → CONFLICT
        if v_staff.staff_id is null then
          v_conflicts := v_conflicts || jsonb_build_object(
            'date', v_day,
            'shift_type', v_shift.shift_type,
            'reason', 'no_available_staff'
          );
          exit;
        end if;

        -- =========================================================
        -- ⏱ 5. BUILD SHIFT TIMES (IST SAFE)
        -- =========================================================
        v_assignments := v_assignments || jsonb_build_object(
          'staff_id', v_staff.staff_id,

          'shift_start',
            case v_shift.shift_type
              when 'morning' then (v_day + time '09:00') at time zone 'Asia/Kolkata'
              when 'evening' then (v_day + time '14:00') at time zone 'Asia/Kolkata'
              when 'night'   then (v_day + time '22:00') at time zone 'Asia/Kolkata'
            end,

          'shift_end',
            case v_shift.shift_type
              when 'morning' then (v_day + time '17:00') at time zone 'Asia/Kolkata'
              when 'evening' then (v_day + time '22:00') at time zone 'Asia/Kolkata'
              when 'night'   then ((v_day + interval '1 day') + time '06:00') at time zone 'Asia/Kolkata'
            end,

          'shift_type', v_shift.shift_type,
          'zone_id', p_zone_id
        );

        -- 🧠 TRACK IN-PLAN ASSIGNMENT
        v_already_planned := v_already_planned || jsonb_build_object(
          'staff_id', v_staff.staff_id,
          'day', v_day
        );

        v_assigned := v_assigned + 1;

      end loop;

    end loop;
  end loop;

  -- =========================================================
  -- ✅ FINAL RESPONSE
  -- =========================================================
  return jsonb_build_object(
    'assignments', v_assignments,
    'conflicts', v_conflicts
  );

end;
$$;


ALTER FUNCTION "public"."generate_schedule_plan"("p_hotel_id" "uuid", "p_week_start" "date", "p_zone_id" "uuid", "p_demand" "jsonb") OWNER TO "postgres";


