CREATE OR REPLACE FUNCTION "public"."get_dashboard_hourly_volume"("p_hotel_id" "uuid", "p_timezone" "text" DEFAULT 'UTC'::"text") RETURNS TABLE("hour_of_day" integer, "ticket_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_today_start TIMESTAMP;
  v_next_day_start TIMESTAMP;
BEGIN
  -- 🔒 SECURITY CHECK
  IF NOT EXISTS (
    SELECT 1 FROM hotel_members 
    WHERE user_id = auth.uid() 
    AND hotel_id = p_hotel_id
  ) THEN
    RAISE EXCEPTION 'Access Denied: You are not a member of this hotel.';
  END IF;

  -- Today in Hotel Time
  v_today_start := date_trunc('day', now() AT TIME ZONE p_timezone);
  v_next_day_start := v_today_start + interval '1 day';

  RETURN QUERY
  WITH hour_series AS (
    SELECT generate_series(0, 23) AS hr
  ),
  hourly_data AS (
    SELECT
      extract(hour from t.created_at AT TIME ZONE p_timezone)::int as hr,
      count(*) as cnt
    FROM tickets t
    JOIN departments d ON t.service_department_id = d.id
    WHERE
      d.hotel_id = p_hotel_id
      AND t.created_at >= (v_today_start AT TIME ZONE p_timezone)
      AND t.created_at <  (v_next_day_start AT TIME ZONE p_timezone)
    GROUP BY 1
  )
  SELECT
    hs.hr,
    COALESCE(hd.cnt, 0)
  FROM hour_series hs
  LEFT JOIN hourly_data hd ON hs.hr = hd.hr
  ORDER BY hs.hr;
END;
$$;


ALTER FUNCTION "public"."get_dashboard_hourly_volume"("p_hotel_id" "uuid", "p_timezone" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_dashboard_occupancy_trend"("p_hotel_id" "uuid", "p_timezone" "text" DEFAULT 'UTC'::"text", "p_days" integer DEFAULT 30) RETURNS TABLE("date" "date", "occupied_count" bigint, "total_rooms" bigint, "occupancy_pct" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_end_date TIMESTAMP;
  v_start_date TIMESTAMP;
  v_total_rooms BIGINT;
BEGIN
  -- 🔒 SECURITY CHECK
  IF NOT EXISTS (
    SELECT 1 FROM hotel_members 
    WHERE user_id = auth.uid() 
    AND hotel_id = p_hotel_id
  ) THEN
    RAISE EXCEPTION 'Access Denied: You are not a member of this hotel.';
  END IF;

  -- 1. Get snapshot of total rooms (Assuming fairly constant, or usage current count)
  SELECT count(*) INTO v_total_rooms FROM rooms WHERE hotel_id = p_hotel_id;

  -- 2. Date Ranges
  v_end_date := date_trunc('day', now() AT TIME ZONE p_timezone);
  v_start_date := v_end_date - (p_days - 1 || ' days')::interval;

  RETURN QUERY
  WITH date_series AS (
    SELECT generate_series(v_start_date, v_end_date, '1 day'::interval) AS day_ts
  ),
  daily_occupancy AS (
    -- Count stays that overlap with the NIGHT of each date
    SELECT
      ds.day_ts::date as report_date,
      count(s.id) as occupied
    FROM date_series ds
    LEFT JOIN stays s ON 
      s.hotel_id = p_hotel_id
      -- Logic: Stay is active if scheduled_checkin <= date AND scheduled_checkout > date (Standard hotel logic)
      -- Using TZ conversion to ensure date boundaries match
      AND s.scheduled_checkin_at < (ds.day_ts + interval '1 day') AT TIME ZONE p_timezone
      AND s.scheduled_checkout_at > ds.day_ts AT TIME ZONE p_timezone
      AND s.status IN ('arriving', 'inhouse', 'checked_out') -- active/recent stays only
    GROUP BY 1
  )
  SELECT
    occ.report_date,
    occ.occupied,
    v_total_rooms,
    CASE 
      WHEN v_total_rooms > 0 THEN round((occ.occupied::numeric / v_total_rooms) * 100, 1)
      ELSE 0
    END as pct
  FROM daily_occupancy occ
  ORDER BY occ.report_date;
END;
$$;


ALTER FUNCTION "public"."get_dashboard_occupancy_trend"("p_hotel_id" "uuid", "p_timezone" "text", "p_days" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_dashboard_revenue_trend"("p_hotel_id" "uuid", "p_timezone" "text" DEFAULT 'UTC'::"text", "p_days" integer DEFAULT 30) RETURNS TABLE("date" "date", "revenue" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_end_date TIMESTAMP;
  v_start_date TIMESTAMP;
BEGIN
  -- 🔒 SECURITY CHECK
  IF NOT EXISTS (
    SELECT 1 FROM hotel_members 
    WHERE user_id = auth.uid() 
    AND hotel_id = p_hotel_id
  ) THEN
    RAISE EXCEPTION 'Access Denied: You are not a member of this hotel.';
  END IF;

  -- Date Ranges
  v_end_date := date_trunc('day', now() AT TIME ZONE p_timezone);
  v_start_date := v_end_date - (p_days - 1 || ' days')::interval;

  RETURN QUERY
  WITH date_series AS (
    SELECT generate_series(v_start_date, v_end_date, '1 day'::interval) AS day_ts
  ),
  daily_revenue AS (
    SELECT
      date_trunc('day', o.created_at AT TIME ZONE p_timezone) as report_date,
      sum(o.price) as total_rev
    FROM orders o
    WHERE
      o.hotel_id = p_hotel_id
      AND o.price IS NOT NULL -- only orders with price
      AND o.created_at >= (v_start_date AT TIME ZONE p_timezone)
    GROUP BY 1
  )
  SELECT
    ds.day_ts::date,
    COALESCE(dr.total_rev, 0)
  FROM date_series ds
  LEFT JOIN daily_revenue dr ON ds.day_ts = dr.report_date
  ORDER BY ds.day_ts;
END;
$$;


ALTER FUNCTION "public"."get_dashboard_revenue_trend"("p_hotel_id" "uuid", "p_timezone" "text", "p_days" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_dashboard_sla_trend"("p_hotel_id" "uuid", "p_timezone" "text" DEFAULT 'UTC'::"text", "p_days" integer DEFAULT 7) RETURNS TABLE("date" "date", "total_tickets" bigint, "breached_tickets" bigint, "compliant_tickets" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_end_date TIMESTAMP;
  v_start_date TIMESTAMP;
BEGIN
  -- Calculate range in target timezone
  v_end_date := date_trunc('day', now() AT TIME ZONE p_timezone);
  v_start_date := v_end_date - (p_days - 1 || ' days')::interval;

  -- 🔒 SECURITY CHECK
  IF NOT EXISTS (
    SELECT 1 FROM hotel_members 
    WHERE user_id = auth.uid() 
    AND hotel_id = p_hotel_id
  ) THEN
    RAISE EXCEPTION 'Access Denied: You are not a member of this hotel.';
  END IF;

  RETURN QUERY
  WITH date_series AS (
    SELECT generate_series(v_start_date, v_end_date, '1 day'::interval) AS day_ts
  ),
  daily_data AS (
    SELECT
      date_trunc('day', t.created_at AT TIME ZONE p_timezone) as ticket_day,
      count(*) as total,
      count(*) FILTER (WHERE s.breached_at IS NOT NULL) as breached,
      count(*) FILTER (WHERE s.breached_at IS NULL) as compliant
    FROM tickets t
    JOIN departments d ON t.service_department_id = d.id
    LEFT JOIN ticket_sla_state s ON t.id = s.ticket_id
    WHERE
      d.hotel_id = p_hotel_id
      AND t.status IN ('COMPLETED', 'CANCELLED')
      AND t.created_at >= (v_start_date AT TIME ZONE p_timezone)
    GROUP BY 1
  )
  SELECT
    ds.day_ts::date,
    COALESCE(dd.total, 0),
    COALESCE(dd.breached, 0),
    COALESCE(dd.compliant, 0)
  FROM date_series ds
  LEFT JOIN daily_data dd ON ds.day_ts = dd.ticket_day
  ORDER BY ds.day_ts;
END;
$$;


ALTER FUNCTION "public"."get_dashboard_sla_trend"("p_hotel_id" "uuid", "p_timezone" "text", "p_days" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_dashboard_staff_leaderboard"("p_hotel_id" "uuid") RETURNS TABLE("staff_id" "uuid", "display_name" "text", "department_name" "text", "role" "text", "tickets_completed" bigint, "avg_completion_min" numeric, "is_online" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  -- 🔒 SECURITY CHECK
  IF NOT EXISTS (
    SELECT 1 FROM hotel_members 
    WHERE user_id = auth.uid() 
    AND hotel_id = p_hotel_id
  ) THEN
    RAISE EXCEPTION 'Access Denied: You are not a member of this hotel.';
  END IF;

  RETURN QUERY
  SELECT
    hm.id as staff_id,
    COALESCE(p.full_name, 'Staff ' || substring(hm.id::text, 1, 8))::TEXT as display_name,
    COALESCE(d.name, 'General')::TEXT as department_name,
    hm.role::TEXT,
    (SELECT count(*) FROM tickets t WHERE t.current_assignee_id = hm.id AND t.status = 'COMPLETED')::BIGINT as tickets_completed,
    NULL::NUMERIC as avg_completion_min,
    hm.is_active as is_online
  FROM hotel_members hm
  LEFT JOIN profiles p ON p.id = hm.user_id
  LEFT JOIN departments d ON d.id = hm.department_id
  WHERE hm.hotel_id = p_hotel_id
  AND hm.is_active = true
  ORDER BY hm.created_at ASC;
END;
$$;


ALTER FUNCTION "public"."get_dashboard_staff_leaderboard"("p_hotel_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_dashboard_today_stats"("p_hotel_id" "uuid", "p_timezone" "text" DEFAULT 'UTC'::"text") RETURNS TABLE("arrivals_count" bigint, "departures_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_today_start TIMESTAMP;
  v_next_day_start TIMESTAMP;
BEGIN
   -- 🔒 SECURITY CHECK
  IF NOT EXISTS (
    SELECT 1 FROM hotel_members 
    WHERE user_id = auth.uid() 
    AND hotel_id = p_hotel_id
  ) THEN
    RAISE EXCEPTION 'Access Denied: You are not a member of this hotel.';
  END IF;

  -- Today in Hotel Time
  v_today_start := date_trunc('day', now() AT TIME ZONE p_timezone);
  v_next_day_start := v_today_start + interval '1 day';

  RETURN QUERY
  SELECT
    count(*) FILTER (
        WHERE scheduled_checkin_at >= (v_today_start AT TIME ZONE p_timezone)
        AND scheduled_checkin_at < (v_next_day_start AT TIME ZONE p_timezone)
    ) as arrivals,
    count(*) FILTER (
        WHERE scheduled_checkout_at >= (v_today_start AT TIME ZONE p_timezone)
        AND scheduled_checkout_at < (v_next_day_start AT TIME ZONE p_timezone)
    ) as departures
  FROM stays
  WHERE hotel_id = p_hotel_id
  AND status IN ('arriving', 'inhouse', 'checked_out'); -- active/recent stays only
END;
$$;


ALTER FUNCTION "public"."get_dashboard_today_stats"("p_hotel_id" "uuid", "p_timezone" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_deactivated_hotel_members"("p_hotel_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  -- Auth check: ensure caller is an active OWNER/ADMIN/MANAGER of this hotel
  IF NOT EXISTS (
    SELECT 1 FROM public.hotel_members hm
    JOIN public.hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
    JOIN public.hotel_roles hr ON hr.id = hmr.role_id
    WHERE hm.user_id = auth.uid()
      AND hm.hotel_id = p_hotel_id
      AND (hr.code LIKE 'OWNER%' OR hr.code LIKE 'ADMIN%' OR hr.code LIKE 'MANAGER%')
      AND hm.is_active = true
  ) THEN
    RAISE EXCEPTION 'Not authorized to view deactivated members';
  END IF;

  RETURN COALESCE(
    (SELECT jsonb_agg(
      jsonb_build_object(
        'staff_id', hm.id,
        'full_name', COALESCE(p.full_name, p.email, 'Unknown User'),
        'email', p.email,
        'avatar_url', p.profile_photo_url,
        'is_active', hm.is_active,
        'is_verified', hm.is_verified
      ) ORDER BY p.full_name
    )
    FROM public.hotel_members hm
    LEFT JOIN public.profiles p ON p.id = hm.user_id
    WHERE hm.hotel_id = p_hotel_id
      AND hm.is_active = false
    ),
    '[]'::jsonb
  );
END;
$$;


ALTER FUNCTION "public"."get_deactivated_hotel_members"("p_hotel_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_hotel_onboarding_state"("p_hotel_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_has_access boolean;
    v_result jsonb;
BEGIN
    -- Verify caller is authenticated
    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    -- Security Check: The user must either be:
    -- 1. An active Platform Admin
    -- 2. An active member of the hotel
    -- 3. The creator in onboarding phase
    
    SELECT EXISTS (
        SELECT 1 FROM public.platform_admins pa
        WHERE pa.user_id = auth.uid()
        AND pa.is_active = true
    ) INTO v_has_access;

    IF NOT v_has_access THEN
        SELECT EXISTS (
            SELECT 1 FROM public.hotel_members hm
            WHERE hm.hotel_id = p_hotel_id 
            AND hm.user_id = auth.uid()
            AND hm.is_active = true
            AND hm.status = 'active'
        ) INTO v_has_access;
    END IF;

    IF NOT v_has_access THEN
        SELECT EXISTS (
            SELECT 1 FROM public.hotel_audit_logs
            WHERE hotel_id = p_hotel_id
            AND user_id = auth.uid()
            AND action = 'HOTEL_CREATED'
        ) INTO v_has_access;
    END IF;

    IF NOT v_has_access THEN
        RAISE EXCEPTION 'Insufficient permissions to view this hotel state';
    END IF;

    -- Validate existence to prevent returning null hotels
    PERFORM 1 FROM public.hotels WHERE id = p_hotel_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Hotel not found';
    END IF;

    -- Aggregate State
    SELECT jsonb_build_object(
        'hotel', (SELECT to_jsonb(h) FROM public.hotels h WHERE h.id = p_hotel_id),
        'room_types', COALESCE((
            SELECT jsonb_agg(jsonb_build_object(
                'id', rt.id,
                'name', rt.name,
                'base_occupancy', rt.base_occupancy,
                'max_occupancy', rt.max_occupancy
            )) 
            FROM public.room_types rt 
            WHERE rt.hotel_id = p_hotel_id
        ), '[]'::jsonb),
        'rooms', COALESCE((
            SELECT jsonb_agg(jsonb_build_object(
                'id', r.id,
                'room_type_id', r.room_type_id,
                'number', r.number,
                'floor', r.floor,
                'wing', r.wing,
                'status', r.status,
                'is_out_of_order', r.is_out_of_order
            )) 
            FROM public.rooms r 
            WHERE r.hotel_id = p_hotel_id
        ), '[]'::jsonb),
        'roles', COALESCE((
            SELECT jsonb_agg(jsonb_build_object(
                'id', hr.id,
                'name', hr.name,
                'description', hr.description
            )) 
            FROM public.hotel_roles hr 
            WHERE hr.hotel_id = p_hotel_id
        ), '[]'::jsonb),
        'invites', COALESCE((
            SELECT jsonb_agg(jsonb_build_object(
                'id', hi.id,
                'email', hi.email,
                'invite_metadata', hi.invite_metadata,
                'role_name', hr.name
            )) 
            FROM public.hotel_invites hi 
            LEFT JOIN public.hotel_roles hr ON hr.id = hi.role_id
            WHERE hi.hotel_id = p_hotel_id
        ), '[]'::jsonb)
    ) INTO v_result;

    RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."get_hotel_onboarding_state"("p_hotel_id" "uuid") OWNER TO "postgres";


