CREATE OR REPLACE FUNCTION "public"."get_shift_history"("p_hotel_id" "uuid", "p_staff_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 20, "p_offset" integer DEFAULT 0) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_data jsonb;
  v_has_more boolean;
begin
  -- 🛡 Security: Verify caller's membership
  if not exists (
    select 1 from public.hotel_members
    where user_id = auth.uid() and hotel_id = p_hotel_id
  ) then
    raise exception 'Unauthorized';
  end if;

  -- Fetch data (one extra to check has_more)
  select jsonb_agg(row_to_json(t))
  into v_data
  from (
    select
      sal.id,
      sal.shift_id,
      sal.staff_id,
      p.full_name as staff_name,
      sal.action,
      sal.diff,
      sal.action_reason,
      sal.changed_by,
      cp.full_name as changed_by_name,
      sal.changed_at
    from public.shift_audit_log sal
    left join public.profiles p on p.id = sal.staff_id
    left join public.profiles cp on cp.id = sal.changed_by
    where sal.hotel_id = p_hotel_id
      and (p_staff_id is null or sal.staff_id = p_staff_id)
    order by sal.changed_at desc
    limit p_limit + 1 offset p_offset
  ) t;

  v_has_more := coalesce(jsonb_array_length(v_data), 0) > p_limit;
  
  -- Trim if we have more (using cleaner subquery approach)
  if v_has_more then
    v_data := (
      select jsonb_agg(elem)
      from (
        select elem
        from jsonb_array_elements(v_data) with ordinality as arr(elem, idx)
        where idx <= p_limit
      ) s
    );
  end if;

  return jsonb_build_object(
    'data', coalesce(v_data, '[]'::jsonb),
    'limit', p_limit,
    'offset', p_offset,
    'has_more', v_has_more
  );
end;
$$;


ALTER FUNCTION "public"."get_shift_history"("p_hotel_id" "uuid", "p_staff_id" "uuid", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_staff_shifts_dashboard"("p_hotel_id" "uuid", "p_selected_day" timestamp with time zone, "p_now" timestamp with time zone DEFAULT "now"()) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
declare
  v_next_day timestamptz;
  v_result jsonb;
begin
  -- 🛡️ 1. Normalize to IST day start
  p_selected_day := date_trunc('day', p_selected_day AT TIME ZONE 'Asia/Kolkata') AT TIME ZONE 'Asia/Kolkata';
  v_next_day := p_selected_day + interval '1 day';

  with staff_zones as (
    select distinct on (sza.staff_id)
      sza.staff_id,
      z1.name as zone_name,
      z1.id as zone_id
    from public.staff_zone_assignments sza
    join public.hotel_zones z1 on z1.id = sza.zone_id
    where sza.effective_from <= p_selected_day
      and (sza.effective_to is null or sza.effective_to >= p_selected_day)
    order by sza.staff_id, sza.effective_from desc
  ),

  staff_departments_dedup as (
    select distinct on (sd.staff_id)
      sd.staff_id,
      d.name as department_name
    from public.staff_departments sd
    join public.departments d on d.id = sd.department_id
    order by sd.staff_id
  ),

  timeline_data as (
    select jsonb_agg(sub order by sub.full_name) as timeline
    from (
      select
        hm.id as staff_id,
        coalesce(p.full_name, p.email, 'User ' || left(hm.id::text, 4)) as full_name,
        p.email as email,
        hm.is_active as is_active,
        hm.is_verified as is_verified,
        p.profile_photo_url as avatar_url,
        sdd.department_name,
        sz.zone_name as assigned_zone_name,

        -- shift existence
        coalesce(bool_or(ss.shift_id is not null), false) as has_shift,

        -- current shift (Robust alternative to max(uuid))
        (array_agg(ss.shift_id) filter (where ss.is_current))[1] as current_shift_id,

        coalesce(
          jsonb_agg(
            jsonb_build_object(
              'shift_id', ss.shift_id,
              'staff_id', hm.id,
              'shift_start', ss.shift_start,
              'shift_end', ss.shift_end,
              'shift_type', ss.shift_type,
              'status', ss.status,
              'zone_id', ss.zone_id,
              'zone_name', ss.zone_name,
              'is_on_shift', ss.is_in_day,
              'is_locked', ss.is_locked,
              'locked_by', ss.locked_by,
              'locked_by_name', lp.full_name,
              'version', ss.version
            )
            order by ss.shift_start
          ) filter (where ss.shift_id is not null),
          '[]'::jsonb
        ) as shifts

      from public.hotel_members hm
      left join public.profiles p on p.id = hm.user_id
      left join staff_departments_dedup sdd on sdd.staff_id = hm.id
      left join staff_zones sz on sz.staff_id = hm.id

      -- 🔥 Single optimized shift scan
      left join lateral (
        select 
          vss.id as shift_id,
          vss.shift_start,
          vss.shift_end,
          vss.shift_type,
          vss.status,
          vss.version,
          vss.zone_id,
          vss.locked_at,
          vss.locked_by,
          hz.name as zone_name,

          -- derived flags
          (vss.shift_start < v_next_day and vss.shift_end >= p_selected_day) as is_in_day,
          (vss.shift_start <= p_now and vss.shift_end > p_now) as is_current,
          (vss.locked_at is not null and vss.locked_at > (p_now - interval '5 minutes')) as is_locked

        from public.staff_shifts vss
        left join public.hotel_zones hz on hz.id = vss.zone_id
        where vss.staff_id = hm.id
          and vss.shift_start < v_next_day
          and vss.shift_end >= p_selected_day
          and vss.is_active = true
          and vss.status = 'scheduled'
      ) ss on true

      left join public.profiles lp on lp.id = ss.locked_by

      where hm.hotel_id = p_hotel_id
        and hm.is_active = true

      group by hm.id, p.full_name, p.email, hm.is_active, hm.is_verified, p.profile_photo_url, sdd.department_name, sz.zone_name
      order by full_name
    ) sub
  ),

  available_data as (
    select jsonb_agg(sub order by sub.full_name) as available
    from (
      select 
        hm.id as staff_id,
        coalesce(p.full_name, p.email, 'User ' || left(hm.id::text, 4)) as full_name,
        p.email as email,
        hm.is_active as is_active,
        hm.is_verified as is_verified,
        p.profile_photo_url as avatar_url,
        sdd.department_name,
        sz.zone_id,
        sz.zone_name

      from public.hotel_members hm
      left join public.profiles p on p.id = hm.user_id
      left join staff_departments_dedup sdd on sdd.staff_id = hm.id
      left join staff_zones sz on sz.staff_id = hm.id

      where hm.hotel_id = p_hotel_id
        and hm.is_active = true
        and not exists (
        select 1 from public.staff_shifts ss
        where ss.staff_id = hm.id
          and ss.shift_start < v_next_day
          and ss.shift_end >= p_selected_day
          and ss.is_active = true
          and ss.status = 'scheduled'
      )

      order by full_name
    ) sub
  ),

  summary_data as (
    select jsonb_build_object(
      'total_staff', count(distinct hm.id),

      'on_shift', count(distinct ss.staff_id) filter (
        where ss.shift_start < v_next_day
          and ss.shift_end >= p_selected_day
          and ss.status = 'scheduled'
      ),

      'off_shift',
        count(distinct hm.id)
        - count(distinct ss.staff_id) filter (
            where ss.shift_start < v_next_day
              and ss.shift_end >= p_selected_day
              and ss.status = 'scheduled'
          ),

      'morning', count(distinct ss.staff_id) filter (where ss.shift_type::text = 'morning' and ss.status = 'scheduled'),
      'evening', count(distinct ss.staff_id) filter (where ss.shift_type::text = 'evening' and ss.status = 'scheduled'),
      'night', count(distinct ss.staff_id) filter (where ss.shift_type::text = 'night' and ss.status = 'scheduled')

    ) as summary
    from public.hotel_members hm
    left join public.staff_shifts ss 
      on ss.staff_id = hm.id
      and ss.shift_start < v_next_day
      and ss.shift_end >= p_selected_day
      and ss.is_active = true
      and ss.status = 'scheduled'

    where hm.hotel_id = p_hotel_id
      and hm.is_active = true
  )

  select jsonb_build_object(
    'timeline', coalesce(t.timeline, '[]'::jsonb),
    'available', coalesce(a.available, '[]'::jsonb),
    'summary', coalesce(
      s.summary,
      jsonb_build_object(
        'total_staff',0,'on_shift',0,'off_shift',0,
        'morning',0,'evening',0,'night',0
      )
    )
  )
  into v_result
  from timeline_data t, available_data a, summary_data s;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."get_staff_shifts_dashboard"("p_hotel_id" "uuid", "p_selected_day" timestamp with time zone, "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_ticket_details"("p_display_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_result JSONB;
BEGIN
  SELECT jsonb_build_object(
    'id', t.id,
    'display_id', t.display_id,
    'status', t.status,
    'created_at', t.created_at,
    'completed_at', t.completed_at,
    'description', t.description,
    'stay_id', t.stay_id,
    'current_assignee_id', t.current_assignee_id,
    'booking_code', st.booking_code,
    'sla_started_at', tss.sla_started_at,
    'service', jsonb_build_object(
      'label', s.label,
      'sla_minutes', s.sla_minutes,
      'description_en', s.description_en
    ),
    'room', CASE WHEN r.id IS NOT NULL THEN jsonb_build_object('number', r.number) ELSE null END,
    'zone', CASE WHEN z.id IS NOT NULL THEN jsonb_build_object('id', z.id, 'name', z.name) ELSE null END,
    'attachments', (
       SELECT coalesce(jsonb_agg(jsonb_build_object('file_path', file_path, 'created_at', created_at)), '[]'::jsonb)
       FROM ticket_attachments ta
       WHERE ta.ticket_id = t.id
    )
  ) INTO v_result
  FROM tickets t
  JOIN services s ON s.id = t.service_id
  LEFT JOIN stays st ON st.id = t.stay_id
  LEFT JOIN rooms r ON r.id = t.room_id
  LEFT JOIN hotel_zones z ON z.id = t.zone_id
  LEFT JOIN ticket_sla_state tss ON tss.ticket_id = t.id
  WHERE t.display_id = p_display_id;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."get_ticket_details"("p_display_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."grant_sla_exception"("p_ticket_id" "uuid", "p_comment" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_ticket RECORD;
  v_supervisor_id UUID;
  v_latest_sla_request_at TIMESTAMPTZ;
BEGIN
  -- 1. Lock the ticket row
  SELECT * INTO v_ticket
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found: %', p_ticket_id;
  END IF;

  -- 2. Resolve supervisor ID
  SELECT id INTO v_supervisor_id
  FROM hotel_members
  WHERE user_id = auth.uid()
    AND hotel_id = v_ticket.hotel_id
    AND is_active = true
  LIMIT 1;

  IF v_supervisor_id IS NULL THEN
    RAISE EXCEPTION 'Cannot resolve supervisor membership for hotel %', v_ticket.hotel_id;
  END IF;

  -- 3. Verify pending SLA exception request
  SELECT created_at INTO v_latest_sla_request_at
  FROM ticket_events
  WHERE ticket_id = p_ticket_id
    AND event_type = 'SLA_EXCEPTION_REQUESTED'
    AND NOT EXISTS (
      SELECT 1 FROM ticket_events res
      WHERE res.ticket_id = p_ticket_id
        AND res.created_at > ticket_events.created_at
        AND res.event_type IN ('SLA_EXCEPTION_GRANTED', 'SLA_EXCEPTION_REJECTED')
    )
  ORDER BY created_at DESC
  LIMIT 1;

  IF v_latest_sla_request_at IS NULL THEN
    RAISE EXCEPTION 'No pending SLA exception request for ticket %', p_ticket_id;
  END IF;

  -- 4. Emit SLA_EXCEPTION_GRANTED event
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    reason_code,
    comment,
    actor_type,
    actor_id
  ) VALUES (
    p_ticket_id,
    'SLA_EXCEPTION_GRANTED',
    'sla_exception',
    COALESCE(p_comment, 'SLA exception granted by supervisor'),
    'STAFF',
    v_supervisor_id
  );

  RETURN jsonb_build_object(
    'success', true,
    'ticket_id', p_ticket_id,
    'action', 'SLA_EXCEPTION_GRANTED'
  );
END;
$$;


ALTER FUNCTION "public"."grant_sla_exception"("p_ticket_id" "uuid", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."grid_seed_demo_readings"("p_hotel_id" "uuid", "p_days" integer DEFAULT 7) RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  dev record;
  ts  timestamptz;
  start_at timestamptz;
BEGIN
  start_at := date_trunc('hour', now() - (p_days || ' days')::interval);

  FOR dev IN
    SELECT d.*
    FROM public.grid_devices d
    WHERE d.hotel_id = p_hotel_id
  LOOP
    -- 30-min resolution
    FOR ts IN
      SELECT start_at + (g * interval '30 minutes')
      FROM generate_series(0, p_days * 48 - 1) AS g
    LOOP
      INSERT INTO public.grid_readings (device_id, reading_at, power_kw, state, source)
      VALUES (
        dev.id,
        ts,
        CASE
          -- ~20% of the time treat as OFF
          WHEN random() < 0.2 THEN 0
          ELSE
            COALESCE(dev.power_kw, dev.capacity_kw, 1) * (0.4 + random() * 0.6)
        END,
        CASE WHEN random() < 0.2 THEN 'off' ELSE 'on' END,
        'demo'
      );
    END LOOP;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."grid_seed_demo_readings"("p_hotel_id" "uuid", "p_days" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."guest_update_ticket"("p_display_id" "text", "p_details" "text" DEFAULT NULL::"text", "p_media_urls" "jsonb" DEFAULT NULL::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
 v_ticket_id UUID;
 v_old_description TEXT;
 v_created_by_id UUID;
 v_url TEXT;
 v_mapped_guest_id UUID;
BEGIN
 -- We assume they can only see the ticket if they passed the VIEW policy, but strictly we could enforce ownership.
 SELECT id, description, created_by_id INTO v_ticket_id, v_old_description, v_created_by_id
 FROM public.tickets
 WHERE display_id = p_display_id AND status NOT IN ('COMPLETED', 'CANCELLED');

 IF v_ticket_id IS NULL THEN RAISE EXCEPTION 'Ticket not found or closed for updates'; END IF;

 -- Get mapping
 v_mapped_guest_id := public.current_guest_id();

 IF p_details IS NOT NULL AND length(trim(p_details)) > 0 THEN
 UPDATE public.tickets 
 SET description = COALESCE(description, '') || E'\n\n[Guest Update]: ' || p_details, updated_at = now()
 WHERE id = v_ticket_id;

 INSERT INTO public.ticket_events (ticket_id, event_type, actor_type, actor_id, comment)
 VALUES (v_ticket_id, 'COMMENT_ADDED', 'GUEST', v_mapped_guest_id, p_details);
 END IF;

 IF p_media_urls IS NOT NULL AND jsonb_array_length(p_media_urls) > 0 THEN
 FOR v_url IN SELECT * FROM jsonb_array_elements_text(p_media_urls) LOOP
 v_url := trim(both '"' from v_url);
 IF v_url NOT LIKE 'tickets/%' THEN RAISE EXCEPTION 'Invalid file path: %', v_url; END IF;
 INSERT INTO public.ticket_attachments (ticket_id, file_path, uploaded_by, uploaded_by_type)
 VALUES (v_ticket_id, v_url, NULL, 'GUEST'); 
 END LOOP;
 END IF;

 RETURN jsonb_build_object('success', true);
END;
$$;


ALTER FUNCTION "public"."guest_update_ticket"("p_display_id" "text", "p_details" "text", "p_media_urls" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  insert into public.profiles (id, email)
  values (new.id, new.email)
  on conflict (id) do nothing;
  return new;
end;
$$;


ALTER FUNCTION "public"."handle_new_user"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."has_hotel_role"("p_user_id" "uuid", "p_hotel_id" "uuid", "p_roles" "text"[]) RETURNS boolean
    LANGUAGE "sql" STABLE
    AS $$
SELECT EXISTS (
    SELECT 1
    FROM hotel_members hm
    JOIN hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
    JOIN hotel_roles hr ON hr.id = hmr.role_id
    WHERE hm.user_id = p_user_id
      AND hm.hotel_id = p_hotel_id
      AND hm.is_active = true
      AND hr.is_active = true
      AND hr.code = ANY(p_roles)
);
$$;


ALTER FUNCTION "public"."has_hotel_role"("p_user_id" "uuid", "p_hotel_id" "uuid", "p_roles" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."hk_assign_task"("p_room_id" "uuid", "p_staff_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_task_id UUID;
    v_hotel_id UUID;
    v_old_assignee UUID;
    v_current_status housekeeping_status_enum;
BEGIN
    SELECT hotel_id, housekeeping_status INTO v_hotel_id, v_current_status
    FROM rooms WHERE id = p_room_id FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Room not found: %', p_room_id;
    END IF;

    IF NOT public.has_hotel_role(
        auth.uid(),
        v_hotel_id,
        ARRAY['OWNER', 'ADMIN', 'GENERAL_MANAGER', 'SUPERVISOR', 'HOUSEKEEPING_MANAGER', 'HOUSEKEEPING_SUPERVISOR']
    ) THEN
        RAISE EXCEPTION 'Unauthorized: you do not have supervisor-level permission to modify room % in hotel %', p_room_id, v_hotel_id;
    END IF;

    -- Block assignment if room is out of order
    IF v_current_status = 'out_of_order'::housekeeping_status_enum THEN
        RAISE EXCEPTION 'Cannot assign task. Room is out of order.';
    END IF;

    -- Block assignment if room is already clean/ready
    IF v_current_status IN ('clean'::housekeeping_status_enum, 'inspected'::housekeeping_status_enum) THEN
        RAISE EXCEPTION 'Room is already ready.';
    END IF;

    -- Validate staff belongs to same hotel (multi-property safety)
    IF NOT EXISTS (
        SELECT 1
        FROM hotel_members
        WHERE id = p_staff_id
          AND hotel_id = v_hotel_id
    ) THEN
        RAISE EXCEPTION 'Staff does not belong to this hotel';
    END IF;

    -- Find the active task for this room
    SELECT id, assigned_to INTO v_task_id, v_old_assignee
    FROM housekeeping_tasks
    WHERE room_id = p_room_id
      AND status IN ('pending', 'in_progress')
    ORDER BY created_at DESC
    LIMIT 1
    FOR UPDATE;

    IF v_task_id IS NULL THEN
        -- No active task — create one in pending state
        INSERT INTO housekeeping_tasks (room_id, hotel_id, status, assigned_to, priority_score)
        VALUES (p_room_id, v_hotel_id, 'pending', p_staff_id, 0)
        RETURNING id INTO v_task_id;
    ELSE
        -- Update existing task
        UPDATE housekeeping_tasks
        SET assigned_to = p_staff_id
        WHERE id = v_task_id;
    END IF;

    -- Audit event
    INSERT INTO housekeeping_events (hotel_id, room_id, old_status, new_status, changed_by, event_type, details)
    VALUES (v_hotel_id, p_room_id, v_current_status, v_current_status, auth.uid(), 'TASK_ASSIGNED',
            jsonb_build_object(
                'task_id', v_task_id,
                'staff_id', p_staff_id,
                'old_assignee', v_old_assignee
            ));

    RETURN jsonb_build_object('success', true, 'task_id', v_task_id, 'assigned_to', p_staff_id);
END;
$$;


ALTER FUNCTION "public"."hk_assign_task"("p_room_id" "uuid", "p_staff_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."hk_bulk_assign"("p_room_ids" "uuid"[], "p_staff_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_hotel_id UUID;
    v_distinct_rooms UUID[];
    v_updated_count INT := 0;
    v_dirty_count INT := 0;
    v_inspect_count INT := 0;
    v_backfill_count INT := 0;
BEGIN
    -- 1. Deduplication & Cleanup
    SELECT array_agg(DISTINCT id) INTO v_distinct_rooms FROM unnest(p_room_ids) id WHERE id IS NOT NULL;
    IF v_distinct_rooms IS NULL OR array_length(v_distinct_rooms, 1) = 0 THEN
        RETURN jsonb_build_object('success', true, 'rooms_affected', 0);
    END IF;

    -- 2. Existence & Single-Hotel Validation
    SELECT hotel_id INTO v_hotel_id FROM rooms WHERE id = ANY(v_distinct_rooms) LIMIT 1;
    IF EXISTS (SELECT 1 FROM rooms WHERE id = ANY(v_distinct_rooms) AND hotel_id <> v_hotel_id) THEN
        RAISE EXCEPTION 'Bulk operations must target rooms from the same hotel.';
    END IF;
    IF (SELECT count(*) FROM rooms WHERE id = ANY(v_distinct_rooms)) <> array_length(v_distinct_rooms, 1) THEN
        RAISE EXCEPTION 'One or more room IDs do not exist';
    END IF;

    -- 3. Authorization
    IF NOT public.has_hotel_role(
        auth.uid(), v_hotel_id, 
        ARRAY['OWNER', 'ADMIN', 'GENERAL_MANAGER', 'SUPERVISOR', 'HOUSEKEEPING_MANAGER', 'HOUSEKEEPING_SUPERVISOR']
    ) THEN
        RAISE EXCEPTION 'Unauthorized for bulk assignment';
    END IF;

    -- 4. Staff Validation
    IF NOT EXISTS (SELECT 1 FROM hotel_members WHERE id = p_staff_id AND hotel_id = v_hotel_id AND is_active = true) THEN
        RAISE EXCEPTION 'Staff does not belong to this hotel or is inactive';
    END IF;

    -- 5a. For dirty/in_progress rooms: cancel old tasks and create new pending tasks with assignment
    UPDATE housekeeping_tasks 
    SET status = 'cancelled', completed_at = now()
    WHERE room_id = ANY(v_distinct_rooms) 
      AND status IN ('pending', 'in_progress')
      AND hotel_id = v_hotel_id;

    INSERT INTO housekeeping_tasks (room_id, hotel_id, status, assigned_to, priority_score)
    SELECT id, v_hotel_id, 'pending', p_staff_id, 0
    FROM rooms 
    WHERE id = ANY(v_distinct_rooms)
    AND housekeeping_status IN ('dirty', 'in_progress');

    GET DIAGNOSTICS v_dirty_count = ROW_COUNT;

    -- 5b. For clean rooms (pending inspection): update the existing inspection_pending task's assignment
    UPDATE housekeeping_tasks
    SET assigned_to = p_staff_id
    WHERE room_id = ANY(v_distinct_rooms)
      AND status = 'inspection_pending'
      AND hotel_id = v_hotel_id;

    GET DIAGNOSTICS v_inspect_count = ROW_COUNT;

    -- 5c. If a clean room has no inspection_pending task (legacy data), create one
    INSERT INTO housekeeping_tasks (room_id, hotel_id, status, started_at, priority_score, assigned_to)
    SELECT r.id, v_hotel_id, 'inspection_pending', now(), 0, p_staff_id
    FROM rooms r
    WHERE r.id = ANY(v_distinct_rooms)
      AND r.housekeeping_status = 'clean'
      AND NOT EXISTS (
        SELECT 1 FROM housekeeping_tasks ht
        WHERE ht.room_id = r.id AND ht.status = 'inspection_pending' AND ht.hotel_id = v_hotel_id
      );

    GET DIAGNOSTICS v_backfill_count = ROW_COUNT;

    v_updated_count := v_dirty_count + v_inspect_count + v_backfill_count;

    -- 6. Audit Events
    INSERT INTO housekeeping_events (hotel_id, room_id, old_status, new_status, changed_by, event_type, details)
    SELECT v_hotel_id, id, housekeeping_status, housekeeping_status, auth.uid(), 'BULK_TASK_ASSIGNED',
           jsonb_build_object('staff_id', p_staff_id, 'bulk', true)
    FROM rooms WHERE id = ANY(v_distinct_rooms)
    AND housekeeping_status NOT IN ('out_of_order', 'inspected');

    RETURN jsonb_build_object('success', true, 'rooms_affected', v_updated_count);
END;
$$;


