      AND status IN ('pending', 'in_progress')
      AND hotel_id = v_hotel_id;

    -- Update rooms and log events
    WITH update_result AS (
        UPDATE rooms
        SET housekeeping_status = 'out_of_order', is_out_of_order = true, updated_at = now()
