CREATE OR REPLACE FUNCTION "public"."hk_pause_cleaning"("p_room_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_task_id UUID;
    v_hotel_id UUID;
    v_old_status housekeeping_status_enum;
BEGIN
    SELECT hotel_id, housekeeping_status INTO v_hotel_id, v_old_status
    FROM rooms WHERE id = p_room_id FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Room not found: %', p_room_id;
    END IF;

    IF NOT public.has_hotel_role(
        auth.uid(),
        v_hotel_id,
        ARRAY['OWNER', 'ADMIN', 'GENERAL_MANAGER', 'SUPERVISOR', 'HOUSEKEEPING_MANAGER', 'HOUSEKEEPING_SUPERVISOR']
    ) THEN
        RAISE EXCEPTION 'Unauthorized: you do not have supervisor-level permission to modify room % in hotel %', p_room_id, v_hotel_id;
    END IF;

    -- Block if room not currently being cleaned
    IF v_old_status <> 'in_progress'::housekeeping_status_enum THEN
        RAISE EXCEPTION 'Room is not currently being cleaned.';
    END IF;

    -- Pause active task
    UPDATE housekeeping_tasks
    SET status = 'pending'
    WHERE room_id = p_room_id 
      AND status = 'in_progress'
      AND hotel_id = v_hotel_id
    RETURNING id INTO v_task_id;

    IF v_task_id IS NULL THEN
        RAISE EXCEPTION 'No active cleaning task found for room %', p_room_id;
    END IF;

    -- Update room status to pickup (paused state)
    UPDATE rooms
    SET housekeeping_status = 'pickup'::housekeeping_status_enum,
        updated_at = now()
    WHERE id = p_room_id;

    -- Audit event
    INSERT INTO housekeeping_events (hotel_id, room_id, old_status, new_status, changed_by, event_type)
    VALUES (v_hotel_id, p_room_id, v_old_status, 'pickup', auth.uid(), 'CLEANING_PAUSED');

    RETURN jsonb_build_object('success', true, 'task_id', v_task_id, 'new_status', 'pickup');
END;
$$;


ALTER FUNCTION "public"."hk_pause_cleaning"("p_room_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."hk_start_cleaning"("p_room_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_task_id UUID;
    v_hotel_id UUID;
    v_old_status housekeeping_status_enum;
    v_member_id UUID;
    v_existing_assignee UUID;
BEGIN
    -- Get current room state
    SELECT hotel_id, housekeeping_status INTO v_hotel_id, v_old_status
    FROM rooms WHERE id = p_room_id FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Room not found: %', p_room_id;
    END IF;

    IF NOT public.has_hotel_role(
        auth.uid(),
        v_hotel_id,
        ARRAY['OWNER', 'ADMIN', 'GENERAL_MANAGER', 'SUPERVISOR', 'HOUSEKEEPING_MANAGER', 'HOUSEKEEPING_SUPERVISOR']
    ) THEN
        RAISE EXCEPTION 'Unauthorized: you do not have supervisor-level permission to modify room % in hotel %', p_room_id, v_hotel_id;
    END IF;

    -- Block if room is out of order
    IF v_old_status = 'out_of_order'::housekeeping_status_enum THEN
        RAISE EXCEPTION 'Cannot start cleaning. Room is out of order.';
    END IF;

    -- Block if room is already clean (prevent accidental restarts)
    IF v_old_status IN ('clean'::housekeeping_status_enum, 'inspected'::housekeeping_status_enum) THEN
        RAISE EXCEPTION 'Room is already clean.';
    END IF;

    -- Resolve the calling user's hotel_member ID for this hotel
    SELECT id INTO v_member_id
    FROM hotel_members
    WHERE user_id = auth.uid()
      AND hotel_id = v_hotel_id
      AND is_active = true
    LIMIT 1;

    IF v_member_id IS NULL THEN
        RAISE EXCEPTION 'You are not an active member of this hotel.';
    END IF;

    -- Check if there's an existing pending task with a pre-assigned staff member (from bulk assign)
    SELECT assigned_to INTO v_existing_assignee
    FROM housekeeping_tasks
    WHERE room_id = p_room_id
      AND status IN ('pending', 'in_progress')
      AND hotel_id = v_hotel_id
    ORDER BY created_at DESC
    LIMIT 1;

    -- Close any existing active task
    UPDATE housekeeping_tasks
    SET status = 'cancelled', completed_at = now()
    WHERE room_id = p_room_id 
      AND status IN ('pending', 'in_progress')
      AND hotel_id = v_hotel_id;

    -- Create new task with assignment:
    -- If room was pre-assigned (bulk assign), keep that staff member.
    -- Otherwise, auto-assign to the calling user.
    INSERT INTO housekeeping_tasks (room_id, hotel_id, status, started_at, priority_score, assigned_to)
    VALUES (p_room_id, v_hotel_id, 'in_progress', now(), 0, COALESCE(v_existing_assignee, v_member_id))
    RETURNING id INTO v_task_id;

    -- Update room status → in_progress
    UPDATE rooms
    SET housekeeping_status = 'in_progress'::housekeeping_status_enum,
        updated_at = now()
    WHERE id = p_room_id;

    -- Audit event
    INSERT INTO housekeeping_events (hotel_id, room_id, old_status, new_status, changed_by, event_type, details)
    VALUES (v_hotel_id, p_room_id, v_old_status, 'in_progress', auth.uid(), 'CLEANING_STARTED',
            jsonb_build_object('task_id', v_task_id, 'assigned_to', COALESCE(v_existing_assignee, v_member_id)));

    RETURN jsonb_build_object('success', true, 'task_id', v_task_id, 'new_status', 'in_progress',
                              'assigned_to', COALESCE(v_existing_assignee, v_member_id));
END;
$$;


ALTER FUNCTION "public"."hk_start_cleaning"("p_room_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."hk_supervisor_override"("p_room_id" "uuid", "p_new_status" "text", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_hotel_id UUID;
    v_old_status housekeeping_status_enum;
    v_new_status housekeeping_status_enum;
    v_member_id UUID;
BEGIN
    -- Safe enum validation
    IF NOT EXISTS (
      SELECT 1 FROM unnest(enum_range(NULL::housekeeping_status_enum)) s
      WHERE s::text = p_new_status
    ) THEN
        RAISE EXCEPTION 'Invalid housekeeping status: %', p_new_status;
    END IF;

    v_new_status := p_new_status::housekeeping_status_enum;

    SELECT hotel_id, housekeeping_status INTO v_hotel_id, v_old_status
    FROM rooms WHERE id = p_room_id FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Room not found: %', p_room_id;
    END IF;

    IF NOT public.has_hotel_role(
        auth.uid(),
        v_hotel_id,
        ARRAY['OWNER', 'ADMIN', 'GENERAL_MANAGER', 'SUPERVISOR', 'HOUSEKEEPING_MANAGER', 'HOUSEKEEPING_SUPERVISOR']
    ) THEN
        RAISE EXCEPTION 'Unauthorized: you do not have supervisor-level permission to modify room % in hotel %', p_room_id, v_hotel_id;
    END IF;

    -- Resolve the calling user's hotel_member ID for inspector tracking
    SELECT id INTO v_member_id
    FROM hotel_members
    WHERE user_id = auth.uid()
      AND hotel_id = v_hotel_id
      AND is_active = true
    LIMIT 1;

    -- Cancel any active tasks if overriding to clean/inspected
    IF p_new_status IN ('clean', 'inspected') THEN
        -- For inspection: assign the inspector before completing the task
        IF p_new_status = 'inspected' AND v_member_id IS NOT NULL THEN
            UPDATE housekeeping_tasks
            SET status = 'completed', completed_at = now(), assigned_to = COALESCE(assigned_to, v_member_id)
            WHERE room_id = p_room_id 
              AND status IN ('pending', 'in_progress', 'inspection_pending')
              AND hotel_id = v_hotel_id;
        ELSE
            UPDATE housekeeping_tasks
            SET status = 'completed', completed_at = now()
            WHERE room_id = p_room_id 
              AND status IN ('pending', 'in_progress', 'inspection_pending')
              AND hotel_id = v_hotel_id;
        END IF;
    END IF;

    -- Update room
    UPDATE rooms
    SET housekeeping_status = v_new_status,
        is_out_of_order = (p_new_status = 'out_of_order'),
        updated_at = now()
    WHERE id = p_room_id;

    -- Audit event
    INSERT INTO housekeeping_events (hotel_id, room_id, old_status, new_status, changed_by, event_type, details)
    VALUES (v_hotel_id, p_room_id, v_old_status, v_new_status, auth.uid(), 'SUPERVISOR_OVERRIDE',
            jsonb_build_object('reason', COALESCE(p_reason, 'Supervisor override'), 'override', true,
                               'inspector_id', v_member_id));

    RETURN jsonb_build_object('success', true, 'old_status', v_old_status::text, 'new_status', p_new_status);
END;
$$;


ALTER FUNCTION "public"."hk_supervisor_override"("p_room_id" "uuid", "p_new_status" "text", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."hotel_has_owner"("p_hotel_id" "uuid") RETURNS boolean
    LANGUAGE "sql"
    AS $$
    SELECT EXISTS (
        -- Check 1: Active member with OWNER role (invite already accepted)
        SELECT 1
        FROM public.hotel_members hm
        JOIN public.hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
        JOIN public.hotel_roles hr ON hr.id = hmr.role_id
        WHERE hm.hotel_id = p_hotel_id
          AND hr.code = 'OWNER'
          AND hm.is_active = true
          AND hr.is_active = true

        UNION ALL

        -- Check 2: Pending invite with OWNER role (invite sent but not yet accepted)
        SELECT 1
        FROM public.hotel_invites hi
        JOIN public.hotel_roles hr ON hr.id = hi.role_id
        WHERE hi.hotel_id = p_hotel_id
          AND hr.code = 'OWNER'
          AND hi.status = 'pending'
          AND hr.is_active = true
    );
$$;


ALTER FUNCTION "public"."hotel_has_owner"("p_hotel_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ingest_booking"("p_payload" "jsonb", "p_source" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    v_booking_reference text;
BEGIN
    v_booking_reference := trim(p_payload->>'booking_reference');

    IF v_booking_reference IS NULL OR v_booking_reference = '' THEN
       RAISE EXCEPTION 'booking_reference missing in payload';
    END IF;

    INSERT INTO public.import_rows(
        booking_reference,
        row_data,
        status,
        source
    )
    SELECT
        v_booking_reference,
        p_payload,
        'pending',
        p_source
    WHERE NOT EXISTS (
        SELECT 1
        FROM public.import_rows
        WHERE booking_reference = v_booking_reference
        AND status IN ('pending', 'processing')
    );

    -- Workers process via cron — do not process inline to avoid transaction locks during bulk uploads
    RETURN jsonb_build_object(
        'success', true,
        'booking_reference', v_booking_reference
    );
END;
$$;


ALTER FUNCTION "public"."ingest_booking"("p_payload" "jsonb", "p_source" "text") OWNER TO "postgres";


