CREATE OR REPLACE VIEW "public"."live_orders_eta_v" AS
 SELECT "o"."hotel_id",
    "o"."id" AS "order_id",
    "o"."created_at",
    ("o"."status")::"text" AS "status",
    "o"."price",
    NULL::"text" AS "assigned_staff",
    (GREATEST((0)::numeric, (("t"."target_minutes")::numeric - (EXTRACT(epoch FROM ("now"() - "o"."created_at")) / (60)::numeric))))::integer AS "eta_min_left",
    ((EXTRACT(epoch FROM ("now"() - "o"."created_at")) / (60)::numeric) > ("t"."target_minutes")::numeric) AS "sla_breached"
   FROM ("public"."orders" "o"
     JOIN "public"."sla_targets" "t" ON ((("t"."hotel_id" = "o"."hotel_id") AND ("t"."key" = 'order_delivery_min'::"text"))))
  WHERE ("o"."status" = ANY (ARRAY['open'::"public"."order_status", 'preparing'::"public"."order_status"]));


