CREATE OR REPLACE FUNCTION "public"."lock_shift"("p_id" "uuid", "p_user" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
begin
  update public.staff_shifts
  set locked_at = now(), locked_by = p_user
  where id = p_id
    and (
      locked_at is null
      or locked_at < now() - interval '5 minutes'
      or locked_by = p_user
    );
end;
$$;


