    LANGUAGE "plpgsql"
    AS $$
begin
  insert into public.ai_usage (hotel_id, month_utc, used_tokens, budget_tokens)
  values (p_hotel_id, date_trunc('month', now())::date, p_tokens, 200000)
  on conflict (hotel_id, month_utc)
  do update set used_tokens = public.ai_usage.used_tokens + excluded.used_tokens;

  insert into public.ai_usage_events(hotel_id, tokens, model, func)
  values (p_hotel_id, p_tokens, p_model, p_func);
end
$$;


