    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    IF (OLD.housekeeping_status IS DISTINCT FROM NEW.housekeeping_status) THEN
        INSERT INTO housekeeping_events (hotel_id, room_id, old_status, new_status, changed_by)
        VALUES (NEW.hotel_id, NEW.id, OLD.housekeeping_status, NEW.housekeeping_status, COALESCE(auth.uid(), NULL));
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."log_housekeeping_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_room_assignment_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_hotel_id UUID;
BEGIN
    SELECT hotel_id INTO v_hotel_id FROM bookings WHERE id = COALESCE(NEW.booking_id, OLD.booking_id);
    IF (OLD.room_id IS NULL AND NEW.room_id IS NOT NULL) THEN
        INSERT INTO arrival_events (hotel_id, booking_id, event_type, new_value, performed_by)
        VALUES (v_hotel_id, NEW.booking_id, 'ROOM_ASSIGNED', NEW.room_id::text, COALESCE(auth.uid(), NULL));
    ELSIF (OLD.room_id IS NOT NULL AND NEW.room_id IS NULL) THEN
        INSERT INTO arrival_events (hotel_id, booking_id, event_type, old_value, performed_by)
        VALUES (v_hotel_id, OLD.booking_id, 'ROOM_UNASSIGNED', OLD.room_id::text, COALESCE(auth.uid(), NULL));
    ELSIF (OLD.room_id IS DISTINCT FROM NEW.room_id) THEN
        INSERT INTO arrival_events (hotel_id, booking_id, event_type, old_value, new_value, performed_by)
        VALUES (v_hotel_id, NEW.booking_id, 'ROOM_REASSIGNED', OLD.room_id::text, NEW.room_id::text, COALESCE(auth.uid(), NULL));
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."log_room_assignment_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."lookup_guest_profile"("p_hotel_id" "uuid", "p_mobile" "text", "p_email" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_clean_phone TEXT;
    v_guest RECORD;
BEGIN
    -- Normalize phone
    v_clean_phone := regexp_replace(p_mobile, '[^0-9]', '', 'g');

    -- Handle India country code (91XXXXXXXXXX -> XXXXXXXXXX)
    IF length(v_clean_phone) = 12 AND left(v_clean_phone,2) = '91' THEN
        v_clean_phone := right(v_clean_phone,10);
    END IF;

    -------------------------------------------------
    -- Stage 1 : Mobile lookup (strong identity)
    -------------------------------------------------
    IF length(v_clean_phone) = 10 THEN
        SELECT * INTO v_guest
        FROM guests
        WHERE mobile_normalized = v_clean_phone
        ORDER BY created_at DESC
        LIMIT 1;

        IF FOUND THEN
            RETURN jsonb_build_object(
                'found', true,
                'match_type', 'mobile',
                'guest', jsonb_build_object(
                    'id', v_guest.id,
                    'full_name', v_guest.full_name,
                    'email', v_guest.email,
                    'mobile', v_guest.mobile,
                    'nationality', v_guest.nationality,
                    'address', v_guest.address
                )
            );
        END IF;
    END IF;

    -------------------------------------------------
    -- Stage 2 : Email fallback
    -------------------------------------------------
    IF COALESCE(trim(p_email),'') <> '' THEN
        SELECT * INTO v_guest
        FROM guests
        WHERE lower(email) = lower(trim(p_email))
        ORDER BY created_at DESC
        LIMIT 1;

        IF FOUND THEN
            RETURN jsonb_build_object(
                'found', true,
                'match_type', 'email',
                'guest', jsonb_build_object(
                    'id', v_guest.id,
                    'full_name', v_guest.full_name,
                    'email', v_guest.email,
                    'mobile', v_guest.mobile,
                    'nationality', v_guest.nationality,
                    'address', v_guest.address
                )
            );
        END IF;
    END IF;

    RETURN jsonb_build_object('found', false);
END;
$$;


ALTER FUNCTION "public"."lookup_guest_profile"("p_hotel_id" "uuid", "p_mobile" "text", "p_email" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_food_order_preparing"("p_order_id" "uuid", "p_hotel_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM hotel_members hm
        JOIN hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
        JOIN hotel_roles r ON r.id = hmr.role_id
        WHERE hm.hotel_id = p_hotel_id
          AND hm.user_id = auth.uid()
          AND r.code IN ('KITCHEN','KITCHEN_MANAGER','ADMIN','OWNER')
    ) THEN
        RAISE EXCEPTION 'Unauthorized kitchen action';
    END IF;

    PERFORM 1 FROM food_orders WHERE id = p_order_id FOR UPDATE;

    UPDATE food_orders
    SET status = 'PREPARING', updated_at = now()
    WHERE id = p_order_id
      AND status = 'ACCEPTED';

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Invalid state transition';
    END IF;

    INSERT INTO food_order_events
    VALUES (
        gen_random_uuid(),
        p_order_id,
        'ORDER_PREPARING',
        'KITCHEN',
        auth.uid(),
        '{}',
        now()
    );
END;
$$;


ALTER FUNCTION "public"."mark_food_order_preparing"("p_order_id" "uuid", "p_hotel_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_food_order_ready"("p_order_id" "uuid", "p_hotel_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_runner UUID;
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM hotel_members hm
        JOIN hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
        JOIN hotel_roles r ON r.id = hmr.role_id
        WHERE hm.hotel_id = p_hotel_id
          AND hm.user_id = auth.uid()
          AND r.code IN ('KITCHEN','KITCHEN_MANAGER','ADMIN','OWNER')
    ) THEN
        RAISE EXCEPTION 'Unauthorized kitchen action';
    END IF;

    PERFORM 1 FROM food_orders WHERE id = p_order_id FOR UPDATE;

    UPDATE food_orders
    SET status = 'READY', updated_at = now()
    WHERE id = p_order_id
      AND status = 'PREPARING';

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Invalid state transition';
    END IF;

    UPDATE food_order_items
    SET status = 'READY'
    WHERE food_order_id = p_order_id;

    -- Auto-assign runner (least load = fewest active READY orders)
    v_runner := (
        SELECT hm.id
        FROM hotel_members hm
        JOIN hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
        JOIN hotel_roles r ON r.id = hmr.role_id
        WHERE hm.hotel_id = p_hotel_id
          AND r.code = 'RUNNER'
        ORDER BY (
            SELECT COUNT(*)
            FROM food_order_assignments foa
            JOIN food_orders fo ON fo.id = foa.food_order_id
            WHERE foa.hotel_member_id = hm.id
              AND foa.role = 'RUNNER'
              AND fo.status = 'READY'
        ) ASC
        LIMIT 1
    );

    IF v_runner IS NOT NULL THEN
        INSERT INTO food_order_assignments (
            id,
            food_order_id,
            hotel_member_id,
            role,
            assigned_at
        )
        VALUES (
            gen_random_uuid(),
            p_order_id,
            v_runner,
            'RUNNER',
            now()
        )
        ON CONFLICT DO NOTHING;
    END IF;

    INSERT INTO food_order_events
    VALUES (
        gen_random_uuid(),
        p_order_id,
        'ORDER_READY',
        'KITCHEN',
        auth.uid(),
        '{}',
        now()
    );
END;
$$;


ALTER FUNCTION "public"."mark_food_order_ready"("p_order_id" "uuid", "p_hotel_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_notification_failed"("p_id" "uuid", "p_error" "text") RETURNS "void"
    LANGUAGE "sql"
    AS $$
UPDATE public.notification_queue
SET
    status = CASE WHEN retry_count >= 10 THEN 'failed' ELSE 'pending' END,
    retry_count = retry_count + 1,
    next_attempt_at = now() + (interval '2 minutes' * (retry_count + 1)),
    error_message = p_error
WHERE id = p_id;
$$;


ALTER FUNCTION "public"."mark_notification_failed"("p_id" "uuid", "p_error" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_notification_sent"("p_id" "uuid") RETURNS "void"
    LANGUAGE "sql"
    AS $$
UPDATE public.notification_queue
SET
    status = 'sent',
    sent_at = now(),
    error_message = NULL
WHERE id = p_id;
$$;


ALTER FUNCTION "public"."mark_notification_sent"("p_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_onboarding_step_complete"("p_hotel_id" "uuid", "p_step" "public"."hotel_onboarding_step") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    PERFORM 1 FROM public.hotels
    WHERE id = p_hotel_id
    FOR UPDATE;

    INSERT INTO public.hotel_onboarding_progress (
        hotel_id,
        step_name,
        completed_by
    )
    VALUES (
        p_hotel_id,
        p_step,
        auth.uid()
    )
    ON CONFLICT (hotel_id, step_name)
    DO UPDATE SET completed_at = now();

    UPDATE public.hotels
    SET lifecycle_status = 'CONFIGURING',
        onboarding_started_at = COALESCE(onboarding_started_at, now()),
        onboarding_due_at = COALESCE(onboarding_due_at, now() + (onboarding_sla_days || ' days')::interval)
    WHERE id = p_hotel_id
      AND lifecycle_status = 'DRAFT';

    IF public.are_required_onboarding_steps_complete(p_hotel_id) THEN
        UPDATE public.hotels
        SET lifecycle_status = 'READY_FOR_REVIEW',
            is_setup_complete = true
        WHERE id = p_hotel_id;
    END IF;
END;
$$;


ALTER FUNCTION "public"."mark_onboarding_step_complete"("p_hotel_id" "uuid", "p_step" "public"."hotel_onboarding_step") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."move_shift"("p_id" "uuid", "p_start" timestamp with time zone, "p_end" timestamp with time zone, "p_version" integer, "p_user" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
declare v record;
begin
  select * into v from public.staff_shifts where id = p_id for update;

  if not found then raise exception 'Shift not found'; end if;
  if v.version != p_version then raise exception 'Version mismatch'; end if;

  if v.locked_at is not null
     and v.locked_at > now() - interval '5 minutes'
     and v.locked_by is distinct from p_user then
    raise exception 'Locked';
  end if;

  if p_end <= p_start then raise exception 'Invalid time'; end if;

  update public.staff_shifts
  set shift_start = p_start,
      shift_end = p_end
  where id = p_id
    and status = 'scheduled'
    and is_active = true;

exception when exclusion_violation then
  raise exception 'Overlap';
end;
$$;


ALTER FUNCTION "public"."move_shift"("p_id" "uuid", "p_start" timestamp with time zone, "p_end" timestamp with time zone, "p_version" integer, "p_user" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."owner_nps_for_slug"("p_slug" "text") RETURNS TABLE("hotel_id" "uuid", "total_responses" integer, "promoters" integer, "passives" integer, "detractors" integer, "nps_30d" numeric)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    h.id as hotel_id,
    coalesce(n.total_responses, 0) as total_responses,
    coalesce(n.promoters, 0) as promoters,
    coalesce(n.passives, 0) as passives,
    coalesce(n.detractors, 0) as detractors,
    n.nps_30d
  from public.hotels h
  left join public.owner_nps_30d n
    on n.hotel_id = h.id
  where h.slug = p_slug
  limit 1;
$$;


ALTER FUNCTION "public"."owner_nps_for_slug"("p_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."patch_menu_item"("p_item_id" "uuid", "p_hotel_id" "uuid", "p_price" numeric DEFAULT NULL::numeric, "p_active" boolean DEFAULT NULL::boolean, "p_category_id" "uuid" DEFAULT NULL::"uuid", "p_is_veg" boolean DEFAULT NULL::boolean, "p_metadata" "jsonb" DEFAULT NULL::"jsonb", "p_internal_notes" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    -- --------------------------------------------------------
    -- 0. AUTHORIZATION
    -- --------------------------------------------------------
    IF NOT EXISTS (
        SELECT 1
        FROM hotel_members hm
        JOIN hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
        JOIN hotel_roles r ON r.id = hmr.role_id
        JOIN menu_items mi ON mi.hotel_id = hm.hotel_id
        WHERE mi.id = p_item_id
          AND hm.hotel_id = p_hotel_id
          AND hm.user_id = auth.uid()
          AND r.code IN ('OWNER', 'ADMIN', 'KITCHEN_MANAGER')
    ) THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Unauthorized menu item update',
            ERRCODE = 'P2001';
    END IF;

    -- --------------------------------------------------------
    -- 1. FIELD VALIDATION (ONLY IF PROVIDED)
    -- --------------------------------------------------------
    IF p_price IS NOT NULL AND p_price < 0 THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Price must be non-negative',
            ERRCODE = 'P2002';
    END IF;

    IF p_category_id IS NOT NULL AND NOT EXISTS (
        SELECT 1
        FROM menu_categories
        WHERE id = p_category_id
          AND hotel_id = p_hotel_id
          AND active = true
    ) THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Invalid or inactive category',
            ERRCODE = 'P2003';
    END IF;

    -- --------------------------------------------------------
    -- 2. PATCH UPDATE
    -- --------------------------------------------------------
    UPDATE menu_items
    SET
        price = COALESCE(p_price, price),
        active = COALESCE(p_active, active),
        category_id = COALESCE(p_category_id, category_id),
        is_veg = COALESCE(p_is_veg, is_veg),
        metadata = CASE
            WHEN p_metadata IS NULL THEN metadata
            ELSE metadata || p_metadata
        END,
        internal_notes = COALESCE(p_internal_notes, internal_notes),
        updated_at = now()
    WHERE id = p_item_id
      AND hotel_id = p_hotel_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Menu item not found',
            ERRCODE = 'P2004';
    END IF;
END;
$$;


ALTER FUNCTION "public"."patch_menu_item"("p_item_id" "uuid", "p_hotel_id" "uuid", "p_price" numeric, "p_active" boolean, "p_category_id" "uuid", "p_is_veg" boolean, "p_metadata" "jsonb", "p_internal_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."pause_ticket"("p_ticket_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  UPDATE tickets SET status = 'BLOCKED' WHERE id = p_ticket_id;

  UPDATE ticket_sla_state
  SET sla_paused_at = now()
  WHERE ticket_id = p_ticket_id;

  INSERT INTO ticket_events (ticket_id, event_type, new_status)
  VALUES (p_ticket_id, 'BLOCKED', 'BLOCKED');
END;
$$;


ALTER FUNCTION "public"."pause_ticket"("p_ticket_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."prevent_sla_policy_update"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF EXISTS (
    SELECT 1
    FROM ticket_sla_state
    WHERE sla_policy_id = OLD.id
  )
  AND (
    NEW.target_minutes      IS DISTINCT FROM OLD.target_minutes
    OR NEW.warn_minutes     IS DISTINCT FROM OLD.warn_minutes
    OR NEW.escalate_minutes IS DISTINCT FROM OLD.escalate_minutes
    OR NEW.sla_start_trigger IS DISTINCT FROM OLD.sla_start_trigger
  )
  THEN
    RAISE EXCEPTION
      'SLA policy % is already used by tickets and cannot be modified',
      OLD.id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."prevent_sla_policy_update"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_booking_group"("p_booking_reference" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
    v_booking_id UUID;
    v_hotel_id UUID;
    v_primary_guest_id UUID;
    v_token TEXT;
    v_slug_hotel_id UUID;
    
    -- Variables from CTE
    v_guest_name TEXT;
    v_phone TEXT;
    v_email TEXT;
    v_checkin_date DATE;
    v_checkout_date DATE;
    v_adults_total INT;
    v_children_total INT;
    v_rooms_total INT;
    v_booking_status TEXT;
    v_row_data JSONB;
BEGIN
    -- CRITICAL FIX: Normalize booking reference early (prevent phantom duplicates)
    p_booking_reference := trim(p_booking_reference);

    -- SAFETY FIX: Prevent empty booking reference
    IF p_booking_reference IS NULL OR p_booking_reference = '' THEN
       RAISE EXCEPTION 'booking_reference missing';
    END IF;

    -- =========================================================
    -- IDEMPOTENCY GUARD (enterprise crash-safe)
    -- =========================================================
    BEGIN
        INSERT INTO public.import_idempotency(booking_reference,status)
        VALUES (p_booking_reference,'processing');
    EXCEPTION WHEN unique_violation THEN
        -- Allow retry if previous attempt stuck
        IF EXISTS (
            SELECT 1
            FROM public.import_idempotency
            WHERE booking_reference = p_booking_reference
            AND status = 'processing'
            AND locked_at < now() - interval '20 minutes'
        ) THEN
            UPDATE public.import_idempotency
            SET locked_at = now(),
                status = 'processing'
            WHERE booking_reference = p_booking_reference;
        ELSE
            -- Still mark rows as imported so batch counters update and UI completes
            UPDATE public.import_rows
            SET status = 'imported',
                processed_at = now()
            WHERE booking_reference = p_booking_reference
              AND status = 'processing';

            RETURN jsonb_build_object(
                'success', true,
                'message', 'Already processed (idempotent skip)'
            );
        END IF;
    END;

    ----------------------------------------------------------------
    -- 0. Optimization: Materialized CTE for Booking Rows
    ----------------------------------------------------------------
    -- Using a temporary table concept via CTE to avoid repeated scans
    WITH booking_rows AS (
        SELECT *
        FROM public.import_rows
        WHERE booking_reference = p_booking_reference
    ),
    agg AS (
        SELECT
            MIN((row_data->>'checkin_date')::date) AS checkin_date,
            MAX((row_data->>'checkout_date')::date) AS checkout_date,
            SUM(COALESCE((row_data->>'adults')::int, 1)) AS adults_total,
            SUM(COALESCE((row_data->>'children')::int, 0)) AS children_total,
            COUNT(DISTINCT COALESCE((row_data->>'room_seq')::int, 1)) AS rooms_total,
            UPPER(MAX(row_data->>'booking_status')) AS booking_status,
            -- Get primary row data for guest info
            (ARRAY_AGG(row_data ORDER BY primary_guest_flag DESC, id ASC))[1] as primary_data,
            (ARRAY_AGG(hotel_id ORDER BY primary_guest_flag DESC, id ASC))[1] as primary_hotel_id
        FROM booking_rows
    )
    SELECT 
        checkin_date, 
        checkout_date, 
        adults_total, 
        children_total, 
        rooms_total,
        booking_status,
        primary_data,
        primary_hotel_id
    INTO 
        v_checkin_date, 
        v_checkout_date, 
        v_adults_total, 
        v_children_total, 
        v_rooms_total,
        v_booking_status,
        v_row_data,
        v_hotel_id -- Initial hotel_id from row
    FROM agg;

    IF v_row_data IS NULL THEN
         RETURN jsonb_build_object('success', false, 'error', 'No rows found');
    END IF;

    -- SAFETY FIX: Enforce hotel_slug presence logic (same as before but using CTE data)
    IF (v_row_data->>'hotel_slug') IS NULL OR (v_row_data->>'hotel_slug') = '' THEN
       RAISE EXCEPTION 'hotel_slug missing in import row';
    END IF;

    -- CRITICAL FIX: Deterministic Hotel Lookup
    -- We can resolve hotel_id once here.
    -- CRITICAL FIX: Deterministic Hotel Lookup
    -- We can resolve hotel_id once here.
    SELECT id INTO v_slug_hotel_id FROM public.hotels WHERE slug = (v_row_data->>'hotel_slug');
    IF v_slug_hotel_id IS NOT NULL THEN
        v_hotel_id := v_slug_hotel_id;
    END IF;

    -- CRITICAL FIX: Guard against missing hotel
    IF v_hotel_id IS NULL THEN
       RAISE EXCEPTION 'Invalid hotel_slug in import';
    END IF;
    
    v_guest_name := v_row_data->>'guest_name';
    -- CRITICAL FIX-4: Normalize phone number (Enterprise Safe)
    v_phone := NULLIF(regexp_replace(trim(COALESCE(v_row_data->>'guest_phone', v_row_data->>'phone', '')), '[^0-9]', '', 'g'), '');
    v_email := NULLIF(trim(COALESCE(v_row_data->>'guest_email', v_row_data->>'email')), '');

    ----------------------------------------------------------------
    -- 2. Resovle / Create Primary Guest (Canonical Resolver)
    ----------------------------------------------------------------
    -- Uses the shared identity logic to find or create the guest idempotently.
    
    SELECT public.resolve_guest_identity(
        v_hotel_id,
        v_guest_name,
        v_phone,
        v_email
    )
    INTO v_primary_guest_id;

    ----------------------------------------------------------------
    -- 3. Create / Upsert Booking (Race Condition Guard)
    ----------------------------------------------------------------
    
    -- SAFETY GUARD: Lock booking reference deterministically
    PERFORM 1
    FROM public.bookings
    WHERE code = p_booking_reference
    FOR UPDATE;

    INSERT INTO public.bookings (
        code,
        hotel_id,
        guest_id,
        guest_name,
        phone,
        email,
        status,
        scheduled_checkin_at,
        scheduled_checkout_at,
        adults_total,
        children_total,
        rooms_total,
        source, 
        created_at,
        updated_at
    )
    VALUES (
        p_booking_reference,
        v_hotel_id,
        v_primary_guest_id,
        v_guest_name,
        v_phone,
        v_email,
        COALESCE(v_booking_status, 'CONFIRMED'),
        v_checkin_date,
        v_checkout_date,
        v_adults_total,
        v_children_total,
        v_rooms_total,
        'pms_sync',
        now(),
        now()
    )
    ON CONFLICT (code)
    DO UPDATE SET
        guest_id = COALESCE(EXCLUDED.guest_id, bookings.guest_id),
        guest_name = EXCLUDED.guest_name,
        phone = EXCLUDED.phone,
        email = EXCLUDED.email,
        status = EXCLUDED.status,
        scheduled_checkin_at = EXCLUDED.scheduled_checkin_at,
        scheduled_checkout_at = EXCLUDED.scheduled_checkout_at,
        adults_total = EXCLUDED.adults_total,
        children_total = EXCLUDED.children_total,
        rooms_total = EXCLUDED.rooms_total,
        updated_at = now()
    RETURNING id INTO v_booking_id;

    ----------------------------------------------------------------
    -- 4. Insert booking_rooms (Optimized & Deduped)
    ----------------------------------------------------------------
    -- Re-using source table pattern for clarity in DISTINCT ON logic, 
    -- as we must handle multiple rate plans/room types per booking group correctly.
    
    WITH resolved_rooms AS (
        SELECT
            ir.id AS row_id,
            v_booking_id AS booking_id,
            v_hotel_id AS hotel_id,
            COALESCE(
                (ir.row_data->>'room_type_id')::uuid,
                (SELECT id FROM public.room_types WHERE hotel_id = v_hotel_id AND (name = (ir.row_data->>'room_type') OR name = (ir.row_data->>'room_type_name') OR name = (ir.row_data->>'room_type_code') ) LIMIT 1)
            ) AS room_type_id,
             COALESCE(
                (ir.row_data->>'room_id')::uuid,
                 (SELECT id FROM public.rooms WHERE hotel_id = v_hotel_id AND number = (ir.row_data->>'room_number') LIMIT 1)
            ) AS room_id,
            -- CRITICAL FIX-1: Explicit table alias & dense_rank for uniqueness if missing
            COALESCE(ir.room_seq, (dense_rank() OVER (ORDER BY ir.room_seq NULLS LAST, ir.id))::int) AS effective_room_seq,
            
            COALESCE((ir.row_data->>'adults')::int, 1) AS adults,
            COALESCE((ir.row_data->>'children')::int, 0) AS children,
            ir.row_data->>'rate_plan' AS rate_plan_code,
            (ir.row_data->>'total_amount')::numeric AS amount_total
        FROM public.import_rows ir
        WHERE ir.booking_reference = p_booking_reference
    )
    INSERT INTO public.booking_rooms (
        booking_id,
        hotel_id,
        room_type_id,
        room_id,
        room_seq,
        adults,
        children,
        rate_plan_code,
        amount_total
    )
    SELECT DISTINCT ON (effective_room_seq)
        booking_id,
        hotel_id,
        room_type_id,
        room_id,
        effective_room_seq,
        adults,
        children,
        rate_plan_code,
        amount_total
    FROM resolved_rooms
    ORDER BY effective_room_seq, row_id -- stable sort for distinct
    ON CONFLICT (booking_id, room_seq)
    DO UPDATE SET
        adults = EXCLUDED.adults,
        children = EXCLUDED.children,
        amount_total = EXCLUDED.amount_total,
        updated_at = now();

    -- MANDATORY SYNC: Update rooms_total from actual room count
    UPDATE public.bookings
    SET rooms_total = (
        SELECT COUNT(*)
        FROM public.booking_rooms br
        WHERE br.booking_id = v_booking_id
    )
    WHERE id = v_booking_id;

    ----------------------------------------------------------------
    -- 5. Helper: Generate/Fetch precheckin token
    ----------------------------------------------------------------
    SELECT token
    INTO v_token
    FROM public.precheckin_tokens
    WHERE booking_id = v_booking_id
    AND used_at IS NULL
    ORDER BY created_at DESC
    LIMIT 1;

    IF v_token IS NULL THEN
        SELECT (public.create_precheckin_token(v_booking_id)->>'token') INTO v_token;
    END IF;

    ----------------------------------------------------------------
    -- 6. Notification Queue
    ----------------------------------------------------------------
    IF v_token IS NOT NULL THEN
        -- Fire EMAIL
        IF v_email IS NOT NULL AND v_email <> '' THEN
            INSERT INTO public.notification_queue (
                booking_id, channel, template_code, payload, status
            ) VALUES (
                v_booking_id, 'email', 'precheckin_link',
                jsonb_build_object(
                    'token', v_token,
                    'guest_name', v_guest_name,
                    'link', 'https://vaiyu.co.in/precheckin/' || v_token
                ),
                'pending'
            )
            ON CONFLICT (booking_id, template_code, channel) WHERE template_code = 'precheckin_link' DO NOTHING;
        END IF;

        -- Fire WHATSAPP
        IF v_phone IS NOT NULL AND v_phone <> '' THEN
            INSERT INTO public.notification_queue (
                booking_id, channel, template_code, payload, status
            ) VALUES (
                v_booking_id, 'whatsapp', 'precheckin_link',
                jsonb_build_object(
                    'token', v_token,
                    'guest_name', v_guest_name,
                    'link', 'https://vaiyu.co.in/precheckin/' || v_token
                ),
                'pending'
            )
            ON CONFLICT (booking_id, template_code, channel) WHERE template_code = 'precheckin_link' DO NOTHING;
        END IF;
    END IF;

    ----------------------------------------------------------------
    -- 7. Completeness Guard (Partial Import Safety)
    ----------------------------------------------------------------
    
    -- Validate room completeness
    IF (
        SELECT COUNT(DISTINCT COALESCE(ir.room_seq::text, ir.id::text))
        FROM public.import_rows ir
        WHERE ir.booking_reference = p_booking_reference
    ) <>
    (
        SELECT COUNT(DISTINCT COALESCE(br.room_seq::text, br.id::text))
        FROM public.booking_rooms br
        WHERE br.booking_id = v_booking_id
    )
    THEN
        RAISE EXCEPTION 'Room ingestion incomplete, retry required';
    END IF;

    ----------------------------------------------------------------
    -- 8. Mark rows imported
    ----------------------------------------------------------------
    UPDATE public.import_rows
    SET status = 'imported',
        processed_at = now()
    WHERE booking_reference = p_booking_reference;

    -- Mark Idempotency Complete
    UPDATE public.import_idempotency
    SET status='completed',
        processed_at = now()
    WHERE booking_reference = p_booking_reference;

    RETURN jsonb_build_object(
        'success', true,
        'booking_id', v_booking_id,
        'token', v_token
    );

EXCEPTION WHEN OTHERS THEN
    UPDATE public.import_rows
    SET status = 'error',
        error_message = SQLERRM,
        processed_at = now()
    WHERE booking_reference = p_booking_reference;
    
    RETURN jsonb_build_object(
        'success', false,
        'booking_reference', p_booking_reference,
        'error', SQLERRM
    );
END;
$$;


ALTER FUNCTION "public"."process_booking_group"("p_booking_reference" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_checkin"("p_booking_id" "uuid", "p_guest_details" "jsonb", "p_room_id" "uuid" DEFAULT NULL::"uuid", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_guest_id UUID;
  v_stay_id UUID;
  v_booking bookings%ROWTYPE;
BEGIN
  -- 1. Validate Booking (Concurrency Lock)
  -- Global Advisory Lock (Cluster Safety - Stable 64-bit hash)
  PERFORM pg_advisory_xact_lock(hashtextextended(p_booking_id::text, 0));

  SELECT * INTO v_booking
  FROM bookings
  WHERE id = p_booking_id
  FOR UPDATE;
  
  IF v_booking.id IS NULL THEN
    RAISE EXCEPTION 'Booking not found';
  END IF;

  IF v_booking.hotel_id IS NULL THEN
     RAISE EXCEPTION 'Booking missing hotel association';
  END IF;
  
  -- Idempotency: Check if stay already exists (Double-click protection)
  -- Cluster-safe check
  PERFORM 1
  FROM stays
  WHERE booking_id = p_booking_id
  AND status IN ('arriving', 'inhouse')
  FOR UPDATE;

  IF FOUND THEN
      -- Fetch ID safely
      SELECT id INTO v_stay_id FROM stays WHERE booking_id = p_booking_id AND status IN ('arriving', 'inhouse') LIMIT 1;
      RETURN jsonb_build_object('stay_id', v_stay_id, 'status', 'ALREADY_CHECKED_IN');
  END IF;
  
  IF v_booking.status NOT IN ('CREATED', 'CONFIRMED') THEN
    RAISE EXCEPTION 'Booking status % is not eligible for check-in', v_booking.status;
  END IF;

  IF v_booking.scheduled_checkout_at <= v_booking.scheduled_checkin_at THEN
     RAISE EXCEPTION 'Invalid booking time window';
  END IF;

  -- Room Validation & Lock (Critical)
  IF p_room_id IS NULL THEN
    RAISE EXCEPTION 'Room must be assigned before check-in';
  END IF;

  PERFORM 1 
  FROM rooms 
  WHERE id = p_room_id 
  AND hotel_id = v_booking.hotel_id 
  FOR UPDATE;
  
  IF NOT FOUND THEN
     RAISE EXCEPTION 'Room does not belong to the booking hotel';
  END IF;

  -- Overlap Guard (Defensive)
  PERFORM 1
  FROM stays
  WHERE room_id = p_room_id
  AND status IN ('arriving', 'inhouse')
  AND tstzrange(scheduled_checkin_at, scheduled_checkout_at, '[)')
      && tstzrange(v_booking.scheduled_checkin_at, v_booking.scheduled_checkout_at, '[)')
  FOR UPDATE;

  IF FOUND THEN
     RAISE EXCEPTION 'Room already occupied for the selected period';
  END IF;

  -- 2. Handle Guest (Smart Upsert)
  IF coalesce(trim(p_guest_details->>'full_name'),'') = '' THEN
     RAISE EXCEPTION 'Guest name required';
  END IF;

  -- Deduplicate by Mobile + Hotel if not provided
  IF v_booking.guest_id IS NOT NULL THEN
    v_guest_id := v_booking.guest_id;
  ELSE
    -- Try to find existing guest
    -- Normalize phone before lookup
    DECLARE
       v_input_phone TEXT := p_guest_details->>'mobile';
    BEGIN
       v_input_phone := regexp_replace(v_input_phone, '[^0-9]', '', 'g');
       
       SELECT id INTO v_guest_id
       FROM guests
       WHERE hotel_id = v_booking.hotel_id
       AND mobile = COALESCE(v_input_phone, v_booking.phone)
       LIMIT 1;
    
       IF v_guest_id IS NULL THEN
           INSERT INTO guests (hotel_id, full_name, mobile, email)
           VALUES (
               v_booking.hotel_id, 
               COALESCE(p_guest_details->>'full_name', v_booking.guest_name),
               COALESCE(v_input_phone, v_booking.phone),
               p_guest_details->>'email'
           )
           RETURNING id INTO v_guest_id;
       END IF;
    END;
    
    -- Link to booking
    UPDATE bookings SET guest_id = v_guest_id WHERE id = p_booking_id;
  END IF;

  -- 2b. Insert Guest Documents (Anti-spam)
  IF p_guest_details->>'front_image_path' IS NOT NULL THEN
    INSERT INTO guest_id_documents (guest_id, document_type, front_image_url, back_image_url, verification_status)
    SELECT
      v_guest_id,
      COALESCE((p_guest_details->>'id_type')::guest_document_type, 'other'),
      p_guest_details->>'front_image_path',
      p_guest_details->>'back_image_path',
      'pending'
    WHERE NOT EXISTS (
       SELECT 1
       FROM guest_id_documents
       WHERE guest_id = v_guest_id
       AND document_type = COALESCE((p_guest_details->>'id_type')::guest_document_type, 'other')
    );
  END IF;

  -- 3. Create Stay (Physical Occupancy)
  INSERT INTO stays (
    hotel_id,
    guest_id,
    room_id,
    booking_id,
    booking_code,
    status,
    scheduled_checkin_at,
    scheduled_checkout_at,
    actual_checkin_at,
    source
  ) VALUES (
    v_booking.hotel_id,
    v_guest_id,
    p_room_id,
    p_booking_id,
    v_booking.code,
    'inhouse', -- Immediately inhouse
    v_booking.scheduled_checkin_at,
    v_booking.scheduled_checkout_at,
    now(),
    'pms_sync'
  ) RETURNING id INTO v_stay_id;

  -- 4. Update Booking (Concurrency Safe)
  UPDATE bookings
  SET status = 'CHECKED_IN'
  WHERE id = p_booking_id
  AND status IN ('CREATED','CONFIRMED');

  IF NOT FOUND THEN
     RAISE EXCEPTION 'Booking state changed concurrently during check-in';
  END IF;

  -- 5. Log Event (Standardized)
  INSERT INTO checkin_events (stay_id, event_type, actor_id, meta)
  VALUES (
    v_stay_id, 
    'COMPLETED', 
    p_actor_id, 
    jsonb_build_object(
       'method', 'booking_checkin',
       'actor_id', p_actor_id,
       'device', 'kiosk',
       'hotel_id', v_booking.hotel_id,
       'room_id', p_room_id
    )
  );

  RETURN jsonb_build_object('stay_id', v_stay_id, 'status', 'SUCCESS');
END;
$$;


ALTER FUNCTION "public"."process_checkin"("p_booking_id" "uuid", "p_guest_details" "jsonb", "p_room_id" "uuid", "p_actor_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_checkin_v2"("p_booking_id" "uuid", "p_guest_details" "jsonb", "p_room_assignments" "jsonb", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_guest_id UUID;
  v_stay_id UUID;
  v_booking bookings%ROWTYPE;
  v_assignment JSONB;
  v_br_id UUID;
  v_booking_id UUID;
  v_room_id UUID;
  v_stay_ids UUID[] := '{}';
  v_rooms_count INT;
  v_rooms_checked INT := 0;
BEGIN
  -- ── 1. Validate Input ──
  IF p_room_assignments IS NULL OR jsonb_array_length(p_room_assignments) = 0 THEN
    RAISE EXCEPTION 'At least one room assignment is required';
  END IF;
  v_rooms_count := jsonb_array_length(p_room_assignments);

  -- ── 2. Lock & Validate Booking ──
  PERFORM pg_advisory_xact_lock(hashtextextended(p_booking_id::text, 0));

  SELECT * INTO v_booking
  FROM bookings
  WHERE id = p_booking_id
  FOR UPDATE;

  IF v_booking.id IS NULL THEN
    RAISE EXCEPTION 'Booking not found';
  END IF;

  IF v_booking.hotel_id IS NULL THEN
    RAISE EXCEPTION 'Booking missing hotel association';
  END IF;

  -- Use UPPERCASE for status checks
  IF v_booking.status NOT IN ('CREATED', 'CONFIRMED', 'PRE_CHECKED_IN', 'CHECKED_IN', 'PARTIALLY_CHECKED_IN') THEN
    RAISE EXCEPTION 'Booking status % is not eligible for check-in', v_booking.status;
  END IF;

  IF v_booking.scheduled_checkout_at <= v_booking.scheduled_checkin_at THEN
    RAISE EXCEPTION 'Invalid booking time window';
  END IF;

  -- ── 3. Handle Guest (Modular) ──
  IF coalesce(trim(p_guest_details->>'full_name'),'') = '' AND v_booking.guest_id IS NULL THEN
    RAISE EXCEPTION 'Guest name required for check-in';
  END IF;

  -- Use modular helper
  v_guest_id := public.upsert_guest_v2(p_guest_details);

  -- Link guest to booking if not already linked
  IF v_booking.guest_id IS NULL OR v_booking.guest_id != v_guest_id THEN
    UPDATE bookings SET guest_id = v_guest_id, updated_at = now() WHERE id = p_booking_id;
  END IF;

  -- ── 4. Pre-loop: Duplicate Guards ──
  IF (
    SELECT COUNT(DISTINCT (a->>'room_id'))
    FROM jsonb_array_elements(p_room_assignments) a
  ) != jsonb_array_length(p_room_assignments)
  THEN
    RAISE EXCEPTION 'Duplicate rooms assigned';
  END IF;

  IF (
    SELECT COUNT(DISTINCT (a->>'booking_room_id'))
    FROM jsonb_array_elements(p_room_assignments) a
  ) != jsonb_array_length(p_room_assignments)
  THEN
    RAISE EXCEPTION 'Duplicate booking_room_ids provided';
  END IF;

  -- ── 5. Process Each Room Assignment (Loop) ──
  FOR v_assignment IN SELECT * FROM jsonb_array_elements(p_room_assignments)
  LOOP
    v_br_id  := (v_assignment->>'booking_room_id')::UUID;
    v_room_id := (v_assignment->>'room_id')::UUID;

    -- 5a. Validate booking_room belongs to this booking
    PERFORM 1
    FROM booking_rooms
    WHERE id = v_br_id
    AND booking_id = p_booking_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'booking_room % does not belong to booking %', v_br_id, p_booking_id;
    END IF;

    -- 5a-ii. Room-level idempotency & Arriving Transition
    v_stay_id := NULL;
    
    -- Check for inhouse (already done)
    SELECT id INTO v_stay_id FROM stays 
    WHERE booking_room_id = v_br_id AND status = 'inhouse' LIMIT 1;

    IF v_stay_id IS NOT NULL THEN
      -- Already checked in
      v_stay_ids := array_append(v_stay_ids, v_stay_id);
      CONTINUE; 
    END IF;

    -- Check for arriving (transition needed)
    SELECT id INTO v_stay_id FROM stays 
    WHERE booking_room_id = v_br_id AND status = 'arriving'
    FOR UPDATE;

    IF v_stay_id IS NOT NULL THEN
      -- Critical: Validate room overlap before updating room_id (prevent race conditions)
      PERFORM 1
      FROM stays
      WHERE room_id = v_room_id
      AND (status = 'arriving' OR status = 'inhouse')
      AND booking_room_id <> v_br_id
      AND tstzrange(scheduled_checkin_at, scheduled_checkout_at, '[)')
          && tstzrange(v_booking.scheduled_checkin_at, v_booking.scheduled_checkout_at, '[)')
      FOR UPDATE;

      IF FOUND THEN
        RAISE EXCEPTION 'Room % already occupied for the selected period', v_room_id;
      END IF;

      -- Transition existing stay to inhouse
      UPDATE stays 
      SET status = 'inhouse', 
          actual_checkin_at = now(),
          room_id = v_room_id -- Ensure room matches assignment
      WHERE id = v_stay_id;
      
      -- Proceed to update booking_room below
    ELSE
      -- 5b. Validate room belongs to hotel (only if creating new or updating room)
      PERFORM 1
      FROM rooms
      WHERE id = v_room_id
      AND hotel_id = v_booking.hotel_id
      FOR UPDATE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'Room % does not belong to hotel', v_room_id;
      END IF;

      -- 5c. Overlap guard
      PERFORM 1
      FROM stays
      WHERE room_id = v_room_id
      AND (status = 'arriving' OR status = 'inhouse')
      AND tstzrange(scheduled_checkin_at, scheduled_checkout_at, '[)')
          && tstzrange(v_booking.scheduled_checkin_at, v_booking.scheduled_checkout_at, '[)')
      FOR UPDATE;

      IF FOUND THEN
        RAISE EXCEPTION 'Room % already occupied for the selected period', v_room_id;
      END IF;

      -- 5d. Create Stay (New)
      INSERT INTO stays (
        hotel_id, guest_id, room_id, booking_id, booking_room_id,
        booking_code, status, scheduled_checkin_at, scheduled_checkout_at,
        actual_checkin_at, source
      ) VALUES (
        v_booking.hotel_id, v_guest_id, v_room_id, p_booking_id, v_br_id,
        v_booking.code, 'inhouse', v_booking.scheduled_checkin_at,
        v_booking.scheduled_checkout_at, now(), 'arrival_checkin'
      ) RETURNING id INTO v_stay_id;
    END IF;

    v_stay_ids := array_append(v_stay_ids, v_stay_id);
    v_rooms_checked := v_rooms_checked + 1;

    -- 5e. Update booking_rooms (Source of Truth) - Use UPPERCASEstatus
    UPDATE booking_rooms
    SET room_id = v_room_id,
        status = 'CHECKED_IN',
        updated_at = now()
    WHERE id = v_br_id
    AND (
      room_id IS DISTINCT FROM v_room_id
      OR status IS DISTINCT FROM 'CHECKED_IN'
    );

    -- 5f. Log event per room
    INSERT INTO checkin_events (stay_id, event_type, actor_id, meta)
    VALUES (
      v_stay_id, 'COMPLETED', p_actor_id,
      jsonb_build_object(
        'method', 'multi_room_checkin',
        'actor_id', p_actor_id,
        'hotel_id', v_booking.hotel_id,
        'room_id', v_room_id,
        'booking_room_id', v_br_id
      )
    );
  END LOOP;

  -- ── 6. Update Booking Status ──
  IF EXISTS (
      SELECT 1
      FROM booking_rooms
      WHERE booking_id = p_booking_id
      AND status != 'CHECKED_IN'
  ) THEN
      UPDATE bookings
      SET status = 'PARTIALLY_CHECKED_IN',
          checked_in_at = COALESCE(checked_in_at, now()),
          updated_at = now()
      WHERE id = p_booking_id
      AND status != 'CHECKED_IN';
  ELSE
      UPDATE bookings
      SET status = 'CHECKED_IN',
          checked_in_at = COALESCE(checked_in_at, now()),
          updated_at = now()
      WHERE id = p_booking_id
      RETURNING id INTO v_booking_id;
  END IF;

  RETURN jsonb_build_object(
    'stay_ids', to_jsonb(v_stay_ids),
    'rooms_checked_in', v_rooms_checked,
    'rooms_total', v_rooms_count,
    'status', 'SUCCESS'
  );
END;
$$;


ALTER FUNCTION "public"."process_checkin_v2"("p_booking_id" "uuid", "p_guest_details" "jsonb", "p_room_assignments" "jsonb", "p_actor_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reassign_shift"("p_id" "uuid", "p_staff" "uuid", "p_start" timestamp with time zone, "p_end" timestamp with time zone, "p_zone" "uuid", "p_version" integer, "p_user" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
declare v record;
begin
  select * into v from public.staff_shifts where id = p_id for update;

  if not found then raise exception 'Shift not found'; end if;
  if v.version != p_version then raise exception 'Version mismatch'; end if;

  if v.locked_at is not null
     and v.locked_at > now() - interval '5 minutes'
     and v.locked_by is distinct from p_user then
    raise exception 'Locked';
  end if;

  if p_end <= p_start then raise exception 'Invalid time'; end if;

  update public.staff_shifts
  set staff_id = p_staff,
      shift_start = p_start,
      shift_end = p_end,
      zone_id = p_zone
  where id = p_id
    and status = 'scheduled'
    and is_active = true;

exception when exclusion_violation then
  raise exception 'Overlap';
end;
$$;


ALTER FUNCTION "public"."reassign_shift"("p_id" "uuid", "p_staff" "uuid", "p_start" timestamp with time zone, "p_end" timestamp with time zone, "p_zone" "uuid", "p_version" integer, "p_user" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reassign_task"("p_ticket_id" "uuid", "p_new_assignee_id" "uuid", "p_supervisor_id" "uuid", "p_comment" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_status TEXT;
  v_reason TEXT;
  v_old_assignee UUID;
  v_new_assignee_exists BOOLEAN;
  v_is_supervisor BOOLEAN;
BEGIN
  -- 1. Verify supervisor role
  SELECT EXISTS(
    SELECT 1
    FROM hotel_member_roles hmr
    JOIN hotel_roles hr ON hr.id = hmr.role_id
    WHERE hmr.hotel_member_id = p_supervisor_id
      AND hr.code IN ('SUPERVISOR', 'MANAGER')
  ) INTO v_is_supervisor;

  IF NOT v_is_supervisor THEN
    RAISE EXCEPTION 'Only supervisors can reassign tasks';
  END IF;

  -- 2. Lock ticket row and get current state (concurrency protection)
  SELECT 
    status, 
    reason_code, 
    current_assignee_id
  INTO 
    v_status, 
    v_reason, 
    v_old_assignee
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;  -- Lock row to prevent race conditions

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found: %', p_ticket_id;
  END IF;

  -- 3. HARD FAIL if not BLOCKED
  IF v_status != 'BLOCKED' THEN
    RAISE EXCEPTION 'Cannot reassign: ticket is not blocked (status: %)', v_status;
  END IF;

  -- 4. HARD FAIL if not supervisor approval (UPPERCASE)
  IF v_reason != 'SUPERVISOR_APPROVAL' THEN
    RAISE EXCEPTION 'Cannot reassign: ticket not waiting for supervisor approval (reason: %)', v_reason;
  END IF;

  -- 5. Verify new assignee exists and is active
  SELECT EXISTS(
    SELECT 1 FROM hotel_members
    WHERE id = p_new_assignee_id
      AND is_active = true
  ) INTO v_new_assignee_exists;

  IF NOT v_new_assignee_exists THEN
    RAISE EXCEPTION 'New assignee not found or inactive: %', p_new_assignee_id;
  END IF;

  -- 6. Prevent no-op reassignment (same assignee)
  IF p_new_assignee_id = v_old_assignee THEN
    RAISE EXCEPTION 'New assignee must be different from current assignee';
  END IF;

  -- 7. Update assignment and status (triggers will handle SLA)
  UPDATE tickets
  SET current_assignee_id = p_new_assignee_id,
      status = 'IN_PROGRESS',
      reason_code = NULL
  WHERE id = p_ticket_id;

  -- 8. Event 1: REASSIGNED (ownership change) with full context
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    previous_status,
    new_status,
    actor_type,
    actor_id,
    comment,
    created_at
  ) VALUES (
    p_ticket_id,
    'REASSIGNED',
    'BLOCKED',
    'IN_PROGRESS',
    'SUPERVISOR',
    p_supervisor_id,
    format('Reassigned from %s to %s. %s', 
      COALESCE(v_old_assignee::TEXT, 'unassigned'), 
      p_new_assignee_id::TEXT, 
      COALESCE(p_comment, '')),
    NOW()
  );

  -- 8. Event 2: UNBLOCKED (work resumed) with full context
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    reason_code,
    previous_status,
    new_status,
    actor_type,
    actor_id,
    created_at
  ) VALUES (
    p_ticket_id,
    'UNBLOCKED',
    'REASSIGNED_BY_SUPERVISOR',
    'BLOCKED',
    'IN_PROGRESS',
    'SUPERVISOR',
    p_supervisor_id,
    NOW()
  );

  -- NOTE: SLA resume happens automatically via trigger on status change
  -- We do NOT manually update ticket_sla_state

  -- Return success
  RETURN jsonb_build_object(
    'success', true,
    'ticket_id', p_ticket_id,
    'new_assignee_id', p_new_assignee_id,
    'old_assignee_id', v_old_assignee,
    'status', 'IN_PROGRESS'
  );
END;
$$;


ALTER FUNCTION "public"."reassign_task"("p_ticket_id" "uuid", "p_new_assignee_id" "uuid", "p_supervisor_id" "uuid", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reassign_ticket"("p_ticket_id" "uuid", "p_new_assigned_to" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  UPDATE tickets
  SET current_assignee_id = p_new_assigned_to
  WHERE id = p_ticket_id;

  INSERT INTO ticket_events (ticket_id, event_type)
  VALUES (p_ticket_id, 'REASSIGNED');
END;
$$;


