CREATE OR REPLACE FUNCTION "public"."reject_owner_application"("p_app_id" "uuid", "p_reviewer" "uuid", "p_reason" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
declare
  app record;
begin
  select * into app
  from public.owner_applications
  where id = p_app_id and status = 'pending';

  if not found then
    raise exception 'Application not found or not pending';
  end if;

  update public.owner_applications
  set status = 'rejected',
      reviewer_id = p_reviewer,
      reviewed_at = now(),
      review_notes = coalesce(p_reason, 'rejected')
  where id = p_app_id;
end;
$$;


ALTER FUNCTION "public"."reject_owner_application"("p_app_id" "uuid", "p_reviewer" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reject_sla_exception"("p_ticket_id" "uuid", "p_comment" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_ticket RECORD;
  v_supervisor_id UUID;
  v_latest_sla_request_at TIMESTAMPTZ;
BEGIN
  ---------------------------------------------------------------------------
  -- 1. Lock the ticket row (prevents concurrent decisions)
  ---------------------------------------------------------------------------
  SELECT *
  INTO v_ticket
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket % does not exist', p_ticket_id;
  END IF;

  ---------------------------------------------------------------------------
  -- 2. Reject terminal tickets
  ---------------------------------------------------------------------------
  IF v_ticket.status IN ('COMPLETED', 'CANCELLED') THEN
    RAISE EXCEPTION 'Cannot reject SLA exception on terminal ticket';
  END IF;

  ---------------------------------------------------------------------------
  -- 3. Supervisor validation (must be active supervisor for this hotel)
  ---------------------------------------------------------------------------
  SELECT hm.id
  INTO v_supervisor_id
  FROM hotel_members hm
  JOIN hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
  JOIN hotel_roles hr ON hr.id = hmr.role_id
  WHERE hm.user_id = auth.uid()
    AND hm.hotel_id = v_ticket.hotel_id
    AND hm.is_active = TRUE
    AND hr.code = 'SUPERVISOR'
    AND hr.is_active = TRUE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Unauthorized: not a supervisor for this hotel';
  END IF;

  ---------------------------------------------------------------------------
  -- 4. Validate: pending SLA_EXCEPTION_REQUESTED must exist
  ---------------------------------------------------------------------------
  SELECT te.created_at
  INTO v_latest_sla_request_at
  FROM ticket_events te
  WHERE te.ticket_id = p_ticket_id
    AND te.event_type = 'SLA_EXCEPTION_REQUESTED'
    AND NOT EXISTS (
      SELECT 1
      FROM ticket_events res
      WHERE res.ticket_id = p_ticket_id
        AND res.created_at > te.created_at
        AND res.event_type IN (
          'SLA_EXCEPTION_GRANTED',
          'SLA_EXCEPTION_REJECTED'
        )
    )
  ORDER BY te.created_at DESC
  LIMIT 1;

  IF v_latest_sla_request_at IS NULL THEN
    RAISE EXCEPTION 'No pending SLA exception request for ticket %', p_ticket_id;
  END IF;

  ---------------------------------------------------------------------------
  -- 5. Idempotency check (already decided = return success)
  ---------------------------------------------------------------------------
  IF EXISTS (
    SELECT 1
    FROM ticket_events te_decision
    WHERE te_decision.ticket_id = p_ticket_id
      AND te_decision.event_type IN (
        'SLA_EXCEPTION_GRANTED',
        'SLA_EXCEPTION_REJECTED'
      )
      AND te_decision.created_at > v_latest_sla_request_at
  ) THEN
    RETURN jsonb_build_object(
      'success', TRUE,
      'ticket_id', p_ticket_id,
      'sla_exception', 'REJECTED',
      'message', 'SLA exception decision already recorded',
      'idempotent', TRUE
    );
  END IF;

  ---------------------------------------------------------------------------
  -- 6. Comment is mandatory for audit trail
  ---------------------------------------------------------------------------
  IF p_comment IS NULL OR TRIM(p_comment) = '' THEN
    RAISE EXCEPTION 'Rejection comment is required';
  END IF;

  ---------------------------------------------------------------------------
  -- 7. Emit SLA_EXCEPTION_REJECTED event
  ---------------------------------------------------------------------------
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    reason_code,
    actor_type,
    actor_id,
    comment,
    created_at
  ) VALUES (
    p_ticket_id,
    'SLA_EXCEPTION_REJECTED',
    'sla_exception',
    'STAFF',
    v_supervisor_id,
    TRIM(p_comment),
    NOW()
  );

  ---------------------------------------------------------------------------
  -- 8. NO ticket status change
  --    SLA continues normally
  ---------------------------------------------------------------------------

  RETURN jsonb_build_object(
    'success', TRUE,
    'ticket_id', p_ticket_id,
    'sla_exception', 'REJECTED',
    'message', 'SLA exception rejected. SLA continues normally.',
    'idempotent', FALSE
  );
END;
$$;


ALTER FUNCTION "public"."reject_sla_exception"("p_ticket_id" "uuid", "p_comment" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."reject_sla_exception"("p_ticket_id" "uuid", "p_comment" "text") IS 'Supervisor rejects a pending SLA exception request.
- Validates pending SLA_EXCEPTION_REQUESTED exists
- Idempotent-safe: duplicate calls return success
- Emits SLA_EXCEPTION_REJECTED event with reason_code=sla_exception
- SLA continues normally, no exemption granted';



CREATE OR REPLACE FUNCTION "public"."reject_supervisor_approval"("p_ticket_id" "uuid", "p_comment" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_ticket_status TEXT;
  v_ticket_hotel_id UUID;
  v_supervisor_id UUID;
  v_latest_block_created_at TIMESTAMPTZ;
  v_latest_block_reason_code TEXT;
BEGIN
  ---------------------------------------------------------------------------
  -- 1. Lock the ticket row (prevents concurrent decisions)
  ---------------------------------------------------------------------------
  SELECT status, hotel_id
  INTO v_ticket_status, v_ticket_hotel_id
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket % does not exist', p_ticket_id;
  END IF;

  ---------------------------------------------------------------------------
  -- 2. Ticket must be BLOCKED
  ---------------------------------------------------------------------------
  IF v_ticket_status <> 'BLOCKED' THEN
    RAISE EXCEPTION
      'Cannot reject supervisor approval: ticket % is not BLOCKED (status=%)',
      p_ticket_id, v_ticket_status;
  END IF;

  ---------------------------------------------------------------------------
  -- 3. Supervisor validation (must be active supervisor for this hotel)
  ---------------------------------------------------------------------------
  SELECT hm.id
  INTO v_supervisor_id
  FROM hotel_members hm
  JOIN hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
  JOIN hotel_roles hr ON hr.id = hmr.role_id
  WHERE hm.user_id = auth.uid()
    AND hm.hotel_id = v_ticket_hotel_id
    AND hm.is_active = TRUE
    AND hr.code = 'SUPERVISOR'
    AND hr.is_active = TRUE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Unauthorized: not a supervisor for this hotel';
  END IF;

  ---------------------------------------------------------------------------
  -- 4. Get the latest BLOCKED event (source of truth - NOT snapshot column)
  --    Events never lie, snapshots may drift.
  ---------------------------------------------------------------------------
  SELECT te.created_at, te.reason_code
  INTO v_latest_block_created_at, v_latest_block_reason_code
  FROM ticket_events te
  WHERE te.ticket_id = p_ticket_id
    AND te.event_type = 'BLOCKED'
  ORDER BY te.created_at DESC
  LIMIT 1;

  ---------------------------------------------------------------------------
  -- 5. Validate: latest BLOCKED event must have reason_code = 'supervisor_approval'
  --    This is the authoritative check - derived from events, not snapshots.
  ---------------------------------------------------------------------------
  IF v_latest_block_reason_code IS DISTINCT FROM 'supervisor_approval' THEN
    RAISE EXCEPTION
      'Cannot reject supervisor approval: latest BLOCKED event has reason_code=%, not supervisor_approval',
      v_latest_block_reason_code;
  END IF;

  ---------------------------------------------------------------------------
  -- 6. Idempotent-safe: If decision already exists, return success (no duplicate insert)
  --    This makes UI retries safe, network retries harmless, logs cleaner.
  ---------------------------------------------------------------------------
  IF EXISTS (
    SELECT 1
    FROM ticket_events te_decision
    WHERE te_decision.ticket_id = p_ticket_id
      AND te_decision.event_type IN (
        'SUPERVISOR_APPROVED',
        'SUPERVISOR_REJECTED'
      )
      AND te_decision.created_at > COALESCE(v_latest_block_created_at, '1970-01-01'::timestamptz)
  ) THEN
    -- Already decided - return success for idempotency
    RETURN jsonb_build_object(
      'success', TRUE,
      'ticket_id', p_ticket_id,
      'decision', 'REJECTED',
      'message', 'Supervisor decision already recorded',
      'idempotent', TRUE
    );
  END IF;

  ---------------------------------------------------------------------------
  -- 7. Emit SUPERVISOR_REJECTED event (decision-only, immutable)
  ---------------------------------------------------------------------------
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    reason_code,
    comment,
    actor_type,
    actor_id,
    created_at
  ) VALUES (
    p_ticket_id,
    'SUPERVISOR_REJECTED',
    'supervisor_approval',
    COALESCE(NULLIF(TRIM(p_comment), ''), 'Supervisor rejected approval'),
    'STAFF',  -- Supervisors are staff members; actor_type constraint only allows STAFF/SYSTEM/GUEST/FRONT_DESK
    v_supervisor_id,
    NOW()
  );

  ---------------------------------------------------------------------------
  -- 8. NO ticket status change
  --    NO SLA math
  --    NO block reason mutation
  --    Ticket stays BLOCKED - staff must decide next steps
  ---------------------------------------------------------------------------

  RETURN jsonb_build_object(
    'success', TRUE,
    'ticket_id', p_ticket_id,
    'decision', 'REJECTED',
    'message', 'Supervisor approval rejected. Ticket remains blocked. Staff must take next action.',
    'idempotent', FALSE
  );
END;
$$;


ALTER FUNCTION "public"."reject_supervisor_approval"("p_ticket_id" "uuid", "p_comment" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."reject_supervisor_approval"("p_ticket_id" "uuid", "p_comment" "text") IS 'Supervisor rejects a BLOCKED + supervisor_approval request.
- Validates using EVENTS (source of truth), not snapshot columns
- Idempotent-safe: duplicate calls return success without re-inserting
- Does NOT unblock the ticket. Staff must decide next steps.
- Emits SUPERVISOR_REJECTED event for audit trail.';



