CREATE OR REPLACE FUNCTION "public"."reopen_ticket"("p_ticket_id" "uuid", "p_stay_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
 v_status TEXT;
 v_ticket_stay_id UUID;
 v_reopen_count INT;
BEGIN
 SELECT status, stay_id INTO v_status, v_ticket_stay_id FROM public.tickets WHERE id = p_ticket_id FOR UPDATE;

 IF NOT FOUND THEN RAISE EXCEPTION 'Ticket not found: %', p_ticket_id; END IF;

 -- Replaced auth.uid() check with lookup
 IF NOT EXISTS (
 SELECT 1 FROM public.stays
 WHERE id = p_stay_id AND (
 guest_id = public.current_guest_id()
 OR EXISTS (SELECT 1 FROM public.stay_guests sg WHERE sg.stay_id = p_stay_id AND sg.guest_id = public.current_guest_id())
 )
 ) THEN
 RAISE EXCEPTION 'Unauthorized reopen attempt';
 END IF;

 IF v_ticket_stay_id != p_stay_id THEN RAISE EXCEPTION 'Ticket does not belong to this stay'; END IF;
 IF v_status != 'COMPLETED' THEN RAISE EXCEPTION 'Only COMPLETED tickets can be reopened. Current status: %', v_status; END IF;

 UPDATE public.tickets SET status = 'NEW', updated_at = now() WHERE id = p_ticket_id;

 INSERT INTO public.ticket_events (ticket_id, event_type, actor_type, actor_id, comment)
 VALUES (
 p_ticket_id, 'STATUS_CHANGED', 'GUEST', 
 public.current_guest_id(), 
 COALESCE(p_reason, 'Guest requested reopen')
 );

 SELECT count(*) INTO v_reopen_count FROM public.ticket_events WHERE ticket_id = p_ticket_id AND event_type = 'STATUS_CHANGED' AND comment LIKE '%reopen%';

 INSERT INTO public.internal_jobs (job_type, payload)
 VALUES ('routing.ticket_assigned', jsonb_build_object('ticket_id', p_ticket_id, 'is_reopen', true, 'reopen_count', v_reopen_count));

 UPDATE public.ticket_sla_state SET sla_started_at = NULL, sla_target_at = NULL, breached = false WHERE ticket_id = p_ticket_id;

 RETURN jsonb_build_object('success', true, 'new_status', 'NEW', 'reopen_count', v_reopen_count);
END;
$$;


ALTER FUNCTION "public"."reopen_ticket"("p_ticket_id" "uuid", "p_stay_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."request_checkout"("p_booking_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_stay_id UUID;
    v_hotel_id UUID;
    v_pending_amount NUMERIC;
    v_now TIMESTAMPTZ := now();
BEGIN
    -- 1A: Lock Booking
    PERFORM 1 FROM bookings WHERE id = p_booking_id FOR UPDATE;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Booking not found');
    END IF;

    -- 1B: Lock Active Stay
    SELECT id, hotel_id INTO v_stay_id, v_hotel_id
    FROM stays
    WHERE booking_id = p_booking_id
      AND status = 'inhouse'
    FOR UPDATE;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'No active inhouse stay found. Checkout may already be requested or completed.');
    END IF;

    -- 1C: Lock Folio explicitly OR Create Just-In-Time
    PERFORM 1 FROM folios WHERE booking_id = p_booking_id FOR UPDATE;
    IF NOT FOUND THEN
        INSERT INTO folios (booking_id, hotel_id, status)
        VALUES (p_booking_id, v_hotel_id, 'OPEN')
        ON CONFLICT (booking_id) DO NOTHING;
        
        -- Lock newly created folio
        PERFORM 1 FROM folios WHERE booking_id = p_booking_id FOR UPDATE;
    END IF;

    -- 2A: No Open Tickets
    IF EXISTS (
        SELECT 1 FROM tickets
        WHERE stay_id = v_stay_id
        AND status NOT IN ('COMPLETED', 'CANCELLED')
    ) THEN
        RETURN jsonb_build_object('success', false, 'error', 'You have open service requests. Please let the front desk close them before checkout.');
    END IF;

    -- 2B: No Pending Food Orders
    IF EXISTS (
        SELECT 1 FROM food_orders
        WHERE stay_id = v_stay_id
        AND status NOT IN ('DELIVERED', 'CANCELLED', 'REJECTED')
    ) THEN
        RETURN jsonb_build_object('success', false, 'error', 'You have an active or pending food order. Please wait for delivery before checkout.');
    END IF;

    -- 3: Financial Validation
    SELECT COALESCE(SUM(amount), 0)
    INTO v_pending_amount
    FROM folio_entries
    WHERE folio_id IN (
        SELECT id FROM folios WHERE booking_id = p_booking_id
    );

    IF v_pending_amount > 0 THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Please settle your outstanding balance before requesting checkout.',
            'pending_amount', v_pending_amount
        );
    END IF;

    -- 4: Set Status to Requested
    UPDATE stays
    SET status = 'checkout_requested',
        updated_at = v_now
    WHERE id = v_stay_id;

    -- 5: Log Event
    INSERT INTO arrival_events (
        hotel_id, booking_id, event_type, details, performed_by
    )
    VALUES (
        v_hotel_id, p_booking_id, 'CHECKOUT_REQUESTED',
        jsonb_build_object('stay_id', v_stay_id, 'balance_at_request', v_pending_amount),
        COALESCE(auth.uid(), NULL)
    );

    RETURN jsonb_build_object('success', true, 'message', 'Checkout requested successfully.');
END;
$$;


ALTER FUNCTION "public"."request_checkout"("p_booking_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."request_shift_override"("p_shift_id" "uuid", "p_user" "uuid", "p_reason" "text") RETURNS "uuid"
