CREATE OR REPLACE FUNCTION "public"."request_sla_exception"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_ticket RECORD;
  v_staff_id UUID;
BEGIN
  -- Lock ticket to avoid duplicate requests
  SELECT *
  INTO v_ticket
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found';
  END IF;

  -- 1. Validate Ticket State
  -- Reject terminal tickets
  IF v_ticket.status IN ('COMPLETED', 'CANCELLED') THEN
    RAISE EXCEPTION 'Cannot request SLA exception on terminal ticket';
  END IF;

  -- Only allowed when work is active
  IF v_ticket.status NOT IN ('IN_PROGRESS', 'BLOCKED') THEN
    RAISE EXCEPTION
      'SLA exception can only be requested when ticket is IN_PROGRESS or BLOCKED';
  END IF;

  -- 2. Validate Staff
  SELECT id
  INTO v_staff_id
  FROM hotel_members
  WHERE user_id = auth.uid()
    AND hotel_id = v_ticket.hotel_id
    AND is_active = TRUE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Unauthorized staff';
  END IF;

  -- 3. Validate Reason Code
  IF NOT EXISTS (
    SELECT 1
    FROM sla_exception_reasons
    WHERE code = p_reason_code
      AND is_active = TRUE
      AND allowed_for_staff = TRUE
  ) THEN
    RAISE EXCEPTION 'Invalid SLA exception reason';
  END IF;

  -- 4. Prevent Duplicate Requests
  IF EXISTS (
    SELECT 1
    FROM ticket_events te
    WHERE te.ticket_id = p_ticket_id
      AND te.event_type = 'SLA_EXCEPTION_REQUESTED'
      AND NOT EXISTS (
        SELECT 1
        FROM ticket_events te2
        WHERE te2.ticket_id = p_ticket_id
          AND te2.event_type IN (
            'SLA_EXCEPTION_GRANTED',
            'SLA_EXCEPTION_REJECTED'
          )
          AND te2.created_at > te.created_at
      )
  ) THEN
    RAISE EXCEPTION 'SLA exception already requested and pending';
  END IF;

  -- 5. Validate Comment (Dynamic based on reason)
  IF EXISTS (
    SELECT 1
    FROM sla_exception_reasons
    WHERE code = p_reason_code
      AND requires_comment = TRUE
  )
  AND (p_comment IS NULL OR TRIM(p_comment) = '') THEN
    RAISE EXCEPTION 'Comment required for this SLA exception reason';
  END IF;

  -- 6. Insert Event
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    actor_type,
    actor_id,
    comment,
    reason_code,
    created_at
  ) VALUES (
    p_ticket_id,
    'SLA_EXCEPTION_REQUESTED',
    'STAFF',
    v_staff_id,
    TRIM(p_comment),
    p_reason_code,
    NOW()
  );

  RETURN jsonb_build_object(
    'success', TRUE,
    'ticket_id', p_ticket_id
  );
END;
$$;


ALTER FUNCTION "public"."request_sla_exception"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."request_supervisor"("p_ticket_id" "uuid", "p_comment" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_current_status TEXT;
  v_staff_id UUID;
  v_result JSONB;
BEGIN
  -- 1. Check ticket existence and lock it
  SELECT status INTO v_current_status
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found';
  END IF;

  -- 2. Resolve Staff Identity correctly
  -- Look up the hotel_member ID associated with the auth user AND the ticket's hotel
  SELECT hm.id INTO v_staff_id
  FROM hotel_members hm
  JOIN tickets t ON t.hotel_id = hm.hotel_id
  WHERE t.id = p_ticket_id
  AND hm.user_id = auth.uid()
  AND hm.is_active = true;

  IF v_staff_id IS NULL THEN
    RAISE EXCEPTION 'Not authorized: User is not an active member of this hotel';
  END IF;

  -- 3. Update Ticket
  UPDATE tickets
  SET
    status = 'BLOCKED',
    reason_code = 'supervisor_approval',
    updated_at = now()
  WHERE id = p_ticket_id;

  -- 4. Audit Log
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    previous_status,
    new_status,
    reason_code,
    actor_type,
    actor_id,
    comment
  ) VALUES (
    p_ticket_id,
    'SUPERVISOR_REQUESTED',
    v_current_status,
    'BLOCKED',
    'supervisor_approval',
    'STAFF',
    v_staff_id,
    COALESCE(p_comment, 'Supervisor intervention requested')
  );

  v_result := jsonb_build_object(
    'success', true,
    'message', 'Supervisor requested successfully'
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."request_supervisor"("p_ticket_id" "uuid", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resend_hotel_invite"("p_invite_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_invite RECORD;
    v_max_resend integer := 5;
BEGIN
    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    -- Lock invite row
    SELECT *
    INTO v_invite
    FROM public.hotel_invites
    WHERE id = p_invite_id
    FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Invite not found';
    END IF;

    -- 🔒 Ensure caller is platform admin or OWNER/ADMIN/MANAGER
    IF NOT public.is_platform_admin() AND NOT EXISTS (
        SELECT 1
        FROM public.hotel_members hm
        JOIN public.hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
        JOIN public.hotel_roles hr ON hr.id = hmr.role_id
        WHERE hm.hotel_id = v_invite.hotel_id
        AND hm.user_id = auth.uid()
        AND hr.code IN ('OWNER','ADMIN','MANAGER')
        AND hm.is_active = true
        AND hr.is_active = true
    ) THEN
        RAISE EXCEPTION 'Insufficient permissions for this hotel';
    END IF;

    -- State validation
    IF v_invite.status = 'accepted' THEN
        RAISE EXCEPTION 'Cannot resend accepted invite';
    END IF;

    IF v_invite.status = 'revoked' THEN
        RAISE EXCEPTION 'Cannot resend revoked invite';
    END IF;

    -- Resend limit
    IF v_invite.resend_count >= v_max_resend THEN
        RAISE EXCEPTION 'Resend limit exceeded';
    END IF;

    -- Optional cooldown (enterprise safety)
    IF v_invite.last_sent_at IS NOT NULL
       AND v_invite.last_sent_at > now() - interval '30 seconds'
    THEN
        RAISE EXCEPTION 'Invite recently sent. Please wait.';
    END IF;

    -- If expired, reactivate and extend expiry
    IF v_invite.status = 'expired' OR v_invite.expires_at < now() THEN
        UPDATE public.hotel_invites
        SET status = 'pending',
            expires_at = now() + interval '7 days'
        WHERE id = v_invite.id;
    END IF;

    -- Increment resend tracking
    UPDATE public.hotel_invites
    SET resend_count = resend_count + 1,
        last_sent_at = now()
    WHERE id = v_invite.id;

    -- Re-fetch latest values
    SELECT *
    INTO v_invite
    FROM public.hotel_invites
    WHERE id = p_invite_id;

    -- Enterprise Audit Log
    INSERT INTO public.hotel_audit_logs (
        hotel_id,
        user_id,
        action,
        entity_type,
        entity_id,
        changes
    )
    VALUES (
        v_invite.hotel_id,
        auth.uid(),
        'INVITE_RESENT',
        'hotel_invites',
        v_invite.id,
        jsonb_build_object(
            'email', v_invite.email,
            'resend_count', v_invite.resend_count
        )
    );

    -- Queue the email notification (Resend)
    INSERT INTO public.notification_queue (
        channel,
        template_code,
        payload
    )
    VALUES (
        'email',
        'staff_invite',
        jsonb_build_object(
            'email', v_invite.email,
            'invite_token', v_invite.token,
            'hotel_id', v_invite.hotel_id,
            'role_id', v_invite.role_id
        )
    );

    RETURN jsonb_build_object(
        'success', true,
        'invite_id', v_invite.id,
        'resend_count', v_invite.resend_count,
        'expires_at', v_invite.expires_at
    );
END;
$$;


ALTER FUNCTION "public"."resend_hotel_invite"("p_invite_id" "uuid") OWNER TO "postgres";


