CREATE OR REPLACE FUNCTION "public"."resolve_guest_identity"("p_hotel_id" "uuid", "p_name" "text", "p_mobile" "text", "p_email" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
 v_guest_id uuid;
 v_mobile text;
 v_email text;
 v_auth_user_id uuid;
BEGIN
 v_mobile := NULLIF(regexp_replace(trim(p_mobile), '[^0-9]', '', 'g'), '');
 v_email := NULLIF(lower(trim(p_email)), '');

 IF length(v_mobile) < 6 THEN v_mobile := NULL; END IF;

 -- 1. Try match by mobile
 IF v_mobile IS NOT NULL THEN
 SELECT id INTO v_guest_id FROM public.guests WHERE mobile_normalized = v_mobile LIMIT 1;
 IF v_guest_id IS NOT NULL THEN RETURN v_guest_id; END IF;
 END IF;

 -- 2. Try match by email
 IF v_email IS NOT NULL THEN
 SELECT id INTO v_guest_id FROM public.guests WHERE email_normalized = v_email LIMIT 1;
 IF v_guest_id IS NOT NULL THEN RETURN v_guest_id; END IF;
 END IF;

 -- 3. Create new guest (with race-condition safety via EXCEPTION instead of ON CONFLICT)
 BEGIN
 INSERT INTO public.guests(full_name, mobile, email, created_at, updated_at)
 VALUES(COALESCE(p_name,'Guest'), p_mobile, v_email, now(), now())
 RETURNING id INTO v_guest_id;
 EXCEPTION WHEN unique_violation THEN
   -- Race condition: another transaction inserted first, just look up again
   IF v_mobile IS NOT NULL THEN
     SELECT id INTO v_guest_id FROM public.guests WHERE mobile_normalized = v_mobile LIMIT 1;
   END IF;
   IF v_guest_id IS NULL AND v_email IS NOT NULL THEN
     SELECT id INTO v_guest_id FROM public.guests WHERE email_normalized = v_email LIMIT 1;
   END IF;
 END;

 -- 4. Bidirectional mapping
 IF v_guest_id IS NOT NULL THEN
 IF v_email IS NOT NULL THEN
 SELECT id INTO v_auth_user_id FROM auth.users WHERE lower(email) = v_email LIMIT 1;
 END IF;

 IF v_auth_user_id IS NULL AND v_mobile IS NOT NULL THEN
 SELECT id INTO v_auth_user_id FROM auth.users WHERE regexp_replace(COALESCE(phone, ''), '[^0-9]', '', 'g') = v_mobile LIMIT 1;
 END IF;

 IF v_auth_user_id IS NOT NULL THEN
 PERFORM 1 FROM public.guest_user_map WHERE user_id = v_auth_user_id FOR UPDATE;
 INSERT INTO public.guest_user_map (user_id, guest_id)
 VALUES (v_auth_user_id, v_guest_id)
 ON CONFLICT (user_id) DO NOTHING;
 END IF;
 END IF;

 RETURN v_guest_id;
END;
$$;


ALTER FUNCTION "public"."resolve_guest_identity"("p_hotel_id" "uuid", "p_name" "text", "p_mobile" "text", "p_email" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_shift_override"("p_id" "uuid", "p_action" "text", "p_user" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
declare v_shift uuid;
begin
  if p_action not in ('approved','rejected') then
    raise exception 'Invalid action';
  end if;

  select shift_id into v_shift
  from shift_override_requests
  where id = p_id and status='pending';

  if not found then raise exception 'Invalid request'; end if;

  update shift_override_requests
  set status=p_action, resolved_at=now(), resolved_by=p_user
  where id = p_id;

  if p_action='approved' then
    update staff_shifts set locked_at=null, locked_by=null where id=v_shift;
  end if;
end;
$$;


ALTER FUNCTION "public"."resolve_shift_override"("p_id" "uuid", "p_action" "text", "p_user" "uuid") OWNER TO "postgres";


