CREATE OR REPLACE FUNCTION "public"."resolve_ticket"("p_ticket_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  UPDATE tickets
  SET status = 'COMPLETED',
      completed_at = now()
  WHERE id = p_ticket_id;

  INSERT INTO ticket_events (ticket_id, event_type, new_status)
  VALUES (p_ticket_id, 'COMPLETED', 'COMPLETED');
END;
$$;


ALTER FUNCTION "public"."resolve_ticket"("p_ticket_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resume_ticket"("p_ticket_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  UPDATE tickets SET status = 'IN_PROGRESS' WHERE id = p_ticket_id;

  UPDATE ticket_sla_state
  SET
    total_paused_seconds =
      total_paused_seconds +
      EXTRACT(EPOCH FROM (now() - sla_paused_at))::int,
    sla_paused_at = NULL
  WHERE ticket_id = p_ticket_id;

  INSERT INTO ticket_events (ticket_id, event_type, new_status)
  VALUES (p_ticket_id, 'UNBLOCKED', 'IN_PROGRESS');
END;
$$;


ALTER FUNCTION "public"."resume_ticket"("p_ticket_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."revoke_hotel_invite"("p_invite_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_invite RECORD;
BEGIN
    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    -- Lock invite row
    SELECT *
    INTO v_invite
    FROM public.hotel_invites
    WHERE id = p_invite_id
    FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Invite not found';
    END IF;

    -- 🔒 Ensure caller is platform admin or OWNER/ADMIN/MANAGER
    IF NOT public.is_platform_admin() AND NOT EXISTS (
        SELECT 1
        FROM public.hotel_members hm
        JOIN public.hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
        JOIN public.hotel_roles hr ON hr.id = hmr.role_id
        WHERE hm.hotel_id = v_invite.hotel_id
        AND hm.user_id = auth.uid()
        AND hr.code IN ('OWNER','ADMIN','MANAGER')
        AND hm.is_active = true
        AND hr.is_active = true
    ) THEN
        RAISE EXCEPTION 'Insufficient permissions for this hotel';
    END IF;

    -- Idempotent behavior
    IF v_invite.status = 'revoked' THEN
        RETURN jsonb_build_object(
            'success', true,
            'invite_id', v_invite.id,
            'status', 'revoked',
            'message', 'Invite already revoked'
        );
    END IF;

    -- Cannot revoke accepted invite
    IF v_invite.status = 'accepted' THEN
        RAISE EXCEPTION 'Cannot revoke an accepted invite';
    END IF;

    UPDATE public.hotel_invites
    SET status = 'revoked'
    WHERE id = v_invite.id
    AND status IN ('pending','expired');

    -- Enterprise Audit Log
    INSERT INTO public.hotel_audit_logs (
        hotel_id,
        user_id,
        action,
        entity_type,
        entity_id,
        changes
    )
    VALUES (
        v_invite.hotel_id,
        auth.uid(),
        'INVITE_REVOKED',
        'hotel_invites',
        v_invite.id,
        jsonb_build_object(
            'email', v_invite.email
        )
    );

    RETURN jsonb_build_object(
        'success', true,
        'invite_id', v_invite.id,
        'status', 'revoked'
    );
END;
$$;


ALTER FUNCTION "public"."revoke_hotel_invite"("p_invite_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."search_booking"("p_query" "text", "p_hotel_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 10) RETURNS TABLE("booking_id" "uuid", "booking_code" "text", "status" "text", "guest_name" "text", "phone" "text", "email" "text", "scheduled_checkin_at" timestamp with time zone, "scheduled_checkout_at" timestamp with time zone, "room_type" "text", "adults" integer, "children" integer, "source" "text", "hotel_id" "uuid", "nationality" "text", "address" "text", "room_type_id" "uuid", "room_id" "uuid", "guest_id" "uuid", "identity_proof" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  p_query := trim(p_query);
  IF length(p_query) < 2 THEN
     RAISE EXCEPTION 'Search query too short';
  END IF;

  p_limit := LEAST(GREATEST(p_limit,1),50);

  RETURN QUERY
  SELECT DISTINCT ON (b.id)
    b.id::UUID,
    b.code::TEXT,
    b.status::TEXT,
    b.guest_name::TEXT,
    b.phone::TEXT,
    COALESCE(p.email, b.email)::TEXT,
    b.scheduled_checkin_at::TIMESTAMPTZ,
    b.scheduled_checkout_at::TIMESTAMPTZ,
    rt.name::TEXT,
    COALESCE(b.adults_total, 1)::INT,
    COALESCE(b.children_total, 0)::INT,
    b.source::TEXT,
    b.hotel_id::UUID,
    g.nationality::TEXT,
    g.address::TEXT,
    br.room_type_id::UUID,
    br.room_id::UUID,
    b.guest_id::UUID,
    (SELECT jsonb_build_object(
        'type', gid.document_type,
        'number', gid.document_number_masked,
        'front_image', gid.front_image_url,
        'back_image', gid.back_image_url
     )
     FROM guest_id_documents gid
     WHERE gid.guest_id = b.guest_id
     AND gid.is_active = true
     ORDER BY gid.created_at DESC LIMIT 1
    )::JSONB
  FROM bookings b
  LEFT JOIN profiles p ON b.guest_profile_id = p.id
  LEFT JOIN booking_rooms br ON br.booking_id = b.id
  LEFT JOIN room_types rt ON rt.id = br.room_type_id
  LEFT JOIN guests g ON g.id = b.guest_id
  WHERE (p_hotel_id IS NULL OR b.hotel_id = p_hotel_id)
    AND (
        b.code ILIKE '%' || p_query || '%'
        OR b.phone ILIKE '%' || p_query || '%'
        OR p.email ILIKE '%' || p_query || '%'
        OR b.email ILIKE '%' || p_query || '%'
    )
    AND b.status IN ('CREATED','CONFIRMED','PRE_CHECKED_IN')
  ORDER BY b.id, br.room_seq NULLS LAST, b.scheduled_checkin_at
  LIMIT p_limit;
END;
$$;


ALTER FUNCTION "public"."search_booking"("p_query" "text", "p_hotel_id" "uuid", "p_limit" integer) OWNER TO "postgres";


