CREATE OR REPLACE FUNCTION "public"."split_shift"("p_id" "uuid", "p_split" timestamp with time zone, "p_version" integer, "p_user" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
declare v record; v_new uuid;
begin
  select * into v from public.staff_shifts where id = p_id for update;

  if not found then raise exception 'Shift not found'; end if;
  if v.version != p_version then raise exception 'Version mismatch'; end if;

  if v.locked_at is not null
     and v.locked_at > now() - interval '5 minutes'
     and v.locked_by is distinct from p_user then
    raise exception 'Locked';
  end if;

  if p_split <= v.shift_start or p_split >= v.shift_end then
    raise exception 'Invalid split';
  end if;

  insert into public.staff_shifts (
    staff_id, shift_start, shift_end,
    shift_type, zone_id, status, is_active, created_by
  )
  values (
    v.staff_id, p_split, v.shift_end,
    v.shift_type, v.zone_id, v.status, true, v.created_by
  )
  returning id into v_new;

  update public.staff_shifts
  set shift_end = p_split
  where id = p_id;

  return jsonb_build_object('original', p_id, 'new', v_new);
end;
$$;


ALTER FUNCTION "public"."split_shift"("p_id" "uuid", "p_split" timestamp with time zone, "p_version" integer, "p_user" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."staff_shifts_before_write"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  is_business_data_changed boolean;
  is_lock_changing boolean;
begin
  if TG_OP = 'INSERT' then
    new.version = coalesce(new.version, 1);
  end if;

  if TG_OP = 'UPDATE' then
    is_business_data_changed := (
      new.shift_start is distinct from old.shift_start or
      new.shift_end   is distinct from old.shift_end   or
      new.zone_id     is distinct from old.zone_id     or
      new.shift_type  is distinct from old.shift_type  or
      new.status      is distinct from old.status      or
      new.is_active   is distinct from old.is_active
    );

    is_lock_changing := (
      new.locked_at is distinct from old.locked_at or
      new.locked_by is distinct from old.locked_by
    );
  end if;

  if TG_OP = 'UPDATE' and is_lock_changing then
    if old.locked_at is not null
       and old.locked_at > now() - interval '5 minutes'
       and old.locked_by is not null
       and (
         new.locked_by is null 
         or new.locked_by is distinct from old.locked_by
       ) then
      raise exception 'Shift is currently locked by another user';
    end if;
  end if;

  if TG_OP = 'UPDATE' and is_business_data_changed then
    new.version = old.version + 1;
  end if;

  if TG_OP = 'UPDATE' then
    if old.status = 'cancelled' and new.status != 'cancelled' then
      raise exception 'Cannot reactivate a cancelled shift';
    end if;

    if old.status = 'completed' and is_business_data_changed then
      raise exception 'Cannot modify a completed shift';
    end if;
  end if;

  if new.status = 'cancelled' then
    if new.cancelled_at is null then
      new.cancelled_at = now();
    end if;
  else
    new.cancelled_at = null;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."staff_shifts_before_write"() OWNER TO "postgres";


