    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Prefer whichever is set; copy to the other
  IF NEW.assigned_to IS NULL AND NEW.staff_id IS NOT NULL THEN
    NEW.assigned_to := NEW.staff_id;
  ELSIF NEW.staff_id IS NULL AND NEW.assigned_to IS NOT NULL THEN
    NEW.staff_id := NEW.assigned_to;
  END IF;

  RETURN NEW;
END
$$;


