CREATE OR REPLACE FUNCTION "public"."staffing_plan_for_day"("p_hotel_id" "uuid", "p_date" "date") RETURNS TABLE("department" "text", "recommended_count" integer, "min_count" integer, "max_count" integer, "reason" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_weekday int := EXTRACT(DOW FROM p_date);
BEGIN
  RETURN QUERY
  WITH recent_tickets AS (
    SELECT
      CASE
        WHEN s.key ILIKE 'hk%' THEN 'HK'
        WHEN s.key ILIKE 'fnb%' OR s.key ILIKE 'fb%' THEN 'FNB'
        WHEN s.key ILIKE 'desk%' OR s.key ILIKE 'front%' THEN 'FRONT_DESK'
        ELSE 'OTHER'
      END AS department,
      COUNT(*) AS ticket_count
    FROM public.tickets t
    JOIN public.services s ON s.id = t.service_id
    WHERE t.hotel_id = p_hotel_id
      AND t.created_at >= (p_date - INTERVAL '28 days')
      AND t.created_at < p_date
      AND EXTRACT(DOW FROM t.created_at) = v_weekday
    GROUP BY 1
  ),
  base AS (
    SELECT
      department,
      ticket_count,
      -- Heuristic: ~12 tickets per staff/day → adjust as needed later
      GREATEST(1, CEIL(ticket_count::numeric / 12.0))::int AS rec_count
    FROM recent_tickets
  )
  SELECT
    department,
    rec_count AS recommended_count,
    GREATEST(1, rec_count - 1) AS min_count,
    rec_count + 1 AS max_count,
    FORMAT(
      'Based on ~%s tickets on this weekday in last 4 weeks (≈12 tickets/staff).',
      ticket_count
    ) AS reason
  FROM base

  UNION ALL

  -- Fallback row if we have no history at all
  SELECT
    'HK' AS department,
    1    AS recommended_count,
    1    AS min_count,
    2    AS max_count,
    'Fallback: no history yet, minimum housekeeping coverage.' AS reason
  WHERE NOT EXISTS (SELECT 1 FROM base WHERE department = 'HK');
END;
$$;


ALTER FUNCTION "public"."staffing_plan_for_day"("p_hotel_id" "uuid", "p_date" "date") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."staffing_plan_for_day"("p_hotel_id" "uuid", "p_date" "date") IS 'Returns per-department staffing recommendation for a given hotel + date based on ticket history.';



