CREATE OR REPLACE FUNCTION "public"."start_task"("p_ticket_id" "uuid", "p_comment" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
  v_hotel_id UUID;
  v_member_id UUID;
  v_status TEXT;
  v_assigned_member_id UUID;
  v_updated_ticket JSONB;
BEGIN
  -- 1. Auth
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  -- 2. Lock ticket row
  SELECT hotel_id, status, current_assignee_id
  INTO v_hotel_id, v_status, v_assigned_member_id
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found';
  END IF;

  -- 3. Validate status
  IF v_status != 'NEW' THEN
    RAISE EXCEPTION 'Task cannot be started (current status: %)', v_status;
  END IF;

  -- 4. Validate staff membership
  SELECT id
  INTO v_member_id
  FROM hotel_members
  WHERE user_id = v_user_id
    AND hotel_id = v_hotel_id
    AND is_active = true;

  IF v_member_id IS NULL THEN
    RAISE EXCEPTION 'Unauthorized: not an active staff member';
  END IF;

  -- 5. Ownership guard
  IF v_assigned_member_id IS NOT NULL
     AND v_assigned_member_id != v_member_id THEN
    RAISE EXCEPTION 'Task already assigned to another staff member';
  END IF;

  -- 6. Update ticket
  UPDATE tickets
  SET 
    status = 'IN_PROGRESS',
    current_assignee_id = COALESCE(current_assignee_id, v_member_id),
    updated_at = now()
  WHERE id = p_ticket_id
    AND status = 'NEW';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Task was updated by another process';
  END IF;

  -- 7. Log event
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    previous_status,
    new_status,
    actor_type,
    actor_id,
    comment
  ) VALUES (
    p_ticket_id,
    'STARTED',
    'NEW',
    'IN_PROGRESS',
    'STAFF',
    v_member_id,
    p_comment
  );

  -- 8. Return updated ticket
  SELECT to_jsonb(t.*)
  INTO v_updated_ticket
  FROM tickets t
  WHERE id = p_ticket_id;

  RETURN v_updated_ticket;
END;
$$;


ALTER FUNCTION "public"."start_task"("p_ticket_id" "uuid", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."submit_precheckin"("p_token" "text", "p_data" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_token_id UUID;
  v_booking_id UUID;
  v_used_at TIMESTAMPTZ;
  v_expires_at TIMESTAMPTZ;
  v_guest_id UUID;
  v_first_room_id UUID;
  v_mobile_normalized TEXT;
  v_hotel_id UUID;
  v_doc_type guest_document_type;
  v_auth_user_id UUID;
BEGIN
  -- 1. Validate token (with optimized Hotel ID lookup & lock)
  SELECT pt.id, pt.booking_id, pt.used_at, pt.expires_at, b.hotel_id
  INTO v_token_id, v_booking_id, v_used_at, v_expires_at, v_hotel_id
  FROM precheckin_tokens pt
  JOIN bookings b ON b.id = pt.booking_id
  WHERE pt.token = p_token
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid token');
  END IF;

  IF v_used_at IS NOT NULL THEN
    RETURN jsonb_build_object(
      'success', true,
      'booking_id', v_booking_id,
      'already_completed', true
    );
  END IF;

  IF v_expires_at IS NOT NULL AND v_expires_at < now() THEN
    RETURN jsonb_build_object('success', false, 'error', 'This link has expired');
  END IF;

  -- 2. Resolve / Create Primary Guest Identity
  -- Lock booking row to prevent race conditions
  SELECT guest_id
  INTO v_guest_id
  FROM bookings 
  WHERE id = v_booking_id
  FOR UPDATE;

  IF v_guest_id IS NULL THEN
      -- Create new guest if missing (Fallback)
      v_mobile_normalized := regexp_replace(NULLIF(p_data->>'phone', ''), '[^0-9]', '', 'g');

      -- 2A. Global Guest Lookup by Mobile
      IF v_mobile_normalized IS NOT NULL AND v_mobile_normalized <> '' THEN
          SELECT id INTO v_guest_id 
          FROM public.guests 
          WHERE mobile_normalized = v_mobile_normalized 
          ORDER BY created_at DESC LIMIT 1;
      END IF;

      -- 2B. Global Guest Fallback to Email
      IF v_guest_id IS NULL AND p_data->>'email' IS NOT NULL AND p_data->>'email' <> '' THEN
          SELECT id INTO v_guest_id 
          FROM public.guests 
          WHERE lower(email) = lower(trim(p_data->>'email')) 
          ORDER BY created_at DESC LIMIT 1;
      END IF;

      -- 2C. Global Guest Creation
      IF v_guest_id IS NULL THEN
          INSERT INTO public.guests (
              full_name,
              email,
              mobile,
              mobile_normalized,
              nationality,
              address
          )
          VALUES (
              p_data->>'guest_name',
              NULLIF(p_data->>'email', ''),
              NULLIF(p_data->>'phone', ''),
              v_mobile_normalized,
              p_data->>'nationality',
              p_data->>'address'
          )
          ON CONFLICT (mobile) WHERE mobile IS NOT NULL 
          DO UPDATE SET
              full_name = EXCLUDED.full_name,
              email = COALESCE(EXCLUDED.email, guests.email),
              updated_at = now()
          RETURNING id INTO v_guest_id;
      END IF;
      
      -- Link to booking
      UPDATE bookings SET guest_id = v_guest_id WHERE id = v_booking_id;
  ELSE
      -- Update existing guest profile safely
      UPDATE guests
      SET 
          full_name = COALESCE(p_data->>'guest_name', full_name),
          email = COALESCE(NULLIF(p_data->>'email', ''), email),
          mobile = COALESCE(NULLIF(p_data->>'phone', ''), mobile),
          nationality = COALESCE(p_data->>'nationality', nationality),
          address = COALESCE(p_data->>'address', address),
          updated_at = now()
      WHERE id = v_guest_id;
  END IF;

  -- 2.1 Safety Check: Ensure booking_rooms exist
  IF NOT EXISTS (SELECT 1 FROM booking_rooms WHERE booking_id = v_booking_id) THEN
      RETURN jsonb_build_object('success', false, 'error', 'Booking has no assigned rooms. Please contact front desk.');
  END IF;

  -- 3. Update booking header
  UPDATE bookings
  SET
    guest_name = COALESCE(p_data->>'guest_name', guest_name),
    phone = COALESCE(p_data->>'phone', phone),
    email = COALESCE(p_data->>'email', email),
    status = 'PRE_CHECKED_IN',
    updated_at = now()
  WHERE id = v_booking_id;

  -- 4. Mark all rooms as PRE_CHECKED_IN
  UPDATE booking_rooms
  SET status = 'PRE_CHECKED_IN', updated_at = now()
  WHERE booking_id = v_booking_id
  AND status = 'RESERVED';

  -- 5. Assign Primary Guest to ALL Rooms
  INSERT INTO booking_room_guests (booking_room_id, guest_id, is_primary)
  SELECT id, v_guest_id, true
  FROM booking_rooms
  WHERE booking_id = v_booking_id
  ON CONFLICT (booking_room_id) WHERE is_primary = true
  DO UPDATE SET guest_id = EXCLUDED.guest_id;

  -- 6. Assign Additional Guests to First Room
  IF p_data->'additional_guests' IS NOT NULL AND jsonb_array_length(p_data->'additional_guests') > 0 THEN
      SELECT id INTO v_first_room_id
      FROM booking_rooms 
      WHERE booking_id = v_booking_id 
      ORDER BY room_seq ASC NULLS LAST, created_at ASC 
      LIMIT 1;

      IF v_first_room_id IS NOT NULL THEN
          BEGIN
              WITH new_guests AS (
                  INSERT INTO guests (
                      full_name,
                      mobile,
                      is_vip,
                      created_at,
                      updated_at
                  )
                  SELECT DISTINCT
                      g->>'name',
                      NULLIF(g->>'mobile', ''),
                      false,
                      now(),
                      now()
                  FROM jsonb_array_elements(p_data->'additional_guests') g
                  ON CONFLICT (mobile) WHERE mobile IS NOT NULL
                  DO UPDATE SET updated_at = now()
                  RETURNING id
              )
              INSERT INTO booking_room_guests (
                  booking_room_id,
                  guest_id,
                  is_primary
              )
              SELECT v_first_room_id, id, false
              FROM new_guests
              ON CONFLICT (booking_room_id, guest_id) DO NOTHING;
          EXCEPTION WHEN OTHERS THEN
              RAISE WARNING 'Failed to add additional guests: %', SQLERRM;
          END;
      END IF;
  END IF;

  -- 7. Hardened ID Document Persistence (Metadata & History Aware)
  IF p_data->>'id_number' IS NOT NULL AND p_data->>'id_number' != '' THEN
      v_doc_type := COALESCE((p_data->>'id_type')::guest_document_type, 'other');

      -- IF duplicate exists with same front_hash and is active, skip insertion
      IF NOT EXISTS (
        SELECT 1 FROM guest_id_documents
        WHERE guest_id = v_guest_id
          AND document_type = v_doc_type
          AND front_hash = p_data->>'front_hash'
          AND is_active = true
      ) THEN
          -- Deactivate previous active doc with concurrency lock
          UPDATE guest_id_documents
          SET is_active = false
          WHERE id IN (
              SELECT id
              FROM guest_id_documents
              WHERE guest_id = v_guest_id
                AND document_type = v_doc_type
                AND is_active = true
              FOR UPDATE
          );

          -- Insert New Hardened Document
          INSERT INTO guest_id_documents (
              guest_id, 
              document_type, 
              document_number_masked, 
              front_image_url, 
              back_image_url, 
              storage_key,
              front_hash,
              back_hash,
              issuing_country,
              verification_status, 
              is_active
          )
          VALUES (
            v_guest_id,
            v_doc_type,
            CASE 
              WHEN length(p_data->>'id_number') > 4
              THEN repeat('X', length(p_data->>'id_number') - 4) || right(p_data->>'id_number', 4)
              ELSE p_data->>'id_number'
            END,
            p_data->>'front_image_url',
            p_data->>'back_image_url',
            NULLIF(p_data->>'storage_key', '')::UUID,
            p_data->>'front_hash',
            p_data->>'back_hash',
            p_data->>'issuing_country',
            'pending',
            true
          );
      END IF;
  END IF;

  -- 8. Bidirectional Mapping Trigger (Hardened Identity)
  BEGIN
    -- Sequential match by verified properties
    IF p_data->>'email' IS NOT NULL AND p_data->>'email' != '' THEN
      SELECT id INTO v_auth_user_id FROM auth.users WHERE lower(email) = lower(trim(p_data->>'email')) LIMIT 1;
    END IF;
    
    IF v_auth_user_id IS NULL AND v_mobile_normalized IS NOT NULL AND v_mobile_normalized != '' THEN
      SELECT id INTO v_auth_user_id FROM auth.users WHERE regexp_replace(COALESCE(phone, ''), '[^0-9]', '', 'g') = v_mobile_normalized LIMIT 1;
    END IF;

    IF v_auth_user_id IS NOT NULL THEN
      -- Create mapping if it doesn't exist
      INSERT INTO public.guest_user_map (user_id, guest_id) 
      VALUES (v_auth_user_id, v_guest_id) 
      ON CONFLICT (user_id) DO NOTHING;
    END IF;
  EXCEPTION WHEN OTHERS THEN
    RAISE WARNING 'Identity mapping failed: %', SQLERRM;
  END;

  -- 9. Mark Token Used
  UPDATE precheckin_tokens
  SET
    precheckin_data = p_data,
    used_at = now(),
    updated_at = now()
  WHERE id = v_token_id;

  -- 9. Notification Queueing
  IF (p_data->>'email') IS NOT NULL AND (p_data->>'email') != '' THEN
    INSERT INTO public.notification_queue (booking_id, channel, template_code, payload, status)
    VALUES (
      v_booking_id,
      'email',
      'precheckin_completed_access',
      jsonb_build_object(
        'booking_id', v_booking_id,
        'guest_name', COALESCE(p_data->>'guest_name', 'Guest'),
        'email', p_data->>'email'
      ),
      'pending'
    );
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'booking_id', v_booking_id,
    'guest_id', v_guest_id,
    'token', p_token,
    'qr_url', 'https://vaiyu.co.in/checkin?tkn=' || p_token,
    'completed_at', now()
  );
END;
$$;


ALTER FUNCTION "public"."submit_precheckin"("p_token" "text", "p_data" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."submit_public_feedback"("p_token" "text", "p_data" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_token_id UUID;
    v_booking_id UUID;
    v_hotel_id UUID;
    v_guest_id UUID;
    v_stay_id UUID;
    v_used_at TIMESTAMPTZ;
    v_expires_at TIMESTAMPTZ;
    v_review_id UUID;
    v_overall_rating INT;
    v_review_text TEXT;
    v_category_ratings JSONB;
BEGIN
    -- 1. Validate & lock token
    SELECT ft.id, ft.booking_id, ft.hotel_id, ft.used_at, ft.expires_at, b.guest_id
    INTO v_token_id, v_booking_id, v_hotel_id, v_used_at, v_expires_at, v_guest_id
    FROM public.feedback_tokens ft
    JOIN public.bookings b ON b.id = ft.booking_id
    WHERE ft.token = p_token
    FOR UPDATE OF ft;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Invalid feedback link');
    END IF;

    IF v_used_at IS NOT NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Feedback has already been submitted. Thank you!',
            'already_submitted', true
        );
    END IF;

    IF v_expires_at IS NOT NULL AND v_expires_at < now() THEN
        RETURN jsonb_build_object('success', false, 'error', 'This feedback link has expired');
    END IF;

    -- 2. Parse input
    v_overall_rating := COALESCE((p_data->>'overall_rating')::int, 0);
    v_review_text := p_data->>'review_text';
    v_category_ratings := p_data->'category_ratings';  -- JSONB array of {category_id, rating}

    IF v_overall_rating < 1 OR v_overall_rating > 5 THEN
        RETURN jsonb_build_object('success', false, 'error', 'Please provide a rating between 1 and 5');
    END IF;

    -- 3. Find the stay (if exists)
    SELECT id INTO v_stay_id
    FROM public.stays
    WHERE booking_id = v_booking_id
    AND status IN ('checked_out', 'checkout_requested')
    ORDER BY actual_checkout_at DESC NULLS LAST
    LIMIT 1;

    -- 4. Check for existing review (idempotency)
    IF EXISTS (SELECT 1 FROM public.guest_reviews WHERE booking_id = v_booking_id) THEN
        -- Mark token used even if review already exists
        UPDATE public.feedback_tokens SET used_at = now(), updated_at = now() WHERE id = v_token_id;
        RETURN jsonb_build_object(
            'success', false,
            'error', 'A review has already been submitted for this stay',
            'already_submitted', true
        );
    END IF;

    -- 5. Insert review (bypass booking state trigger since we're SECURITY DEFINER
    --    and we've already validated the token represents a checked-out booking)
    INSERT INTO public.guest_reviews (
        hotel_id,
        booking_id,
        stay_id,
        guest_id,
        overall_rating,
        review_text,
        is_public,
        is_anonymous
    )
    VALUES (
        v_hotel_id,
        v_booking_id,
        v_stay_id,
        v_guest_id,
        v_overall_rating,
        v_review_text,
        v_overall_rating >= 4,  -- Auto-public for high ratings
        COALESCE((p_data->>'is_anonymous')::boolean, false)
    )
    RETURNING id INTO v_review_id;

    -- 6. Insert category ratings
    IF v_category_ratings IS NOT NULL AND jsonb_array_length(v_category_ratings) > 0 THEN
        INSERT INTO public.review_ratings (hotel_id, review_id, category_id, rating)
        SELECT
            v_hotel_id,
            v_review_id,
            (elem->>'category_id')::uuid,
            (elem->>'rating')::int
        FROM jsonb_array_elements(v_category_ratings) elem
        WHERE (elem->>'rating')::int > 0
        ON CONFLICT (review_id, category_id) DO NOTHING;
    END IF;

    -- 7. Mark token as used (one-time)
    UPDATE public.feedback_tokens
    SET used_at = now(), updated_at = now()
    WHERE id = v_token_id;

    RETURN jsonb_build_object(
        'success', true,
        'review_id', v_review_id,
        'message', 'Thank you for your feedback!'
    );
END;
$$;


ALTER FUNCTION "public"."submit_public_feedback"("p_token" "text", "p_data" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_staff_shift_version"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  if (
    NEW.shift_start is distinct from OLD.shift_start or
    NEW.shift_end is distinct from OLD.shift_end or
    NEW.shift_type is distinct from OLD.shift_type or
    NEW.zone_id is distinct from OLD.zone_id or
    NEW.status is distinct from OLD.status or
    NEW.staff_id is distinct from OLD.staff_id
  ) then
    NEW.version = OLD.version + 1;
  end if;

  NEW.updated_at = now();
  return NEW;
end;
$$;


