CREATE OR REPLACE FUNCTION "public"."trg_escalate_low_rating"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    -- Evaluate only on insert or if the rating drops below threshold during an update
    IF NEW.overall_rating <= 2 AND (TG_OP = 'INSERT' OR OLD.overall_rating > 2) THEN
        
        -- Gap 5: Race condition fix using ON CONFLICT DO NOTHING
        INSERT INTO review_flags (hotel_id, review_id, flag_type, severity, status)
        VALUES (NEW.hotel_id, NEW.id, 'low_rating', 'high', 'open')
        ON CONFLICT (review_id, flag_type) DO NOTHING;
        
        -- Emit event
        INSERT INTO review_events (hotel_id, review_id, event_type, actor_type, metadata)
        VALUES (NEW.hotel_id, NEW.id, 'REVIEW_FLAGGED', 'SYSTEM', jsonb_build_object('reason', 'low_rating_auto_escalation'));
        
    -- Gap 2: De-escalation condition
    ELSIF TG_OP = 'UPDATE' AND NEW.overall_rating > 2 AND OLD.overall_rating <= 2 THEN
        UPDATE review_flags SET status = 'resolved', updated_at = now()
        WHERE review_id = NEW.id AND flag_type = 'low_rating' AND status != 'resolved';
        
        IF FOUND THEN
            INSERT INTO review_events (hotel_id, review_id, event_type, actor_type, metadata)
            VALUES (NEW.hotel_id, NEW.id, 'REVIEW_UPDATED', 'SYSTEM', jsonb_build_object('reason', 'rating_improved_de_escalated'));
        END IF;
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_escalate_low_rating"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_finalize_sla_on_completion"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_started_at TIMESTAMPTZ;
  v_total_paused INT;
  v_is_breached BOOLEAN;
  v_target_minutes INT;
  v_elapsed INT;
BEGIN
  -- 1. Guard: Only run on transition to terminal status (Defensive)
  IF NOT (
    OLD.status IS DISTINCT FROM NEW.status
    AND NEW.status IN ('COMPLETED', 'CANCELLED')
  ) THEN
    RETURN NEW;
  END IF;

  -- 2. Policy: CANCELLED tickets do not count toward SLA
  IF NEW.status = 'CANCELLED' THEN
    RETURN NEW;
  END IF;

  -- 3. Get SLA state
  SELECT 
    ss.sla_started_at, 
    ss.total_paused_seconds, 
    ss.breached,
    sp.target_minutes
  INTO 
    v_started_at, 
    v_total_paused, 
    v_is_breached,
    v_target_minutes
  FROM ticket_sla_state ss
  JOIN tickets t ON t.id = ss.ticket_id
  JOIN sla_policies sp ON sp.department_id = t.service_department_id
  WHERE ss.ticket_id = NEW.id;

  -- 4. If SLA never started or already flagged, skip
  IF v_started_at IS NULL OR v_is_breached THEN
    RETURN NEW;
  END IF;

  -- 5. Check for exception granted
  IF EXISTS (SELECT 1 FROM ticket_events WHERE ticket_id = NEW.id AND event_type = 'SLA_EXCEPTION_GRANTED') THEN
    RETURN NEW;
  END IF;

  -- 6. Calculate final elapsed time at moment of closure
  v_elapsed := EXTRACT(EPOCH FROM (clock_timestamp() - v_started_at))::INT - COALESCE(v_total_paused, 0);

  -- 7. Mark breached if over limit
  IF v_elapsed > (v_target_minutes * 60) THEN
    UPDATE ticket_sla_state
    SET 
      breached = true,
      breached_at = clock_timestamp()
    WHERE ticket_id = NEW.id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_finalize_sla_on_completion"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_food_to_folio"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    v_folio_id UUID;
    v_booking_id UUID;
BEGIN
    IF NEW.status = 'DELIVERED' AND OLD.status IS DISTINCT FROM 'DELIVERED' THEN

        -- Find booking
        SELECT booking_id
        INTO v_booking_id
        FROM stays
        WHERE id = NEW.stay_id
        LIMIT 1;

        IF v_booking_id IS NULL THEN
            RAISE EXCEPTION 'Stay % has no booking', NEW.stay_id;
        END IF;

        -- Find folio
        SELECT id
        INTO v_folio_id
        FROM folios
        WHERE booking_id = v_booking_id
        LIMIT 1;

        -- Create folio if missing
        IF v_folio_id IS NULL THEN
            INSERT INTO folios (
                id,
                booking_id,
                hotel_id,
                created_at
            )
            VALUES (
                gen_random_uuid(),
                v_booking_id,
                NEW.hotel_id,
                now()
            )
            RETURNING id INTO v_folio_id;
        END IF;

        -- Add food charge
        INSERT INTO folio_entries (
            hotel_id,
            booking_id,
            folio_id,
            entry_type,
            amount,
            description,
            reference_id
        )
        VALUES (
            NEW.hotel_id,
            v_booking_id,
            v_folio_id,
            'FOOD_CHARGE',
            NEW.total_amount,
            'Food Order ' || NEW.display_id,
            NEW.id
        );

    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_food_to_folio"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_pause_sla_on_block"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_pauses BOOLEAN;
BEGIN
  SELECT pauses_sla INTO v_pauses
  FROM block_reasons WHERE code = NEW.reason_code;

  IF v_pauses = true AND NEW.status = 'BLOCKED' THEN
    UPDATE ticket_sla_state
    SET 
      sla_paused_at = clock_timestamp(),
      pause_count = COALESCE(pause_count, 0) + 1 -- 📊 Audit Trail
    WHERE ticket_id = NEW.id
      AND sla_paused_at IS NULL
      AND sla_started_at IS NOT NULL; -- 🛡️ GUARDIAN 2: Must be started
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_pause_sla_on_block"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_payment_to_folio"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    IF NEW.status = 'COMPLETED' THEN

        INSERT INTO folio_entries (
            hotel_id,
            booking_id,
            folio_id,
            entry_type,
            amount,
            description,
            reference_id
        )
        SELECT
            NEW.hotel_id,
            NEW.booking_id,
