CREATE OR REPLACE FUNCTION "public"."trg_shift_audit"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_action text;
  v_changed_by uuid;
  v_hotel_id uuid;
  v_diff jsonb := '{}'::jsonb;
  v_explanation jsonb;
begin
  -- Read explanation from session
  v_explanation := nullif(
    current_setting('vaiyu.explanation', true),
    ''
  )::jsonb;

  -- 👤 Identify Actor
  v_changed_by := coalesce(
    current_setting('request.jwt.claim.sub', true)::uuid,
    auth.uid(),
    NEW.created_by,
    OLD.created_by
  );

  -- 🏢 Lookup hotel_id correctly
  select hm.hotel_id into v_hotel_id
  from public.hotel_members hm
  where hm.id = coalesce(NEW.staff_id, OLD.staff_id)
  limit 1;

  if v_hotel_id is null then
    raise exception 'Audit failed: hotel_id not found for staff %', coalesce(NEW.staff_id, OLD.staff_id);
  end if;

  if tg_op = 'INSERT' then
    v_action := 'created';
    v_diff := jsonb_build_object(
      'staff_id',      jsonb_build_object('new', NEW.staff_id),
      'department_id',  jsonb_build_object('new', NEW.department_id),
      'status',         jsonb_build_object('new', NEW.status),
      'shift_start',   jsonb_build_object('new', NEW.shift_start),
      'shift_end',     jsonb_build_object('new', NEW.shift_end),
      'shift_type',    jsonb_build_object('new', NEW.shift_type),
      'zone_id',       jsonb_build_object('new', NEW.zone_id)
    );
  elsif tg_op = 'UPDATE' then
    if (
      NEW.shift_start is not distinct from OLD.shift_start and
      NEW.shift_end is not distinct from OLD.shift_end and
      NEW.shift_type is not distinct from OLD.shift_type and
      NEW.zone_id is not distinct from OLD.zone_id and
      NEW.status is not distinct from OLD.status and
      NEW.staff_id is not distinct from OLD.staff_id and
      NEW.department_id is not distinct from OLD.department_id
    ) then
      return NEW;
    end if;

    v_action := 'updated';
    if NEW.shift_start is distinct from OLD.shift_start then v_diff := v_diff || jsonb_build_object('shift_start', jsonb_build_object('old', OLD.shift_start, 'new', NEW.shift_start)); end if;
    if NEW.shift_end is distinct from OLD.shift_end then v_diff := v_diff || jsonb_build_object('shift_end', jsonb_build_object('old', OLD.shift_end, 'new', NEW.shift_end)); end if;
    if NEW.department_id is distinct from OLD.department_id then v_diff := v_diff || jsonb_build_object('department_id', jsonb_build_object('old', OLD.department_id, 'new', NEW.department_id)); end if;
    if NEW.zone_id is distinct from OLD.zone_id then v_diff := v_diff || jsonb_build_object('zone_id', jsonb_build_object('old', OLD.zone_id, 'new', NEW.zone_id)); end if;
    if NEW.status is distinct from OLD.status then v_diff := v_diff || jsonb_build_object('status', jsonb_build_object('old', OLD.status, 'new', NEW.status)); end if;
  
  elsif tg_op = 'DELETE' then
    v_action := 'deleted';
    v_diff := jsonb_build_object(
      'deleted', true,
      'department_id', OLD.department_id,
      'staff_id', OLD.staff_id,
      'shift_start', OLD.shift_start,
      'shift_end', OLD.shift_end
    );
    -- Insert audit log for delete before returning OLD
    insert into public.shift_audit_log (
      hotel_id, shift_id, staff_id, action, diff, 
      action_reason, explanation, changed_by
    )
    values (
      v_hotel_id, OLD.id, OLD.staff_id, v_action, v_diff, 
      nullif(current_setting('vaiyu.action_reason', true), ''),
      v_explanation,
      v_changed_by
    );
    return OLD;
  end if;

  -- 💾 Insert audit log for insert/update
  insert into public.shift_audit_log (
    hotel_id, shift_id, staff_id, action, diff, 
    action_reason, explanation, changed_by
  )
  values (
    v_hotel_id, NEW.id, NEW.staff_id, v_action, v_diff, 
    nullif(current_setting('vaiyu.action_reason', true), ''),
    v_explanation,
    v_changed_by
  );

  return NEW;
end;
$$;


ALTER FUNCTION "public"."trg_shift_audit"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_start_sla_on_assign"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_start_policy TEXT;
  v_target_minutes INT;
BEGIN
  -- Validate: Don't restart if Completed or Cancelled
  IF NEW.status IN ('COMPLETED', 'CANCELLED') THEN
    RETURN NEW;
  END IF;

  SELECT sla_start_trigger, target_minutes
  INTO v_start_policy, v_target_minutes
  FROM sla_policies
  WHERE department_id = NEW.service_department_id
    AND is_active = true;

  IF v_start_policy = 'ON_ASSIGN'
     AND NEW.current_assignee_id IS NOT NULL
     AND OLD.current_assignee_id IS NULL THEN

    -- 🛡️ GUARDIAN 1: Ensure Row Exists (Self-Healing)
    INSERT INTO ticket_sla_state (ticket_id)
    VALUES (NEW.id)
    ON CONFLICT (ticket_id) DO NOTHING;

    -- Update State
    UPDATE ticket_sla_state
    SET
      sla_started_at = clock_timestamp(), -- 🕒 Precise Time
      sla_resumed_at = clock_timestamp(),
      current_remaining_seconds = (v_target_minutes * 60)
    WHERE ticket_id = NEW.id
      AND sla_started_at IS NULL; -- Idempotent: Only start once
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_start_sla_on_assign"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_touch_kpis"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- handle INSERT/UPDATE/DELETE and hotel_id changes
  IF TG_OP IN ('INSERT','UPDATE') THEN
    PERFORM refresh_kpis_for_hotel(NEW.hotel_id);
  END IF;
  IF TG_OP IN ('UPDATE','DELETE') THEN
    IF TG_OP = 'UPDATE' AND NEW.hotel_id <> OLD.hotel_id THEN
      PERFORM refresh_kpis_for_hotel(OLD.hotel_id);
    ELSIF TG_OP = 'DELETE' THEN
      PERFORM refresh_kpis_for_hotel(OLD.hotel_id);
    END IF;
  END IF;
  RETURN NULL;
END $$;


ALTER FUNCTION "public"."trg_touch_kpis"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_validate_review_booking_state"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_status TEXT;
    v_hotel_id UUID;
BEGIN
    -- Get booking status and hotel_id
    SELECT status, hotel_id INTO v_status, v_hotel_id 
    FROM bookings 
    WHERE id = NEW.booking_id;

    -- Allow reviews if:
    -- 1. Booking is officially CHECKED_OUT or COMPLETED
    -- 2. OR at least one stay in this booking has 'checkout_requested' (guest is done with service)
    -- 3. OR at least one stay is already 'checked_out'
    IF UPPER(v_status) NOT IN ('CHECKED_OUT', 'COMPLETED') THEN
        IF NOT EXISTS (
            SELECT 1 FROM stays 
            WHERE booking_id = NEW.booking_id 
            AND status IN ('checkout_requested', 'checked_out')
        ) THEN
            RAISE EXCEPTION 'Reviews can only be submitted post-service (Booking Status: %, No requested checkouts found)', v_status;
        END IF;
    END IF;
    
    -- Hotel integrity check (Security)
    IF v_hotel_id != NEW.hotel_id THEN
        RAISE EXCEPTION 'Booking hotel does not match review hotel';
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_validate_review_booking_state"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_validate_review_target"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    IF NEW.target_type = 'staff' THEN
        IF NOT EXISTS (SELECT 1 FROM hotel_members WHERE id = NEW.target_id AND hotel_id = NEW.hotel_id) THEN
            RAISE EXCEPTION 'Invalid staff member target constraint violation';
        END IF;
    ELSIF NEW.target_type = 'service' THEN
        IF NOT EXISTS (SELECT 1 FROM services WHERE id = NEW.target_id AND hotel_id = NEW.hotel_id) THEN
            RAISE EXCEPTION 'Invalid service target constraint violation';
        END IF;
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_validate_review_target"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_validate_stay_room_hotel"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM rooms r
    WHERE r.id = NEW.room_id
      AND r.hotel_id = NEW.hotel_id
  ) THEN
    RAISE EXCEPTION
      'Room % does not belong to hotel %',
      NEW.room_id, NEW.hotel_id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_validate_stay_room_hotel"() OWNER TO "postgres";


