CREATE OR REPLACE FUNCTION "public"."update_batch_counters"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    v_total INT;
    v_imported INT;
    v_errors INT;
BEGIN
    IF NEW.status IS DISTINCT FROM OLD.status THEN

        SELECT
            COUNT(*) FILTER (WHERE r.status IN ('imported','notified')),
            COUNT(*) FILTER (WHERE r.status = 'error')
        INTO v_imported, v_errors
        FROM public.import_rows r
        WHERE r.batch_id = NEW.batch_id;

        SELECT COALESCE(b.total_rows,0)
        INTO v_total
        FROM public.import_batches b
        WHERE b.id = NEW.batch_id;

        UPDATE public.import_batches
        SET
            imported_rows = v_imported,
            error_rows = v_errors,
            status = CASE
                WHEN (v_imported + v_errors) >= v_total AND v_errors = (v_imported + v_errors)
                    THEN 'failed'
                WHEN (v_imported + v_errors) >= v_total
                    THEN 'completed'
                ELSE status
            END,
            completed_at = CASE
                WHEN (v_imported + v_errors) >= v_total
                     AND completed_at IS NULL
                THEN now()
                ELSE completed_at
            END
        WHERE id = NEW.batch_id;

    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_batch_counters"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_block_task"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text" DEFAULT NULL::"text", "p_resume_after" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
  v_member_id UUID;
  v_hotel_id UUID;
  v_status TEXT;
  v_current_assignee UUID;
  v_ticket JSONB;
BEGIN
  ----------------------------------------------------------------
  -- 1️⃣ Authentication
  ----------------------------------------------------------------
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  ----------------------------------------------------------------
  -- 2️⃣ Lock ticket row
  ----------------------------------------------------------------
  SELECT
    hotel_id,
    status,
    current_assignee_id
  INTO
    v_hotel_id,
    v_status,
    v_current_assignee
  FROM tickets
  WHERE id = p_ticket_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Ticket not found';
  END IF;

  ----------------------------------------------------------------
  -- 3️⃣ Validate ticket state
  ----------------------------------------------------------------
  IF v_status <> 'BLOCKED' THEN
    RAISE EXCEPTION
      'Only BLOCKED tasks can be updated (current status: %)',
      v_status;
  END IF;

  ----------------------------------------------------------------
  -- 4️⃣ Validate staff (must be assignee)
  ----------------------------------------------------------------
  SELECT id
  INTO v_member_id
  FROM hotel_members
  WHERE user_id = v_user_id
    AND hotel_id = v_hotel_id
    AND is_active = true;

  IF v_member_id IS NULL THEN
    RAISE EXCEPTION 'Unauthorized: not an active staff member';
  END IF;

  IF v_current_assignee IS DISTINCT FROM v_member_id THEN
    RAISE EXCEPTION 'Only the assigned staff can update this block';
  END IF;

  ----------------------------------------------------------------
  -- 5️⃣ Validate block reason
  ----------------------------------------------------------------
  IF NOT EXISTS (
    SELECT 1
    FROM block_reasons
    WHERE code = p_reason_code
      AND is_active = true
  ) THEN
    RAISE EXCEPTION 'Invalid block reason: %', p_reason_code;
  END IF;

  ----------------------------------------------------------------
  -- 6️⃣ Update ticket (still BLOCKED)
  ----------------------------------------------------------------
  UPDATE tickets
  SET
    reason_code = p_reason_code,
    updated_at = now()
  WHERE id = p_ticket_id
    AND status = 'BLOCKED';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Task was modified concurrently';
  END IF;

  ----------------------------------------------------------------
  -- 7️⃣ Insert immutable BLOCK_UPDATED event
  ----------------------------------------------------------------
  INSERT INTO ticket_events (
    ticket_id,
    event_type,
    previous_status,
    new_status,
    reason_code,
    comment,
    resume_after,
    actor_type,
    actor_id
  )
  VALUES (
    p_ticket_id,
    'BLOCKED',
    'BLOCKED',
    'BLOCKED',
    p_reason_code,
    p_comment,
    p_resume_after,
    'STAFF',
    v_member_id
  );

  ----------------------------------------------------------------
  -- 8️⃣ Return updated ticket
  ----------------------------------------------------------------
  SELECT to_jsonb(t.*)
  INTO v_ticket
  FROM tickets t
  WHERE id = p_ticket_id;

  RETURN v_ticket;
END;
$$;


ALTER FUNCTION "public"."update_block_task"("p_ticket_id" "uuid", "p_reason_code" "text", "p_comment" "text", "p_resume_after" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_hotel_member"("p_member_id" "uuid", "p_is_active" boolean DEFAULT NULL::boolean, "p_is_verified" boolean DEFAULT NULL::boolean) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
declare
begin
  -- Ensure the hotel member actually exists
  if not exists (select 1 from public.hotel_members where id = p_member_id) then
    raise exception 'Member not found';
  end if;

  -- Ensure the executing user is part of the same hotel (and ideally an ADMIN/OWNER)
  if not exists (
    select 1 from public.hotel_members hm
    join public.hotel_member_roles hmr on hmr.hotel_member_id = hm.id
    join public.hotel_roles hr on hr.id = hmr.role_id
    where hm.user_id = auth.uid()
      and hm.hotel_id = (select hotel_id from public.hotel_members where id = p_member_id limit 1)
      and hr.code in ('OWNER', 'ADMIN', 'MANAGER')
      and hm.is_active = true
  ) then
    raise exception 'Not authorized to modify this member';
  end if;

  -- Apply the update
  if p_is_active is not null then
    -- If deactivating, ensure we correspond to a safe state
    if p_is_active = false then
      -- Check if the member being deactivated is currently an active owner
      if exists (
        select 1 from public.hotel_member_roles hmr
        join public.hotel_roles hr on hr.id = hmr.role_id
        join public.hotel_members hm on hm.id = hmr.hotel_member_id
        where hmr.hotel_member_id = p_member_id 
          and hr.code = 'OWNER'
          and hm.is_active = true
      ) then
        -- Check if there are any *other* active owners in this hotel
        if not exists (
          select 1
          from public.hotel_members hm
          join public.hotel_member_roles hmr on hmr.hotel_member_id = hm.id
          join public.hotel_roles hr on hr.id = hmr.role_id
          where hm.hotel_id = (select hotel_id from public.hotel_members where id = p_member_id limit 1)  -- Using a robust subquery instead of the local variable
            and hm.is_active = true
            and hr.code = 'OWNER'
            and hm.id != p_member_id
        ) then
          raise exception 'Cannot deactivate the only remaining active owner of the hotel';
        end if;
      end if;
    end if;

    update public.hotel_members set is_active = p_is_active where id = p_member_id;
  end if;
  
  if p_is_verified is not null then
    update public.hotel_members set is_verified = p_is_verified where id = p_member_id;
  end if;

end;
$$;


ALTER FUNCTION "public"."update_hotel_member"("p_member_id" "uuid", "p_is_active" boolean, "p_is_verified" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_hotel_settings_onboarding"("p_hotel_id" "uuid", "payload" "jsonb", "p_action" "text" DEFAULT 'HOTEL_UPDATED'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $_$
DECLARE
    v_has_access boolean;
    v_rowcount integer;
BEGIN
    SET LOCAL statement_timeout = '10s';

    -- Require authentication
    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    -- Protect against empty payload
    IF payload IS NULL OR payload = '{}'::jsonb THEN
        RAISE EXCEPTION 'Payload cannot be empty';
    END IF;

    -- Prevent absurdly large payloads
    IF (SELECT count(*) FROM jsonb_object_keys(payload)) > 50 THEN
        RAISE EXCEPTION 'Payload is too large';
    END IF;

    -- Slug handling moved after row lock

    -- Validate existence and grab row lock in one operation
    PERFORM 1 FROM public.hotels WHERE id = p_hotel_id FOR UPDATE;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Hotel not found';
    END IF;


    -- Block restricted fields from being updated directly via this RPC
    IF payload ? 'plan' 
       OR payload ? 'plan_status' 
       OR payload ? 'status' 
       OR payload ? 'lifecycle_status' 
       OR payload ? 'go_live_at' THEN
        RAISE EXCEPTION 'Restricted core lifecycle fields cannot be updated via the onboarding settings RPC';
    END IF;

    -- Security Check: The user must either be:
    -- 1. An active Platform Admin
    -- 2. An active OWNER/ADMIN/MANAGER of the hotel
    -- 3. In the middle of an active onboarding session triggered by them
    
    -- Check Platform Admin
    SELECT EXISTS (
        SELECT 1 FROM public.platform_admins
        WHERE user_id = auth.uid()
        AND is_active = true
    ) INTO v_has_access;

    IF NOT v_has_access THEN
        -- Check Hotel Member
        SELECT EXISTS (
            SELECT 1
            FROM public.hotel_members hm
            JOIN public.hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
            JOIN public.hotel_roles hr ON hr.id = hmr.role_id
            WHERE hm.user_id = auth.uid()
            AND hm.hotel_id = p_hotel_id
            AND hr.code IN ('OWNER','ADMIN','MANAGER')
            AND hm.is_active = true
            AND hr.is_active = true
        ) INTO v_has_access;
    END IF;

    IF NOT v_has_access THEN
        -- Check if they are actively onboarding this specific hotel right now
        -- (They ran step 1, creating progress logs but aren't members yet)
        SELECT EXISTS (
            SELECT 1 
            FROM public.hotel_audit_logs
            WHERE hotel_id = p_hotel_id
            AND user_id = auth.uid()
            AND action = 'HOTEL_CREATED'
        ) INTO v_has_access;
    END IF;

    IF NOT v_has_access THEN
        RAISE EXCEPTION 'Insufficient permissions to update this hotel';
    END IF;

    -- Validate slug format, ensure uniqueness, and normalize
    IF payload ? 'slug' THEN
        -- Safely normalize first to gracefully handle spaces and uppercase from legacy data
        payload := jsonb_set(
            payload,
            '{slug}',
            to_jsonb(lower(trim(payload->>'slug')))
        );

        -- Format validation: only lowercase alphanumerics and hyphens
        IF payload->>'slug' = '' THEN
            RAISE EXCEPTION 'Slug cannot be empty';
        END IF;
        IF payload->>'slug' !~ '^[a-z0-9\-]+$' THEN
            RAISE EXCEPTION 'Invalid slug format';
        END IF;

        -- Ensure slug uniqueness (excluding current hotel)
        IF EXISTS (
            SELECT 1
            FROM public.hotels
            WHERE slug = payload->>'slug'
            AND id <> p_hotel_id
        ) THEN
            RAISE EXCEPTION 'Slug already exists';
        END IF;
    END IF;

    -- Dynamic Update Logic via JSONB
    UPDATE public.hotels
    SET 
        name = COALESCE((payload->>'name'), name),
        slug = CASE WHEN payload ? 'slug' THEN payload->>'slug' ELSE slug END,
        description = COALESCE((payload->>'description'), description),
        phone = COALESCE((payload->>'phone'), phone),
        email = COALESCE((payload->>'email'), email),
        address = COALESCE((payload->>'address'), address),
        city = COALESCE((payload->>'city'), city),
        state = COALESCE((payload->>'state'), state),
        country = COALESCE((payload->>'country'), country),
        postal_code = COALESCE((payload->>'postal_code'), postal_code),
        latitude = CASE WHEN payload ? 'latitude' AND payload->>'latitude' IS NOT NULL THEN (payload->>'latitude')::numeric ELSE latitude END,
        longitude = CASE WHEN payload ? 'longitude' AND payload->>'longitude' IS NOT NULL THEN (payload->>'longitude')::numeric ELSE longitude END,
        legal_name = COALESCE((payload->>'legal_name'), legal_name),
        gst_number = COALESCE((payload->>'gst_number'), gst_number),
        logo_path = COALESCE((payload->>'logo_path'), logo_path),
        cover_image_path = COALESCE((payload->>'cover_image_path'), cover_image_path),
        brand_color = COALESCE((payload->>'brand_color'), brand_color),
        
        default_checkin_time = COALESCE(NULLIF(payload->>'default_checkin_time', '')::time, default_checkin_time),
        default_checkout_time = COALESCE(NULLIF(payload->>'default_checkout_time', '')::time, default_checkout_time),
        timezone = COALESCE((payload->>'timezone'), timezone),
        currency_code = COALESCE((payload->>'currency_code'), currency_code),
        tax_percentage = CASE WHEN payload ? 'tax_percentage' AND payload->>'tax_percentage' IS NOT NULL THEN (payload->>'tax_percentage')::numeric ELSE tax_percentage END,
        service_charge_percentage = CASE WHEN payload ? 'service_charge_percentage' AND payload->>'service_charge_percentage' IS NOT NULL THEN (payload->>'service_charge_percentage')::numeric ELSE service_charge_percentage END,
        invoice_prefix = COALESCE((payload->>'invoice_prefix'), invoice_prefix),
        invoice_counter = CASE WHEN payload ? 'invoice_counter' AND payload->>'invoice_counter' IS NOT NULL THEN (payload->>'invoice_counter')::integer ELSE invoice_counter END,
        upi_id = CASE WHEN payload ? 'upi_id' THEN payload->>'upi_id' ELSE upi_id END,
        booking_url = CASE WHEN payload ? 'booking_url' THEN payload->>'booking_url' ELSE booking_url END,
        amenities = CASE 
            WHEN payload ? 'amenities' AND jsonb_typeof(payload->'amenities') = 'array' 
            THEN ARRAY(SELECT jsonb_array_elements_text(payload->'amenities')) 
            ELSE amenities 
        END,
        early_checkin_allowed = CASE WHEN payload ? 'early_checkin_allowed' THEN (payload->>'early_checkin_allowed')::boolean ELSE early_checkin_allowed END,
        late_checkout_allowed = CASE WHEN payload ? 'late_checkout_allowed' THEN (payload->>'late_checkout_allowed')::boolean ELSE late_checkout_allowed END,
        
        updated_at = now()
    WHERE id = p_hotel_id;

    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
        RAISE EXCEPTION 'Hotel update failed or no rows matched';
    END IF;

    -- Update Guest Info if provided in payload
    IF payload ? 'wifi_ssid' OR payload ? 'wifi_password' OR payload ? 'breakfast_start' OR payload ? 'breakfast_end' OR payload ? 'guest_notes' THEN
        UPDATE public.hotel_guest_info
        SET
            wifi_ssid = CASE WHEN payload ? 'wifi_ssid' THEN payload->>'wifi_ssid' ELSE wifi_ssid END,
            wifi_password = CASE WHEN payload ? 'wifi_password' THEN payload->>'wifi_password' ELSE wifi_password END,
            breakfast_start = CASE WHEN payload ? 'breakfast_start' THEN CAST(NULLIF(payload->>'breakfast_start', '') AS time) ELSE breakfast_start END,
            breakfast_end = CASE WHEN payload ? 'breakfast_end' THEN CAST(NULLIF(payload->>'breakfast_end', '') AS time) ELSE breakfast_end END,
            notes = CASE WHEN payload ? 'guest_notes' THEN payload->>'guest_notes' ELSE notes END,
            updated_at = now()
        WHERE hotel_id = p_hotel_id;
        
        -- If update affected 0 rows (missing relation), then insert
        IF NOT FOUND THEN
            INSERT INTO public.hotel_guest_info (
                hotel_id, 
                wifi_ssid, 
                wifi_password, 
                breakfast_start, 
                breakfast_end, 
                notes
            )
            VALUES (
                p_hotel_id,
                payload->>'wifi_ssid',
                payload->>'wifi_password',
                CAST(NULLIF(payload->>'breakfast_start', '') AS time),
                CAST(NULLIF(payload->>'breakfast_end', '') AS time),
                payload->>'guest_notes'
            );
        END IF;
    END IF;

    -- Audit Log the Update
    INSERT INTO public.hotel_audit_logs (
        hotel_id, user_id, action, entity_type, entity_id, changes, created_at
    )
    VALUES (
        p_hotel_id,
        auth.uid(),
        p_action,
        'hotels',
        p_hotel_id,
        jsonb_build_object('updated_fields', payload),
        now()
    );

    RETURN p_hotel_id;
END;
$_$;


ALTER FUNCTION "public"."update_hotel_settings_onboarding"("p_hotel_id" "uuid", "payload" "jsonb", "p_action" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_menu_item"("p_item_id" "uuid", "p_hotel_id" "uuid", "p_name" "text", "p_category_id" "uuid", "p_price" numeric, "p_is_veg" boolean, "p_active" boolean, "p_metadata" "jsonb", "p_internal_notes" "text", "p_availability_days" integer[], "p_start_time" time without time zone, "p_end_time" time without time zone, "p_hide_outside" boolean) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    -- --------------------------------------------------------
    -- 0. AUTHORIZATION
    -- --------------------------------------------------------
    IF NOT EXISTS (
        SELECT 1
        FROM hotel_members hm
        JOIN hotel_member_roles hmr ON hmr.hotel_member_id = hm.id
        JOIN hotel_roles r ON r.id = hmr.role_id
        JOIN menu_items mi ON mi.hotel_id = hm.hotel_id
        WHERE mi.id = p_item_id
          AND hm.hotel_id = p_hotel_id
          AND hm.user_id = auth.uid()
          AND r.code IN ('OWNER', 'ADMIN', 'KITCHEN_MANAGER')
    ) THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Unauthorized menu item update',
            ERRCODE = 'P1001';
    END IF;

    -- --------------------------------------------------------
    -- 1. VALIDATION
    -- --------------------------------------------------------
    IF p_name IS NULL OR trim(p_name) = '' THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Item name cannot be empty',
            ERRCODE = 'P1002';
    END IF;

    IF p_price < 0 THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Price must be non-negative',
            ERRCODE = 'P1002';
    END IF;

    IF p_start_time >= p_end_time THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Start time must be before end time',
            ERRCODE = 'P1002';
    END IF;

    IF p_availability_days IS NOT NULL
       AND EXISTS (
           SELECT 1 FROM unnest(p_availability_days) d
           WHERE d < 1 OR d > 7
       ) THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Availability days must be between 1 and 7',
            ERRCODE = 'P1002';
    END IF;

    IF NOT EXISTS (
        SELECT 1
        FROM menu_categories
        WHERE id = p_category_id
          AND hotel_id = p_hotel_id
          AND active = true
    ) THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Invalid or inactive category',
            ERRCODE = 'P1003';
    END IF;

    -- --------------------------------------------------------
    -- 2. UPDATE MENU ITEM (NO item_key change)
    -- --------------------------------------------------------
    UPDATE menu_items
    SET
        name = p_name,
        category_id = p_category_id,
        price = p_price,
        is_veg = p_is_veg,
        active = p_active,
        metadata = COALESCE(
          '{"veg":false,"jain":false,"vegan":false}'::jsonb || p_metadata,
          '{"veg":false,"jain":false,"vegan":false}'::jsonb
        ),
        internal_notes = p_internal_notes,
        updated_at = now()
    WHERE id = p_item_id
      AND hotel_id = p_hotel_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION USING
            MESSAGE = 'Menu item not found',
            ERRCODE = 'P1004';
    END IF;

    -- --------------------------------------------------------
    -- 3. REPLACE AVAILABILITY
    -- --------------------------------------------------------
    DELETE FROM menu_item_availability
    WHERE menu_item_id = p_item_id;

    IF p_availability_days IS NOT NULL
       AND array_length(p_availability_days, 1) > 0 THEN

        INSERT INTO menu_item_availability (
            menu_item_id,
            day_of_week,
            start_time,
            end_time,
            hide_outside_window
        )
        SELECT
            p_item_id,
            d.day,
            p_start_time,
            p_end_time,
            p_hide_outside
        FROM unnest(p_availability_days) AS d(day);

    END IF;
END;
$$;


ALTER FUNCTION "public"."update_menu_item"("p_item_id" "uuid", "p_hotel_id" "uuid", "p_name" "text", "p_category_id" "uuid", "p_price" numeric, "p_is_veg" boolean, "p_active" boolean, "p_metadata" "jsonb", "p_internal_notes" "text", "p_availability_days" integer[], "p_start_time" time without time zone, "p_end_time" time without time zone, "p_hide_outside" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_shift"("p_shift_id" "uuid", "p_start" timestamp with time zone, "p_end" timestamp with time zone, "p_type" "text", "p_zone" "uuid", "p_version" integer, "p_user" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
declare v record;
begin
  select * into v from public.staff_shifts where id = p_shift_id for update;

  if not found then raise exception 'Shift not found'; end if;
  if v.version != p_version then raise exception 'Version mismatch'; end if;

  if p_type not in ('morning','evening','night') then
    raise exception 'Invalid shift type';
  end if;

  if v.locked_at is not null
     and v.locked_at > now() - interval '5 minutes'
     and v.locked_by is distinct from p_user then
    raise exception 'Locked';
  end if;

  if v.status != 'scheduled' or v.is_active != true then
    raise exception 'Not editable';
  end if;

  if p_end <= p_start then raise exception 'Invalid time'; end if;

  update public.staff_shifts
  set shift_start = p_start,
      shift_end = p_end,
      shift_type = p_type,
      zone_id = p_zone
  where id = p_shift_id;

exception when exclusion_violation then
  raise exception 'Overlap';
end;
$$;


ALTER FUNCTION "public"."update_shift"("p_shift_id" "uuid", "p_start" timestamp with time zone, "p_end" timestamp with time zone, "p_type" "text", "p_zone" "uuid", "p_version" integer, "p_user" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_ticket_sla_statuses"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Only update breaches for tickets without SLA exception that are NOT completed/cancelled
  UPDATE ticket_sla_state ss
  SET
    breached = true,
    breached_at = COALESCE(breached_at, clock_timestamp())
  FROM tickets t
  JOIN sla_policies sp
    ON sp.department_id = t.service_department_id
  WHERE ss.ticket_id = t.id
    AND t.status NOT IN ('COMPLETED', 'CANCELLED')
    AND ss.breached = false
    AND ss.sla_started_at IS NOT NULL
    AND ss.sla_paused_at IS NULL
    AND NOT EXISTS (
      SELECT 1
      FROM ticket_events te
      WHERE te.ticket_id = t.id
        AND te.event_type = 'SLA_EXCEPTION_GRANTED'
    )
    AND (
      (sp.target_minutes * 60)
      - (
          EXTRACT(EPOCH FROM (clock_timestamp() - ss.sla_started_at))::INT
          - COALESCE(ss.total_paused_seconds, 0)
      )
    ) <= 0;
END;
$$;


ALTER FUNCTION "public"."update_ticket_sla_statuses"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."update_ticket_sla_statuses"() IS 'SLA breach cron function that marks tickets as breached.
EXCLUDES tickets with SLA_EXCEPTION_GRANTED event (event-derived exemption).
Run every minute via pg_cron.';



CREATE OR REPLACE FUNCTION "public"."upsert_department_sla"("p_department_id" "uuid", "p_target_minutes" integer, "p_warn_minutes" integer, "p_escalate_minutes" integer, "p_sla_start_trigger" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_existing_sla_id UUID;
  v_new_sla_id UUID;
BEGIN
  -- ============================================================
  -- Step 1: Check if current active SLA has identical values
  -- If so, return existing ID (no-op prevention)
  -- ============================================================
  SELECT id INTO v_existing_sla_id
  FROM sla_policies
  WHERE department_id = p_department_id
    AND valid_to IS NULL
    AND is_active = true
    AND target_minutes = p_target_minutes
    AND warn_minutes = p_warn_minutes
    AND escalate_minutes = p_escalate_minutes
    AND sla_start_trigger = p_sla_start_trigger;

  -- If values are identical, return existing SLA (no versioning needed)
  IF v_existing_sla_id IS NOT NULL THEN
    RETURN v_existing_sla_id;
  END IF;

  -- ============================================================
  -- Step 2: Mark existing active SLA as inactive (if exists)
  -- ============================================================
  UPDATE sla_policies
  SET 
    valid_to = now(),
    is_active = false,
    updated_at = now()
  WHERE department_id = p_department_id
    AND valid_to IS NULL
    AND is_active = true;

  -- ============================================================
  -- Step 3: Insert new SLA policy
  -- ============================================================
  INSERT INTO sla_policies (
    department_id,
    target_minutes,
    warn_minutes,
    escalate_minutes,
    sla_start_trigger,
    valid_from,
    valid_to,
    is_active,
    created_at,
    updated_at
  )
  VALUES (
    p_department_id,
    p_target_minutes,
    p_warn_minutes,
    p_escalate_minutes,
    p_sla_start_trigger,
    now(),
    NULL,
    true,
    now(),
    now()
  )
  RETURNING id INTO v_new_sla_id;

  RETURN v_new_sla_id;
END;
$$;


ALTER FUNCTION "public"."upsert_department_sla"("p_department_id" "uuid", "p_target_minutes" integer, "p_warn_minutes" integer, "p_escalate_minutes" integer, "p_sla_start_trigger" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."upsert_department_sla"("p_department_id" "uuid", "p_target_minutes" integer, "p_warn_minutes" integer, "p_escalate_minutes" integer, "p_sla_start_trigger" "text") IS 'Upserts SLA policy for a department with historical tracking. 
Prevents no-op versioning by checking if values are identical.
Marks old SLA as inactive and creates new version if values changed.';



CREATE OR REPLACE FUNCTION "public"."upsert_guest_v2"("p_guest_details" "jsonb", "p_hotel_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_guest_id UUID;
    v_mobile TEXT;
    v_email TEXT;
    v_mobile_norm TEXT;
    v_doc_type public.guest_document_type;
    v_full_name TEXT;
BEGIN
    -- 1. Normalize Inputs
    v_full_name := NULLIF(trim(COALESCE(p_guest_details->>'full_name', p_guest_details->>'guest_name')), '');
    v_mobile := NULLIF(regexp_replace(COALESCE(p_guest_details->>'mobile', p_guest_details->>'phone'), '[^0-9]', '', 'g'), '');
    v_email := NULLIF(lower(trim(p_guest_details->>'email')), '');
    v_mobile_norm := v_mobile; -- Character-stripping IS the normalization in this schema

    -- Mobile validation guard (from original create_walkin_v2)
    IF v_mobile_norm IS NOT NULL AND length(v_mobile_norm) < 6 THEN
      RAISE EXCEPTION 'A valid mobile number (min 6 digits) is required';
    END IF;

    -- 2. Lookup existing guest (Global)
    -- Priority 1: mobile_normalized
    IF v_mobile_norm IS NOT NULL AND v_mobile_norm != '' THEN
        SELECT id INTO v_guest_id FROM public.guests WHERE mobile_normalized = v_mobile_norm ORDER BY created_at LIMIT 1;
    END IF;

    -- Priority 2: email
    IF v_guest_id IS NULL AND v_email IS NOT NULL AND v_email != '' THEN
        SELECT id INTO v_guest_id FROM public.guests WHERE lower(email) = v_email ORDER BY created_at LIMIT 1;
    END IF;

    -- 3. Upsert Logic
    IF v_guest_id IS NOT NULL THEN
        UPDATE public.guests
        SET 
            full_name = COALESCE(NULLIF(v_full_name, ''), full_name),
            email = COALESCE(NULLIF(v_email, ''), email),
            mobile = COALESCE(NULLIF(v_mobile, ''), mobile),
            nationality = COALESCE(NULLIF(trim(p_guest_details->>'nationality'), ''), nationality),
            address = COALESCE(NULLIF(trim(p_guest_details->>'address'), ''), address),
            updated_at = now()
        WHERE id = v_guest_id;
    ELSE
        INSERT INTO public.guests (
            full_name, 
            mobile, 
            mobile_normalized,
            email, 
            nationality, 
            address
        )
        VALUES (
            COALESCE(v_full_name, 'Guest'), 
            v_mobile, 
            v_mobile_norm,
            v_email, 
            NULLIF(trim(p_guest_details->>'nationality'), ''), 
            NULLIF(trim(p_guest_details->>'address'), '')
        )
        ON CONFLICT (mobile) WHERE mobile IS NOT NULL 
        DO UPDATE SET
            full_name = EXCLUDED.full_name,
            email = COALESCE(EXCLUDED.email, guests.email),
            updated_at = now()
        RETURNING id INTO v_guest_id;
    END IF;

    -- 4. Hardened Identity Documents (Privacy & Concurrency Aware)
    IF coalesce(p_guest_details->>'front_image_path', '') != '' THEN
        -- Link doc type
        v_doc_type := COALESCE((p_guest_details->>'id_type')::guest_document_type, 'other');
        BEGIN
            -- IF duplicate exists with same front_hash and is active, skip insertion
            IF NOT EXISTS (
              SELECT 1 FROM public.guest_id_documents
              WHERE guest_id = v_guest_id
                AND document_type = v_doc_type
                AND front_hash = p_guest_details->>'front_hash'
                AND is_active = true
            ) THEN
                -- Deactivate previous active doc with concurrency lock
                UPDATE public.guest_id_documents
                SET is_active = false
                WHERE id IN (
                    SELECT id
                    FROM public.guest_id_documents
                    WHERE guest_id = v_guest_id
                      AND document_type = v_doc_type
                      AND is_active = true
                    FOR UPDATE
                );

                -- Insert New Hardened Document
                INSERT INTO public.guest_id_documents (
                    guest_id, 
                    document_type, 
                    document_number_masked, 
                    front_image_url, 
                    back_image_url, 
                    storage_key,
                    front_hash,
                    back_hash,
                    issuing_country,
                    verification_status, 
                    is_active
                )
                VALUES (
                    v_guest_id,
                    v_doc_type,
                    CASE 
                        WHEN length(p_guest_details->>'id_number') > 4
                        THEN repeat('X', length(p_guest_details->>'id_number') - 4) || right(p_guest_details->>'id_number', 4)
                        ELSE p_guest_details->>'id_number'
                    END,
                    p_guest_details->>'front_image_path',
                    p_guest_details->>'back_image_path',
                    NULLIF(p_guest_details->>'storage_key', '')::UUID,
                    p_guest_details->>'front_hash',
                    p_guest_details->>'back_hash',
                    p_guest_details->>'issuing_country',
                    'pending',
                    true
                );
            END IF;
        END;
    END IF;

    RETURN v_guest_id;
END;
$$;


ALTER FUNCTION "public"."upsert_guest_v2"("p_guest_details" "jsonb", "p_hotel_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_feedback_token"("p_token" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_record RECORD;
BEGIN
    -- Find token with booking + hotel context
    SELECT
        ft.id AS token_id,
        ft.booking_id,
        ft.hotel_id,
        ft.expires_at,
        ft.used_at,
        b.code AS booking_code,
        b.guest_name,
        b.scheduled_checkin_at,
        b.scheduled_checkout_at,
        b.guest_id,
        h.name AS hotel_name,
        h.slug AS hotel_slug
    INTO v_record
    FROM public.feedback_tokens ft
    JOIN public.bookings b ON b.id = ft.booking_id
    JOIN public.hotels h ON h.id = ft.hotel_id
    WHERE ft.token = p_token;

    -- Token not found
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'valid', false,
            'error', 'Invalid feedback link'
        );
    END IF;

    -- Token already used (one-time submission)
    IF v_record.used_at IS NOT NULL THEN
        RETURN jsonb_build_object(
            'valid', false,
            'error', 'Feedback has already been submitted. Thank you!',
            'already_submitted', true,
            'submitted_at', v_record.used_at
        );
    END IF;

    -- Token expired
    IF v_record.expires_at IS NOT NULL AND v_record.expires_at < now() THEN
        RETURN jsonb_build_object(
            'valid', false,
            'error', 'This feedback link has expired'
        );
    END IF;

    -- Valid — return context for the feedback form
    RETURN jsonb_build_object(
        'valid', true,
        'token_id', v_record.token_id,
        'booking_id', v_record.booking_id,
        'booking_code', v_record.booking_code,
        'guest_name', v_record.guest_name,
        'hotel_id', v_record.hotel_id,
        'hotel_name', v_record.hotel_name,
        'hotel_slug', v_record.hotel_slug,
        'checkin_date', v_record.scheduled_checkin_at,
        'checkout_date', v_record.scheduled_checkout_at,
        'guest_id', v_record.guest_id
    );
END;
$$;


ALTER FUNCTION "public"."validate_feedback_token"("p_token" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_hotel_invite"("p_token" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_invite RECORD;
BEGIN
    SELECT 
        hi.email,
        hi.status,
        hi.expires_at,
        hi.hotel_id,
        h.name as hotel_name,
        hr.code as role_code,
        hr.name as role_name
    INTO v_invite
    FROM public.hotel_invites hi
    JOIN public.hotels h ON h.id = hi.hotel_id
    JOIN public.hotel_roles hr ON hr.id = hi.role_id
    WHERE hi.token = p_token;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('valid', false, 'error', 'Invite not found');
    END IF;

    IF v_invite.status <> 'pending' THEN
        RETURN jsonb_build_object('valid', false, 'error', 'Invite already used or revoked');
    END IF;

    IF v_invite.expires_at < now() THEN
        RETURN jsonb_build_object('valid', false, 'error', 'Invite has expired');
    END IF;

    RETURN jsonb_build_object(
        'valid', true,
        'email', v_invite.email,
        'hotel_id', v_invite.hotel_id,
        'hotel_name', v_invite.hotel_name,
        'role_code', v_invite.role_code,
        'role_name', v_invite.role_name
    );
END;
$$;


ALTER FUNCTION "public"."validate_hotel_invite"("p_token" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_precheckin_token"("p_token" "text", "p_hotel_id" "uuid" DEFAULT NULL::"uuid", "p_ignore_usage" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_token_record RECORD;
BEGIN
  -- Find valid token (with concurrency lock - Blocking FOR UPDATE to ensure consistency)
  SELECT
    pt.id AS token_id,
    pt.booking_id,
    pt.expires_at,
    pt.used_at,
    pt.precheckin_data,
    b.code AS booking_code,
    b.guest_name,
    COALESCE(g.mobile, b.phone) AS phone,
    COALESCE(g.email, b.email, (SELECT email FROM profiles WHERE id = b.guest_profile_id)) AS email,
    b.scheduled_checkin_at,
    b.scheduled_checkout_at,
    b.status AS booking_status,
    b.adults_total,
    b.children_total,
    b.rooms_total,
    b.guest_id,
    h.id AS hotel_id,
    h.name AS hotel_name,
    h.phone AS hotel_phone,
    h.address AS hotel_address,
    h.latitude AS hotel_latitude,
    h.longitude AS hotel_longitude,
    (SELECT rt.name FROM booking_rooms br
     JOIN room_types rt ON rt.id = br.room_type_id
     WHERE br.booking_id = b.id
     ORDER BY br.room_seq LIMIT 1) AS room_type_name,
    (SELECT br.room_type_id FROM booking_rooms br
     WHERE br.booking_id = b.id
     ORDER BY br.room_seq LIMIT 1) AS room_type_id,
    (SELECT br.room_id FROM booking_rooms br
     WHERE br.booking_id = b.id
     ORDER BY br.room_seq LIMIT 1) AS room_id,
    g.nationality,
    g.address,
    (SELECT jsonb_build_object(
        'type', gid.document_type,
        'number', gid.document_number_masked,
        'front_image', gid.front_image_url,
        'back_image', gid.back_image_url
     )
     FROM guest_id_documents gid
     WHERE gid.guest_id = b.guest_id
     ORDER BY gid.updated_at DESC LIMIT 1
    ) AS identity_proof
  INTO v_token_record
  FROM precheckin_tokens pt
  JOIN bookings b ON b.id = pt.booking_id
  JOIN hotels h ON h.id = b.hotel_id
  LEFT JOIN guests g ON g.id = b.guest_id
  WHERE pt.token = p_token
    AND (p_hotel_id IS NULL OR pt.hotel_id = p_hotel_id)
  FOR UPDATE OF pt;

  -- Token not found
  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'valid', false,
      'error', 'Invalid token'
    );
  END IF;

  -- Token already used (Bypass if p_ignore_usage is TRUE)
  IF v_token_record.used_at IS NOT NULL AND NOT p_ignore_usage THEN
    RETURN jsonb_build_object(
      'valid', false,
      'error', 'Pre-check-in already completed',
      'completed_at', v_token_record.used_at
    );
  END IF;

  -- Token expired (NEVER bypassed by p_ignore_usage)
  IF v_token_record.expires_at IS NOT NULL 
     AND v_token_record.expires_at < now() THEN
    RETURN jsonb_build_object(
      'valid', false,
      'error', 'This link has expired'
    );
  END IF;

  -- Valid — return booking details
  RETURN jsonb_build_object(
    'valid', true,
    'token_id', v_token_record.token_id,
    'booking_id', v_token_record.booking_id,
    'id', v_token_record.booking_id,
    'code', v_token_record.booking_code,
    'booking_code', v_token_record.booking_code,
    'guest_name', v_token_record.guest_name,
    'phone', v_token_record.phone,
    'email', v_token_record.email,
    'scheduled_checkin_at', v_token_record.scheduled_checkin_at,
    'scheduled_checkout_at', v_token_record.scheduled_checkout_at,
    'status', v_token_record.booking_status,
    'booking_status', v_token_record.booking_status,
    'hotel_id', v_token_record.hotel_id,
    'hotel_name', v_token_record.hotel_name,
    'hotel_phone', v_token_record.hotel_phone,
    'hotel_address', v_token_record.hotel_address,
    'hotel_latitude', v_token_record.hotel_latitude,
    'hotel_longitude', v_token_record.hotel_longitude,
    'adults', COALESCE(v_token_record.adults_total, 1),
    'children', COALESCE(v_token_record.children_total, 0),
    'rooms_total', COALESCE(v_token_record.rooms_total, 1),
    'room_type', v_token_record.room_type_name,
    'room_type_id', v_token_record.room_type_id,
    'room_id', v_token_record.room_id,
    'guest_id', v_token_record.guest_id,
    'nationality', v_token_record.nationality,
    'address', v_token_record.address,
    'identity_proof', v_token_record.identity_proof,
    'precheckin_completed', (v_token_record.used_at IS NOT NULL),
    'precheckin_data', v_token_record.precheckin_data
  );
END;
$$;


ALTER FUNCTION "public"."validate_precheckin_token"("p_token" "text", "p_hotel_id" "uuid", "p_ignore_usage" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."vip_arrivals_for_slug"("p_slug" "text") RETURNS TABLE("stay_id" "uuid", "room" "text", "is_vip" boolean, "has_open_complaint" boolean, "needs_courtesy_call" boolean, "check_in_start" timestamp with time zone, "check_out_end" timestamp with time zone)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    s.id as stay_id,
    s.room,
    s.is_vip,
    s.has_open_complaint,
    s.needs_courtesy_call,
    s.check_in_start,
    s.check_out_end
  from public.hotels h
  join public.stays s
    on s.hotel_id = h.id
  where h.slug = p_slug
    and s.check_in_start::date = current_date
    and (
      s.is_vip
      or s.has_open_complaint
      or s.needs_courtesy_call
    )
  order by s.check_in_start;
$$;


ALTER FUNCTION "public"."vip_arrivals_for_slug"("p_slug" "text") OWNER TO "postgres";


