CREATE OR REPLACE VIEW "public"."grid_device_energy_samples" AS
 WITH "ordered" AS (
         SELECT "r"."id",
            "r"."device_id",
            "d"."hotel_id",
            "d"."zone",
            "d"."device_type",
            "date_trunc"('day'::"text", "r"."reading_at") AS "day",
            "r"."reading_at",
            "lead"("r"."reading_at") OVER (PARTITION BY "r"."device_id" ORDER BY "r"."reading_at") AS "next_at",
            COALESCE("r"."power_kw", "d"."power_kw", "d"."capacity_kw", (0)::numeric) AS "sample_kw",
            "r"."source"
           FROM ("public"."grid_readings" "r"
             JOIN "public"."grid_devices" "d" ON (("d"."id" = "r"."device_id")))
        ), "with_interval" AS (
         SELECT "ordered"."id",
            "ordered"."device_id",
            "ordered"."hotel_id",
            "ordered"."zone",
            "ordered"."device_type",
            "ordered"."day",
            "ordered"."reading_at",
            "ordered"."next_at",
            "ordered"."sample_kw",
            "ordered"."source",
            COALESCE("ordered"."next_at", ("ordered"."reading_at" + '00:15:00'::interval)) AS "effective_next_at"
           FROM "ordered"
        )
 SELECT "device_id",
    "hotel_id",
    "zone",
    "device_type",
    ("day")::"date" AS "day",
    "reading_at",
    "effective_next_at",
    (EXTRACT(epoch FROM ("effective_next_at" - "reading_at")) / 3600.0) AS "hours",
    "sample_kw",
    ("sample_kw" * (EXTRACT(epoch FROM ("effective_next_at" - "reading_at")) / 3600.0)) AS "energy_kwh",
    "source"
   FROM "with_interval";


ALTER VIEW "public"."grid_device_energy_samples" OWNER TO "postgres";


COMMENT ON VIEW "public"."grid_device_energy_samples" IS 'Per-reading energy approximation for each grid device (kWh per sample).';



CREATE OR REPLACE VIEW "public"."grid_device_energy_daily" AS
 SELECT "device_id",
    "hotel_id",
    "zone",
    "device_type",
    "day",
    "sum"("energy_kwh") AS "energy_kwh",
    "sum"("hours") AS "hours_covered",
    "avg"("sample_kw") AS "avg_kw",
    "min"("reading_at") AS "first_sample_at",
    "max"("effective_next_at") AS "last_sample_at"
   FROM "public"."grid_device_energy_samples"
  GROUP BY "device_id", "hotel_id", "zone", "device_type", "day";


ALTER VIEW "public"."grid_device_energy_daily" OWNER TO "postgres";


COMMENT ON VIEW "public"."grid_device_energy_daily" IS 'Daily energy (kWh) per device derived from grid_device_energy_samples.';



CREATE OR REPLACE VIEW "public"."grid_device_waste_daily" AS
 WITH "classified" AS (
         SELECT "s"."device_id",
            "s"."hotel_id",
            "s"."zone",
            "s"."device_type",
            "s"."day",
            "s"."reading_at",
            "s"."effective_next_at",
            "s"."hours",
            "s"."sample_kw",
            "s"."energy_kwh",
            "s"."source",
                CASE
                    WHEN ((EXTRACT(hour FROM "s"."reading_at") >= (0)::numeric) AND (EXTRACT(hour FROM "s"."reading_at") <= (5)::numeric)) THEN 'night'::"text"
                    WHEN ((EXTRACT(hour FROM "s"."reading_at") >= (18)::numeric) AND (EXTRACT(hour FROM "s"."reading_at") <= (21)::numeric)) THEN 'peak_evening'::"text"
                    ELSE 'day'::"text"
                END AS "period"
           FROM "public"."grid_device_energy_samples" "s"
        ), "agg" AS (
         SELECT "classified"."device_id",
            "classified"."hotel_id",
            "classified"."zone",
            "classified"."device_type",
            "classified"."day",
            "sum"("classified"."energy_kwh") AS "total_kwh",
            "sum"("classified"."energy_kwh") FILTER (WHERE ("classified"."period" = 'night'::"text")) AS "night_kwh",
            "sum"("classified"."energy_kwh") FILTER (WHERE ("classified"."period" = 'peak_evening'::"text")) AS "peak_kwh"
           FROM "classified"
          GROUP BY "classified"."device_id", "classified"."hotel_id", "classified"."zone", "classified"."device_type", "classified"."day"
        )
 SELECT "device_id",
    "hotel_id",
    "zone",
    "device_type",
    "day",
    "total_kwh",
    "night_kwh",
    "peak_kwh",
        CASE
            WHEN (("total_kwh" IS NULL) OR ("total_kwh" <= (0)::numeric)) THEN (0)::numeric
            ELSE LEAST((100)::numeric, "round"(((COALESCE("night_kwh", (0)::numeric) / "total_kwh") * 100.0)))
        END AS "waste_score"
   FROM "agg";


ALTER VIEW "public"."grid_device_waste_daily" OWNER TO "postgres";


COMMENT ON VIEW "public"."grid_device_waste_daily" IS 'Daily "waste" metrics per device: total_kwh, night_kwh, peak_kwh, simple waste_score (0–100).';



CREATE OR REPLACE VIEW "public"."grid_silent_killers_top5" AS
 WITH "ranked" AS (
         SELECT "grid_device_waste_daily"."device_id",
            "grid_device_waste_daily"."hotel_id",
            "grid_device_waste_daily"."zone",
            "grid_device_waste_daily"."device_type",
            "grid_device_waste_daily"."day",
            "grid_device_waste_daily"."total_kwh",
            "grid_device_waste_daily"."night_kwh",
            "grid_device_waste_daily"."peak_kwh",
            "grid_device_waste_daily"."waste_score",
            "rank"() OVER (PARTITION BY "grid_device_waste_daily"."hotel_id", "grid_device_waste_daily"."day" ORDER BY "grid_device_waste_daily"."waste_score" DESC, "grid_device_waste_daily"."total_kwh" DESC) AS "r"
           FROM "public"."grid_device_waste_daily"
        )
 SELECT "device_id",
    "hotel_id",
    "zone",
    "device_type",
    "day",
    "total_kwh",
    "night_kwh",
    "peak_kwh",
    "waste_score",
    "r" AS "rank_within_hotel"
   FROM "ranked"
  WHERE ("r" <= 5);


ALTER VIEW "public"."grid_silent_killers_top5" OWNER TO "postgres";


COMMENT ON VIEW "public"."grid_silent_killers_top5" IS 'Top-5 high-waste devices per hotel/day (ranked by waste_score and total_kwh).';



CREATE OR REPLACE VIEW "public"."grid_zone_energy_daily" AS
 SELECT "hotel_id",
    COALESCE("zone", 'Unassigned'::"text") AS "zone",
    "day",
    "sum"("energy_kwh") AS "energy_kwh",
    "sum"("hours_covered") AS "hours_covered"
   FROM "public"."grid_device_energy_daily"
  GROUP BY "hotel_id", COALESCE("zone", 'Unassigned'::"text"), "day";


ALTER VIEW "public"."grid_zone_energy_daily" OWNER TO "postgres";


COMMENT ON VIEW "public"."grid_zone_energy_daily" IS 'Daily energy (kWh) aggregated per zone for each hotel.';



