CREATE MATERIALIZED VIEW "public"."owner_dashboard_kpis" AS
 WITH "today" AS (
         SELECT ((CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Kolkata'::"text"))::"date" AS "as_of_date"
        ), "hotel_set" AS (
         SELECT "h"."id" AS "hotel_id",
            "h"."slug" AS "hotel_slug",
            "h"."name" AS "hotel_name"
           FROM "public"."hotels" "h"
        ), "rooms_today" AS (
         SELECT "b"."hotel_id",
            "t"."as_of_date",
            ("count"(*))::integer AS "occupied_today"
           FROM ("public"."bookings" "b"
             CROSS JOIN "today" "t")
          WHERE (("date"("b"."scheduled_checkin_at") <= "t"."as_of_date") AND ("date"("b"."scheduled_checkout_at") > "t"."as_of_date"))
          GROUP BY "b"."hotel_id", "t"."as_of_date"
        ), "orders_today" AS (
         SELECT "o"."hotel_id",
            "t"."as_of_date",
            ("count"(*))::integer AS "orders_today",
            COALESCE("sum"((COALESCE("o"."price", (0)::numeric) * (GREATEST(COALESCE("o"."qty", 1), 1))::numeric)), (0)::numeric) AS "revenue_today"
           FROM ("public"."orders" "o"
             CROSS JOIN "today" "t")
          WHERE ((("o"."created_at" AT TIME ZONE 'Asia/Kolkata'::"text"))::"date" = "t"."as_of_date")
          GROUP BY "o"."hotel_id", "t"."as_of_date"
        ), "pickup_7d" AS (
         SELECT "b"."hotel_id",
            "t"."as_of_date",
            ("count"(*))::integer AS "pickup_7d"
           FROM ("public"."bookings" "b"
             CROSS JOIN "today" "t")
          WHERE (("date"("b"."scheduled_checkin_at") >= ("t"."as_of_date" - '6 days'::interval)) AND ("date"("b"."scheduled_checkin_at") <= "t"."as_of_date"))
          GROUP BY "b"."hotel_id", "t"."as_of_date"
        ), "rating_30d" AS (
         SELECT "r"."hotel_id",
            "t"."as_of_date",
            ("avg"("r"."rating"))::numeric(4,2) AS "avg_rating_30d"
           FROM ("public"."reviews" "r"
             CROSS JOIN "today" "t")
          WHERE (((("r"."created_at" AT TIME ZONE 'Asia/Kolkata'::"text"))::"date" >= ("t"."as_of_date" - '30 days'::interval)) AND ((("r"."created_at" AT TIME ZONE 'Asia/Kolkata'::"text"))::"date" <= "t"."as_of_date"))
          GROUP BY "r"."hotel_id", "t"."as_of_date"
        ), "final" AS (
         SELECT "h"."hotel_id",
            "h"."hotel_slug",
            "h"."hotel_name",
            "t"."as_of_date",
            COALESCE("rt"."occupied_today", 0) AS "occupied_today",
            COALESCE("ot"."orders_today", 0) AS "orders_today",
            COALESCE("ot"."revenue_today", (0)::numeric) AS "revenue_today",
            COALESCE("pk"."pickup_7d", 0) AS "pickup_7d",
            "r30"."avg_rating_30d",
            "now"() AS "updated_at"
           FROM ((((("hotel_set" "h"
             CROSS JOIN "today" "t")
             LEFT JOIN "rooms_today" "rt" ON ((("rt"."hotel_id" = "h"."hotel_id") AND ("rt"."as_of_date" = "t"."as_of_date"))))
             LEFT JOIN "orders_today" "ot" ON ((("ot"."hotel_id" = "h"."hotel_id") AND ("ot"."as_of_date" = "t"."as_of_date"))))
             LEFT JOIN "pickup_7d" "pk" ON ((("pk"."hotel_id" = "h"."hotel_id") AND ("pk"."as_of_date" = "t"."as_of_date"))))
             LEFT JOIN "rating_30d" "r30" ON ((("r30"."hotel_id" = "h"."hotel_id") AND ("r30"."as_of_date" = "t"."as_of_date"))))
        )
 SELECT "hotel_id",
    "hotel_slug",
    "hotel_name",
    "as_of_date",
    "occupied_today",
    "orders_today",
    "revenue_today",
    "pickup_7d",
    "avg_rating_30d",
    "updated_at"
   FROM "final"
  WITH NO DATA;


ALTER MATERIALIZED VIEW "public"."owner_dashboard_kpis" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."owner_hotel_occupancy_daily" AS
 WITH "days" AS (
         SELECT "generate_series"(((("now"())::"date" - '29 days'::interval))::timestamp with time zone, (("now"())::"date")::timestamp with time zone, '1 day'::interval) AS "day_start"
        )
 SELECT "h"."id" AS "hotel_id",
    "h"."slug" AS "hotel_slug",
    "h"."name" AS "hotel_name",
    "h"."rooms_total",
    ("d"."day_start")::"date" AS "day",
    "count"("b"."id") AS "occupied_rooms",
        CASE
            WHEN (COALESCE("h"."rooms_total", 0) > 0) THEN "round"(((("count"("b"."id"))::numeric / ("h"."rooms_total")::numeric) * (100)::numeric), 1)
            ELSE (0)::numeric
        END AS "occupancy_percent"
   FROM (("public"."hotels" "h"
     CROSS JOIN "days" "d")
     LEFT JOIN "public"."bookings" "b" ON ((("b"."hotel_id" = "h"."id") AND ("b"."scheduled_checkin_at" <= "d"."day_start") AND ("b"."scheduled_checkout_at" > "d"."day_start"))))
  GROUP BY "h"."id", "h"."slug", "h"."name", "h"."rooms_total", "d"."day_start"
  ORDER BY "h"."slug", (("d"."day_start")::"date");


ALTER VIEW "public"."owner_hotel_occupancy_daily" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."owner_hotel_occupancy_snapshot" AS
 SELECT "h"."id" AS "hotel_id",
    "h"."slug" AS "hotel_slug",
    "h"."name" AS "hotel_name",
    "h"."rooms_total",
    "count"("b"."id") AS "occupied_rooms",
        CASE
            WHEN (COALESCE("h"."rooms_total", 0) > 0) THEN "round"(((("count"("b"."id"))::numeric / ("h"."rooms_total")::numeric) * (100)::numeric), 1)
            ELSE (0)::numeric
        END AS "occupancy_percent"
   FROM ("public"."hotels" "h"
     LEFT JOIN "public"."bookings" "b" ON ((("b"."hotel_id" = "h"."id") AND ("b"."scheduled_checkin_at" <= "now"()) AND ("b"."scheduled_checkout_at" > "now"()))))
  GROUP BY "h"."id", "h"."slug", "h"."name", "h"."rooms_total";


ALTER VIEW "public"."owner_hotel_occupancy_snapshot" OWNER TO "postgres";


