    "created_at",
    "closed_at" AS "completed_at"
   FROM "public"."orders" "o"
  WHERE ("closed_at" IS NOT NULL);


ALTER VIEW "public"."owner_orders_completed" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."owner_hotel_revenue_daily" AS
 SELECT "h"."id" AS "hotel_id",
    "h"."slug" AS "hotel_slug",
    "h"."name" AS "hotel_name",
    "date"("o"."completed_at") AS "day",
    "sum"("o"."line_total") AS "total_revenue"
   FROM ("public"."hotels" "h"
     JOIN "public"."owner_orders_completed" "o" ON (("o"."hotel_id" = "h"."id")))
  GROUP BY "h"."id", "h"."slug", "h"."name", ("date"("o"."completed_at"))
  ORDER BY "h"."slug", ("date"("o"."completed_at"));


ALTER VIEW "public"."owner_hotel_revenue_daily" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."owner_hotel_revenue_daily_split" AS
 SELECT "h"."id" AS "hotel_id",
    "h"."slug" AS "hotel_slug",
    "h"."name" AS "hotel_name",
    "date"("o"."completed_at") AS "day",
    "sum"(
        CASE
            WHEN ("o"."item_key" ~~* 'room%'::"text") THEN "o"."line_total"
            ELSE (0)::numeric
        END) AS "room_revenue",
    "sum"(
        CASE
            WHEN (("o"."item_key" ~~* 'fb%'::"text") OR ("o"."item_key" ~~* 'fnb%'::"text") OR ("o"."item_key" ~~* 'f&b%'::"text")) THEN "o"."line_total"
            ELSE (0)::numeric
        END) AS "fnb_revenue",
    "sum"("o"."line_total") AS "total_revenue"
   FROM ("public"."hotels" "h"
     JOIN "public"."owner_orders_completed" "o" ON (("o"."hotel_id" = "h"."id")))
  GROUP BY "h"."id", "h"."slug", "h"."name", ("date"("o"."completed_at"))
  ORDER BY "h"."slug", ("date"("o"."completed_at"));


ALTER VIEW "public"."owner_hotel_revenue_daily_split" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."owner_nps_30d" AS
 SELECT "hotel_id",
    ("count"(*))::integer AS "total_responses",
    ("sum"(
        CASE
            WHEN ("nps_score" >= 9) THEN 1
            ELSE 0
        END))::integer AS "promoters",
    ("sum"(
        CASE
            WHEN (("nps_score" >= 7) AND ("nps_score" <= 8)) THEN 1
            ELSE 0
        END))::integer AS "passives",
    ("sum"(
        CASE
            WHEN ("nps_score" <= 6) THEN 1
            ELSE 0
        END))::integer AS "detractors",
        CASE
            WHEN ("count"(*) = 0) THEN NULL::numeric
            ELSE (((("sum"(
            CASE
                WHEN ("nps_score" >= 9) THEN 1
                ELSE 0
            END) - "sum"(
            CASE
                WHEN ("nps_score" <= 6) THEN 1
                ELSE 0
            END)))::numeric / ("count"(*))::numeric) * (100)::numeric)
        END AS "nps_30d"
   FROM "public"."reviews" "r"
  WHERE (("created_at" >= (("now"() AT TIME ZONE 'utc'::"text") - '30 days'::interval)) AND ("nps_score" IS NOT NULL))
  GROUP BY "hotel_id";


ALTER VIEW "public"."owner_nps_30d" OWNER TO "postgres";


