CREATE OR REPLACE VIEW "public"."owner_revenue_daily_v" AS
 WITH "orders_daily" AS (
         SELECT "o"."hotel_id",
            ("date_trunc"('day'::"text", "o"."closed_at"))::"date" AS "day",
            "sum"(COALESCE("o"."price", (0)::numeric)) AS "room_revenue"
           FROM "public"."orders" "o"
          WHERE ("o"."closed_at" IS NOT NULL)
          GROUP BY "o"."hotel_id", (("date_trunc"('day'::"text", "o"."closed_at"))::"date")
        ), "rooms_sold_by_day" AS (
         SELECT "se"."hotel_id",
            "se"."day",
            ("count"(DISTINCT "se"."room_id"))::integer AS "rooms_sold"
           FROM ( SELECT "s"."hotel_id",
                    "s"."room_id",
                    ("gs"."d")::"date" AS "day"
                   FROM ("public"."stays" "s"
                     CROSS JOIN LATERAL "generate_series"((("date_trunc"('day'::"text", "s"."scheduled_checkin_at"))::"date")::timestamp with time zone, ((("date_trunc"('day'::"text", "s"."scheduled_checkout_at") - '1 day'::interval))::"date")::timestamp with time zone, '1 day'::interval) "gs"("d"))
                  WHERE (("s"."scheduled_checkin_at" IS NOT NULL) AND ("s"."scheduled_checkout_at" IS NOT NULL))) "se"
          GROUP BY "se"."hotel_id", "se"."day"
        ), "rooms_per_hotel" AS (
         SELECT "rooms"."hotel_id",
            ("count"(*))::integer AS "rooms_available"
           FROM "public"."rooms"
          GROUP BY "rooms"."hotel_id"
        )
 SELECT "od"."hotel_id",
    "od"."day",
    "r"."rooms_available",
    COALESCE("rs"."rooms_sold", 0) AS "rooms_sold",
    COALESCE("od"."room_revenue", 0.0) AS "room_revenue"
   FROM (("orders_daily" "od"
     LEFT JOIN "rooms_per_hotel" "r" ON (("r"."hotel_id" = "od"."hotel_id")))
     LEFT JOIN "rooms_sold_by_day" "rs" ON ((("rs"."hotel_id" = "od"."hotel_id") AND ("rs"."day" = "od"."day"))));


ALTER VIEW "public"."owner_revenue_daily_v" OWNER TO "postgres";


