CREATE OR REPLACE VIEW "public"."user_recent_stays" AS
 SELECT "stay_id" AS "id",
    "guest_id",
    "hotel_id",
    "booking_code",
    "is_vip",
    "is_active",
    "stay_status" AS "status",
    "lifecycle_phase",
