    "display_checkin_at",
    "display_checkout_at",
    "checkin_label",
    "checkout_label",
    "can_checkin",
    "can_request_service",
    "can_express_checkout",
    "can_order_food",
    "can_view_bill",
    "can_download_invoice",
    "can_book_again",
    "can_modify_booking",
    "can_cancel_booking",
    "badge_variant",
    "badge_text",
    NULL::numeric AS "bill_total",
    "created_at",
    "updated_at"
   FROM "public"."v_guest_stay_hero";


ALTER VIEW "public"."user_recent_stays" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."user_roles" (
    "user_id" "uuid" NOT NULL,
    "role" "text" NOT NULL
);


ALTER TABLE "public"."user_roles" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."user_stay_detail" AS
 SELECT "s"."id" AS "stay_id",
    "s"."guest_id" AS "user_id",
    "s"."hotel_id",
    "s"."scheduled_checkin_at" AS "checkin_at",
    "s"."scheduled_checkout_at" AS "checkout_at",
    "s"."actual_checkin_at",
    "s"."actual_checkout_at",
    "s"."status",
    "s"."source",
    "s"."booking_code",
    "r"."number" AS "room_number",
    "h"."name" AS "hotel_name",
    "h"."slug"
   FROM (("public"."stays" "s"
     JOIN "public"."hotels" "h" ON (("h"."id" = "s"."hotel_id")))
     JOIN "public"."rooms" "r" ON (("r"."id" = "s"."room_id")))
  WHERE (("s"."guest_id" = "public"."current_guest_id"()) OR (EXISTS ( SELECT 1
           FROM "public"."stay_guests" "sg"
          WHERE (("sg"."stay_id" = "s"."id") AND ("sg"."guest_id" = "public"."current_guest_id"())))));


ALTER VIEW "public"."user_stay_detail" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."user_stays_overview" AS
 SELECT "s"."id" AS "stay_id",
    "s"."scheduled_checkin_at" AS "checkin_at",
    "s"."scheduled_checkout_at" AS "checkout_at",
    ("s"."status")::"text" AS "status",
    "h"."id" AS "hotel_id",
    "h"."name" AS "hotel_name",
    "h"."slug",
    NULL::"text" AS "cover_image_url",
    NULL::integer AS "guest_rating",
    NULL::"text" AS "guest_comment_preview",
    0 AS "earned_paise"
   FROM ("public"."stays" "s"
     JOIN "public"."hotels" "h" ON (("h"."id" = "s"."hotel_id")))
  WHERE ("s"."guest_id" = "auth"."uid"())
  ORDER BY "s"."scheduled_checkin_at" DESC NULLS LAST;


ALTER VIEW "public"."user_stays_overview" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_active_checkins" AS
 SELECT "hotel_id",
    "count"(*) AS "active_sessions"
   FROM "public"."checkin_sessions"
  WHERE ("status" = 'active'::"public"."checkin_session_status")
  GROUP BY "hotel_id";


ALTER VIEW "public"."v_active_checkins" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_api_24h" AS
 SELECT "date_trunc"('hour'::"text", "at") AS "hour_bucket",
    "count"(*) AS "calls",
    COALESCE(("avg"("ms"))::integer, 0) AS "avg_ms",
    "sum"(
        CASE
            WHEN (("status" >= 400) AND ("status" <= 499)) THEN 1
            ELSE 0
        END) AS "err_4xx",
    "sum"(
        CASE
            WHEN ("status" >= 500) THEN 1
            ELSE 0
        END) AS "err_5xx"
   FROM "public"."api_hits"
  WHERE ("at" >= ("now"() - '24:00:00'::interval))
  GROUP BY ("date_trunc"('hour'::"text", "at"))
  ORDER BY ("date_trunc"('hour'::"text", "at"));


ALTER VIEW "public"."v_api_24h" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_api_top_fns_24h" AS
 SELECT "fn",
    "count"(*) AS "calls",
    COALESCE(("avg"("ms"))::integer, 0) AS "avg_ms"
   FROM "public"."api_hits"
  WHERE ("at" >= ("now"() - '24:00:00'::interval))
  GROUP BY "fn"
  ORDER BY ("count"(*)) DESC
 LIMIT 10;


ALTER VIEW "public"."v_api_top_fns_24h" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_arrival_guest_labels" AS
 SELECT "b"."id" AS "booking_id",
    "g"."vip_flag",
    "g"."loyalty_tier",
    "b"."source" AS "booking_source",
        CASE
            WHEN "g"."vip_flag" THEN 'VIP'::"text"
            WHEN (("b"."source")::"text" = ANY (ARRAY['booking.com'::"text", 'expedia'::"text", 'airbnb'::"text"])) THEN 'OTA'::"text"
            ELSE 'DIRECT'::"text"
        END AS "arrival_badge"
   FROM ("public"."bookings" "b"
     LEFT JOIN "public"."guests" "g" ON (("g"."id" = "b"."guest_id")));


ALTER VIEW "public"."v_arrival_guest_labels" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_arrival_housekeeping_eta" AS
 SELECT "room_id",
    "min"("estimated_completion_at") AS "estimated_completion_at",
    "min"((EXTRACT(epoch FROM ("estimated_completion_at" - "now"())) / (60)::numeric)) AS "minutes_remaining"
   FROM "public"."housekeeping_tasks"
  WHERE ("status" = 'in_progress'::"text")
  GROUP BY "room_id";


ALTER VIEW "public"."v_arrival_housekeeping_eta" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_arrival_operational_state" AS
 WITH "room_states" AS (
         SELECT "br"."booking_id",
            "string_agg"("r"."number", ', '::"text") AS "room_numbers",
            "count"(*) AS "rooms_total",
            "count"(*) FILTER (WHERE ("br"."status" = 'CHECKED_IN'::"text")) AS "rooms_checked_in",
            "count"(*) FILTER (WHERE ("br"."room_id" IS NULL)) AS "rooms_unassigned",
            "count"(*) FILTER (WHERE (("br"."room_id" IS NOT NULL) AND ("r"."housekeeping_status" = 'dirty'::"public"."housekeeping_status_enum"))) AS "rooms_dirty",
            "count"(*) FILTER (WHERE (("br"."room_id" IS NOT NULL) AND ("r"."housekeeping_status" = ANY (ARRAY['clean'::"public"."housekeeping_status_enum", 'inspected'::"public"."housekeeping_status_enum", 'pickup'::"public"."housekeeping_status_enum"])))) AS "rooms_clean"
           FROM ("public"."booking_rooms" "br"
             LEFT JOIN "public"."rooms" "r" ON (("r"."id" = "br"."room_id")))
          GROUP BY "br"."booking_id"
        ), "stay_states" AS (
         SELECT "stays"."booking_id",
            "count"(*) FILTER (WHERE ("stays"."status" = 'inhouse'::"public"."stay_status")) AS "inhouse_count",
            "count"(*) FILTER (WHERE ("stays"."status" = 'checkout_requested'::"public"."stay_status")) AS "checkout_requested_count",
            ("max"(("stays"."id")::"text") FILTER (WHERE ("stays"."status" = ANY (ARRAY['inhouse'::"public"."stay_status", 'checkout_requested'::"public"."stay_status"]))))::"uuid" AS "active_stay_id"
           FROM "public"."stays"
          GROUP BY "stays"."booking_id"
        )
 SELECT "b"."id" AS "booking_id",
    "b"."hotel_id",
    "b"."code" AS "booking_code",
    "b"."guest_name",
    "b"."phone",
    "b"."status" AS "booking_status",
    "b"."scheduled_checkin_at",
    "b"."scheduled_checkout_at",
    "rs"."room_numbers",
    COALESCE("rs"."rooms_total", (0)::bigint) AS "rooms_total",
    COALESCE("rs"."rooms_checked_in", (0)::bigint) AS "rooms_checked_in",
    COALESCE("rs"."rooms_unassigned", (0)::bigint) AS "rooms_unassigned",
    COALESCE("rs"."rooms_dirty", (0)::bigint) AS "rooms_dirty",
    COALESCE("rs"."rooms_clean", (0)::bigint) AS "rooms_clean",
    COALESCE("ss"."inhouse_count", (0)::bigint) AS "inhouse_rooms",
    "ss"."active_stay_id",
        CASE
            WHEN (COALESCE("ss"."checkout_requested_count", (0)::bigint) > 0) THEN 'CHECKOUT_REQUESTED'::"text"
            WHEN ("b"."status" = 'CHECKED_IN'::"text") THEN 'CHECKED_IN'::"text"
            WHEN ("b"."status" = 'PARTIALLY_CHECKED_IN'::"text") THEN 'PARTIALLY_ARRIVED'::"text"
            WHEN ("b"."status" = 'CHECKED_OUT'::"text") THEN 'CHECKED_OUT'::"text"
            WHEN (COALESCE("rs"."rooms_total", (0)::bigint) = 0) THEN 'NO_ROOMS'::"text"
            WHEN ((COALESCE("rs"."rooms_checked_in", (0)::bigint) = COALESCE("rs"."rooms_total", (0)::bigint)) AND (COALESCE("rs"."rooms_total", (0)::bigint) > 0)) THEN 'CHECKED_IN'::"text"
            WHEN (COALESCE("rs"."rooms_checked_in", (0)::bigint) > 0) THEN 'PARTIALLY_ARRIVED'::"text"
            WHEN (COALESCE("rs"."rooms_dirty", (0)::bigint) > 0) THEN 'WAITING_HOUSEKEEPING'::"text"
            WHEN (COALESCE("rs"."rooms_unassigned", (0)::bigint) > 0) THEN 'WAITING_ROOM_ASSIGNMENT'::"text"
            WHEN ((COALESCE("rs"."rooms_clean", (0)::bigint) = COALESCE("rs"."rooms_total", (0)::bigint)) AND (COALESCE("rs"."rooms_total", (0)::bigint) > 0)) THEN 'READY_TO_CHECKIN'::"text"
            ELSE 'EXPECTED'::"text"
        END AS "arrival_operational_state",
        CASE
            WHEN ((COALESCE("rs"."rooms_clean", (0)::bigint) = COALESCE("rs"."rooms_total", (0)::bigint)) AND (COALESCE("rs"."rooms_total", (0)::bigint) > 0)) THEN true
            ELSE false
        END AS "rooms_ready_for_arrival",
        CASE
            WHEN ((COALESCE("rs"."rooms_total", (0)::bigint) = 0) OR (COALESCE("rs"."rooms_checked_in", (0)::bigint) = COALESCE("rs"."rooms_total", (0)::bigint))) THEN 'NONE'::"text"
            WHEN (COALESCE("rs"."rooms_dirty", (0)::bigint) > 0) THEN 'WAIT_HOUSEKEEPING'::"text"
            ELSE 'CHECKIN'::"text"
        END AS "primary_action"
   FROM (("public"."bookings" "b"
     LEFT JOIN "room_states" "rs" ON (("rs"."booking_id" = "b"."id")))
     LEFT JOIN "stay_states" "ss" ON (("ss"."booking_id" = "b"."id")))
  WHERE (("b"."status" = ANY (ARRAY['CREATED'::"text", 'CONFIRMED'::"text", 'PRE_CHECKED_IN'::"text", 'PARTIALLY_CHECKED_IN'::"text", 'CHECKED_IN'::"text"])) AND ("b"."status" <> ALL (ARRAY['CANCELLED'::"text", 'NO_SHOW'::"text"])));


ALTER VIEW "public"."v_arrival_operational_state" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_arrival_payment_state" AS
 SELECT "b"."id" AS "booking_id",
    COALESCE("sum"("fe"."amount") FILTER (WHERE ("fe"."amount" > (0)::numeric)), (0)::numeric) AS "total_amount",
    COALESCE("sum"("abs"("fe"."amount")) FILTER (WHERE ("fe"."amount" < (0)::numeric)), (0)::numeric) AS "paid_amount",
    COALESCE("sum"("fe"."amount"), (0)::numeric) AS "pending_amount",
        CASE
            WHEN (COALESCE("sum"("fe"."amount"), (0)::numeric) > (0)::numeric) THEN true
            ELSE false
        END AS "payment_pending"
   FROM ("public"."bookings" "b"
     LEFT JOIN "public"."folio_entries" "fe" ON (("fe"."booking_id" = "b"."id")))
  GROUP BY "b"."id";


ALTER VIEW "public"."v_arrival_payment_state" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_arrivals_dashboard" AS
 WITH "base" AS (
         SELECT "v_arrival_operational_state"."booking_id",
            "v_arrival_operational_state"."hotel_id",
            "v_arrival_operational_state"."booking_code",
            "v_arrival_operational_state"."guest_name",
            "v_arrival_operational_state"."phone",
            "v_arrival_operational_state"."booking_status",
            "v_arrival_operational_state"."scheduled_checkin_at",
            "v_arrival_operational_state"."scheduled_checkout_at",
            "v_arrival_operational_state"."room_numbers",
            "v_arrival_operational_state"."rooms_total",
            "v_arrival_operational_state"."rooms_checked_in",
            "v_arrival_operational_state"."rooms_unassigned",
            "v_arrival_operational_state"."rooms_dirty",
            "v_arrival_operational_state"."rooms_clean",
            "v_arrival_operational_state"."inhouse_rooms",
            "v_arrival_operational_state"."active_stay_id",
            "v_arrival_operational_state"."arrival_operational_state",
            "v_arrival_operational_state"."rooms_ready_for_arrival",
            "v_arrival_operational_state"."primary_action"
           FROM "public"."v_arrival_operational_state"
        ), "timers" AS (
         SELECT "base"."booking_id",
            (EXTRACT(epoch FROM ("now"() - "base"."scheduled_checkin_at")) / (60)::numeric) AS "minutes_since_scheduled_arrival"
           FROM "base"
        )
 SELECT "b"."booking_id",
    "b"."hotel_id",
    "b"."booking_code",
    "b"."booking_status",
    "b"."guest_name",
    "b"."phone",
    "b"."scheduled_checkin_at",
    "b"."scheduled_checkout_at",
    "b"."room_numbers",
    "b"."rooms_total",
    "b"."rooms_checked_in",
    "b"."rooms_unassigned",
    "b"."rooms_dirty",
    "b"."rooms_clean",
    "b"."inhouse_rooms",
    "b"."active_stay_id",
    "b"."arrival_operational_state",
    "b"."rooms_ready_for_arrival",
    "b"."primary_action",
    "t"."minutes_since_scheduled_arrival",
        CASE
            WHEN ("t"."minutes_since_scheduled_arrival" > (60)::numeric) THEN 'CRITICAL'::"text"
            WHEN ("t"."minutes_since_scheduled_arrival" > (30)::numeric) THEN 'HIGH'::"text"
            WHEN ("t"."minutes_since_scheduled_arrival" > (10)::numeric) THEN 'MEDIUM'::"text"
            ELSE 'LOW'::"text"
        END AS "urgency_level",
    "b"."rooms_ready_for_arrival" AS "eligible_for_bulk_checkin"
   FROM ("base" "b"
     LEFT JOIN "timers" "t" ON (("t"."booking_id" = "b"."booking_id")));


ALTER VIEW "public"."v_owner_arrivals_dashboard" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_arrival_dashboard_rows" AS
 SELECT "a"."booking_id",
    "a"."hotel_id",
    "a"."booking_code",
    "a"."booking_status",
    "a"."guest_name",
    "a"."phone",
    "a"."scheduled_checkin_at",
    "a"."scheduled_checkout_at",
    "a"."room_numbers",
    "a"."rooms_total",
    "a"."rooms_checked_in",
    "a"."rooms_unassigned",
    "a"."rooms_dirty",
    "a"."rooms_clean",
    "a"."inhouse_rooms",
    "a"."active_stay_id",
    "a"."arrival_operational_state",
    "a"."rooms_ready_for_arrival",
    "a"."primary_action",
    "a"."minutes_since_scheduled_arrival",
    "a"."urgency_level",
    "a"."eligible_for_bulk_checkin",
    COALESCE("p"."payment_pending", false) AS "payment_pending",
    COALESCE("p"."pending_amount", (0)::numeric) AS "pending_amount",
    "l"."arrival_badge",
    COALESCE("l"."vip_flag", false) AS "vip_flag",
    "hk"."cleaning_minutes_remaining",
    COALESCE("p"."total_amount", (0)::numeric) AS "total_amount",
    COALESCE("p"."paid_amount", (0)::numeric) AS "paid_amount"
   FROM ((("public"."v_owner_arrivals_dashboard" "a"
     LEFT JOIN "public"."v_arrival_payment_state" "p" ON (("p"."booking_id" = "a"."booking_id")))
     LEFT JOIN "public"."v_arrival_guest_labels" "l" ON (("l"."booking_id" = "a"."booking_id")))
     LEFT JOIN ( SELECT "br"."booking_id",
            "min"("h"."minutes_remaining") AS "cleaning_minutes_remaining"
           FROM ("public"."booking_rooms" "br"
             JOIN "public"."v_arrival_housekeeping_eta" "h" ON (("h"."room_id" = "br"."room_id")))
          GROUP BY "br"."booking_id") "hk" ON (("hk"."booking_id" = "a"."booking_id")));


ALTER VIEW "public"."v_arrival_dashboard_rows" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_arrival_dashboard_summary" AS
 SELECT "hotel_id",
    "count"(*) AS "total_arrivals",
    "count"(*) FILTER (WHERE ("arrival_operational_state" = ANY (ARRAY['CHECKED_IN'::"text", 'PARTIALLY_ARRIVED'::"text"]))) AS "arrived",
    "count"(*) FILTER (WHERE "rooms_ready_for_arrival") AS "ready_to_checkin",
    "count"(*) FILTER (WHERE ("arrival_operational_state" = 'WAITING_ROOM_ASSIGNMENT'::"text")) AS "waiting_room_assignment",
    "count"(*) FILTER (WHERE "payment_pending") AS "payment_pending",
    "count"(*) FILTER (WHERE "vip_flag") AS "vip_today"
   FROM "public"."v_arrival_dashboard_rows"
  GROUP BY "hotel_id";


ALTER VIEW "public"."v_arrival_dashboard_summary" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_arrival_priority" AS
 SELECT "br"."room_id",
    "b"."id" AS "booking_id",
    "b"."code" AS "booking_code",
    "b"."guest_name",
    "b"."scheduled_checkin_at",
    GREATEST(((EXTRACT(epoch FROM ("b"."scheduled_checkin_at" - "now"())))::integer / 60), 0) AS "arrival_needed_in_minutes",
        CASE
            WHEN ((EXTRACT(epoch FROM ("b"."scheduled_checkin_at" - "now"())) / (60)::numeric) <= (30)::numeric) THEN 'CRITICAL'::"text"
            WHEN ((EXTRACT(epoch FROM ("b"."scheduled_checkin_at" - "now"())) / (60)::numeric) <= (120)::numeric) THEN 'HIGH'::"text"
            WHEN ((EXTRACT(epoch FROM ("b"."scheduled_checkin_at" - "now"())) / (60)::numeric) <= (360)::numeric) THEN 'MEDIUM'::"text"
            ELSE 'LOW'::"text"
        END AS "arrival_urgency"
   FROM ("public"."bookings" "b"
     JOIN "public"."booking_rooms" "br" ON (("br"."booking_id" = "b"."id")))
  WHERE (("b"."status" = ANY (ARRAY['CONFIRMED'::"text", 'PRE_CHECKED_IN'::"text"])) AND ("b"."scheduled_checkin_at" > "now"()));


ALTER VIEW "public"."v_arrival_priority" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_available_staff" AS
 SELECT "hm"."id" AS "staff_id",
    "p"."full_name",
    "d"."id" AS "department_id",
    "d"."name" AS "department_name",
    "z"."id" AS "zone_id",
    "z"."name" AS "zone_name"
   FROM ((((("public"."hotel_members" "hm"
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
     LEFT JOIN "public"."staff_departments" "sd" ON (("sd"."staff_id" = "hm"."id")))
     LEFT JOIN "public"."departments" "d" ON (("d"."id" = "sd"."department_id")))
     LEFT JOIN "public"."staff_zone_assignments" "sza" ON ((("sza"."staff_id" = "hm"."id") AND ("sza"."effective_to" IS NULL))))
     LEFT JOIN "public"."hotel_zones" "z" ON (("z"."id" = "sza"."zone_id")))
  WHERE (NOT (EXISTS ( SELECT 1
           FROM "public"."staff_shifts" "ss"
          WHERE (("ss"."staff_id" = "hm"."id") AND ("ss"."status" = 'scheduled'::"text") AND ("ss"."is_active" = true) AND (("now"() >= "ss"."shift_start") AND ("now"() <= "ss"."shift_end"))))));


ALTER VIEW "public"."v_available_staff" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_booking_activity" AS
 SELECT "ae"."booking_id",
    "ae"."created_at" AS "event_time",
    'ARRIVAL'::"text" AS "event_category",
    "ae"."event_type",
    "ae"."event_type" AS "title",
        CASE
            WHEN (("ae"."event_type" = 'CHECKIN'::"text") OR (("ae"."event_type" = 'STATUS_CHANGE'::"text") AND ("upper"("ae"."new_value") = ANY (ARRAY['CHECKED_IN'::"text", 'INHOUSE'::"text"])))) THEN 'Guest checked in'::"text"
            WHEN (("ae"."event_type" = 'STATUS_CHANGE'::"text") AND ("upper"("ae"."new_value") = ANY (ARRAY['PRECHECKIN'::"text", 'PRE_CHECKED_IN'::"text"]))) THEN 'Guest completed pre-checkin'::"text"
            WHEN (("ae"."event_type" = 'CHECKOUT'::"text") OR (("ae"."event_type" = 'STATUS_CHANGE'::"text") AND ("upper"("ae"."new_value") = 'CHECKED_OUT'::"text"))) THEN 'Guest checked out'::"text"
            WHEN ("ae"."event_type" = 'ROOM_ASSIGNED'::"text") THEN ('Room '::"text" || COALESCE("ae"."new_value", 'assigned'::"text"))
            WHEN ("ae"."event_type" = 'ROOM_REASSIGNED'::"text") THEN ((('Room changed from '::"text" || "ae"."old_value") || ' to '::"text") || "ae"."new_value")
            WHEN (("ae"."event_type" = 'CANCEL'::"text") OR (("ae"."event_type" = 'STATUS_CHANGE'::"text") AND ("upper"("ae"."new_value") = 'CANCELLED'::"text"))) THEN 'Booking cancelled'::"text"
            WHEN (("ae"."event_type" = 'NO_SHOW'::"text") OR (("ae"."event_type" = 'STATUS_CHANGE'::"text") AND ("upper"("ae"."new_value") = 'NO_SHOW'::"text"))) THEN 'Marked as no show'::"text"
            ELSE COALESCE(('Status changed to '::"text" || "ae"."new_value"), 'Status changed'::"text")
        END AS "description",
    NULL::numeric AS "amount",
    NULL::"text" AS "reference_id",
    "ae"."performed_by" AS "actor_id",
    4 AS "sort_priority"
   FROM "public"."arrival_events" "ae"
UNION ALL
 SELECT "s"."booking_id",
    "fo"."created_at" AS "event_time",
    'FOOD'::"text" AS "event_category",
    "fo"."status" AS "event_type",
    ('Food Order '::"text" || "fo"."display_id") AS "title",
    ('Order '::"text" || "fo"."status") AS "description",
    "fo"."total_amount" AS "amount",
    "fo"."display_id" AS "reference_id",
    NULL::"uuid" AS "actor_id",
    2 AS "sort_priority"
   FROM ("public"."food_orders" "fo"
     JOIN "public"."stays" "s" ON (("s"."id" = "fo"."stay_id")))
  WHERE ("fo"."status" = ANY (ARRAY['CREATED'::"text", 'DELIVERED'::"text", 'CANCELLED'::"text"]))
UNION ALL
 SELECT "p"."booking_id",
    "p"."created_at" AS "event_time",
    'PAYMENT'::"text" AS "event_category",
    "p"."status" AS "event_type",
    'Payment Received'::"text" AS "title",
    ((('₹'::"text" || "p"."amount") || ' via '::"text") || "replace"("p"."method", '_'::"text", ' '::"text")) AS "description",
    "p"."amount",
    ("p"."id")::"text" AS "reference_id",
    "p"."collected_by" AS "actor_id",
    1 AS "sort_priority"
   FROM "public"."payments" "p"
  WHERE (("p"."status" = 'COMPLETED'::"text") AND ("p"."booking_id" IS NOT NULL))
UNION ALL
 SELECT "s"."booking_id",
    "te"."created_at" AS "event_time",
    'SERVICE'::"text" AS "event_category",
    "te"."event_type",
    ('Request '::"text" || "t"."display_id") AS "title",
    COALESCE("te"."comment", 'Status updated'::"text") AS "description",
    NULL::numeric AS "amount",
    "t"."display_id" AS "reference_id",
    "te"."actor_id",
    3 AS "sort_priority"
   FROM (("public"."ticket_events" "te"
     JOIN "public"."tickets" "t" ON (("t"."id" = "te"."ticket_id")))
     JOIN "public"."stays" "s" ON (("s"."id" = "t"."stay_id")))
  WHERE ("te"."event_type" = ANY (ARRAY['CREATED'::"text", 'COMPLETED'::"text", 'CANCELLED'::"text"]));


ALTER VIEW "public"."v_booking_activity" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_folio_balance" AS
 SELECT "booking_id",
    "sum"("amount") AS "balance"
   FROM "public"."folio_entries"
  GROUP BY "booking_id";


ALTER VIEW "public"."v_folio_balance" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_food_orders_sla_risk" AS
 SELECT "fo"."id" AS "order_id",
    "fo"."status",
    "fo"."created_at",
    "fo"."room_id",
    "r"."number" AS "room_number",
    "sla"."sla_target_at",
    "sla"."breached",
    (EXTRACT(epoch FROM (("sla"."sla_target_at")::timestamp with time zone - "now"())) / (60)::numeric) AS "minutes_to_breach"
   FROM (("public"."food_orders" "fo"
     LEFT JOIN "public"."rooms" "r" ON (("r"."id" = "fo"."room_id")))
     JOIN "public"."food_order_sla_state" "sla" ON (("sla"."food_order_id" = "fo"."id")))
  WHERE (("fo"."status" = ANY (ARRAY['ACCEPTED'::"text", 'PREPARING'::"text", 'READY'::"text"])) AND (("sla"."breached" = true) OR ("sla"."sla_target_at" < ("now"() + '00:05:00'::interval))));


ALTER VIEW "public"."v_food_orders_sla_risk" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_guest_active_bookings" AS
 SELECT "b"."id" AS "booking_id",
    "b"."hotel_id",
    "b"."code" AS "booking_code",
    "b"."status" AS "booking_status",
    "h"."name" AS "hotel_name",
    "h"."slug" AS "hotel_slug",
    "h"."city" AS "hotel_city",
    "h"."phone" AS "hotel_phone",
    "h"."wa_display_number" AS "hotel_whatsapp",
    "h"."email" AS "hotel_email",
    NULL::"uuid" AS "primary_stay_id",
    COALESCE("rs"."room_numbers", 'Unassigned'::"text") AS "room_numbers_display",
    COALESCE("rs"."room_ids", '{}'::"uuid"[]) AS "room_ids",
    COALESCE("rs"."room_types", '{}'::"text"[]) AS "room_types",
    COALESCE("rs"."room_count", (0)::bigint) AS "room_count",
    '[]'::"jsonb" AS "rooms_detail",
    'arriving'::"public"."stay_status" AS "status",
    "b"."scheduled_checkin_at" AS "checkin_min",
    "b"."scheduled_checkin_at" AS "checkin_max",
    "b"."scheduled_checkout_at" AS "checkout_min",
    "b"."scheduled_checkout_at" AS "checkout_max",
    false AS "has_mixed_schedule",
    COALESCE("ceil"((EXTRACT(epoch FROM ("b"."scheduled_checkout_at" - "b"."scheduled_checkin_at")) / (86400)::numeric)), (0)::numeric) AS "total_nights",
    "b"."scheduled_checkin_at" AS "check_in",
    "b"."scheduled_checkout_at" AS "check_out",
    COALESCE("ps"."total_amount", (0)::numeric) AS "total_amount",
    COALESCE("ps"."paid_amount", (0)::numeric) AS "paid_amount",
    (COALESCE("ps"."total_amount", (0)::numeric) - COALESCE("ps"."paid_amount", (0)::numeric)) AS "outstanding_balance",
    "b"."guest_id",
    "b"."updated_at" AS "last_updated",
    "pt"."token" AS "precheckin_token",
    "pt"."expires_at" AS "precheckin_expires_at",
    "pt"."used_at" AS "precheckin_used_at"
   FROM (((("public"."bookings" "b"
     JOIN "public"."hotels" "h" ON (("h"."id" = "b"."hotel_id")))
     LEFT JOIN LATERAL ( SELECT "string_agg"("r"."number", ', '::"text" ORDER BY "r"."number") AS "room_numbers",
            "array_agg"(DISTINCT "r"."id") AS "room_ids",
            "array_agg"(DISTINCT "rt"."name") AS "room_types",
            "count"(DISTINCT "r"."id") AS "room_count"
           FROM (("public"."booking_rooms" "br"
             JOIN "public"."rooms" "r" ON (("r"."id" = "br"."room_id")))
             LEFT JOIN "public"."room_types" "rt" ON (("rt"."id" = "r"."room_type_id")))
          WHERE ("br"."booking_id" = "b"."id")) "rs" ON (true))
     LEFT JOIN LATERAL ( SELECT "pt_1"."token",
            "pt_1"."expires_at",
            "pt_1"."used_at"
           FROM "public"."precheckin_tokens" "pt_1"
          WHERE ("pt_1"."booking_id" = "b"."id")
          ORDER BY "pt_1"."created_at" DESC
         LIMIT 1) "pt" ON (true))
     LEFT JOIN LATERAL ( SELECT "ps_1"."total_amount",
            "ps_1"."paid_amount"
           FROM "public"."v_arrival_payment_state" "ps_1"
          WHERE ("ps_1"."booking_id" = "b"."id")
         LIMIT 1) "ps" ON (true))
  WHERE (("b"."status" = ANY (ARRAY['CONFIRMED'::"text", 'PRE_CHECKED_IN'::"text", 'PARTIALLY_CHECKED_IN'::"text"])) AND ("b"."guest_id" = "public"."current_guest_id"()) AND (NOT (EXISTS ( SELECT 1
           FROM "public"."stays" "s"
          WHERE ("s"."booking_id" = "b"."id")))))
UNION ALL
 SELECT "s"."booking_id",
    "s"."hotel_id",
    "b"."code" AS "booking_code",
    "b"."status" AS "booking_status",
    "h"."name" AS "hotel_name",
    "h"."slug" AS "hotel_slug",
    "h"."city" AS "hotel_city",
    "h"."phone" AS "hotel_phone",
    "h"."wa_display_number" AS "hotel_whatsapp",
    "h"."email" AS "hotel_email",
    COALESCE(("array_agg"("s"."id" ORDER BY "s"."created_at") FILTER (WHERE ("s"."status" = 'inhouse'::"public"."stay_status")))[1], ("array_agg"("s"."id" ORDER BY "s"."created_at"))[1]) AS "primary_stay_id",
    "string_agg"(DISTINCT "r"."number", ', '::"text" ORDER BY "r"."number") AS "room_numbers_display",
    "array_agg"(DISTINCT "r"."id") AS "room_ids",
    "array_remove"("array_agg"(DISTINCT "rt"."name"), NULL::"text") AS "room_types",
    "count"(DISTINCT "s"."id") AS "room_count",
    COALESCE("rooms"."rooms_detail", '[]'::"jsonb") AS "rooms_detail",
    'inhouse'::"public"."stay_status" AS "status",
    "min"("s"."scheduled_checkin_at") AS "checkin_min",
    "max"("s"."scheduled_checkin_at") AS "checkin_max",
    "min"("s"."scheduled_checkout_at") AS "checkout_min",
    "max"("s"."scheduled_checkout_at") AS "checkout_max",
    (("min"("s"."scheduled_checkin_at") <> "max"("s"."scheduled_checkin_at")) OR ("min"("s"."scheduled_checkout_at") <> "max"("s"."scheduled_checkout_at"))) AS "has_mixed_schedule",
    COALESCE("ceil"((EXTRACT(epoch FROM ("max"("s"."scheduled_checkout_at") - "min"("s"."scheduled_checkin_at"))) / (86400)::numeric)), (0)::numeric) AS "total_nights",
    "min"("s"."scheduled_checkin_at") AS "check_in",
    "max"("s"."scheduled_checkout_at") AS "check_out",
    COALESCE("ps"."total_amount", (0)::numeric) AS "total_amount",
    COALESCE("ps"."paid_amount", (0)::numeric) AS "paid_amount",
    (COALESCE("ps"."total_amount", (0)::numeric) - COALESCE("ps"."paid_amount", (0)::numeric)) AS "outstanding_balance",
    "s"."guest_id",
    "max"("s"."updated_at") AS "last_updated",
    "max"("pt"."token") AS "precheckin_token",
    "max"("pt"."expires_at") AS "precheckin_expires_at",
    "max"("pt"."used_at") AS "precheckin_used_at"
   FROM ((((((("public"."stays" "s"
     JOIN "public"."bookings" "b" ON (("b"."id" = "s"."booking_id")))
     JOIN "public"."hotels" "h" ON (("h"."id" = "s"."hotel_id")))
     JOIN "public"."rooms" "r" ON (("r"."id" = "s"."room_id")))
     LEFT JOIN "public"."room_types" "rt" ON (("rt"."id" = "r"."room_type_id")))
     LEFT JOIN LATERAL ( SELECT "pt_1"."token",
            "pt_1"."expires_at",
            "pt_1"."used_at"
           FROM "public"."precheckin_tokens" "pt_1"
          WHERE ("pt_1"."booking_id" = "s"."booking_id")
          ORDER BY "pt_1"."created_at" DESC
         LIMIT 1) "pt" ON (true))
     LEFT JOIN LATERAL ( SELECT "ps_1"."total_amount",
            "ps_1"."paid_amount"
           FROM "public"."v_arrival_payment_state" "ps_1"
          WHERE ("ps_1"."booking_id" = "s"."booking_id")
         LIMIT 1) "ps" ON (true))
     LEFT JOIN ( SELECT "t"."booking_id",
            "t"."guest_id",
            "jsonb_agg"("t"."room_obj" ORDER BY "t"."room_number") AS "rooms_detail"
           FROM ( SELECT DISTINCT "s2"."booking_id",
                    "s2"."guest_id",
                    "r2"."number" AS "room_number",
                    "jsonb_build_object"('id', "s2"."id", 'room_id', "r2"."id", 'number', "r2"."number", 'status', "s2"."status", 'type', "rt2"."name", 'check_in', "s2"."scheduled_checkin_at", 'check_out', "s2"."scheduled_checkout_at") AS "room_obj"
                   FROM (("public"."stays" "s2"
                     JOIN "public"."rooms" "r2" ON (("r2"."id" = "s2"."room_id")))
                     LEFT JOIN "public"."room_types" "rt2" ON (("rt2"."id" = "r2"."room_type_id")))
                  WHERE ("s2"."status" = 'inhouse'::"public"."stay_status")) "t"
          GROUP BY "t"."booking_id", "t"."guest_id") "rooms" ON ((("rooms"."booking_id" = "s"."booking_id") AND ("rooms"."guest_id" = "s"."guest_id"))))
  WHERE (("s"."status" = 'inhouse'::"public"."stay_status") AND ("s"."guest_id" = "public"."current_guest_id"()))
  GROUP BY "s"."booking_id", "s"."hotel_id", "b"."code", "b"."status", "h"."id", "h"."name", "h"."slug", "h"."city", "h"."phone", "h"."wa_display_number", "h"."email", "s"."guest_id", "ps"."total_amount", "ps"."paid_amount", "rooms"."rooms_detail";


ALTER VIEW "public"."v_guest_active_bookings" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_guest_active_bookings" IS 'Aggregated view of active journeys: Confirmed future bookings (bookings) and currently checked-in stays (stays).';



CREATE OR REPLACE VIEW "public"."v_guest_food_orders" AS
 SELECT "fo"."id" AS "order_id",
    "fo"."display_id",
    "fo"."status",
    "fo"."created_at",
    "fo"."updated_at",
    "fo"."total_amount",
    "fo"."currency",
    "fo"."special_instructions",
    "r"."number" AS "room_number",
    "st"."booking_code",
    "sla"."sla_target_at",
    (EXTRACT(epoch FROM (("sla"."sla_target_at")::timestamp with time zone - "now"())) / (60)::numeric) AS "sla_minutes_remaining",
    "sla"."breached" AS "sla_breached",
    "items"."items",
    "items"."total_items"
   FROM (((("public"."food_orders" "fo"
     LEFT JOIN "public"."stays" "st" ON (("st"."id" = "fo"."stay_id")))
     LEFT JOIN "public"."rooms" "r" ON (("r"."id" = "fo"."room_id")))
     LEFT JOIN "public"."food_order_sla_state" "sla" ON (("sla"."food_order_id" = "fo"."id")))
     LEFT JOIN LATERAL ( SELECT "count"(*) AS "total_items",
            COALESCE("jsonb_agg"("jsonb_build_object"('name', "food_order_items"."item_name", 'quantity', "food_order_items"."quantity", 'price', "food_order_items"."total_price")) FILTER (WHERE ("food_order_items"."id" IS NOT NULL)), '[]'::"jsonb") AS "items"
           FROM "public"."food_order_items"
          WHERE ("food_order_items"."food_order_id" = "fo"."id")) "items" ON (true))
  WHERE (("st"."guest_id" = "public"."current_guest_id"()) OR (EXISTS ( SELECT 1
           FROM "public"."stay_guests" "sg"
          WHERE (("sg"."stay_id" = "st"."id") AND ("sg"."guest_id" = "public"."current_guest_id"())))))
  GROUP BY "fo"."id", "fo"."display_id", "fo"."status", "fo"."created_at", "fo"."updated_at", "fo"."total_amount", "fo"."currency", "fo"."special_instructions", "r"."number", "st"."booking_code", "sla"."sla_target_at", "sla"."breached", "items"."items", "items"."total_items";


ALTER VIEW "public"."v_guest_food_orders" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_guest_home_dashboard_base" AS
 SELECT "vh"."stay_id",
    "vh"."guest_id",
    "vh"."hotel_id",
    "vh"."booking_code",
    "vh"."hotel_name",
    "vh"."hotel_city",
    "vh"."hotel_slug",
    "vh"."hotel_phone",
    "vh"."hotel_whatsapp",
    "vh"."hotel_email",
    "vh"."room_id",
    "vh"."room_number",
    "vh"."room_type",
    "vh"."stay_status",
    "vh"."lifecycle_phase",
    "vh"."display_checkin_at",
    "vh"."display_checkout_at",
    "vh"."checkin_label",
    "vh"."checkout_label",
    "vh"."hero_title",
    "vh"."badge_variant",
    "vh"."badge_text",
    "vh"."can_checkin",
    "vh"."can_request_service",
    "vh"."can_express_checkout",
    "vh"."can_order_food",
    "vh"."can_view_bill",
    "vh"."can_download_invoice",
    (COALESCE("svc"."active_count", 0) > 0) AS "has_active_service_request",
    COALESCE("svc"."active_count", 0) AS "active_service_count",
    "vh"."can_view_bill" AS "has_bill",
    NULL::numeric AS "bill_total",
    NULL::integer AS "reward_points",
    NULL::"text" AS "reward_tier",
    "vh"."is_vip",
    "vh"."is_active",
    "vh"."created_at",
    "vh"."updated_at"
   FROM ("public"."v_guest_stay_hero_base" "vh"
     LEFT JOIN LATERAL ( SELECT ("count"(*))::integer AS "active_count"
           FROM "public"."tickets" "t"
          WHERE (("t"."stay_id" = "vh"."stay_id") AND ("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text"])))) "svc" ON (true));


ALTER VIEW "public"."v_guest_home_dashboard_base" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_guest_home_dashboard" AS
 SELECT "stay_id",
