    "hotel_phone",
    "hotel_whatsapp",
    "hotel_email",
    "room_id",
    "room_number",
    "room_type",
    "stay_status",
    "lifecycle_phase",
    "display_checkin_at",
    "display_checkout_at",
    "checkin_label",
    "checkout_label",
    "hero_title",
    "badge_variant",
    "badge_text",
    "can_checkin",
    "can_request_service",
    "can_express_checkout",
    "can_order_food",
    "can_view_bill",
    "can_download_invoice",
    "has_active_service_request",
