ALTER VIEW "public"."v_guest_home_dashboard" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_guest_stay_display" AS
 SELECT "s"."id",
    "s"."guest_id",
    "s"."hotel_id",
    "s"."room_id",
    "s"."booking_code",
    ("s"."status")::"text" AS "status",
    "s"."is_vip",
    "s"."scheduled_checkin_at",
    "s"."scheduled_checkout_at",
    "s"."actual_checkin_at",
    "s"."actual_checkout_at",
    COALESCE("s"."actual_checkin_at", "s"."scheduled_checkin_at") AS "display_checkin_at",
        CASE
            WHEN ("s"."status" = 'checked_out'::"public"."stay_status") THEN COALESCE("s"."actual_checkout_at", "s"."scheduled_checkout_at")
            ELSE "s"."scheduled_checkout_at"
        END AS "display_checkout_at",
        CASE
            WHEN (("s"."status" = 'inhouse'::"public"."stay_status") AND ("s"."actual_checkin_at" IS NOT NULL)) THEN 'Checked-in'::"text"
            ELSE 'Check-in'::"text"
        END AS "checkin_label",
        CASE
            WHEN ("s"."status" = 'inhouse'::"public"."stay_status") THEN 'Checkout'::"text"
            ELSE 'Check-out'::"text"
        END AS "checkout_label",
    "h"."name" AS "hotel_name",
    "h"."slug" AS "hotel_slug",
    "h"."city" AS "hotel_city",
    "r"."number" AS "room_number",
    "s"."created_at",
    "s"."updated_at"
   FROM (("public"."stays" "s"
     JOIN "public"."hotels" "h" ON (("h"."id" = "s"."hotel_id")))
     JOIN "public"."rooms" "r" ON (("r"."id" = "s"."room_id")))
  WHERE ("s"."guest_id" = "auth"."uid"());


ALTER VIEW "public"."v_guest_stay_display" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_guest_tickets" AS
 SELECT "t"."id",
    "t"."display_id",
    "t"."status",
    "t"."reason_code",
    "t"."created_at",
    "t"."completed_at",
    "t"."cancelled_at",
    "t"."description",
    "t"."stay_id",
    "r"."number" AS "room_number",
    "s"."label" AS "service_name",
    "s"."sla_minutes",
    "tss"."sla_started_at",
    "z"."name" AS "zone_name",
        CASE
            WHEN ("t"."zone_id" IS NOT NULL) THEN "z"."name"
            ELSE "concat"('Room ', "r"."number")
        END AS "location_label",
    "st"."booking_code"
   FROM ((((("public"."tickets" "t"
     JOIN "public"."stays" "st" ON ((("st"."id" = "t"."stay_id") AND (("st"."guest_id" = "public"."current_guest_id"()) OR (EXISTS ( SELECT 1
           FROM "public"."stay_guests" "sg"
          WHERE (("sg"."stay_id" = "st"."id") AND ("sg"."guest_id" = "public"."current_guest_id"()))))))))
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     LEFT JOIN "public"."ticket_sla_state" "tss" ON (("tss"."ticket_id" = "t"."id")))
     LEFT JOIN "public"."rooms" "r" ON (("r"."id" = "st"."room_id")))
     LEFT JOIN "public"."hotel_zones" "z" ON (("z"."id" = "t"."zone_id")))
  WHERE ("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text", 'BLOCKED'::"text", 'COMPLETED'::"text", 'CANCELLED'::"text"]))
  ORDER BY "t"."created_at" DESC;


ALTER VIEW "public"."v_guest_tickets" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_hotel_kpis_today" AS
 WITH "p" AS (
         SELECT (("now"() AT TIME ZONE 'Asia/Kolkata'::"text"))::"date" AS "local_today",
            ("now"() AT TIME ZONE 'Asia/Kolkata'::"text") AS "local_now"
        )
 SELECT "h"."id" AS "hotel_id",
    "p"."local_today" AS "d",
    ( SELECT "count"(*) AS "count"
           FROM "public"."rooms" "r"
          WHERE ("r"."hotel_id" = "h"."id")) AS "total_rooms",
    COALESCE(( SELECT "count"(*) AS "count"
           FROM "public"."stays" "s"
          WHERE (("s"."hotel_id" = "h"."id") AND ((("s"."scheduled_checkin_at" AT TIME ZONE 'Asia/Kolkata'::"text"))::"date" = "p"."local_today"))), (0)::bigint) AS "arrivals",
    COALESCE(( SELECT "count"(*) AS "count"
           FROM "public"."stays" "s"
          WHERE (("s"."hotel_id" = "h"."id") AND ((("s"."scheduled_checkout_at" AT TIME ZONE 'Asia/Kolkata'::"text"))::"date" = "p"."local_today"))), (0)::bigint) AS "departures",
    COALESCE(( SELECT "count"(*) AS "count"
           FROM "public"."stays" "s"
          WHERE (("s"."hotel_id" = "h"."id") AND (("s"."scheduled_checkin_at" AT TIME ZONE 'Asia/Kolkata'::"text") <= "p"."local_now") AND (("s"."scheduled_checkout_at" AT TIME ZONE 'Asia/Kolkata'::"text") > "p"."local_now"))), (0)::bigint) AS "inhouse",
    COALESCE(( SELECT "sum"("n"."revenue") AS "sum"
           FROM "public"."nightly_revenue" "n"
          WHERE (("n"."hotel_id" = "h"."id") AND ("n"."d" = "p"."local_today"))), (0)::numeric) AS "room_revenue_today",
    COALESCE(( SELECT "count"(*) AS "count"
           FROM "public"."stays" "s"
          WHERE (("s"."hotel_id" = "h"."id") AND (("s"."scheduled_checkin_at" AT TIME ZONE 'Asia/Kolkata'::"text") <= "p"."local_now") AND (("s"."scheduled_checkout_at" AT TIME ZONE 'Asia/Kolkata'::"text") > "p"."local_now"))), (0)::bigint) AS "occupied_rooms_today"
   FROM ("public"."hotels" "h"
     CROSS JOIN "p");


ALTER VIEW "public"."v_hotel_kpis_today" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_hotel_review_metrics" AS
 SELECT "gr"."hotel_id",
    "count"(DISTINCT "gr"."id") AS "total_reviews",
    "round"("avg"("gr"."overall_rating"), 2) AS "average_rating",
    "count"(DISTINCT "gr"."id") FILTER (WHERE ("gr"."overall_rating" >= 4)) AS "positive_reviews",
    "count"(DISTINCT "gr"."id") FILTER (WHERE ("gr"."overall_rating" <= 2)) AS "negative_reviews",
    "count"(DISTINCT "f"."review_id") FILTER (WHERE ("f"."status" = ANY (ARRAY['open'::"text", 'in_progress'::"text"]))) AS "active_escalations",
    "max"("gr"."created_at") AS "last_review_at"
   FROM ("public"."guest_reviews" "gr"
     LEFT JOIN "public"."review_flags" "f" ON (("gr"."id" = "f"."review_id")))
  GROUP BY "gr"."hotel_id";


ALTER VIEW "public"."v_hotel_review_metrics" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_housekeeping_operational_board" AS
 SELECT "r"."id" AS "room_id",
    "r"."hotel_id",
    "r"."number" AS "room_number",
    "r"."floor",
    "r"."housekeeping_status",
    "r"."is_out_of_order",
    "rt"."id" AS "room_type_id",
    "rt"."name" AS "room_type_name",
    "ht"."id" AS "task_id",
    "ht"."status" AS "task_status",
    "ht"."assigned_to" AS "task_assigned_to",
    "ht"."started_at" AS "task_started_at",
    "ht"."eta" AS "task_eta",
    "ht"."priority_score" AS "task_priority_score",
    COALESCE("p"."full_name", 'Unassigned'::"text") AS "assigned_staff_name",
    "ap"."arrival_needed_in_minutes",
    "ap"."arrival_urgency",
    "ap"."booking_id" AS "arrival_booking_id",
    "ap"."booking_code" AS "arrival_booking_code",
    "ap"."guest_name" AS "arrival_guest_name",
    "ap"."scheduled_checkin_at" AS "arrival_checkin_at",
        CASE
            WHEN (("ap"."arrival_needed_in_minutes" IS NOT NULL) AND ("r"."housekeeping_status" <> ALL (ARRAY['clean'::"public"."housekeeping_status_enum", 'inspected'::"public"."housekeeping_status_enum"]))) THEN true
            ELSE false
        END AS "arrival_blocked",
    "r"."updated_at" AS "room_updated_at",
    "last_ht"."completed_at" AS "last_task_completed_at",
    "last_ht"."started_at" AS "last_task_started_at",
    "last_p"."full_name" AS "last_cleaner_name"
   FROM (((((((("public"."rooms" "r"
     LEFT JOIN "public"."room_types" "rt" ON (("rt"."id" = "r"."room_type_id")))
     LEFT JOIN LATERAL ( SELECT "ht2"."id",
            "ht2"."room_id",
            "ht2"."status",
            "ht2"."estimated_completion_at",
            "ht2"."assigned_to",
            "ht2"."created_at",
            "ht2"."hotel_id",
            "ht2"."started_at",
            "ht2"."completed_at",
            "ht2"."eta",
            "ht2"."priority_score"
           FROM "public"."housekeeping_tasks" "ht2"
          WHERE (("ht2"."room_id" = "r"."id") AND ("ht2"."status" = ANY (ARRAY['pending'::"text", 'in_progress'::"text", 'inspection_pending'::"text"])))
          ORDER BY "ht2"."created_at" DESC
         LIMIT 1) "ht" ON (true))
     LEFT JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "ht"."assigned_to")))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
     LEFT JOIN LATERAL ( SELECT "ht_comp"."completed_at",
            "ht_comp"."started_at",
            "ht_comp"."assigned_to"
           FROM "public"."housekeeping_tasks" "ht_comp"
          WHERE (("ht_comp"."room_id" = "r"."id") AND ("ht_comp"."status" = 'completed'::"text"))
          ORDER BY "ht_comp"."completed_at" DESC
         LIMIT 1) "last_ht" ON (true))
     LEFT JOIN "public"."hotel_members" "last_hm" ON (("last_hm"."id" = "last_ht"."assigned_to")))
     LEFT JOIN "public"."profiles" "last_p" ON (("last_p"."id" = "last_hm"."user_id")))
     LEFT JOIN LATERAL ( SELECT "ap2"."room_id",
            "ap2"."booking_id",
            "ap2"."booking_code",
            "ap2"."guest_name",
            "ap2"."scheduled_checkin_at",
            "ap2"."arrival_needed_in_minutes",
            "ap2"."arrival_urgency"
           FROM "public"."v_arrival_priority" "ap2"
          WHERE ("ap2"."room_id" = "r"."id")
          ORDER BY "ap2"."arrival_needed_in_minutes"
         LIMIT 1) "ap" ON (true));


ALTER VIEW "public"."v_housekeeping_operational_board" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_kitchen_queue" AS
 SELECT "fo"."id" AS "order_id",
    "fo"."display_id",
    "fo"."hotel_id",
    "fo"."room_id",
    "r"."number" AS "room_number",
    "fo"."status",
    "fo"."special_instructions",
    "fo"."created_at",
    "fo"."updated_at",
    "sla"."sla_started_at",
    "sla"."sla_target_at",
        CASE
            WHEN ("sla"."sla_started_at" IS NULL) THEN NULL::numeric
            ELSE (EXTRACT(epoch FROM (("sla"."sla_target_at")::timestamp with time zone - "now"())) / (60)::numeric)
        END AS "sla_minutes_remaining",
    "ka"."hotel_member_id" AS "assigned_kitchen_staff",
    "items"."total_items",
    "items"."total_amount",
    "items"."items"
   FROM (((("public"."food_orders" "fo"
     LEFT JOIN "public"."rooms" "r" ON (("r"."id" = "fo"."room_id")))
     LEFT JOIN "public"."food_order_sla_state" "sla" ON (("sla"."food_order_id" = "fo"."id")))
     LEFT JOIN "public"."food_order_assignments" "ka" ON ((("ka"."food_order_id" = "fo"."id") AND ("ka"."role" = 'KITCHEN'::"text") AND ("ka"."unassigned_at" IS NULL))))
     LEFT JOIN LATERAL ( SELECT "count"(*) AS "total_items",
            "sum"("food_order_items"."total_price") AS "total_amount",
            COALESCE("jsonb_agg"("jsonb_build_object"('id', "food_order_items"."id", 'name', "food_order_items"."item_name", 'quantity', "food_order_items"."quantity", 'modifiers', "food_order_items"."modifiers")) FILTER (WHERE ("food_order_items"."id" IS NOT NULL)), '[]'::"jsonb") AS "items"
           FROM "public"."food_order_items"
          WHERE ("food_order_items"."food_order_id" = "fo"."id")) "items" ON (true))
  WHERE ("fo"."status" = ANY (ARRAY['CREATED'::"text", 'ACCEPTED'::"text", 'PREPARING'::"text"]))
  GROUP BY "fo"."id", "fo"."display_id", "fo"."hotel_id", "fo"."room_id", "r"."number", "fo"."status", "fo"."special_instructions", "fo"."created_at", "fo"."updated_at", "sla"."sla_started_at", "sla"."sla_target_at", "ka"."hotel_member_id", "items"."total_items", "items"."total_amount", "items"."items";


ALTER VIEW "public"."v_kitchen_queue" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_my_food_orders" AS
SELECT
    NULL::"uuid" AS "order_id",
