    NULL::"text" AS "status",
    NULL::timestamp without time zone AS "created_at",
    NULL::timestamp without time zone AS "updated_at",
    NULL::"uuid" AS "room_id",
    NULL::"text" AS "room_number",
    NULL::"uuid" AS "hotel_member_id",
    NULL::"text" AS "role",
    NULL::timestamp without time zone AS "assigned_at",
    NULL::timestamp without time zone AS "sla_target_at",
    NULL::numeric AS "sla_minutes_remaining",
    NULL::bigint AS "total_items",
    NULL::numeric AS "total_amount",
    NULL::"jsonb" AS "items";


ALTER VIEW "public"."v_my_food_orders" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_agent_risk" WITH ("security_invoker"='on') AS
 SELECT "hm"."hotel_id",
    "p"."full_name" AS "agent_name",
    "p"."profile_photo_url" AS "avatar_url",
    "d"."name" AS "department_name",
    "count"(*) AS "at_risk_count"
   FROM (((((("public"."tickets" "t"
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     JOIN "public"."sla_policies" "sp" ON (("sp"."id" = "ss"."sla_policy_id")))
     JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "t"."current_assignee_id")))
     JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     JOIN "public"."departments" "d" ON (("d"."id" = "s"."department_id")))
  WHERE (("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text"])) AND ("ss"."breached" = false) AND ((((("sp"."target_minutes" * 60))::numeric - EXTRACT(epoch FROM ("now"() - "ss"."sla_started_at"))) + ("ss"."total_paused_seconds")::numeric) <= (3600)::numeric))
  GROUP BY "hm"."hotel_id", "p"."full_name", "p"."profile_photo_url", "d"."name"
  ORDER BY ("count"(*)) DESC
 LIMIT 5;


ALTER VIEW "public"."v_ops_agent_risk" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_agent_risk_details" AS
 SELECT "t"."hotel_id",
    "t"."id" AS "ticket_id",
    "substring"(("t"."id")::"text", 1, 8) AS "display_id",
    "t"."title",
    "t"."status",
    "d"."name" AS "department_name",
    "p"."full_name" AS "agent_name",
    "p"."profile_photo_url" AS "assignee_avatar",
    (((("sp"."target_minutes" * 60))::numeric - EXTRACT(epoch FROM ("now"() - "ss"."sla_started_at"))) + ("ss"."total_paused_seconds")::numeric) AS "remaining_seconds",
    ("sp"."target_minutes" * 60) AS "target_seconds"
   FROM (((((("public"."tickets" "t"
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     JOIN "public"."sla_policies" "sp" ON (("sp"."id" = "ss"."sla_policy_id")))
     JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "t"."current_assignee_id")))
     JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     JOIN "public"."departments" "d" ON (("d"."id" = "s"."department_id")))
  WHERE (("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text"])) AND ("ss"."breached" = false) AND ((((("sp"."target_minutes" * 60))::numeric - EXTRACT(epoch FROM ("now"() - "ss"."sla_started_at"))) + ("ss"."total_paused_seconds")::numeric) <= (3600)::numeric));


ALTER VIEW "public"."v_ops_agent_risk_details" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_at_risk_departments" WITH ("security_invoker"='on') AS
 SELECT "t"."hotel_id",
    "d"."name" AS "department_name",
    "count"(*) AS "at_risk_count",
    "min"(GREATEST((((("sp"."target_minutes" * 60))::numeric - EXTRACT(epoch FROM ("now"() - "ss"."sla_started_at"))) + ("ss"."total_paused_seconds")::numeric), (0)::numeric)) AS "worst_remaining_seconds"
   FROM ((((("public"."tickets" "t"
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     JOIN "public"."departments" "d" ON (("d"."id" = "s"."department_id")))
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     JOIN "public"."sla_policies" "sp" ON (("sp"."id" = "ss"."sla_policy_id")))
     LEFT JOIN "public"."sla_risk_policies" "srp" ON ((("srp"."department_id" = "d"."id") AND ("srp"."hotel_id" = "t"."hotel_id") AND ("srp"."is_active" = true))))
  WHERE (("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text"])) AND ("ss"."breached" = false) AND ("ss"."sla_started_at" IS NOT NULL) AND ((((("sp"."target_minutes" * 60))::numeric - EXTRACT(epoch FROM ("now"() - "ss"."sla_started_at"))) + ("ss"."total_paused_seconds")::numeric) <= (LEAST(("srp"."max_risk_minutes")::numeric, GREATEST(("srp"."min_risk_minutes")::numeric, ((("sp"."target_minutes" * "srp"."risk_percent"))::numeric / 100.0))) * (60)::numeric)))
  GROUP BY "t"."hotel_id", "d"."name"
  ORDER BY ("count"(*)) DESC;


ALTER VIEW "public"."v_ops_at_risk_departments" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_at_risk_details" AS
 SELECT "t"."hotel_id",
    "t"."id" AS "ticket_id",
    "substring"(("t"."id")::"text", 1, 8) AS "display_id",
    "t"."title",
    "t"."status",
    "d"."name" AS "department_name",
    COALESCE("p"."full_name", 'Unassigned'::"text") AS "assignee_name",
    "p"."profile_photo_url" AS "assignee_avatar",
    (((("sp"."target_minutes" * 60))::numeric - EXTRACT(epoch FROM ("now"() - "ss"."sla_started_at"))) + ("ss"."total_paused_seconds")::numeric) AS "remaining_seconds",
    ("sp"."target_minutes" * 60) AS "target_seconds"
   FROM ((((((("public"."tickets" "t"
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     JOIN "public"."sla_policies" "sp" ON (("sp"."id" = "ss"."sla_policy_id")))
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     JOIN "public"."departments" "d" ON (("d"."id" = "s"."department_id")))
     LEFT JOIN "public"."sla_risk_policies" "srp" ON ((("srp"."department_id" = "d"."id") AND ("srp"."hotel_id" = "t"."hotel_id") AND ("srp"."is_active" = true))))
     LEFT JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "t"."current_assignee_id")))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
  WHERE (("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text"])) AND ("ss"."breached" = false) AND ("ss"."sla_started_at" IS NOT NULL) AND ((((("sp"."target_minutes" * 60))::numeric - EXTRACT(epoch FROM ("now"() - "ss"."sla_started_at"))) + ("ss"."total_paused_seconds")::numeric) <= (LEAST(("srp"."max_risk_minutes")::numeric, GREATEST(("srp"."min_risk_minutes")::numeric, ((("sp"."target_minutes" * "srp"."risk_percent"))::numeric / 100.0))) * (60)::numeric)));


ALTER VIEW "public"."v_ops_at_risk_details" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_backlog_trend" WITH ("security_invoker"='on') AS
 WITH "daily" AS (
         SELECT "tickets"."hotel_id",
            ("generate_series"((CURRENT_DATE - '29 days'::interval), (CURRENT_DATE)::timestamp without time zone, '1 day'::interval))::"date" AS "day"
           FROM "public"."tickets"
          GROUP BY "tickets"."hotel_id"
        )
 SELECT "d"."hotel_id",
    "d"."day",
    "count"("t"."id") AS "backlog_count"
   FROM ("daily" "d"
     LEFT JOIN "public"."tickets" "t" ON ((("t"."hotel_id" = "d"."hotel_id") AND (("t"."created_at")::"date" <= "d"."day") AND (("t"."completed_at" IS NULL) OR (("t"."completed_at")::"date" > "d"."day")))))
  GROUP BY "d"."hotel_id", "d"."day"
  ORDER BY "d"."day";


ALTER VIEW "public"."v_ops_backlog_trend" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_blocked_stagnation_risk" WITH ("security_invoker"='on') AS
 SELECT "t"."hotel_id",
    "d"."name" AS "department_name",
    "count"(*) AS "blocked_count",
    "max"(GREATEST((EXTRACT(epoch FROM ("now"() - "ss"."sla_paused_at")) / (3600)::numeric), (0)::numeric)) AS "max_hours_blocked"
   FROM ((("public"."tickets" "t"
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     JOIN "public"."departments" "d" ON (("d"."id" = "s"."department_id")))
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
  WHERE (("t"."status" = 'BLOCKED'::"text") AND ("ss"."sla_paused_at" IS NOT NULL) AND (("now"() - "ss"."sla_paused_at") > '02:00:00'::interval) AND ("t"."completed_at" IS NULL) AND ("t"."cancelled_at" IS NULL))
  GROUP BY "t"."hotel_id", "d"."name"
  ORDER BY ("count"(*)) DESC;


ALTER VIEW "public"."v_ops_blocked_stagnation_risk" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_blocked_tickets_detail" AS
 SELECT "t"."hotel_id",
    "t"."id" AS "ticket_id",
    "substring"(("t"."id")::"text", 1, 8) AS "display_id",
    "t"."title",
    "d"."name" AS "department_name",
    "p"."full_name" AS "assignee_name",
    "p"."profile_photo_url" AS "assignee_avatar",
    "br"."label" AS "block_reason",
    "ss"."sla_paused_at",
    GREATEST(EXTRACT(epoch FROM ("now"() - "ss"."sla_paused_at")), (0)::numeric) AS "blocked_seconds"
   FROM ((((((("public"."tickets" "t"
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     JOIN "public"."departments" "d" ON (("d"."id" = "s"."department_id")))
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     LEFT JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "t"."current_assignee_id")))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
     LEFT JOIN LATERAL ( SELECT "te"."reason_code"
           FROM "public"."ticket_events" "te"
          WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'BLOCKED'::"text"))
          ORDER BY "te"."created_at" DESC
         LIMIT 1) "blk" ON (true))
     LEFT JOIN "public"."block_reasons" "br" ON (("br"."code" = "blk"."reason_code")))
  WHERE (("t"."status" = 'BLOCKED'::"text") AND ("ss"."sla_paused_at" IS NOT NULL) AND (("now"() - "ss"."sla_paused_at") > '02:00:00'::interval) AND ("t"."completed_at" IS NULL) AND ("t"."cancelled_at" IS NULL))
  ORDER BY GREATEST(EXTRACT(epoch FROM ("now"() - "ss"."sla_paused_at")), (0)::numeric) DESC;


ALTER VIEW "public"."v_ops_blocked_tickets_detail" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_board_tickets" AS
 SELECT "t"."id",
    "t"."hotel_id",
    "t"."service_id",
    "s"."department_id" AS "service_department_id",
    "t"."room_id",
    "t"."zone_id",
    "s"."label" AS "service_label",
    "s"."key" AS "service_key",
    "t"."title" AS "legacy_title",
    "t"."description",
    "t"."status",
    NULL::"text" AS "priority",
    "t"."current_assignee_id" AS "assignee_id",
    COALESCE("p"."full_name", 'Unassigned'::"text") AS "assignee_name",
    "t"."created_by_type",
    "t"."created_by_id",
    "t"."created_at",
    "t"."updated_at",
    "t"."completed_at",
    "sp"."target_minutes" AS "sla_minutes",
    ("ss"."sla_started_at" + (("sp"."target_minutes" || ' minutes'::"text"))::interval) AS "sla_deadline",
        CASE
            WHEN ("ss"."current_remaining_seconds" IS NOT NULL) THEN ("ss"."current_remaining_seconds" / 60)
            ELSE NULL::integer
        END AS "mins_remaining",
    COALESCE(LEAST(("srp"."max_risk_minutes")::numeric, GREATEST(("srp"."min_risk_minutes")::numeric, ((("sp"."target_minutes" * "srp"."risk_percent"))::numeric / 100.0))), LEAST((30)::numeric, (("sp"."target_minutes")::numeric * 0.25))) AS "risk_threshold_minutes",
    ((("pending_event_action"."event_type" IS NOT NULL) OR ("pending_block_action"."event_type" IS NOT NULL)) AND ("t"."status" <> ALL (ARRAY['COMPLETED'::"text", 'CANCELLED'::"text"]))) AS "needs_supervisor_action",
    COALESCE("pending_event_action"."event_type", "pending_block_action"."event_type") AS "supervisor_request_type",
    COALESCE("pending_event_action"."reason_code", "pending_block_action"."reason_code") AS "supervisor_reason_code",
    COALESCE("pending_event_action"."created_at", "pending_block_action"."created_at") AS "supervisor_requested_at",
    "t"."reason_code" AS "primary_reason_code",
    "r"."number" AS "room_number",
    "d"."name" AS "department_name",
        CASE
            WHEN ("r"."number" IS NOT NULL) THEN "concat"('Room ', "r"."number")
            WHEN ("z"."name" IS NOT NULL) THEN "z"."name"
            ELSE 'Unknown Location'::"text"
        END AS "location_label",
    "sla_exempted"."is_exempted" AS "sla_exception_granted",
        CASE
            WHEN "sla_exempted"."is_exempted" THEN 'EXEMPTED'::"text"
            WHEN ("ss"."sla_started_at" IS NULL) THEN 'NOT_STARTED'::"text"
            WHEN ("ss"."breached" = true) THEN 'BREACHED'::"text"
            WHEN ("ss"."sla_paused_at" IS NOT NULL) THEN 'PAUSED'::"text"
            ELSE 'RUNNING'::"text"
        END AS "sla_state"
   FROM (((((((((((("public"."tickets" "t"
     LEFT JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     LEFT JOIN "public"."rooms" "r" ON (("r"."id" = "t"."room_id")))
     LEFT JOIN "public"."hotel_zones" "z" ON (("z"."id" = "t"."zone_id")))
     LEFT JOIN "public"."departments" "d" ON (("d"."id" = "s"."department_id")))
     LEFT JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "t"."current_assignee_id")))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
     LEFT JOIN "public"."sla_policies" "sp" ON ((("sp"."department_id" = "s"."department_id") AND ("sp"."is_active" = true))))
     LEFT JOIN "public"."sla_risk_policies" "srp" ON ((("srp"."department_id" = "s"."department_id") AND ("srp"."hotel_id" = "t"."hotel_id") AND ("srp"."is_active" = true))))
     LEFT JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     LEFT JOIN LATERAL ( SELECT "te"."event_type",
            "te"."reason_code",
            "te"."created_at"
           FROM "public"."ticket_events" "te"
          WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = ANY (ARRAY['SUPERVISOR_REQUESTED'::"text", 'SLA_EXCEPTION_REQUESTED'::"text"])) AND (NOT (EXISTS ( SELECT 1
                   FROM "public"."ticket_events" "res"
                  WHERE (("res"."ticket_id" = "t"."id") AND ("res"."created_at" > "te"."created_at") AND ("res"."event_type" = ANY (ARRAY['SUPERVISOR_APPROVED'::"text", 'SUPERVISOR_REJECTED'::"text", 'SLA_EXCEPTION_GRANTED'::"text", 'SLA_EXCEPTION_REJECTED'::"text", 'SUPERVISOR_REQUEST_CANCELLED'::"text"])))))))
          ORDER BY "te"."created_at" DESC
         LIMIT 1) "pending_event_action" ON (true))
     LEFT JOIN LATERAL ( SELECT "te"."event_type",
            "te"."reason_code",
            "te"."created_at"
           FROM "public"."ticket_events" "te"
          WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'BLOCKED'::"text") AND ("te"."reason_code" = 'supervisor_approval'::"text") AND (NOT (EXISTS ( SELECT 1
                   FROM "public"."ticket_events" "res"
                  WHERE (("res"."ticket_id" = "t"."id") AND ("res"."created_at" > "te"."created_at") AND (("res"."event_type" = ANY (ARRAY['SUPERVISOR_APPROVED'::"text", 'SUPERVISOR_REJECTED'::"text"])) OR (("res"."event_type" = 'UNBLOCKED'::"text") AND ("res"."reason_code" = 'supervisor_request_cancelled'::"text"))))))))
          ORDER BY "te"."created_at" DESC
         LIMIT 1) "pending_block_action" ON (true))
     LEFT JOIN LATERAL ( SELECT (EXISTS ( SELECT 1
                   FROM "public"."ticket_events" "te"
                  WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'SLA_EXCEPTION_GRANTED'::"text")))) AS "is_exempted") "sla_exempted" ON (true));


ALTER VIEW "public"."v_ops_board_tickets" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_created_resolved_30d" WITH ("security_invoker"='on') AS
 WITH "daily" AS (
         SELECT "tickets"."hotel_id",
            ("generate_series"((CURRENT_DATE - '29 days'::interval), (CURRENT_DATE)::timestamp without time zone, '1 day'::interval))::"date" AS "day"
           FROM "public"."tickets"
          GROUP BY "tickets"."hotel_id"
        )
 SELECT "d"."hotel_id",
    "d"."day",
    "count"(DISTINCT
        CASE
            WHEN (("t"."created_at")::"date" = "d"."day") THEN "t"."id"
            ELSE NULL::"uuid"
        END) AS "created_count",
    "count"(DISTINCT
        CASE
            WHEN (("t"."status" = 'COMPLETED'::"text") AND (("t"."completed_at")::"date" = "d"."day")) THEN "t"."id"
            ELSE NULL::"uuid"
        END) AS "resolved_count"
   FROM ("daily" "d"
     LEFT JOIN "public"."tickets" "t" ON ((("t"."hotel_id" = "d"."hotel_id") AND ((("t"."created_at")::"date" = "d"."day") OR (("t"."completed_at")::"date" = "d"."day")))))
  GROUP BY "d"."hotel_id", "d"."day"
  ORDER BY "d"."day" DESC;


ALTER VIEW "public"."v_ops_created_resolved_30d" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_decisions_30d" WITH ("security_invoker"='on') AS
 SELECT "t"."hotel_id",
    "d"."name" AS "department_name",
    "ser"."category" AS "reason_category",
    "count"(DISTINCT "te"."id") AS "requested_count",
    "count"(DISTINCT
        CASE
            WHEN ("de"."event_type" = 'SLA_EXCEPTION_GRANTED'::"text") THEN "te"."id"
            ELSE NULL::"uuid"
        END) AS "granted_count",
    "count"(DISTINCT
        CASE
            WHEN ("de"."event_type" = 'SLA_EXCEPTION_REJECTED'::"text") THEN "te"."id"
            ELSE NULL::"uuid"
        END) AS "rejected_count",
    "count"(DISTINCT
        CASE
            WHEN ("de"."event_type" IS NULL) THEN "te"."id"
            ELSE NULL::"uuid"
        END) AS "pending_count"
   FROM (((("public"."tickets" "t"
     JOIN "public"."departments" "d" ON (("d"."id" = "t"."service_department_id")))
     JOIN "public"."ticket_events" "te" ON ((("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'SLA_EXCEPTION_REQUESTED'::"text"))))
     LEFT JOIN "public"."sla_exception_reasons" "ser" ON (("ser"."code" = "te"."reason_code")))
     LEFT JOIN "public"."ticket_events" "de" ON ((("de"."ticket_id" = "t"."id") AND ("de"."event_type" = ANY (ARRAY['SLA_EXCEPTION_GRANTED'::"text", 'SLA_EXCEPTION_REJECTED'::"text"])) AND ("de"."created_at" > "te"."created_at"))))
  WHERE ("te"."created_at" >= (CURRENT_DATE - '30 days'::interval))
  GROUP BY "t"."hotel_id", "d"."name", "ser"."category";


ALTER VIEW "public"."v_ops_decisions_30d" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_exception_reasons_30d" WITH ("security_invoker"='on') AS
 SELECT "t"."hotel_id",
    COALESCE("ser"."label", 'Other'::"text") AS "reason_label",
    "count"("t"."id") AS "breach_count",
    "round"(((100.0 * ("count"("t"."id"))::numeric) / NULLIF("sum"("count"("t"."id")) OVER (PARTITION BY "t"."hotel_id"), (0)::numeric)), 1) AS "percentage"
   FROM ((("public"."tickets" "t"
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     LEFT JOIN "public"."ticket_events" "te" ON ((("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'SLA_EXCEPTION_REQUESTED'::"text"))))
     LEFT JOIN "public"."sla_exception_reasons" "ser" ON (("ser"."code" = "te"."reason_code")))
  WHERE (("ss"."breached" = true) AND ("t"."status" = 'COMPLETED'::"text") AND ("t"."completed_at" >= (CURRENT_DATE - '30 days'::interval)))
  GROUP BY "t"."hotel_id", "ser"."label";


ALTER VIEW "public"."v_ops_exception_reasons_30d" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_exceptions_30d" WITH ("security_invoker"='on') AS
 SELECT "t"."hotel_id",
    "d"."name" AS "department_name",
    "count"("te"."id") FILTER (WHERE ("ser"."category" = 'GUEST_DEPENDENCY'::"text")) AS "guest_count",
    "count"("te"."id") FILTER (WHERE ("ser"."category" = 'INFRASTRUCTURE'::"text")) AS "infra_count",
    "count"("te"."id") FILTER (WHERE ("ser"."category" = 'POLICY'::"text")) AS "policy_count",
    "count"("te"."id") AS "total_exception_requests"
   FROM ((("public"."tickets" "t"
     JOIN "public"."departments" "d" ON (("d"."id" = "t"."service_department_id")))
     JOIN "public"."ticket_events" "te" ON ((("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'SLA_EXCEPTION_REQUESTED'::"text"))))
     LEFT JOIN "public"."sla_exception_reasons" "ser" ON (("ser"."code" = "te"."reason_code")))
  WHERE ("te"."created_at" >= (CURRENT_DATE - '30 days'::interval))
  GROUP BY "t"."hotel_id", "d"."name";


ALTER VIEW "public"."v_ops_exceptions_30d" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_kpi_current" WITH ("security_invoker"='on') AS
 SELECT "t"."hotel_id",
    "round"(((100.0 * ("count"(DISTINCT
        CASE
            WHEN (("t"."status" = 'COMPLETED'::"text") AND ("ss"."breached" = false)) THEN "t"."id"
            ELSE NULL::"uuid"
        END))::numeric) / (NULLIF("count"(DISTINCT
        CASE
            WHEN (("t"."status" = 'COMPLETED'::"text") AND ("ss"."breached" IS NOT NULL)) THEN "t"."id"
            ELSE NULL::"uuid"
        END), 0))::numeric), 1) AS "sla_compliance_percent",
    "round"(((100.0 * ("count"(DISTINCT
        CASE
            WHEN (("t"."status" = 'COMPLETED'::"text") AND ("ss"."breached" = true)) THEN "t"."id"
            ELSE NULL::"uuid"
        END))::numeric) / (NULLIF("count"(DISTINCT
        CASE
            WHEN (("t"."status" = 'COMPLETED'::"text") AND ("ss"."breached" IS NOT NULL)) THEN "t"."id"
            ELSE NULL::"uuid"
        END), 0))::numeric), 1) AS "sla_breach_percent",
    "count"(DISTINCT "t"."id") AS "active_tasks_count",
    "round"("avg"(
        CASE
            WHEN (("t"."status" <> 'COMPLETED'::"text") AND ("ss"."breached" = false)) THEN (("ss"."current_remaining_seconds")::numeric / 60.0)
            ELSE NULL::numeric
        END)) AS "avg_time_to_breach"
   FROM ("public"."tickets" "t"
     LEFT JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
  GROUP BY "t"."hotel_id";


ALTER VIEW "public"."v_ops_kpi_current" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_open_breaches" WITH ("security_invoker"='on') AS
 SELECT "t"."hotel_id",
    "t"."id" AS "ticket_id",
    "substring"(("t"."id")::"text", 1, 8) AS "display_id",
    "d"."name" AS "department_name",
    "p"."full_name" AS "assignee_name",
    "p"."profile_photo_url" AS "assignee_avatar",
    COALESCE("br"."label", 'Direct SLA Breach'::"text") AS "breach_context",
    "round"((EXTRACT(epoch FROM ("now"() - "ss"."breached_at")) / (3600)::numeric), 1) AS "hours_overdue"
   FROM ((((((("public"."tickets" "t"
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     JOIN "public"."departments" "d" ON (("d"."id" = "s"."department_id")))
     LEFT JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "t"."current_assignee_id")))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
     LEFT JOIN LATERAL ( SELECT "te"."reason_code"
           FROM "public"."ticket_events" "te"
          WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'BLOCKED'::"text"))
          ORDER BY "te"."created_at" DESC
         LIMIT 1) "blk" ON (true))
     LEFT JOIN "public"."block_reasons" "br" ON (("br"."code" = "blk"."reason_code")))
  WHERE (("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text"])) AND ("ss"."breached" = true))
  ORDER BY ("round"((EXTRACT(epoch FROM ("now"() - "ss"."breached_at")) / (3600)::numeric), 1)) DESC
 LIMIT 20;


ALTER VIEW "public"."v_ops_open_breaches" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_sla_breach_reasons" WITH ("security_invoker"='on') AS
 SELECT "t"."hotel_id",
    COALESCE("br"."label", 'Other'::"text") AS "reason_label",
    "count"(*) AS "breach_count",
    "round"(((100.0 * ("count"(*))::numeric) / "sum"("count"(*)) OVER (PARTITION BY "t"."hotel_id")), 1) AS "percentage"
   FROM ((("public"."tickets" "t"
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     LEFT JOIN LATERAL ( SELECT "te"."reason_code"
           FROM "public"."ticket_events" "te"
          WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'BLOCKED'::"text"))
          ORDER BY "te"."created_at" DESC
         LIMIT 1) "blk" ON (true))
     LEFT JOIN "public"."block_reasons" "br" ON (("br"."code" = "blk"."reason_code")))
  WHERE (("t"."status" = 'COMPLETED'::"text") AND ("ss"."breached" = true) AND ("t"."completed_at" >= (CURRENT_DATE - '30 days'::interval)))
  GROUP BY "t"."hotel_id", "br"."label";


ALTER VIEW "public"."v_ops_sla_breach_reasons" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_sla_breaches_by_dept" AS
 SELECT "t"."hotel_id",
    "d"."name" AS "department_name",
    "count"(*) FILTER (WHERE ("br"."category" = 'guest_constraint'::"text")) AS "count_guest",
    "count"(*) FILTER (WHERE ("br"."category" = 'dependency'::"text")) AS "count_dependency",
    "count"(*) FILTER (WHERE ("br"."category" = 'inventory'::"text")) AS "count_inventory",
    "count"(*) FILTER (WHERE ("br"."category" = 'approval'::"text")) AS "count_approval",
    "count"(*) FILTER (WHERE (("br"."category" IS NULL) OR ("br"."category" = 'other'::"text"))) AS "count_other"
   FROM ((((("public"."tickets" "t"
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     JOIN "public"."departments" "d" ON (("d"."id" = "s"."department_id")))
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     LEFT JOIN LATERAL ( SELECT "te"."reason_code"
           FROM "public"."ticket_events" "te"
          WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'BLOCKED'::"text"))
          ORDER BY "te"."created_at" DESC
         LIMIT 1) "latest_block" ON (true))
     LEFT JOIN "public"."block_reasons" "br" ON (("br"."code" = "latest_block"."reason_code")))
  WHERE (("t"."status" = 'COMPLETED'::"text") AND ("ss"."breached" = true) AND ("t"."completed_at" >= (CURRENT_DATE - '30 days'::interval)))
  GROUP BY "t"."hotel_id", "d"."name"
  ORDER BY ("count"(*)) DESC
 LIMIT 5;


ALTER VIEW "public"."v_ops_sla_breaches_by_dept" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_sla_exception_decisions_by_reason" AS
 WITH "exception_requests" AS (
         SELECT "te"."ticket_id",
            "te"."reason_code",
            "min"("te"."created_at") AS "requested_at"
           FROM "public"."ticket_events" "te"
          WHERE ("te"."event_type" = 'SLA_EXCEPTION_REQUESTED'::"text")
          GROUP BY "te"."ticket_id", "te"."reason_code"
        ), "decision_events" AS (
         SELECT "te"."ticket_id",
            "max"("te"."created_at") FILTER (WHERE ("te"."event_type" = ANY (ARRAY['SLA_EXCEPTION_GRANTED'::"text", 'SLA_EXCEPTION_REJECTED'::"text"]))) AS "decided_at"
           FROM "public"."ticket_events" "te"
          GROUP BY "te"."ticket_id"
        )
 SELECT "t"."hotel_id",
    "d"."name" AS "department_name",
    COALESCE("ser"."label", 'Other'::"text") AS "reason_label",
    "ser"."category" AS "reason_category",
    "count"(DISTINCT "er"."ticket_id") AS "requested_count",
    "count"(DISTINCT "er"."ticket_id") FILTER (WHERE (EXISTS ( SELECT 1
           FROM "public"."ticket_events" "te2"
          WHERE (("te2"."ticket_id" = "er"."ticket_id") AND ("te2"."event_type" = 'SLA_EXCEPTION_GRANTED'::"text"))))) AS "granted_count",
    "count"(DISTINCT "er"."ticket_id") FILTER (WHERE (EXISTS ( SELECT 1
           FROM "public"."ticket_events" "te2"
          WHERE (("te2"."ticket_id" = "er"."ticket_id") AND ("te2"."event_type" = 'SLA_EXCEPTION_REJECTED'::"text"))))) AS "rejected_count",
    "count"(DISTINCT "er"."ticket_id") FILTER (WHERE ("de"."decided_at" IS NULL)) AS "pending_count"
   FROM ((((("exception_requests" "er"
     JOIN "public"."tickets" "t" ON (("t"."id" = "er"."ticket_id")))
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     JOIN "public"."departments" "d" ON (("d"."id" = "s"."department_id")))
     LEFT JOIN "public"."sla_exception_reasons" "ser" ON ((("ser"."code" = "er"."reason_code") AND ("ser"."is_active" = true))))
     LEFT JOIN "decision_events" "de" ON (("de"."ticket_id" = "er"."ticket_id")))
  WHERE ("er"."requested_at" >= (CURRENT_DATE - '30 days'::interval))
  GROUP BY "t"."hotel_id", "d"."name", COALESCE("ser"."label", 'Other'::"text"), "ser"."category";


ALTER VIEW "public"."v_ops_sla_exception_decisions_by_reason" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_sla_exception_details" AS
 SELECT "t"."hotel_id",
    "t"."id" AS "ticket_id",
    "substring"(("t"."id")::"text", 1, 8) AS "display_id",
    "t"."title",
    "t"."status",
    "d"."name" AS "department_name",
    "p"."full_name" AS "assignee_name",
    "p"."profile_photo_url" AS "assignee_avatar",
    COALESCE("ser"."label", 'Other'::"text") AS "block_reason",
    "ser"."category" AS "exception_category",
    "te"."created_at" AS "exception_occurred_at",
    (0)::numeric AS "blocked_seconds"
   FROM (((((("public"."ticket_events" "te"
     JOIN "public"."tickets" "t" ON (("t"."id" = "te"."ticket_id")))
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     JOIN "public"."departments" "d" ON (("d"."id" = "s"."department_id")))
     LEFT JOIN "public"."sla_exception_reasons" "ser" ON (("ser"."code" = "te"."reason_code")))
     LEFT JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "t"."current_assignee_id")))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
  WHERE (("te"."event_type" = 'SLA_EXCEPTION_REQUESTED'::"text") AND ("te"."created_at" >= (CURRENT_DATE - '30 days'::interval)));


ALTER VIEW "public"."v_ops_sla_exception_details" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_sla_exceptions_by_department" AS
 WITH "exception_requests" AS (
         SELECT DISTINCT ON ("te"."ticket_id") "te"."ticket_id",
            "te"."reason_code",
            "te"."created_at" AS "requested_at"
           FROM "public"."ticket_events" "te"
          WHERE (("te"."event_type" = 'SLA_EXCEPTION_REQUESTED'::"text") AND ("te"."created_at" >= (CURRENT_DATE - '30 days'::interval)))
          ORDER BY "te"."ticket_id", "te"."created_at"
        )
 SELECT "d"."hotel_id",
    "d"."id" AS "department_id",
    "d"."name" AS "department_name",
    "count"("er"."ticket_id") FILTER (WHERE ("ser"."category" = 'GUEST_DEPENDENCY'::"text")) AS "guest_count",
    "count"("er"."ticket_id") FILTER (WHERE ("ser"."category" = 'INFRASTRUCTURE'::"text")) AS "infra_count",
    "count"("er"."ticket_id") FILTER (WHERE ("ser"."category" = 'POLICY'::"text")) AS "policy_count",
    "count"("er"."ticket_id") FILTER (WHERE ("ser"."category" = 'EXTERNAL_DEPENDENCY'::"text")) AS "external_count",
    "count"("er"."ticket_id") FILTER (WHERE ("ser"."category" = 'MANAGEMENT'::"text")) AS "approval_count",
    "count"("er"."ticket_id") FILTER (WHERE ("ser"."category" IS NULL)) AS "other_count",
    "count"("er"."ticket_id") AS "total_exception_requests"
   FROM (((("public"."departments" "d"
     LEFT JOIN "public"."services" "s" ON (("s"."department_id" = "d"."id")))
     LEFT JOIN "public"."tickets" "t" ON (("t"."service_id" = "s"."id")))
     LEFT JOIN "exception_requests" "er" ON (("er"."ticket_id" = "t"."id")))
     LEFT JOIN "public"."sla_exception_reasons" "ser" ON ((("ser"."code" = "er"."reason_code") AND ("ser"."is_active" = true))))
  GROUP BY "d"."hotel_id", "d"."id", "d"."name"
  ORDER BY ("count"("er"."ticket_id")) DESC;


ALTER VIEW "public"."v_ops_sla_exceptions_by_department" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ops_ticket_backlog_30d" WITH ("security_invoker"='on') AS
 WITH "daily" AS (
         SELECT "tickets"."hotel_id",
            ("generate_series"((CURRENT_DATE - '29 days'::interval), (CURRENT_DATE)::timestamp without time zone, '1 day'::interval))::"date" AS "day"
           FROM "public"."tickets"
          GROUP BY "tickets"."hotel_id"
        )
 SELECT "d"."hotel_id",
    "d"."day",
    "count"(DISTINCT "t"."id") AS "backlog_count"
   FROM ("daily" "d"
     LEFT JOIN "public"."tickets" "t" ON ((("t"."hotel_id" = "d"."hotel_id") AND (("t"."created_at")::"date" <= "d"."day") AND (("t"."completed_at" IS NULL) OR (("t"."completed_at")::"date" > "d"."day")))))
  GROUP BY "d"."hotel_id", "d"."day"
  ORDER BY "d"."day" DESC;


ALTER VIEW "public"."v_ops_ticket_backlog_30d" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_activity_breakdown" AS
 SELECT "hotel_id",
    "day",
    "department_name",
    "sum"("created_count") AS "created_count",
    "sum"("resolved_count") AS "resolved_count"
   FROM ( SELECT "t"."hotel_id",
            "date"("t"."created_at") AS "day",
            "sd"."name" AS "department_name",
            "count"(*) AS "created_count",
            0 AS "resolved_count"
           FROM (("public"."tickets" "t"
             JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
             JOIN "public"."departments" "sd" ON (("sd"."id" = "s"."department_id")))
          WHERE ("t"."created_at" >= (CURRENT_DATE - '30 days'::interval))
          GROUP BY "t"."hotel_id", ("date"("t"."created_at")), "sd"."name"
        UNION ALL
         SELECT "t"."hotel_id",
            "date"("t"."completed_at") AS "day",
            "sd"."name" AS "department_name",
            0 AS "created_count",
            "count"(*) AS "resolved_count"
           FROM (("public"."tickets" "t"
             JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
             JOIN "public"."departments" "sd" ON (("sd"."id" = "s"."department_id")))
          WHERE (("t"."status" = 'COMPLETED'::"text") AND ("t"."completed_at" >= (CURRENT_DATE - '30 days'::interval)))
          GROUP BY "t"."hotel_id", ("date"("t"."completed_at")), "sd"."name") "raw"
  GROUP BY "hotel_id", "day", "department_name";


ALTER VIEW "public"."v_owner_activity_breakdown" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_at_risk_breakdown" AS
 SELECT "t"."hotel_id",
        CASE
            WHEN (EXISTS ( SELECT 1
               FROM "public"."ticket_events" "te"
              WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'BLOCKED'::"text") AND (NOT (EXISTS ( SELECT 1
                       FROM "public"."ticket_events" "unblock"
                      WHERE (("unblock"."ticket_id" = "t"."id") AND ("unblock"."event_type" = 'UNBLOCKED'::"text") AND ("unblock"."created_at" > "te"."created_at")))))))) THEN 'Blocked'::"text"
            WHEN ("t"."current_assignee_id" IS NULL) THEN 'Unassigned'::"text"
            ELSE 'Time Critical'::"text"
        END AS "risk_category",
    "count"(DISTINCT "t"."id") AS "risk_count"
   FROM ("public"."tickets" "t"
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
  WHERE (("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text"])) AND ("ss"."current_remaining_seconds" <= 1800))
  GROUP BY "t"."hotel_id",
        CASE
            WHEN (EXISTS ( SELECT 1
               FROM "public"."ticket_events" "te"
              WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'BLOCKED'::"text") AND (NOT (EXISTS ( SELECT 1
                       FROM "public"."ticket_events" "unblock"
                      WHERE (("unblock"."ticket_id" = "t"."id") AND ("unblock"."event_type" = 'UNBLOCKED'::"text") AND ("unblock"."created_at" > "te"."created_at")))))))) THEN 'Blocked'::"text"
            WHEN ("t"."current_assignee_id" IS NULL) THEN 'Unassigned'::"text"
            ELSE 'Time Critical'::"text"
        END;


ALTER VIEW "public"."v_owner_at_risk_breakdown" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_block_reason_analysis" AS
 SELECT "t"."hotel_id",
    "date"("te"."created_at") AS "day",
    "te"."reason_code",
    "count"(*) AS "block_count"
   FROM ("public"."ticket_events" "te"
     JOIN "public"."tickets" "t" ON (("t"."id" = "te"."ticket_id")))
  WHERE (("te"."event_type" = 'BLOCKED'::"text") AND ("te"."created_at" >= (CURRENT_DATE - '30 days'::interval)))
  GROUP BY "t"."hotel_id", ("date"("te"."created_at")), "te"."reason_code";


ALTER VIEW "public"."v_owner_block_reason_analysis" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_checkin_trend_daily" AS
 SELECT "hotel_id",
    "date"("scheduled_checkin_at") AS "day",
    "count"(*) AS "checkin_count"
   FROM "public"."stays"
  WHERE ("scheduled_checkin_at" IS NOT NULL)
  GROUP BY "hotel_id", ("date"("scheduled_checkin_at"))
  ORDER BY ("date"("scheduled_checkin_at")) DESC;


ALTER VIEW "public"."v_owner_checkin_trend_daily" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_kpi_summary" AS
 SELECT "t"."hotel_id",
    "count"(DISTINCT "t"."id") FILTER (WHERE ("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text"]))) AS "total_tickets",
    "count"(DISTINCT "t"."id") FILTER (WHERE (("t"."status" = 'COMPLETED'::"text") AND ("ss"."breached" = false) AND ("t"."completed_at" >= (CURRENT_DATE - '30 days'::interval)) AND (NOT (EXISTS ( SELECT 1
           FROM "public"."ticket_events" "te"
          WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'SLA_EXCEPTION_GRANTED'::"text"))))))) AS "completed_within_sla",
    "count"(DISTINCT "t"."id") FILTER (WHERE ((("ss"."breached" = true) OR (("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text"])) AND ("ss"."current_remaining_seconds" <= 0))) AND (("t"."completed_at" >= (CURRENT_DATE - '30 days'::interval)) OR ("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text"]))))) AS "breached_sla",
    "count"(DISTINCT "t"."id") FILTER (WHERE (("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text"])) AND ("ss"."current_remaining_seconds" <= 1800) AND (NOT (EXISTS ( SELECT 1
           FROM "public"."ticket_events" "te"
          WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'SLA_EXCEPTION_GRANTED'::"text"))))))) AS "at_risk_tickets",
    "round"(((100.0 * ("count"(DISTINCT "t"."id") FILTER (WHERE (("t"."status" = 'COMPLETED'::"text") AND ("ss"."breached" = false) AND ("t"."completed_at" >= (CURRENT_DATE - '30 days'::interval)))))::numeric) / (NULLIF("count"(DISTINCT "t"."id") FILTER (WHERE (("t"."status" = 'COMPLETED'::"text") AND ("t"."completed_at" >= (CURRENT_DATE - '30 days'::interval)))), 0))::numeric), 2) AS "sla_compliance_percent"
   FROM ("public"."tickets" "t"
     LEFT JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
  GROUP BY "t"."hotel_id";


ALTER VIEW "public"."v_owner_kpi_summary" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_kpis_ist" AS
 WITH "cfg"("slugs") AS (
         VALUES (ARRAY['DEMO1'::"text", 'DEMO2'::"text"])
        ), "demo_hotels" AS (
         SELECT "hotels"."id",
            "hotels"."slug",
            "hotels"."name"
           FROM "public"."hotels"
          WHERE ("hotels"."slug" IN ( SELECT "unnest"("cfg"."slugs") AS "unnest"
                   FROM "cfg"))
        ), "tz" AS (
         SELECT (("now"() AT TIME ZONE 'Asia/Kolkata'::"text"))::"date" AS "local_today",
            ("now"() AT TIME ZONE 'Asia/Kolkata'::"text") AS "local_now"
        )
 SELECT "dh"."slug",
    "dh"."name",
    "count"(*) FILTER (WHERE ("s"."status" = 'inhouse'::"public"."stay_status")) AS "inhouse_now",
    "count"(*) FILTER (WHERE (("s"."status" = 'arriving'::"public"."stay_status") AND ((("s"."scheduled_checkin_at" AT TIME ZONE 'Asia/Kolkata'::"text"))::"date" = ( SELECT "tz"."local_today"
           FROM "tz")))) AS "arrivals_today",
    "count"(*) FILTER (WHERE (("s"."status" = 'reserved'::"public"."stay_status") AND ((("s"."scheduled_checkout_at" AT TIME ZONE 'Asia/Kolkata'::"text"))::"date" = ( SELECT "tz"."local_today"
           FROM "tz")))) AS "departures_today"
   FROM ("demo_hotels" "dh"
     LEFT JOIN "public"."stays" "s" ON (("s"."hotel_id" = "dh"."id")))
  GROUP BY "dh"."slug", "dh"."name"
  ORDER BY "dh"."slug";


ALTER VIEW "public"."v_owner_kpis_ist" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_occupancy_stats" AS
 SELECT "r"."hotel_id",
    "count"(*) AS "total_rooms",
    "count"(*) FILTER (WHERE ("r"."status" = 'occupied'::"public"."room_operational_status")) AS "occupied_rooms",
        CASE
            WHEN ("count"(*) > 0) THEN "round"(((("count"(*) FILTER (WHERE ("r"."status" = 'occupied'::"public"."room_operational_status")))::numeric / ("count"(*))::numeric) * (100)::numeric), 2)
            ELSE (0)::numeric
        END AS "occupancy_percent",
    COALESCE("ct"."check_ins_today", (0)::bigint) AS "check_ins_today",
    COALESCE("cy"."check_ins_yesterday", (0)::bigint) AS "check_ins_yesterday"
   FROM (("public"."rooms" "r"
     LEFT JOIN ( SELECT "stays"."hotel_id",
            "count"(*) AS "check_ins_today"
           FROM "public"."stays"
          WHERE (("stays"."scheduled_checkin_at")::"date" = CURRENT_DATE)
          GROUP BY "stays"."hotel_id") "ct" ON (("ct"."hotel_id" = "r"."hotel_id")))
     LEFT JOIN ( SELECT "stays"."hotel_id",
            "count"(*) AS "check_ins_yesterday"
           FROM "public"."stays"
          WHERE (("stays"."scheduled_checkin_at")::"date" = (CURRENT_DATE - '1 day'::interval))
          GROUP BY "stays"."hotel_id") "cy" ON (("cy"."hotel_id" = "r"."hotel_id")))
  WHERE (("r"."is_out_of_order" = false) OR ("r"."is_out_of_order" IS NULL))
  GROUP BY "r"."hotel_id", "ct"."check_ins_today", "cy"."check_ins_yesterday";


ALTER VIEW "public"."v_owner_occupancy_stats" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_sla_breach_breakdown" AS
 SELECT "t"."hotel_id",
    "date"("t"."completed_at") AS "day",
    COALESCE("br"."label", 'Other'::"text") AS "reason_label",
    "te"."reason_code",
    "count"(DISTINCT "t"."id") AS "breached_count"
   FROM ((("public"."tickets" "t"
     JOIN "public"."ticket_sla_state" "ss" ON ((("ss"."ticket_id" = "t"."id") AND ("ss"."breached" = true))))
     JOIN LATERAL ( SELECT "te_1"."reason_code"
           FROM "public"."ticket_events" "te_1"
          WHERE (("te_1"."ticket_id" = "t"."id") AND ("te_1"."event_type" = 'BLOCKED'::"text"))
          ORDER BY "te_1"."created_at" DESC
         LIMIT 1) "te" ON (true))
     LEFT JOIN "public"."block_reasons" "br" ON (("br"."code" = "te"."reason_code")))
  WHERE (("t"."completed_at" >= (CURRENT_DATE - '30 days'::interval)) AND (NOT (EXISTS ( SELECT 1
           FROM "public"."ticket_events" "ex"
          WHERE (("ex"."ticket_id" = "t"."id") AND ("ex"."event_type" = 'SLA_EXCEPTION_GRANTED'::"text"))))))
  GROUP BY "t"."hotel_id", ("date"("t"."completed_at")), "te"."reason_code", "br"."label";


ALTER VIEW "public"."v_owner_sla_breach_breakdown" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_sla_exception_breakdown" AS
 SELECT "t"."hotel_id",
    "te"."reason_code",
    COALESCE("br"."label", "te"."reason_code") AS "reason_label",
    "count"(*) AS "exception_count",
    "round"(((100.0 * ("count"(*))::numeric) / NULLIF("sum"("count"(*)) OVER (PARTITION BY "t"."hotel_id"), (0)::numeric)), 2) AS "exception_percent"
   FROM (("public"."ticket_events" "te"
     JOIN "public"."tickets" "t" ON (("t"."id" = "te"."ticket_id")))
     LEFT JOIN "public"."block_reasons" "br" ON (("br"."code" = "te"."reason_code")))
  WHERE ("te"."event_type" = 'SLA_EXCEPTION_GRANTED'::"text")
  GROUP BY "t"."hotel_id", "te"."reason_code", "br"."label"
  ORDER BY ("count"(*)) DESC;


ALTER VIEW "public"."v_owner_sla_exception_breakdown" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_sla_impact_waterfall" AS
 SELECT "t"."hotel_id",
    "date"("t"."completed_at") AS "day",
    "sd"."name" AS "department_name",
    "count"(*) AS "breached_count"
   FROM ((("public"."tickets" "t"
     JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     JOIN "public"."services" "s" ON (("s"."id" = "t"."service_id")))
     JOIN "public"."departments" "sd" ON (("sd"."id" = "s"."department_id")))
  WHERE (("t"."status" = 'COMPLETED'::"text") AND ("ss"."breached" = true) AND ("t"."completed_at" >= (CURRENT_DATE - '30 days'::interval)) AND (NOT (EXISTS ( SELECT 1
           FROM "public"."ticket_events" "te"
          WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'SLA_EXCEPTION_GRANTED'::"text"))))))
  GROUP BY "t"."hotel_id", ("date"("t"."completed_at")), "sd"."name";


ALTER VIEW "public"."v_owner_sla_impact_waterfall" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_sla_trend_daily" AS
 WITH "daily" AS (
         SELECT "tickets"."hotel_id",
            ("generate_series"((CURRENT_DATE - '29 days'::interval), (CURRENT_DATE)::timestamp without time zone, '1 day'::interval))::"date" AS "day"
           FROM "public"."tickets"
          GROUP BY "tickets"."hotel_id"
        )
 SELECT "d"."hotel_id",
    "d"."day",
    "count"("t"."id") FILTER (WHERE (("ss"."breached" = false) AND (NOT (EXISTS ( SELECT 1
           FROM "public"."ticket_events" "te"
          WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'SLA_EXCEPTION_GRANTED'::"text"))))))) AS "completed_within_sla",
    "count"("t"."id") FILTER (WHERE ("ss"."breached" = true)) AS "breached_sla",
    "count"("t"."id") FILTER (WHERE (EXISTS ( SELECT 1
           FROM "public"."ticket_events" "te"
          WHERE (("te"."ticket_id" = "t"."id") AND ("te"."event_type" = 'SLA_EXCEPTION_GRANTED'::"text"))))) AS "sla_exempted"
   FROM (("daily" "d"
     LEFT JOIN "public"."tickets" "t" ON ((("t"."hotel_id" = "d"."hotel_id") AND ("date"("t"."completed_at") = "d"."day"))))
     LEFT JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
  GROUP BY "d"."hotel_id", "d"."day"
  ORDER BY "d"."day" DESC;


ALTER VIEW "public"."v_owner_sla_trend_daily" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_staff_performance" AS
 SELECT "hm"."hotel_id",
    "date"("t"."completed_at") AS "day",
    "hm"."id" AS "staff_id",
    "p"."full_name",
    "count"(*) FILTER (WHERE ("t"."status" = 'COMPLETED'::"text")) AS "completed_tasks",
    "count"(*) FILTER (WHERE (("t"."status" = 'COMPLETED'::"text") AND ("ss"."breached" = false))) AS "completed_within_sla"
   FROM ((("public"."tickets" "t"
     JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "t"."current_assignee_id")))
     JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
     LEFT JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
  WHERE ("t"."completed_at" >= (CURRENT_DATE - '30 days'::interval))
  GROUP BY "hm"."hotel_id", ("date"("t"."completed_at")), "hm"."id", "p"."full_name";


ALTER VIEW "public"."v_owner_staff_performance" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_owner_ticket_activity" AS
 WITH "daily" AS (
         SELECT "tickets"."hotel_id",
            ("generate_series"((CURRENT_DATE - '29 days'::interval), (CURRENT_DATE)::timestamp without time zone, '1 day'::interval))::"date" AS "day"
           FROM "public"."tickets"
          GROUP BY "tickets"."hotel_id"
        ), "events" AS (
         SELECT "tickets"."hotel_id",
            "date"("tickets"."created_at") AS "day",
            1 AS "created_count",
            0 AS "resolved_count"
           FROM "public"."tickets"
          WHERE ("tickets"."created_at" >= (CURRENT_DATE - '30 days'::interval))
        UNION ALL
         SELECT "tickets"."hotel_id",
            "date"("tickets"."completed_at") AS "day",
            0 AS "created_count",
            1 AS "resolved_count"
           FROM "public"."tickets"
          WHERE (("tickets"."status" = 'COMPLETED'::"text") AND ("tickets"."completed_at" >= (CURRENT_DATE - '30 days'::interval)))
        )
 SELECT "d"."hotel_id",
    "d"."day",
    COALESCE("sum"("e"."created_count"), (0)::bigint) AS "created_count",
    COALESCE("sum"("e"."resolved_count"), (0)::bigint) AS "resolved_count"
   FROM ("daily" "d"
     LEFT JOIN "events" "e" ON ((("e"."hotel_id" = "d"."hotel_id") AND ("e"."day" = "d"."day"))))
  GROUP BY "d"."hotel_id", "d"."day"
  ORDER BY "d"."day" DESC;


ALTER VIEW "public"."v_owner_ticket_activity" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_public_hotels" AS
 SELECT "id",
    "name",
    "slug",
    "description",
    "phone",
    "email",
    "address",
    "city",
    "state",
    "country",
    "postal_code",
