    "status",
    "wa_display_number"
   FROM "public"."hotels"
  WHERE (("status" = 'active'::"text") OR ("status" IS NULL));


ALTER VIEW "public"."v_public_hotels" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_runner_queue" AS
 SELECT "fo"."id" AS "order_id",
    "fo"."display_id",
    "fo"."hotel_id",
    "fo"."room_id",
    "r"."number" AS "room_number",
    "fo"."status",
    "fo"."created_at",
    "fo"."updated_at",
    "sla"."sla_target_at",
    (EXTRACT(epoch FROM (("sla"."sla_target_at")::timestamp with time zone - "now"())) / (60)::numeric) AS "sla_minutes_remaining",
    "ra"."hotel_member_id" AS "assigned_runner",
    COALESCE("p"."full_name", 'Unassigned'::"text") AS "assigned_runner_name",
    "items"."total_items",
    "items"."total_amount",
    "items"."items"
   FROM (((((("public"."food_orders" "fo"
     LEFT JOIN "public"."rooms" "r" ON (("r"."id" = "fo"."room_id")))
     JOIN "public"."food_order_sla_state" "sla" ON (("sla"."food_order_id" = "fo"."id")))
     LEFT JOIN "public"."food_order_assignments" "ra" ON ((("ra"."food_order_id" = "fo"."id") AND ("ra"."role" = 'RUNNER'::"text") AND ("ra"."unassigned_at" IS NULL))))
     LEFT JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "ra"."hotel_member_id")))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
     LEFT JOIN LATERAL ( SELECT "count"(*) AS "total_items",
            "sum"("food_order_items"."total_price") AS "total_amount",
            COALESCE("jsonb_agg"("jsonb_build_object"('id', "food_order_items"."id", 'name', "food_order_items"."item_name", 'quantity', "food_order_items"."quantity", 'modifiers', "food_order_items"."modifiers")) FILTER (WHERE ("food_order_items"."id" IS NOT NULL)), '[]'::"jsonb") AS "items"
           FROM "public"."food_order_items"
          WHERE ("food_order_items"."food_order_id" = "fo"."id")) "items" ON (true))
  WHERE ("fo"."status" = 'READY'::"text")
  GROUP BY "fo"."id", "fo"."display_id", "fo"."hotel_id", "fo"."room_id", "r"."number", "fo"."status", "fo"."created_at", "fo"."updated_at", "sla"."sla_target_at", "ra"."hotel_member_id", "p"."full_name", "items"."total_items", "items"."total_amount", "items"."items";


ALTER VIEW "public"."v_runner_queue" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_staff_runner_tickets" AS
 SELECT "t"."id" AS "ticket_id",
    "t"."display_id",
        CASE
            WHEN ("r"."number" IS NOT NULL) THEN "concat"('Room ', "r"."number")
            ELSE "z"."name"
        END AS "location_label",
    "r"."number" AS "room_number",
    "r"."floor" AS "room_floor",
    "z"."id" AS "zone_id",
    "z"."name" AS "zone_name",
    "t"."hotel_id",
    "t"."title",
    "t"."description",
    "t"."status",
    "t"."reason_code",
    "d"."name" AS "department_name",
    "t"."created_at",
    "t"."current_assignee_id" AS "assigned_staff_id",
    "hm"."user_id" AS "assigned_user_id",
    COALESCE("p"."full_name", 'Auto-queue'::"text") AS "assigned_to_name",
    "sp"."target_minutes" AS "sla_target_minutes",
    "ss"."sla_started_at",
    "ss"."breached" AS "sla_breached",
        CASE
            WHEN ("ss"."sla_started_at" IS NULL) THEN NULL::integer
            ELSE GREATEST((("sp"."target_minutes" * 60) - (((EXTRACT(epoch FROM ("clock_timestamp"() - "ss"."sla_started_at")))::integer - COALESCE("ss"."total_paused_seconds", 0)) -
            CASE
                WHEN ("ss"."sla_paused_at" IS NOT NULL) THEN (EXTRACT(epoch FROM ("clock_timestamp"() - "ss"."sla_paused_at")))::integer
                ELSE 0
            END)), 0)
        END AS "sla_remaining_seconds",
        CASE
            WHEN ("ss"."sla_started_at" IS NULL) THEN 'NOT_STARTED'::"text"
            WHEN ("ss"."breached" = true) THEN 'BREACHED'::"text"
            WHEN ("ss"."sla_paused_at" IS NOT NULL) THEN 'PAUSED'::"text"
            ELSE 'RUNNING'::"text"
        END AS "sla_state",
        CASE
            WHEN ("ss"."sla_started_at" IS NULL) THEN 'Not started'::"text"
            WHEN ("ss"."breached" = true) THEN 'SLA breached'::"text"
            WHEN ("ss"."sla_paused_at" IS NOT NULL) THEN 'SLA paused'::"text"
            ELSE "concat"("ceil"(((GREATEST((("sp"."target_minutes" * 60) - (((EXTRACT(epoch FROM ("clock_timestamp"() - "ss"."sla_started_at")))::integer - COALESCE("ss"."total_paused_seconds", 0)) -
            CASE
                WHEN ("ss"."sla_paused_at" IS NOT NULL) THEN (EXTRACT(epoch FROM ("clock_timestamp"() - "ss"."sla_paused_at")))::integer
                ELSE 0
            END)), 0))::numeric / 60.0)), ' min remaining')
        END AS "sla_label",
        CASE
            WHEN (("t"."status" = 'IN_PROGRESS'::"text") AND ("ss"."sla_paused_at" IS NULL) AND ("ss"."sla_started_at" IS NOT NULL)) THEN ((EXTRACT(epoch FROM ("clock_timestamp"() - "ss"."sla_started_at")))::integer - COALESCE("ss"."total_paused_seconds", 0))
            ELSE NULL::integer
        END AS "active_work_seconds",
        CASE
            WHEN ("ss"."sla_paused_at" IS NOT NULL) THEN (EXTRACT(epoch FROM ("clock_timestamp"() - "ss"."sla_paused_at")))::integer
            ELSE NULL::integer
        END AS "blocked_seconds",
    "t"."created_by_type" AS "requested_by",
        CASE
            WHEN ("t"."status" = 'NEW'::"text") THEN 'START'::"text"
            WHEN ("t"."status" = 'IN_PROGRESS'::"text") THEN 'COMPLETE_OR_BLOCK'::"text"
            WHEN ("t"."status" = 'BLOCKED'::"text") THEN 'UNBLOCK'::"text"
            ELSE 'NONE'::"text"
        END AS "allowed_actions"
   FROM ((((((("public"."tickets" "t"
     LEFT JOIN "public"."departments" "d" ON (("d"."id" = "t"."service_department_id")))
     LEFT JOIN "public"."rooms" "r" ON (("r"."id" = "t"."room_id")))
     LEFT JOIN "public"."hotel_zones" "z" ON (("z"."id" = "t"."zone_id")))
     LEFT JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "t"."current_assignee_id")))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
     LEFT JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     LEFT JOIN "public"."sla_policies" "sp" ON ((("sp"."department_id" = "t"."service_department_id") AND ("sp"."is_active" = true))))
  WHERE ("t"."status" = ANY (ARRAY['NEW'::"text", 'IN_PROGRESS'::"text", 'BLOCKED'::"text"]));


ALTER VIEW "public"."v_staff_runner_tickets" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_staff_shift_board" AS
 SELECT "ss"."id" AS "shift_id",
    "ss"."staff_id",
    "p"."full_name",
    "ss"."shift_start",
    "ss"."shift_end",
    "ss"."shift_type",
    "ss"."status",
    "ss"."zone_id",
    "z"."name" AS "zone_name",
    "ss"."department_id",
    COALESCE("d"."name", 'Unknown'::"text") AS "department_name",
    "ss"."version"
   FROM (((("public"."staff_shifts" "ss"
     JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "ss"."staff_id")))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")))
     LEFT JOIN "public"."hotel_zones" "z" ON (("z"."id" = "ss"."zone_id")))
     LEFT JOIN "public"."departments" "d" ON (("d"."id" = "ss"."department_id")))
  WHERE ("ss"."is_active" = true);


ALTER VIEW "public"."v_staff_shift_board" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_staff_shifts_active" AS
 SELECT "id",
    "staff_id",
    "shift_start",
    "shift_end",
    "is_active",
    "created_at",
    "updated_at",
    "zone_id",
    "shift_type",
    "status",
    "created_by",
    "cancelled_at",
    "version",
    "locked_at",
    "locked_by",
        CASE
            WHEN (("locked_at" IS NOT NULL) AND ("locked_at" > ("now"() - '00:05:00'::interval))) THEN true
            ELSE false
        END AS "is_actively_locked"
   FROM "public"."staff_shifts";


ALTER VIEW "public"."v_staff_shifts_active" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_supervisor_task_header" AS
 SELECT "t"."id" AS "ticket_id",
    "d"."name" AS "task_type",
    "t"."created_by_type" AS "requested_by_type",
        CASE
            WHEN (("t"."created_by_type" = ANY (ARRAY['STAFF'::"text", 'FRONT_DESK'::"text"])) AND ("hm"."id" IS NOT NULL)) THEN "p"."full_name"
            ELSE NULL::"text"
        END AS "requested_by_name",
        CASE
            WHEN "ss"."breached" THEN 'SLA breached'::"text"
            WHEN ("ss"."sla_started_at" IS NULL) THEN 'Not started'::"text"
            ELSE "concat"("ceil"((("ss"."current_remaining_seconds")::numeric / 60.0)), ' min')
        END AS "sla_label",
    "t"."priority",
    "t"."status",
    "t"."reason_code",
    "t"."created_at"
   FROM (((("public"."tickets" "t"
     JOIN "public"."departments" "d" ON (("d"."id" = "t"."service_department_id")))
     LEFT JOIN "public"."ticket_sla_state" "ss" ON (("ss"."ticket_id" = "t"."id")))
     LEFT JOIN "public"."hotel_members" "hm" ON (("hm"."id" = "t"."created_by_id")))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")));


ALTER VIEW "public"."v_supervisor_task_header" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_ticket_timeline" AS
 SELECT "e"."ticket_id",
    "e"."created_at",
        CASE "e"."event_type"
            WHEN 'CREATED'::"text" THEN 'New Task'::"text"
            WHEN 'STARTED'::"text" THEN 'In Progress'::"text"
            WHEN 'BLOCKED'::"text" THEN 'Blocked'::"text"
            WHEN 'COMPLETED'::"text" THEN 'Completed'::"text"
            ELSE "initcap"("e"."event_type")
        END AS "title",
        CASE
            WHEN ("e"."event_type" = 'CREATED'::"text") THEN 'Created'::"text"
            WHEN ("e"."event_type" = 'STARTED'::"text") THEN
            CASE
                WHEN (("e"."actor_type" = ANY (ARRAY['STAFF'::"text", 'FRONT_DESK'::"text"])) AND ("p"."full_name" IS NOT NULL)) THEN ('Started by '::"text" || "p"."full_name")
                WHEN ("e"."actor_type" = 'GUEST'::"text") THEN 'Started by guest'::"text"
                ELSE 'Started'::"text"
            END
            WHEN ("e"."event_type" = 'BLOCKED'::"text") THEN COALESCE("e"."comment", 'Blocked'::"text")
            ELSE "e"."comment"
        END AS "description"
   FROM (("public"."ticket_events" "e"
     LEFT JOIN "public"."hotel_members" "hm" ON ((("hm"."id" = "e"."actor_id") AND ("e"."actor_type" = ANY (ARRAY['STAFF'::"text", 'FRONT_DESK'::"text"])))))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "hm"."user_id")));


ALTER VIEW "public"."v_ticket_timeline" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_user_roles" AS
 SELECT "user_id",
    "role",
    "hotel_id"
   FROM "public"."user_profiles" "u";


ALTER VIEW "public"."v_user_roles" OWNER TO "postgres";


