);


ALTER TABLE "public"."va_audit_logs" OWNER TO "postgres";


CREATE SEQUENCE IF NOT EXISTS "public"."va_audit_logs_id_seq"
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
